update specie set descrizione = 'Il succiamiele del reggente è una specie di uccello passeriforme della famiglia Meliphagidae endemica dell''Australia. È l''unica specie del genere Acanthagenys.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Acanthagenys_rufogularis' where nome_scientifico = 'Acanthagenys rufogularis' and descrizione is null;
update specie set descrizione = 'The peg-billed finch is a passerine bird endemic to the highlands of Costa Rica and western Panama. Despite its name, it is not a true finch, but now recognized as a member of the tanager family (Thraupidae), after being long placed in the Emberizidae. It is the only member of the genus Acanthidops. The scientific name commemorates the American ornithologist Spencer Fullerton Baird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Peg-billed_finch' where nome_scientifico = 'Acanthidops bairdi' and descrizione is null;
