update specie set descrizione = 'Il fuciliere, acantisitta o acantisitta verde è un uccello passeriforme della famiglia degli Acanthisittidae, nell''ambito della quale rappresenta l''unica specie nota del genere Acanthisitta Lafresnaye, 1842.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Acanthisitta_chloris' where nome_scientifico = 'Acanthisitta chloris' and descrizione is null;
update specie set descrizione = 'The inland thornbill was originally described by English ornithologist John Gould in The Birds of Australia. Inland thornbills are within the order passerines. The inland thornbill belongs to the genus Acanthiza, which now has three more species than the eleven outlined by Gould in The Birds of Australia. The Noongar people of southwestern Western Australia call A. apicalis "Djoobi-Djoolbang". The inland thornbill is also known as the broad-tail thornbill and presently contains several subspecies that were once considered independent species. The word apicalis comes from the Latin for ''tipped''.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Inland_thornbill' where nome_scientifico = 'Acanthiza apicalis' and descrizione is null;
update specie set descrizione = 'The yellow-rumped thornbill is a species of passerine bird from the genus Acanthiza. The genus was once placed in the family Pardalotidae but that family was split and it is now in the family Acanthizidae. There are four subspecies of yellow-rumped thornbill. It is a small, brownish bird with a distinctive yellow rump and thin dark bill. It inhabits savannah, scrub and forests across most of Australia and eats insects. The species engages in cooperative breeding.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-rumped_thornbill' where nome_scientifico = 'Acanthiza chrysorrhoa' and descrizione is null;
update specie set descrizione = 'The Tasmanian Thornbill is a small bushland member of the Acanthizidae family, endemic to Tasmania and the Bass Strait Islands. It is a common bird in these regions and is often found occupying the colder, wetter portions of them. The brown thornbill will typically occupy the correspondingly drier portions of habitat.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tasmanian_thornbill' where nome_scientifico = 'Acanthiza ewingii' and descrizione is null;
update specie set descrizione = 'The western thornbill is a species of bird in the family Acanthizidae.
It is endemic to southwestern Australia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_thornbill' where nome_scientifico = 'Acanthiza inornata' and descrizione is null;
update specie set descrizione = 'The striated thornbill is a species of bird in the family Acanthizidae. It is endemic to Australia, where its natural habitat is subtropical or tropical dry forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Striated_thornbill' where nome_scientifico = 'Acanthiza lineata' and descrizione is null;
update specie set descrizione = 'The yellow thornbill, formerly known as the little thornbill, is a tiny passerine bird endemic to the eastern coast of Australia. While currently listed as Least Concern by the IUCN, the general consensus is that the population is decreasing.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow_thornbill' where nome_scientifico = 'Acanthiza nana' and descrizione is null;
update specie set descrizione = 'The brown thornbill is a passerine bird usually found in eastern and south-eastern Australia, including Tasmania. It can grow up to 10 cm (3.9 in) long, and feeds on insects. It is brown, grey and white. The species has five subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_thornbill' where nome_scientifico = 'Acanthiza pusilla' and descrizione is null;
update specie set descrizione = 'The buff-rumped thornbill is a small passerine bird species belonging to the genus 
Acanthiza, most of which are endemic to Australia. Measuring 8–10 cm in length, this unassuming thornbill is characterised by its plain greenish brown upperparts and very pale-yellow underparts, with a distinctive buff coloured rump. The tail has a broad, blackish band with a paler tip. Adults possess white irises, whilst juveniles have dark eyes. The buff-rumped thornbill is one of 14 species within the genus Acanthiza genus, which are recognisable by their thin, pointed bill. Species are unique in their plumage and distribution. Despite their shared name, the genus is not related to hummingbirds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buff-rumped_thornbill' where nome_scientifico = 'Acanthiza reguloides' and descrizione is null;
update specie set descrizione = 'Il becco a spina codacastana, noto anche col nome di beccospino groppacastana, è un uccello della famiglia Acanthizidae diffuso nell''Australia meridionale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Acanthiza_uropygialis' where nome_scientifico = 'Acanthiza uropygialis' and descrizione is null;
update specie set descrizione = 'The western spinebill is a honeyeater found in the heath and woodland of south-western Australia. Ranging between 12–16 centimetres (4.7–6.3 in) long, it weighs around 10 grams (0.35 oz). It has a black head, gray back and wings, with a red band behind its neck and from its throat to its breast. Its curved bill is long and slender.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_spinebill' where nome_scientifico = 'Acanthorhynchus superciliosus' and descrizione is null;
update specie set descrizione = 'The eastern spinebill is a species of honeyeater found in south-eastern Australia in forest and woodland areas, as well as gardens in urban areas of Canberra, Sydney, Melbourne, Adelaide and Hobart. It is around 15 cm long, and has a distinctive black, white and chestnut plumage, a red eye, and a long downcurved bill.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_spinebill' where nome_scientifico = 'Acanthorhynchus tenuirostris' and descrizione is null;
