update specie set descrizione = 'The Burmese myna is a species of starling in the family Sturnidae. It is found in Myanmar and Yunnan, China.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Burmese_myna' where nome_scientifico = 'Acridotheres burmannicus' and descrizione is null;
update specie set descrizione = 'The crested myna, also known as the Chinese starling, is a species of starling in the genus Acridotheres native to southeastern China and Indochina. It is named after the tuft of feathers on its forehead that resembles a crest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crested_myna' where nome_scientifico = 'Acridotheres cristatellus' and descrizione is null;
update specie set descrizione = 'The jungle myna is a myna, a member of the starling family. It is found patchily distributed across much of the mainland of the Indian Subcontinent but absent in the arid zones of India. It is easily recognized by the tuft of feathers on its forehead that form a frontal crest, a feature also found in the closely related Javan myna and the pale-bellied myna which were treated as a subspecies in the past. The eyes are pale, yellow or blue depending on the population and the base of the orange-yellow bill is dark. It has also been introduced either intentionally or accidentally into many other parts of the world including Fiji, Taiwan, the Andaman Islands, and parts of Japan. The species has also spread out on its own to some islands in the Pacific.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Jungle_myna' where nome_scientifico = 'Acridotheres fuscus' and descrizione is null;
update specie set descrizione = 'La maina degli argini è un uccello della famiglia Sturnidae, diffuso in Asia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Acridotheres_ginginianus' where nome_scientifico = 'Acridotheres ginginianus' and descrizione is null;
update specie set descrizione = 'The great myna, also known as the white-vented myna, is a species of starling in the family Sturnidae. Its range extends from Sikkim across Northeast India and Indochina.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Great_myna' where nome_scientifico = 'Acridotheres grandis' and descrizione is null;
update specie set descrizione = 'The Javan myna, also known as the white-vented myna, is a species of myna in the starling family Sturnidae. It is native to Java and Bali in Indonesia, where its population has declined significantly due to excessive trapping for the cage-bird trade. Paradoxically, while the species is considered vulnerable in its native range, it has become a highly successful invasive species in several other countries, most notably Singapore, where it is now the most abundant bird species. The species has been introduced to southeastern Thailand, southern Malaysia, Sumatra, Taiwan, Japan, Nepal, and Puerto Rico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Javan_myna' where nome_scientifico = 'Acridotheres javanicus' and descrizione is null;
update specie set descrizione = 'La maina comune o storno triste è un uccello della famiglia Sturnidae, diffuso in Asia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Acridotheres_tristis' where nome_scientifico = 'Acridotheres tristis' and descrizione is null;
update specie set descrizione = 'Acris crepitans Baird, 1854 è un anfibio della famiglia Hylidae, sottofamiglia Acridinae, endemica del sud-est degli Stati Uniti d''America.
In inglese le rane di questa specie sono comunemente denominate Northern cricket frog.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Acris_crepitans' where nome_scientifico = 'Acris crepitans' and descrizione is null;
update specie set descrizione = 'Acris gryllus è un anfibio della famiglia Hylidae, sottofamiglia Acridinae, endemica del sud-est degli Stati Uniti d''America.
In inglese le rane di questa specie sono comunemente denominate Southern cricket frog.
Sia il nome scientifico sia il nome comune si riferiscono al caratteristico verso, che assomiglia a quello di un grillo.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Acris_gryllus' where nome_scientifico = 'Acris gryllus' and descrizione is null;
update specie set descrizione = 'The pink-legged graveteiro is a species of bird in the family Furnariidae that is endemic to the Atlantic Forest located in the southeast part of Brazil, thriving in local cocoa plantations. As of 2000 the pink-legged graveteiro is listed as a near threatened species. The estimated population of the pink-legged graveteiro is between 2,500 and 9,999 individuals left in the wild. Its main habitat is cocoa plantations. It is the only member of the genus Acrobatornis.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pink-legged_graveteiro' where nome_scientifico = 'Acrobatornis fonsecai' and descrizione is null;
update specie set descrizione = 'The paddyfield warbler is a species of marsh warbler. It was formerly included in the "Old World warbler" assemblage. The Manchurian reed warbler was included in A. agricola as a subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Paddyfield_warbler' where nome_scientifico = 'Acrocephalus agricola' and descrizione is null;
update specie set descrizione = 'Il cannareccione è un uccello passeriforme della famiglia Acrocephalidae, diffuso in quasi tutta Europa, Asia, ed Africa. Ad oggi risulta inserito nella Lista rossa IUCN.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Acrocephalus_arundinaceus' where nome_scientifico = 'Acrocephalus arundinaceus' and descrizione is null;
update specie set descrizione = 'The Australian reed warbler is an Old World warbler in the genus Acrocephalus and is the only Acrocephalus species native to Australia. It has also been observed in Papua New Guinea and nearby islands. The name Acrocephalus refers to the peaked crown found on reed warblers in this genus and can be translated to mean "topmost head" in Greek. The species name australis is translated to mean "southern" in Latin, and refers to the species range, Australia. In its western range the Australian reed warbler is also known as "Koordjikotji" in the local Aboriginal language of Perth and its surrounds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Australian_reed_warbler' where nome_scientifico = 'Acrocephalus australis' and descrizione is null;
update specie set descrizione = 'The common reed warbler or Eurasian reed-warbler is an Old World warbler in the genus Acrocephalus. It breeds across Europe into the temperate western Palaearctic where it is migratory, wintering in sub-Saharan Africa. It is also a resident species over large parts of Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_reed_warbler' where nome_scientifico = 'Acrocephalus baeticatus' and descrizione is null;
update specie set descrizione = 'The black-browed reed warbler is a marsh-warbler in the family Acrocephalidae. It was formerly included in the "Old World warbler" assemblage. The species was first described by Robert Swinhoe in 1860.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-browed_reed_warbler' where nome_scientifico = 'Acrocephalus bistrigiceps' and descrizione is null;
update specie set descrizione = 'The blunt-winged warbler is a marsh-warbler. The species was first described by Robert Swinhoe in 1870. It was formerly included in the "Old World warbler" assemblage.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blunt-winged_warbler' where nome_scientifico = 'Acrocephalus concinens' and descrizione is null;
update specie set descrizione = 'The lesser swamp warbler or Cape reed warbler is an Old World warbler in the genus Acrocephalus. It is sparsely present across sub-Saharan Africa, a common species of reedbeds in standing water.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_swamp_warbler' where nome_scientifico = 'Acrocephalus gracilirostris' and descrizione is null;
