update specie set descrizione = 'The Oriental reed warbler is a passerine bird of eastern Asia belonging to the reed warbler genus Acrocephalus. It was formerly classified as a subspecies of the great reed warbler of the western Palearctic.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Oriental_reed_warbler' where nome_scientifico = 'Acrocephalus orientalis' and descrizione is null;
