update specie set descrizione = 'The greater swamp warbler is a species of Old World warbler in the family Acrocephalidae. It is found in the African countries of Angola, Botswana, Burundi, Cameroon, Central African Republic, Chad, Republic of the Congo, Democratic Republic of the Congo, Equatorial Guinea, Gabon, Ghana, Kenya, Mali, Mauritania, Namibia, Nigeria, Rwanda, Senegal, South Sudan, Tanzania, Togo, Uganda, Zambia, and Zimbabwe. Its natural habitat is swamps.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greater_swamp_warbler' where nome_scientifico = 'Acrocephalus rufescens' and descrizione is null;
