update specie set descrizione = 'The clamorous reed warbler is an Old World warbler in the genus Acrocephalus. It breeds from Egypt eastwards through Pakistan, Afghanistan and northernmost India to south China and southeast Asia. A. s. meridionalis is an endemic race in Sri Lanka.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Clamorous_reed_warbler' where nome_scientifico = 'Acrocephalus stentoreus' and descrizione is null;
update specie set descrizione = 'The Manchurian reed warbler, also known as the Manchurian reed-warbler, is a species of marsh-warbler. It was formerly included in the "Old World warbler" assemblage, and was usually treated as a subspecies of the paddyfield warbler. It is found in Cambodia, China, Hong Kong, South Korea, Laos, Russia, Thailand, Vietnam, Malaysia and possibly Myanmar. Its natural habitat is swamps. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Manchurian_reed_warbler' where nome_scientifico = 'Acrocephalus tangorum' and descrizione is null;
update specie set descrizione = 'The ocellated tapaculo is a large bird found in the northern Andes in South America. It is a highly distinctive tapaculo; traditionally united with its closest relatives in the Rhinocryptidae, this family is paraphyletic with the Formicariidae (ground-antbirds) but instead of merging the tapaculos with the ground-antbird family, recent sources tend to split the antpittas from the Formicariidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ocellated_tapaculo' where nome_scientifico = 'Acropternis orthonyx' and descrizione is null;
update specie set descrizione = 'The rufous-collared kingfisher is a species of bird in the family Alcedinidae.
It is found in Brunei, Indonesia, Malaysia, Myanmar, and Thailand.
Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.
It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-collared_kingfisher' where nome_scientifico = 'Actenoides concretus' and descrizione is null;
update specie set descrizione = 'The spotted wood kingfisher or spotted kingfisher is a species of bird in the family Alcedinidae. It is endemic to the Philippines found on the islands of Luzon, Catanduanes, Marinduque, Negros and Panay where its natural habitat is tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spotted_wood_kingfisher' where nome_scientifico = 'Actenoides lindsayi' and descrizione is null;
