update specie set descrizione = 'The northern saw-whet owl is a species of small owl in the family Strigidae. The species is native to North America. Saw-whet owls of the genus Aegolius are some of the smallest owl species in North America. They can be found in dense thickets, often at eye level, although they can also be found some 20 ft (6.1 m) up. Saw-whets are often in danger of being preyed upon by larger birds of prey. The northern saw-whet owl is a migratory bird without any strict pattern.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_saw-whet_owl' where nome_scientifico = 'Aegolius acadicus' and descrizione is null;
