update specie set descrizione = 'The edible-nest swiftlet, also known as the white-nest swiftlet, is a small bird of the swift family which is found in Southeast Asia. Its opaque and whitish nest is made exclusively of solidified saliva and is the main ingredient of bird''s nest soup, a delicacy of Chinese cuisine. Germain''s swiftlet is now treated as conspecific with this species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Edible-nest_swiftlet' where nome_scientifico = 'Aerodramus fuciphagus' and descrizione is null;
