update specie set descrizione = 'The crimson sunbird is a species of bird in the sunbird family which feed largely on nectar. They may also take insects, especially when feeding their young. Flight is fast and direct on their short wings. Most species can take nectar by hovering like a hummingbird, but usually perch to feed. It is the unofficial national bird of Singapore, as declared by the Nature Society Singapore.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson_sunbird' where nome_scientifico = 'Aethopyga siparaja' and descrizione is null;
