update specie set descrizione = 'The grayish baywing, formerly known as the bay-winged cowbird, is a species of bird in the family Icteridae. It is currently placed in the genus Agelaioides but has traditionally been placed in the genus Molothrus. It is found in the northern half of Argentina, Bolivia, Uruguay, Paraguay and southern and central Brazil, The isolated population in north-eastern Brazil is usually now considered a separate species, the pale baywing. The greyish baywing has been recorded as a vagrant in Chile.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grayish_baywing' where nome_scientifico = 'Agelaioides badius' and descrizione is null;
