update specie set descrizione = 'The pale-eyed blackbird is a species of bird in the family Icteridae. It is found in Ecuador and Peru where its natural habitat is swamps. An inconspicuous bird of very local occurrence, it was first described in 1969 by American ornithologist Lester L. Short.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale-eyed_blackbird' where nome_scientifico = 'Agelasticus xanthophthalmus' and descrizione is null;
