update specie set descrizione = 'The Turkestan short-toed lark is a species of lark in the family Alaudidae. It is found in Ukraine and central Turkey through parts of Central Asia and southern Siberia west to south-central Mongolia and south to southern Afghanistan. This species and the Mediterranean short-toed lark were formerly considered conspecific and called the lesser short-toed lark, but a 2020 study recovered them as distinct species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Turkestan_short-toed_lark' where nome_scientifico = 'Alaudala heinei' and descrizione is null;
