update specie set descrizione = 'The brown-cheeked fulvetta is a babbler-like bird belonging to the family Leiothrichidae found in the forests of South and Southeast Asia. It was formerly called the quaker babbler in India and common nun babbler in Malaya. They forage on trees for insects, sometimes hanging from the branches in a tit-like manner, and visiting flowers for nectar. They are often hard to see in vegetation but they have loud multi-note whistling calls in the morning and afternoon.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-cheeked_fulvetta' where nome_scientifico = 'Alcippe poioicephala' and descrizione is null;
