update specie set descrizione = 'The tawny-headed swallow is a species of bird in the family Hirundinidae. It is the only species placed in the genus Alopochelidon. It is found in Argentina, Bolivia, Brazil, Colombia, Falkland Islands, Paraguay, Peru, Uruguay, and Venezuela, where its natural habitats are dry savanna and subtropical or tropical seasonally wet or flooded lowland grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tawny-headed_swallow' where nome_scientifico = 'Alopochelidon fucata' and descrizione is null;
update specie set descrizione = 'The Egyptian goose is an African member of the Anatidae family including ducks, geese, and swans. Because of their popularity chiefly as an ornamental bird, the species has also been introduced to Europe, the United States and elsewhere outside their natural range. Egyptian geese were regularly represented in ancient Egyptian art.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Egyptian_goose' where nome_scientifico = 'Alopochen aegyptiaca' and descrizione is null;
update specie set descrizione = 'The Yucatán black howler, or Guatemalan black howler, is a species of howler monkey, a type of New World monkey, from Central America. It is found in Belize, Guatemala and Mexico, in and near the Yucatán Peninsula. It lives in evergreen, semideciduous and lowland rain forests. It is also known as the baboon in Belize, although it is not closely related to the baboons in Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yucat%C3%A1n_black_howler' where nome_scientifico = 'Alouatta pigra' and descrizione is null;
