update specie set descrizione = 'The red avadavat, red munia or strawberry finch, is a sparrow-sized bird of the family Estrildidae. It is found in the open fields and grasslands of tropical Asia and is popular as a cage bird due to the colourful plumage of the males in their breeding season. It breeds in the Indian subcontinent in the monsoon season. The species name of amandava and the common name of avadavat are derived from the city of Ahmedabad in Gujarat, India, from where these birds were exported into the pet trade in former times.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red_avadavat' where nome_scientifico = 'Amandava amandava' and descrizione is null;
update specie set descrizione = 'The uniform crake is a species of bird in the subfamily Rallinae of the rail, crake, and coot family Rallidae. It is found in Mexico, most of Central America, and in nine South American countries.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Uniform_crake' where nome_scientifico = 'Amaurolimnas concolor' and descrizione is null;
update specie set descrizione = 'The isabelline bush-hen, also known as Sulawesi waterhen or isabelline waterhen, is a large, up to 40 cm long, rufous and brown rail. The term isabelline refers to the colouration. It is the largest member of the genus Amaurornis. Both sexes are similar with olive brown plumage, pale green bill, greenish brown legs and rufous below.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Isabelline_bush-hen' where nome_scientifico = 'Amaurornis isabellina' and descrizione is null;
