update specie set descrizione = 'The blue seedeater or Cabanis''s seedeater is a species of bird in the cardinal family that is found in southern Mexico and Central America. The Ecuadorian seedeater was formerly considered a subspecies of the blue seedeater.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue_seedeater' where nome_scientifico = 'Amaurospiza concolor' and descrizione is null;
