update specie set descrizione = 'The Honduran emerald is a vulnerable species of hummingbird in the "emeralds" tribe, Trochilini, of the subfamily Trochilinae. It is endemic to Honduras.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Honduran_emerald' where nome_scientifico = 'Amazilia luciae' and descrizione is null;
update specie set descrizione = 'The cinnamon hummingbird is a species of hummingbird in the tribe of the ''emeralds'', Trochilini. Currently, four regional subspecies are recognized.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cinnamon_hummingbird' where nome_scientifico = 'Amazilia rutila' and descrizione is null;
