update specie set descrizione = 'The amazilia hummingbird is a hummingbird in the "emeralds", tribe Trochilini of subfamily Trochilinae. It is the only species placed in the genus Amazilis. It is found in Ecuador and Peru. Its six subspecies differ primarily in their throat and belly colors.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Amazilia_hummingbird' where nome_scientifico = 'Amazilis amazilia' and descrizione is null;
update specie set descrizione = 'L''amazzone fronteblu è un uccello della famiglia degli Psittacidi. È una specie molto diffusa in natura. È tra le specie più popolari in cattività. Si riproduce bene, è un egregio animale da compagnia, anche se molto chiassoso, ed è un’ottima parlatrice.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Amazona_aestiva' where nome_scientifico = 'Amazona aestiva' and descrizione is null;
update specie set descrizione = 'L''amazzone becconero è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Amazona_agilis' where nome_scientifico = 'Amazona agilis' and descrizione is null;
update specie set descrizione = 'L''amazzone frontebianca è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Amazona_albifrons' where nome_scientifico = 'Amazona albifrons' and descrizione is null;
update specie set descrizione = 'The orange-winged amazon, also known as orange-winged parrot and loro guaro, is a large amazon parrot. It is a resident breeding bird in tropical South America, from Colombia, Trinidad and Tobago south to Peru, Bolivia and central Brazil. Its habitat is forest and semi-open country. Although common, it is persecuted as an agricultural pest and by capture for the pet trade. It is also hunted as a food source. Introduced breeding populations have been reported in Puerto Rico and Tenerife in the Canary Islands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-winged_amazon' where nome_scientifico = 'Amazona amazonica' and descrizione is null;
update specie set descrizione = 'The yellow-naped amazon or yellow-naped parrot is a widespread amazon parrot sometimes considered to be a subspecies of the yellow-crowned amazon. It inhabits the Pacific coast of southern Mexico and Central America. It has recently been reclassified as Critically Endangered by the IUCN Red List due to a dramatic decline across the extent of its range. Yellow-naped amazons have lost more than 92% of their population over the last three generations.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-naped_amazon' where nome_scientifico = 'Amazona auropalliata' and descrizione is null;
update specie set descrizione = 'The red-lored amazon or red-lored parrot is a species of amazon parrot, native to tropical regions of the Americas, from eastern Mexico south to Ecuador where it occurs in humid evergreen to semi-deciduous forests up to 1,100 m altitude. It is absent from the Pacific side of Central America north of Costa Rica. Not originally known from El Salvador, a pair - perhaps escaped from captivity - nested successfully in 1995 and 1996 in the outskirts of San Salvador and the species might expand its range permanently into that country in the future. This species has also established feral populations in several California cities.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-lored_amazon' where nome_scientifico = 'Amazona autumnalis' and descrizione is null;
update specie set descrizione = 'The red-tailed amazon, also known as the red-tailed parrot, is a species of parrot in the family Psittacidae. It is native to the Serra do Mar coastal forests. The bird has been threatened by habitat loss and capture for the wild bird trade, and is a symbol of the efforts to conserve one of the Earth''s most biologically diverse ecosystems. Consequently, it is considered Near Threatened by BirdLife International and the IUCN. In 1991–92, the population had fallen below 2000 individuals. Following on-going conservation efforts, a count and estimate from 2015 suggests a population of 9,000–10,000, indicating that this species is recovering from earlier persecution. A recent study shows that the population of this species is stable at Paraná state, Southern Brazil, revealing population trend fluctuation during the last 12 years.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-tailed_amazon' where nome_scientifico = 'Amazona brasiliensis' and descrizione is null;
update specie set descrizione = 'The blue-cheeked amazon, also known as blue-cheeked parrot or Dufresne''s amazon, is a Near Threatened species of bird in subfamily Arinae of the family Psittacidae, the African and New World parrots. It is found in Brazil, the Guianas, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-cheeked_amazon' where nome_scientifico = 'Amazona dufresniana' and descrizione is null;
update specie set descrizione = 'The mealy amazon or mealy parrot is among the largest parrots in the genus Amazona, the amazon parrots. It is a mainly green parrot with a total length of 38–41 cm (15–16 in). It is native to tropical Central and South America. This species, the southern mealy amazon, the northern mealy amazon are considered conspecific.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mealy_amazon' where nome_scientifico = 'Amazona farinosa' and descrizione is null;
