update specie set descrizione = 'The thick-billed weaver, or grosbeak weaver, is a distinctive and bold species of weaver bird that is native to the Afrotropics. It belongs to the monotypic genus Amblyospiza and subfamily Amblyospizinae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Thick-billed_weaver' where nome_scientifico = 'Amblyospiza albifrons' and descrizione is null;
update specie set descrizione = 'The scarlet-headed blackbird is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Argentina, Bolivia, Brazil, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet-headed_blackbird' where nome_scientifico = 'Amblyramphus holosericeus' and descrizione is null;
update specie set descrizione = 'The yellow-browed sparrow is a species of bird in the family Passerellidae. First described by Johann Baptist von Spix in 1825, this American sparrow is found across much of the Amazon basin in South America. Its natural habitats are subtropical or tropical moist shrubland, pastureland, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-browed_sparrow' where nome_scientifico = 'Ammodramus aurifrons' and descrizione is null;
update specie set descrizione = 'The grassland sparrow is a species of bird in the family Passerellidae. It is found in Argentina, Bolivia, Brazil, Colombia, French Guiana, Guyana, Paraguay, Peru, Suriname, Uruguay, and Venezuela. Its natural habitats are dry savannah, subtropical or tropical seasonally wet or flooded lowland grassland, and pastureland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grassland_sparrow' where nome_scientifico = 'Ammodramus humeralis' and descrizione is null;
update specie set descrizione = 'The grasshopper sparrow is a small New World sparrow. It belongs to the genus Ammodramus, which contains three species that inhabit grasslands and prairies. Grasshopper sparrows are sometimes found in crop fields and they will readily colonize reclaimed grassland. In the core of their range, grasshopper sparrows are dependent upon large areas of grassland where they avoid trees and shrubs. They seek out heterogenous patches of prairie that contain clumps of dead grass or other vegetation where they conceal their nest, and also contain barer ground where they forage for insects, spiders, and seeds. Grasshopper sparrows are unusual among New World sparrows in that they sing two distinct song types, the prevalence of which varies with the nesting cycle. The primary male song, a high trill preceded by a stereotyped series of short chips, is reminiscent of the sounds of grasshoppers and is the origin of this species'' name. Like some other birds of the central North American grasslands, this species also moves around a lot, not only via annual migrations, but individuals frequently disperse between breeding attempts or breeding seasons. Grasshopper sparrows are in steep decline across their range, even in the core of the breeding distribution in the tallgrass prairies of the central Great Plains. The Florida grasshopper sparrow is highly endangered.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grasshopper_sparrow' where nome_scientifico = 'Ammodramus savannarum' and descrizione is null;
update specie set descrizione = 'The bar-tailed lark or bar-tailed desert lark is a species of lark in the family Alaudidae. Two other species, the rufous-tailed lark and the Cape clapper lark are both also sometimes referred to using the name bar-tailed lark. It is found from Morocco to Pakistan. Its natural habitat is hot deserts. This is in many places a common species, but elsewhere rather less common. It has a very wide distribution and faces no obvious threats, but surveys have shown that it is slowly decreasing in numbers. The International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bar-tailed_lark' where nome_scientifico = 'Ammomanes cinctura' and descrizione is null;
update specie set descrizione = 'The desert lark breeds in deserts and semi-deserts from Morocco to western India. It has a very wide distribution and faces no obvious threats, and surveys have shown that it is slowly increasing in numbers as it expands its range. The International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Desert_lark' where nome_scientifico = 'Ammomanes deserti' and descrizione is null;
update specie set descrizione = 'The rufous-tailed lark, also sometimes called the rufous-tailed finch-lark, is a ground bird found in the drier open stony habitats of India and parts of Pakistan. Like other species in the genus it has a large finch-like bill with a slightly curved edge to the upper mandible. The dull brown colour matches the soil as it forages for grass seeds, grain and insects. Males and females are indistinguishable in the field but during the breeding season, the male has a courtship display that involves flying up steeply and then nose-diving and pulling up in a series of stepped wavy dips accompanied by calling. They forage on the ground in pairs or small groups.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-tailed_lark' where nome_scientifico = 'Ammomanes phoenicura' and descrizione is null;
update specie set descrizione = 'The grey-bellied antbird is a species of passerine bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found Brazil, Colombia, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-bellied_antbird' where nome_scientifico = 'Ammonastes pelzelni' and descrizione is null;
update specie set descrizione = 'The saltmarsh sparrow is a small New World sparrow found in salt marshes along the Atlantic coast of the United States. At one time, this bird and the Nelson''s sparrow were thought to be a single species, the sharp-tailed sparrow. Because of this, the species was briefly known as the "saltmarsh sharp-tailed sparrow." Saltmarsh sparrow numbers are declining due to habitat loss largely attributed to human activity.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Saltmarsh_sparrow' where nome_scientifico = 'Ammospiza caudacuta' and descrizione is null;
update specie set descrizione = 'The seaside sparrow is a species of American sparrow.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Seaside_sparrow' where nome_scientifico = 'Ammospiza maritima' and descrizione is null;
update specie set descrizione = 'The scaled fruiteater is a species of bird in the family Cotingidae. It is the only member of the genus Ampelioides. This bird is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela, where its natural habitat is the high elevation tropical forests of the Andes mountains. The scaled fruiteater is a chunky, short-tailed, flat-headed bird measuring 19–20 cm (7.5–7.9 in) in length. It uses its green scaled feather pattern to blend in with the dense vegetation of the South American rainforest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scaled_fruiteater' where nome_scientifico = 'Ampelioides tschudii' and descrizione is null;
update specie set descrizione = 'The red-crested cotinga is a species of bird in the family Cotingidae. It is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-crested_cotinga' where nome_scientifico = 'Ampelion rubrocristatus' and descrizione is null;
