update specie set descrizione = 'The grey-headed antbird is a near threatened species of bird in the subfamily Thamnophilinae of the family Thamnophilidae, the "typical antbirds". It is found in Ecuador and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-headed_antbird' where nome_scientifico = 'Ampelornis griseiceps' and descrizione is null;
