update specie set descrizione = 'The scaly-throated foliage-gleaner, also known as the spectacled foliage-gleaner, is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Mexico, in every Central American country except Nicaragua, and in Colombia and Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scaly-throated_foliage-gleaner' where nome_scientifico = 'Anabacerthia variegaticeps' and descrizione is null;
update specie set descrizione = 'The bamboo foliage-gleaner, also known as the crested foliage-gleaner or dusky-cheeked foliage-gleaner, is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Bolivia, Brazil, Colombia, Ecuador, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bamboo_foliage-gleaner' where nome_scientifico = 'Anabazenops dorsalis' and descrizione is null;
