update specie set descrizione = 'The ash-breasted tit-tyrant is a vulnerable species of bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Bolivia and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ash-breasted_tit-tyrant' where nome_scientifico = 'Anairetes alpinus' and descrizione is null;
update specie set descrizione = 'The yellow-billed tit-tyrant is a species of bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Bolivia, Chile, Peru, and as a vagrant in Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-billed_tit-tyrant' where nome_scientifico = 'Anairetes flavirostris' and descrizione is null;
update specie set descrizione = 'The black-crested tit-tyrant or Marañón tit-tyrant is a species of bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Ecuador and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-crested_tit-tyrant' where nome_scientifico = 'Anairetes nigrocristatus' and descrizione is null;
update specie set descrizione = 'The tufted tit-tyrant is a species of bird in the tyrant flycatcher family Tyrannidae. This species is found in western South America; its range stretches from southern Colombia south along the Andes mountains to Tierra del Fuego. It prefers to live in upper montane forests and shrublands; however, it is a habitat generalist and can be found across a wide range of ecosystems. The tufted tit-tyrant has three subspecies, including the nominate subspecies Anairetes parulus parulus, A. p. aequatorialis, and A. p. patagonicus, and is very closely related to the Juan Fernández tit-tyrant. It is very small with a distinctive and conspicuous crest. The bird''s head is black overall with white supraloral and postocular stripes. Its dull grayish-brown back contrasts with its white throat and breast that are covered with black streaks and pale, unmarked yellow underbelly. There are few noticeable differences in plumage between the subspecies. It is a vocal flycatcher with a broad repertoire of songs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tufted_tit-tyrant' where nome_scientifico = 'Anairetes parulus' and descrizione is null;
update specie set descrizione = 'The pied-crested tit-tyrant is a species of bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Chile and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pied-crested_tit-tyrant' where nome_scientifico = 'Anairetes reguloides' and descrizione is null;
update specie set descrizione = 'Il codone comune è un uccello della famiglia delle Anatidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anas_acuta' where nome_scientifico = 'Anas acuta' and descrizione is null;
update specie set descrizione = 'L’anatra delle Ande è un uccello della famiglia degli Anatidi, diffuso in America del Sud.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anas_andium' where nome_scientifico = 'Anas andium' and descrizione is null;
update specie set descrizione = 'The chestnut teal is a dabbling duck found in Australia. It is protected under the National Parks and Wildlife Act 1974.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut_teal' where nome_scientifico = 'Anas castanea' and descrizione is null;
update specie set descrizione = 'The Eurasian teal, common teal, or Eurasian green-winged teal is a common and widespread duck that breeds in temperate Eurosiberia and migrates south in winter. The Eurasian teal is often called simply the teal due to being the only one of these small dabbling ducks in much of its range. The bird gives its name to the blue-green colour teal.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eurasian_teal' where nome_scientifico = 'Anas crecca' and descrizione is null;
update specie set descrizione = 'The Mexican duck is a species of dabbling duck that breeds in Mexico and the southwestern United States.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mexican_duck' where nome_scientifico = 'Anas diazi' and descrizione is null;
update specie set descrizione = 'The yellow-billed teal is a South American species of duck. Like other teals, it belongs to the diverse genus Anas; more precisely it is one of the "true" teals of subgenus Nettion. It occurs in Argentina, the Falkland Islands, Chile, Peru, Bolivia, Uruguay, and Brazil. It has also established itself in South Georgia, where it was first recorded breeding in 1971, and has been recorded as far east as Tristan da Cunha. It inhabits freshwater wetlands, preferring palustrine habitat to rivers. Considering its wide range and local abundance, it is not considered threatened by the IUCN.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-billed_teal' where nome_scientifico = 'Anas flavirostris' and descrizione is null;
update specie set descrizione = 'Il germano maculato è un uccello della famiglia degli Anatidi. A volte viene confuso o considerato erroneamente come una sottospecie del germano reale o del germano nero americano.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anas_fulvigula' where nome_scientifico = 'Anas fulvigula' and descrizione is null;
update specie set descrizione = 'Il codone beccogiallo, anche anatra dal becco giallo è un uccello della famiglia degli Anatidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anas_georgica' where nome_scientifico = 'Anas georgica' and descrizione is null;
