update specie set descrizione = 'Il germano beccogiallo è un''anatra di superficie; è una specie stanziale molto numerosa in Africa meridionale e orientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anas_undulata' where nome_scientifico = 'Anas undulata' and descrizione is null;
update specie set descrizione = 'Il germano delle Hawaii è un uccello della famiglia degli Anatidi endemico delle Hawaii. Attualmente vive nell''isola Kauai e Niihau ed è stata rientrodotta sulle isole Oahu, Hawaii e Maui; secondo la Lista rossa IUCN è in pericolo di estinzione (Endangered).', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anas_wyvilliana' where nome_scientifico = 'Anas wyvilliana' and descrizione is null;
