update specie set descrizione = 'Il rospo americano è un anfibio della famiglia Bufonidae, nativo degli Stati Uniti d''America e del Canada.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anaxyrus_americanus' where nome_scientifico = 'Anaxyrus americanus' and descrizione is null;
update specie set descrizione = 'The Yosemite toad is a species of true toad in the family Bufonidae. Endemic to the Sierra Nevada of California, the species ranges from the Alpine County to Fresno County. Yosemite toads are only found in the montane to subalpine elevational zone of 1,950–3,445 m (6,398–11,302 ft) asl. The Yosemite toad is similar to the nearby western toad, but in many ways adapted to a high elevation lifestyle. It was initially described during the Grinnell Survey of California, by an undergraduate student of Joseph Grinnell named Charles Camp.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yosemite_toad' where nome_scientifico = 'Anaxyrus canorus' and descrizione is null;
update specie set descrizione = 'The Great Plains toad is a relatively large species of true toad native to central North America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Great_Plains_toad' where nome_scientifico = 'Anaxyrus cognatus' and descrizione is null;
update specie set descrizione = 'The Houston toad, formerly Bufo houstonensis, is an endangered species of amphibian that is endemic to Texas in the United States. This toad was discovered in the late 1940s and named in 1953. It was among the first amphibians added to the United States List of Endangered Native Fish and Wildlife and is currently protected by the Endangered Species Act of 1973 as an endangered species. The Houston toad was placed as "endangered" on the IUCN Red List of Threatened Species from 1986 to 2022, and has worsened to "critically endangered" since then, with fewer than 250 mature individuals believed to remain in the wild as of 2021. Their kind is threatened every day as they continue to suffer from a loss of habitat and extreme drought. Their typical life expectancy is at least 3 years but it may exceed this number.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Houston_toad' where nome_scientifico = 'Anaxyrus houstonensis' and descrizione is null;
update specie set descrizione = 'The Arizona toad is a species of toad in the family Bufonidae. It is endemic to the south-western United States, where its natural habitats are temperate lowland forests, rivers and streams, swamps, freshwater marshes, freshwater springs, ponds, open excavations, irrigated land, and seasonally flooded agricultural land.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Arizona_toad' where nome_scientifico = 'Anaxyrus microscaphus' and descrizione is null;
update specie set descrizione = 'The oak toad is a species of toad in the family Bufonidae. It is endemic to the coastal regions of southeastern United States. It is regarded as the smallest species of toad in North America, with a length of 19 to 33 mm.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Oak_toad' where nome_scientifico = 'Anaxyrus quercicus' and descrizione is null;
update specie set descrizione = 'The Texas toad is a species of medium-sized toad that occurs in the southern United States and northern Mexico. It breeds in temporary water pools after heavy rains.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Texas_toad' where nome_scientifico = 'Anaxyrus speciosus' and descrizione is null;
update specie set descrizione = 'The southern toad is a true toad native to the southeastern United States, from eastern Louisiana and southeastern Virginia south to Florida, where it is the largest toad found in that range. It often lives in areas with sandy soils. It is nocturnal and spends the day in a burrow. Its coloring is usually brown but can be red, gray, or black. It is approximately 8 cm (3 inches) long.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_toad' where nome_scientifico = 'Anaxyrus terrestris' and descrizione is null;
update specie set descrizione = 'The chestnut-winged hookbill is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Bolivia, Brazil, Colombia, Ecuador, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-winged_hookbill' where nome_scientifico = 'Ancistrops strigilatus' and descrizione is null;
update specie set descrizione = 'The grey-breasted mountain toucan is a least-concern species of bird in the toucan family, Ramphastidae. It is found in South American countries such as Colombia, Ecuador and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-breasted_mountain_toucan' where nome_scientifico = 'Andigena hypoglauca' and descrizione is null;
update specie set descrizione = 'The plate-billed mountain toucan is a species of bird in the family Ramphastidae. It is native to the west slope of Ecuador and extreme southern Colombia, where it lives in the high-altitude humid mountain forests of the Andes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plate-billed_mountain_toucan' where nome_scientifico = 'Andigena laminirostris' and descrizione is null;
update specie set descrizione = 'The black-billed mountain toucan is a species of bird in the toucan family Ramphastidae. It is found in Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-billed_mountain_toucan' where nome_scientifico = 'Andigena nigrirostris' and descrizione is null;
update specie set descrizione = 'Il colibrì dentato è un uccello della famiglia Trochilidae. È l''unica specie nota del genere Androdon.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Androdon_aequatorialis' where nome_scientifico = 'Androdon aequatorialis' and descrizione is null;
update specie set descrizione = 'The sombre greenbul is a member of the bulbul family of passerine birds. It is a resident breeder in coastal bush, evergreen forest and dry shrub land in eastern and southern Africa. It is the only member of the genus Andropadus.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sombre_greenbul' where nome_scientifico = 'Andropadus importunus' and descrizione is null;
update specie set descrizione = 'Il kamichi cornuto o palamedea cornuta è un uccello anseriforme appartenente alla famiglia Anhimidae, diffuso nelle zone tropicali umide del Sudamerica. Rappresenta l''unica specie del genere Anhima Brisson, 1760.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anhima_cornuta' where nome_scientifico = 'Anhima cornuta' and descrizione is null;
update specie set descrizione = 'L''aninga comune, conosciuta anche come aninga americana o uccello serpente, è un grosso uccello americano appartenente all''ordine dei Suliformes.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anhinga_anhinga' where nome_scientifico = 'Anhinga anhinga' and descrizione is null;
update specie set descrizione = 'L''aninga asiatica anche detta aninga orientale, è un uccello appartenente alla famiglia Anhingidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anhinga_melanogaster' where nome_scientifico = 'Anhinga melanogaster' and descrizione is null;
update specie set descrizione = 'L''aninga australiana è un uccello appartenente alla famiglia Anhingidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anhinga_novaehollandiae' where nome_scientifico = 'Anhinga novaehollandiae' and descrizione is null;
update specie set descrizione = 'The scarlet-bellied mountain tanager is a species of bird in the family Thraupidae. It is found in Andean forest, woodland and shrub in Bolivia, Colombia, Ecuador, Peru, and Venezuela. It is sometimes split into two species: The scarlet-bellied mountain tanager ranging north from central Peru, and the fire-bellied mountain tanager ranging south from central Peru. The latter has a lighter, more orangish belly than the former.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet-bellied_mountain_tanager' where nome_scientifico = 'Anisognathus igniventris' and descrizione is null;
update specie set descrizione = 'The lacrimose mountain tanager is a species of bird in the family Thraupidae. It is found in Andean highland forest from Venezuela, through Colombia and Ecuador, to Peru. Some of its 11 subspecies are quite distinctive and A. l. yariguierum was only scientifically described in 2010.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lacrimose_mountain_tanager' where nome_scientifico = 'Anisognathus lacrymosus' and descrizione is null;
update specie set descrizione = 'The blue-winged mountain tanager is a species of bird in the family Thraupidae, the tanagers. It is found in highland forest and woodland in the Andes of Bolivia, Colombia, Ecuador, Peru and Venezuela, as well as a disjunct population in the Venezuelan Coastal Range. It is a common species and its populations appear to be stable. It is generally bright yellow and black with blue to the wings and tail; some populations have a moss-green back. In Bolivia and southernmost Peru, the rump is blue and the voice is very different; this population is sometimes recognized as a separate species, the Bolivian mountain tanager.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-winged_mountain_tanager' where nome_scientifico = 'Anisognathus somptuosus' and descrizione is null;
update specie set descrizione = 'The hyacinth macaw, or hyacinthine macaw, is a parrot native to central and eastern South America. With a length of about one meter it is longer than any other species of parrot. It is the largest macaw and the largest flying parrot species. While generally easily recognized, it could be confused with the smaller Lear''s macaw. Habitat loss and the trapping of wild birds for the pet trade have taken a heavy toll on their population in the wild, so the species is classified as Vulnerable on the International Union for Conservation of Nature''s Red List, and it is protected by its listing on Appendix I of the Convention on International Trade in Endangered Species of Wild Fauna and Flora (CITES).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hyacinth_macaw' where nome_scientifico = 'Anodorhynchus hyacinthinus' and descrizione is null;
update specie set descrizione = 'Lear''s macaw, also known as the indigo macaw, is a large all-blue Brazilian parrot, a member of a large group of neotropical parrots known as macaws. It was first described by Charles Lucien Bonaparte in 1856. Lear''s macaw is 70–75 cm long and weighs around 950 g. It is coloured almost completely blue, with a yellow patch of skin at the base of the heavy, black bill.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lear''s_macaw' where nome_scientifico = 'Anodorhynchus leari' and descrizione is null;
update specie set descrizione = 'The bushy-crested hornbill is a bird in the hornbill family. It is found in Brunei, Indonesia, Malaysia, Myanmar, and Thailand.
Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bushy-crested_hornbill' where nome_scientifico = 'Anorrhinus galeritus' and descrizione is null;
update specie set descrizione = 'The blue noddy or hinaokū or manuohina is a seabird in the family Laridae. It is also known as the blue-grey noddy.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue_noddy' where nome_scientifico = 'Anous ceruleus' and descrizione is null;
update specie set descrizione = 'The black noddy, also known as white-capped noddy, is a species of tern in the family Laridae. It is a medium-sized seabird with black plumage and a white cap that closely resembles the lesser noddy with which it was at one time considered conspecific. The black noddy has slightly darker plumage and dark rather than pale lores.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_noddy' where nome_scientifico = 'Anous minutus' and descrizione is null;
update specie set descrizione = 'La sterna stolida, è un uccello della famiglia dei Laridae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anous_stolidus' where nome_scientifico = 'Anous stolidus' and descrizione is null;
