update specie set descrizione = 'L''oca lombardella maggiore è un uccello, appartenente alla famiglia degli anatidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anser_albifrons' where nome_scientifico = 'Anser albifrons' and descrizione is null;
update specie set descrizione = 'L''oca selvatica, detta anche oca paglietana, è un uccello, appartenente alla famiglia degli anatidi. È talora chiamata "oca cenerina" proprio per la caratteristica sfumatura grigio-cenere del suo piumaggio. È considerata l''antenata dell''oca domestica europea, le cui penne venivano usate come calamo, volano o dardo per frecce.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anser_anser' where nome_scientifico = 'Anser anser' and descrizione is null;
update specie set descrizione = 'L''oca zamperosee, anche oca delle zampe rosse, è un uccello appartenente alla famiglia Anatidae. Il nome specifico deriva dal greco brachy-/βραχυ- = "corto" e rhynchos/ρυνχος ="becco".', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anser_brachyrhynchus' where nome_scientifico = 'Anser brachyrhynchus' and descrizione is null;
