update specie set descrizione = 'L''oca granaiola della taiga è un uccello della famiglia degli Anatidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anser_fabalis' where nome_scientifico = 'Anser fabalis' and descrizione is null;
update specie set descrizione = 'L''oca indiana è un''oca che nidifica in Asia centrale in colonie di migliaia di esemplari nei pressi dei laghi montani. Depone 3-8 uova in un nido sul suolo.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anser_indicus' where nome_scientifico = 'Anser indicus' and descrizione is null;
