update specie set descrizione = 'L''oca gazza è l''unica specie vivente della famiglia degli Anseranatidi (Anseranatidae) e del genere Anseranas Lesson, 1828. Il nome latino del genere, tradotto letteralmente, significa «oca anatra»: in realtà l''oca gazza non è né un''oca, né un''anatra. Il nome della specie, semipalmata, si riferisce a una delle sue caratteristiche più vistose, e cioè al fatto che le membrane natatorie sono alquanto ridotte e collegano in pratica la sola radice delle dita. Altra peculiarità della specie è l''alluce molto lungo ed inserito allo stesso livello delle altre dita del piede.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anseranas_semipalmata' where nome_scientifico = 'Anseranas semipalmata' and descrizione is null;
update specie set descrizione = 'Il pigliamosche dalla gorgiera, 1845 è un uccello della famiglia Muscicapidae, diffuso in Asia, dall''Himalaya alla Thailandia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthipes_monileger' where nome_scientifico = 'Anthipes monileger' and descrizione is null;
update specie set descrizione = 'The rufous-browed flycatcher is a species of bird in the family Muscicapidae. It is native to Indonesia, Laos, Malaysia, Myanmar, Thailand and Vietnam. Its natural habitat is subtropical or tropical moist montane forests. It was formerly placed in the genus Ficedula.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-browed_flycatcher' where nome_scientifico = 'Anthipes solitaris' and descrizione is null;
update specie set descrizione = 'La nettarinia ventrearancio è un uccello della famiglia Nectariniidae. È l''unica specie nota del genere Anthobaphes Cabanis, 1850.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthobaphes_violacea' where nome_scientifico = 'Anthobaphes violacea' and descrizione is null;
update specie set descrizione = 'The red wattlebird is a passerine bird native to southern Australia. At 33–37 cm in length, it is the second largest species of Australian honeyeater, after the yellow wattlebird. It has mainly grey-brown plumage, with red eyes, distinctive pinkish-red wattles on either side of the neck, white streaks on the chest and a large bright yellow patch on the lower belly. The sexes are similar in plumage. Juveniles have less prominent wattles and browner eyes. John White described the red wattlebird in 1790. Three subspecies are recognized.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red_wattlebird' where nome_scientifico = 'Anthochaera carunculata' and descrizione is null;
update specie set descrizione = 'The little wattlebird, also known as the brush wattlebird, is a passerine bird in the honeyeater family Meliphagidae. It is found in coastal and sub-coastal south-eastern Australia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Little_wattlebird' where nome_scientifico = 'Anthochaera chrysoptera' and descrizione is null;
update specie set descrizione = 'The western wattlebird is a passerine bird in the honeyeater family, Meliphagidae. It is restricted to south-western Australia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_wattlebird' where nome_scientifico = 'Anthochaera lunulata' and descrizione is null;
update specie set descrizione = 'The yellow wattlebird is a species of bird in the honeyeater family Meliphagidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow_wattlebird' where nome_scientifico = 'Anthochaera paradoxa' and descrizione is null;
update specie set descrizione = 'The regent honeyeater is a critically endangered bird endemic to southeastern Australia. It is commonly considered a flagship species within its range, with the efforts going into its conservation having positive effects on many other species that share its habitat. Recent genetic research suggests it is closely related to the wattlebirds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Regent_honeyeater' where nome_scientifico = 'Anthochaera phrygia' and descrizione is null;
update specie set descrizione = 'Il campanaro di Nuova Zelanda, noto anche con i nomi māori di Korimako o Makomako, è un uccello passeriforme endemico della Nuova Zelanda. Presenta una colorazione verdastra ed è l''unica specie vivente del genere Anthornis. È uno dei responsabili dei cori all''alba per i quali è conosciuta la Nuova Zelanda, che tanto stupirono i primi coloni europei. L''esploratore James Cook scrisse, riguardo a questo canto: «Fui svegliato dal canto degli uccelli sulla spiaggia, da cui noi distiamo quasi un quarto di miglio. Erano sicuramente in tanti. Sembrava che sforzassero le loro gole per rivalità, e forse emettevano la musica più melodiosa che io abbia mai sentito, che imitava quasi quella dei campanelli, ma con il più armonioso suono argenteo che si possa immaginare, al quale la distanza contribuiva non poco». Il richiamo emesso dal campanaro viene talvolta confuso con il canto del tui. La specie è comune in gran parte della Nuova Zelanda e delle isole vicine, ed è presente anche sulle isole Auckland.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthornis_melanura' where nome_scientifico = 'Anthornis melanura' and descrizione is null;
update specie set descrizione = 'The Cape penduline tit or southern penduline tit is a species of bird in the family Remizidae. It is found in Angola, Botswana, Namibia, South Africa, and Zimbabwe.
Its natural habitats are dry savannah, subtropical or tropical dry shrubland, and Mediterranean-type shrubby vegetation. At eight centimetres (3 in) in length, it is one of the smallest species of bird found in Africa, along with its cousins the grey penduline tit and the mouse-coloured penduline tit.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cape_penduline_tit' where nome_scientifico = 'Anthoscopus minutus' and descrizione is null;
update specie set descrizione = 'The mouse-coloured penduline tit or mouse-colored penduline tit is a species of bird in the family Remizidae. At 8 cm (3.1 in) in length, it is one of the two shortest birds native to Africa, alongside the tit hylia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mouse-coloured_penduline_tit' where nome_scientifico = 'Anthoscopus musculus' and descrizione is null;
update specie set descrizione = 'Il bucero orientale, noto anche come bucero bianco e nero orientale, è un uccello della famiglia dei Bucerotidi originario del Sud-est asiatico. Come tutti i buceri, nidifica nelle cavità degli alberi: la femmina, all''interno della cavità, mura l''ingresso della camera di cova ad eccezione di una stretta fessura, attraverso la quale il maschio rifornisce di cibo lei e i nidiacei.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthracoceros_albirostris' where nome_scientifico = 'Anthracoceros albirostris' and descrizione is null;
update specie set descrizione = 'Il bucero coronato, noto anche come bucero bianco e nero del Malabar, è un uccello della famiglia dei Bucerotidi originario dell''Asia meridionale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthracoceros_coronatus' where nome_scientifico = 'Anthracoceros coronatus' and descrizione is null;
update specie set descrizione = 'Il bucero nero è una specie di bucero originaria del Sud-est asiatico. Come tutti i buceri, nidifica nelle cavità degli alberi: durante la stagione riproduttiva, la femmina si mura all''interno della camera di cova, lasciando una piccola apertura, e viene nutrita dal maschio per tutta la durata del periodo di incubazione e allevamento dei piccoli.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthracoceros_malayanus' where nome_scientifico = 'Anthracoceros malayanus' and descrizione is null;
update specie set descrizione = 'The black-throated mango is a species in subfamily Polytminae of the hummingbird family Trochilidae. It is found in Panama, in every mainland South American country except Chile, and in Trinidad and Tobago.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_mango' where nome_scientifico = 'Anthracothorax nigricollis' and descrizione is null;
update specie set descrizione = 'La nettarinia golauniforme è un uccello della famiglia Nectariniidae, diffuso nel sud-est asiatico.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthreptes_malacensis' where nome_scientifico = 'Anthreptes malacensis' and descrizione is null;
update specie set descrizione = 'The eastern violet-backed sunbird, also known as the Kenya violet-backed sunbird, is a species of bird in the family Nectariniidae.
It is found in arid savanna of East Africa, ranging from Djibouti in north to Tanzania in south. It is part of the violet-backed sunbird superspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_violet-backed_sunbird' where nome_scientifico = 'Anthreptes orientalis' and descrizione is null;
update specie set descrizione = 'La gru del paradiso è un uccello della famiglia dei Gruidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Grus_paradisea' where nome_scientifico = 'Anthropoides paradiseus' and descrizione is null;
update specie set descrizione = 'The demoiselle crane is a species of crane found in central Eurosiberia, ranging from the Black Sea to Mongolia and Northeast China. There is also a small breeding population in Turkey. These cranes are migratory birds. Birds from western Eurasia will spend the winter in Africa while the birds from Asia, Mongolia and China will spend the winter in the Indian subcontinent. The bird is symbolically significant in the culture of India, where it is known as koonj or kurjaa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Demoiselle_crane' where nome_scientifico = 'Anthropoides virgo' and descrizione is null;
update specie set descrizione = 'The paramo pipit is a species of bird in the family Motacillidae, the wagtails and pipits. It is found in Argentina, Bolivia, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Paramo_pipit' where nome_scientifico = 'Anthus bogotensis' and descrizione is null;
update specie set descrizione = 'The tawny pipit is a medium-large passerine bird which breeds in much of the central Palearctic from northwest Africa and Portugal to Central Siberia and on to Inner Mongolia. It is a migrant moving in winter to tropical Africa and the Indian subcontinent.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tawny_pipit' where nome_scientifico = 'Anthus campestris' and descrizione is null;
update specie set descrizione = 'The red-throated pipit is a small passerine bird, which breeds in the far north of Europe and the Palearctic, with a foothold in northern Alaska. It is a long-distance migrant, wintering to Africa and South-East Asia and western Alaska in North America. It is vagrant to Western Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-throated_pipit' where nome_scientifico = 'Anthus cervinus' and descrizione is null;
update specie set descrizione = 'The Pampas pipit is a species of bird in the family Motacillidae, the wagtails and pipits. It is found in Argentina and Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pampas_pipit' where nome_scientifico = 'Anthus chacoensis' and descrizione is null;
update specie set descrizione = 'The African pipit is a fairly small passerine bird belonging to the pipit genus Anthus in the family Motacillidae. It is also known as the grassveld pipit or grassland pipit. It was formerly lumped together with the Richard''s, Australian, mountain and paddyfield pipits in a single species, Richard''s pipit, but is now often treated as a species in its own right.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_pipit' where nome_scientifico = 'Anthus cinnamomeus' and descrizione is null;
update specie set descrizione = 'The correndera pipit is a species of bird in the family Motacillidae, the wagtails and pipits. It is found in Argentina, Bolivia, Brazil, Chile, the Falkland Islands, Peru, Uruguay, and as a vagrant to Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Correndera_pipit' where nome_scientifico = 'Anthus correndera' and descrizione is null;
update specie set descrizione = 'The yellow-tufted pipit or African rock pipit is a small-sized, passerine bird that is native to South Africa and Lesotho. The yellow-tufted pipit is commonly found in mountain terrain, and they create their habitats in high-altitude shrub-land, grassland, and rocky areas. This species is identified by its brown and gray feathers. The bird has a white-gray eyebrow and yellow markings within its wings and stomach. The call of the yellow-tufted pipit allows the bird to stand out from other pipit species. The bird produces a repeated "whee-tsrreeu" that is loud and high-pitched. The yellow-tufted pipit has a life expectancy ranging from two to three years old.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_rock_pipit' where nome_scientifico = 'Anthus crenatus' and descrizione is null;
update specie set descrizione = 'The short-billed pipit is a species of bird in the family Motacillidae, the wagtails and pipits. It is found in Argentina, Brazil, Paraguay and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Short-billed_pipit' where nome_scientifico = 'Anthus furcatus' and descrizione is null;
update specie set descrizione = 'The Pechora pipit is a small passerine bird which breeds in the East Palearctic tundra and densely vegetated areas near river banks ranges from the Pechora River to the Chukchi Peninsula. It also breeds in Kamchatka and the Commander Islands, and with a disjunct population much further south in northeastern China and southeastern Siberia. It is a long-distance migrant, moving in winter to Indonesia. Rarely in September and October, the Pechora pipit may be observed in western Europe. The species was first described by Robert Swinhoe in 1863.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pechora_pipit' where nome_scientifico = 'Anthus gustavi' and descrizione is null;
update specie set descrizione = 'The olive-backed pipit is a small passerine bird of the pipit (Anthus) genus, which breeds across southern, north central and eastern Asia, as well as in the north-eastern European Russia. It is a long-distance migrant moving in winter to southern Asia and Indonesia. Sometimes it is also called Indian pipit or Hodgson''s pipit, as well as tree pipit owing to its resemblance with the tree pipit. However, its back is more olive-toned and less streaked than that species, and its head pattern is different with a better-marked supercilium.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive-backed_pipit' where nome_scientifico = 'Anthus hodgsoni' and descrizione is null;
update specie set descrizione = 'The plain-backed pipit  or plain pipit is a medium-sized passerine bird which is a resident breeder in Africa south of the Sahara Desert.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plain-backed_pipit' where nome_scientifico = 'Anthus leucophrys' and descrizione is null;
update specie set descrizione = 'The striped pipit is a species of bird in the family Motacillidae, which is native to Africa southwards of the equator.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Striped_pipit' where nome_scientifico = 'Anthus lineiventris' and descrizione is null;
update specie set descrizione = 'The yellowish pipit is a species of bird in the family Motacillidae, the wagtails and pipits. It is found in Panama and in every mainland South American country except Ecuador and Chile.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellowish_pipit' where nome_scientifico = 'Anthus lutescens' and descrizione is null;
update specie set descrizione = 'The ochre-breasted pipit is a Vulnerable species of bird in the family Motacillidae, the wagtails and pipits. It is found in Argentina, Brazil, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ochre-breasted_pipit' where nome_scientifico = 'Anthus nattereri' and descrizione is null;
update specie set descrizione = 'The New Zealand pipit is a fairly small passerine bird of open country in New Zealand and outlying islands. It belongs to the pipit genus Anthus in the family Motacillidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/New_Zealand_pipit' where nome_scientifico = 'Anthus novaeseelandiae' and descrizione is null;
update specie set descrizione = 'The Peruvian pipit is a species of bird in the family Motacillidae, the wagtails and pipits. It is found in Chile and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Peruvian_pipit' where nome_scientifico = 'Anthus peruvianus' and descrizione is null;
update specie set descrizione = 'The European rock pipit, or simply rock pipit, is a species of small passerine bird that breeds in western Europe on rocky coasts. It has streaked greyish-brown upperparts and buff underparts, and is similar in appearance to other European pipits. There are two subspecies, of which the nominate is non-migratory, and the Fennoscandian one is migratory, wintering in shoreline habitats further west and south in Europe. The European rock pipit is territorial at least in the breeding season, and year-round where it is resident. Males will sometimes enter an adjacent territory to assist the resident in repelling an intruder, behaviour only otherwise known from the African fiddler crab.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/European_rock_pipit' where nome_scientifico = 'Anthus petrosus' and descrizione is null;
update specie set descrizione = 'La pispola è un piccolo uccello passeriforme che nidifica in gran parte dell''Europa e dell''Asia settentrionale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthus_pratensis' where nome_scientifico = 'Anthus pratensis' and descrizione is null;
update specie set descrizione = 'The Rosy pipit is a species of bird in the family Motacillidae.
It is found in Afghanistan, Bangladesh, Bhutan, China, India, South Korea, Myanmar, Nepal, Pakistan, Thailand and Vietnam.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rosy_pipit' where nome_scientifico = 'Anthus roseatus' and descrizione is null;
update specie set descrizione = 'The American pipit, formerly known as the buff-bellied pipit, is a small songbird native to North America. It was first described by Marmaduke Tunstall in his 1771 Ornithologia Britannica. It was formerly classified as a form of the water pipit. The former subspecies, Siberian pipit, is now considered a distinct species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/American_pipit' where nome_scientifico = 'Anthus rubescens' and descrizione is null;
update specie set descrizione = 'The paddyfield pipit or Oriental pipit is a small passerine bird in the pipit and wagtail family. It is a resident (non-migratory) breeder in open scrub, grassland and cultivation in southern Asia east to the Philippines. Although among the few breeding pipits in the Asian region, identification becomes difficult in winter when several other species migrate into the region. The taxonomy of the species is complex and has undergone considerable changes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Paddyfield_pipit' where nome_scientifico = 'Anthus rufulus' and descrizione is null;
update specie set descrizione = 'The long-billed pipit or brown rock pipit is a passerine bird which has a wide distribution. A number of subspecies have been created for the populations in Africa, through the Arabian Peninsula and South Asia. The systematics of this complex is yet to be clarified. Most birds are residents or short distance migrants.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-billed_pipit' where nome_scientifico = 'Anthus similis' and descrizione is null;
