update specie set descrizione = 'Il prispolone è un uccello insettivoro della famiglia dei Motacillidae: è possibile osservarlo in Europa, Asia ed Africa.La Sila rappresenta l''estremo limite meridionale per la riproduzione accertata in Italia e in Europa. 
Abita sia i boschi di pianura che quelli di montagna. Si differenzia dalla pispola per il canto che emette volando di ramo in ramo: è un canto più rauco e potente.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Anthus_trivialis' where nome_scientifico = 'Anthus trivialis' and descrizione is null;
update specie set descrizione = 'La gru antigone è una grande gru stanziale che vive in alcune parti del subcontinente indiano, sud-est asiatico e in Australia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Antigone_antigone' where nome_scientifico = 'Antigone antigone' and descrizione is null;
update specie set descrizione = 'La gru canadese è una specie appartenente alla famiglia dei Gruidi diffusa in America del Nord e nell''estremità nord-orientale dell''Asia. È di colore grigio-marrone uniforme e gli esemplari adulti presentano una macchia glabra rossa sulla fronte, le guance bianche e un lungo becco appuntito.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Antigone_canadensis' where nome_scientifico = 'Antigone canadensis' and descrizione is null;
