update specie set descrizione = 'La gru nucabianca è una specie di gru dell''Asia orientale che nidifica nella Mongolia nord-orientale e nella Cina settentrionale e sverna nella penisola coreana e in Giappone. Durante la stagione riproduttiva vive in coppie e conduce un''esistenza molto riservata, ma durante la migrazione e nelle aree di svernamento forma grandi assembramenti.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Antigone_vipio' where nome_scientifico = 'Antigone vipio' and descrizione is null;
update specie set descrizione = 'Il manachino dell''Araripe è un uccello passeriforme della famiglia Pipridae, endemico della Chapada do Araripe, nel nord-est del Brasile.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Antilophia_bokermanni' where nome_scientifico = 'Antilophia bokermanni' and descrizione is null;
update specie set descrizione = 'The helmeted manakin is a species of small passerine bird in the manakin family Pipridae. Unlike most manakins, a family associated with tropical rainforests, the helmeted manakin inhabits the seasonally dry Cerrado savanna of Central Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Helmeted_manakin' where nome_scientifico = 'Antilophia galeata' and descrizione is null;
update specie set descrizione = 'The Mexican whip-poor-will,, is a medium-sized nightjar of the southwestern United States, Mexico, and northern Central America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mexican_whip-poor-will' where nome_scientifico = 'Antrostomus arizonae' and descrizione is null;
update specie set descrizione = 'The Yucatan nightjar is a species of nightjar in the family Caprimulgidae. It is found in Belize, Guatemala, Mexico, and Honduras.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yucatan_nightjar' where nome_scientifico = 'Antrostomus badius' and descrizione is null;
update specie set descrizione = 'The Puerto Rican nightjar, Puerto Rican whip-poor-will or guabairo is a bird in the nightjar family found in the coastal dry scrub forests in localized areas of southwestern Puerto Rico. It was described in 1916 from bones found in a cave in north central Puerto Rico and a single skin specimen from 1888, and was considered extinct until observed in the wild in 1961. The current population is estimated as 1,400-2,000 mature birds. The species is currently classified as Endangered due to pressures from habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Puerto_Rican_nightjar' where nome_scientifico = 'Antrostomus noctitherus' and descrizione is null;
