update specie set descrizione = 'The rufous nightjar is a species of nightjar in the family Caprimulgidae. It is found in Argentina, Bolivia, Brazil, Colombia, Costa Rica, Ecuador, Guyana, Panama, Paraguay, Peru, Saint Lucia, Suriname, Trinidad and Tobago, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous_nightjar' where nome_scientifico = 'Antrostomus rufus' and descrizione is null;
