update specie set descrizione = 'The silky-tailed nightjar is a species of nightjar birds in the family Caprimulgidae. It is found in Brazil, Argentina, Bolivia, Paraguay, and Peru. Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Silky-tailed_nightjar' where nome_scientifico = 'Antrostomus sericocaudatus' and descrizione is null;
update specie set descrizione = 'The eastern whip-poor-will is a medium-sized bird within the nightjar family, Caprimulgidae, from North America. The whip-poor-will is commonly heard within its range, but less often seen because of its camouflage. It is named onomatopoeically after its song.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_whip-poor-will' where nome_scientifico = 'Antrostomus vociferus' and descrizione is null;
