update specie set descrizione = 'The brown-headed apalis is a small passerine bird belonging to the genus Apalis in the family Cisticolidae. Formerly included within the grey apalis but is now commonly considered to be a separate species. It has two subspecies: A. a. alticola and A. a. dowsetti.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-headed_apalis' where nome_scientifico = 'Apalis alticola' and descrizione is null;
