update specie set descrizione = 'Il rallo pettoardesia o rallo boschereccio pettoardesia è un uccello della famiglia dei Rallidi originario delle regioni sud-orientali del Sudamerica.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Aramides_saracura' where nome_scientifico = 'Aramides saracura' and descrizione is null;
update specie set descrizione = 'Il rallo di Wolf o rallo boschereccio bruno è un uccello della famiglia dei Rallidi originario delle regioni comprese tra la Colombia e il Perù. Deve il nome al naturalista tedesco Theodor Wolf.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Aramides_wolfi' where nome_scientifico = 'Aramides wolfi' and descrizione is null;
update specie set descrizione = 'Il rallo ypecaha o rallo boschereccio gigante è un uccello della famiglia dei Rallidi originario delle regioni sud-orientali del Sudamerica.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Aramides_ypecaha' where nome_scientifico = 'Aramides ypecaha' and descrizione is null;
update specie set descrizione = 'L''aramo, anche noto come limpkin, carrao, courlan o uccello piangente, è un uccello gruiforme simile a un rallide, sebbene sia tassonomicamente più vicino alle gru. È l''unica specie esistente del genere Aramus e l''unica tuttora vivente della famiglia Aramidae. Abita principalmente le zone umide, nelle aree calde delle Americhe, dalla Florida al nord dell''Argentina. Si nutre di molluschi, e la sua dieta è dominata dalle lumache ampullariidi del genere Pomacea. Il suo nome inglese, limpkin, deriva dalla sua camminata apparentemente zoppicante.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Aramus_guarauna' where nome_scientifico = 'Aramus guarauna' and descrizione is null;
update specie set descrizione = 'Il parrocchetto capodorato è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Aratinga_auricapillus' where nome_scientifico = 'Aratinga auricapillus' and descrizione is null;
update specie set descrizione = 'Il parrocchetto jandaya è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Aratinga_jandaya' where nome_scientifico = 'Aratinga jandaya' and descrizione is null;
