update specie set descrizione = 'The Taiwan partridge or Taiwan hill partridge is a species of bird in the family Phasianidae. It is found only in Taiwan, and its natural habitat is broadleaf forests. It is threatened by habitat loss, but at present is categorised by the International Union for Conservation of Nature (IUCN) as being of least concern.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Taiwan_partridge' where nome_scientifico = 'Arborophila crudigularis' and descrizione is null;
update specie set descrizione = 'The red-breasted partridge, also known as the Bornean hill-partridge, is a species of bird in the family Phasianidae. It is endemic to hill and montane forest in Borneo, preferring bamboos and thickets. The International Union for Conservation of Nature (IUCN) has assessed it as a least-concern species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-breasted_partridge' where nome_scientifico = 'Arborophila hyperythra' and descrizione is null;
update specie set descrizione = 'The chestnut-bellied partridge also known as chestnut-bellied hill-partridge or Javan hill-partridge is a small, up to 28 cm long, partridge with a rufous crown and nape, red legs, grey breast, brown wings, red facial skin, and a black mask, throat and bill. It has a rufous belly with white on the middle. The sexes are similar. The young has a whitish face and a reddish brown bill.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-bellied_partridge' where nome_scientifico = 'Arborophila javanica' and descrizione is null;
update specie set descrizione = 'The chestnut-breasted partridge is a partridge species endemic to the eastern Himalayas north of the Brahmaputra, and occurs in Bhutan, Darjeeling, Sikkim, Arunachal Pradesh and south-eastern Tibet at elevations from 350 to 2,500 m. It is listed as near threatened on the IUCN Red List, as the estimated population comprises less than 10,000 individuals. It is threatened by forest degradation and by hunting. It is known from at least three protected areas, including Singalila National Park and Namdapha National Park.
The scientific name commemorates the Italian naturalist Louis Mandelli.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-breasted_partridge' where nome_scientifico = 'Arborophila mandellii' and descrizione is null;
update specie set descrizione = 'The rufous-throated partridge is a species of bird in the family Phasianidae. It is found in montane forests in India and Southeast Asia. The International Union for Conservation of Nature (IUCN) has assessed it as a least-concern species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-throated_partridge' where nome_scientifico = 'Arborophila rufogularis' and descrizione is null;
