update specie set descrizione = 'The Chinese pond heron is an East Asian freshwater bird of the heron family, (Ardeidae).
It is one of six species of birds known as "pond herons". It is parapatric with the Indian pond heron to the west and the Javan pond heron to the south, and these three are presumed to form a superspecies. As a group they are variously affiliated with the squacco heron or the Malagasy pond heron. As of mid-2011 there are no published molecular analyses of pond heron interrelationships and osteological data is likewise not analyzed for all relevant comparison taxa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chinese_pond_heron' where nome_scientifico = 'Ardeola bacchus' and descrizione is null;
update specie set descrizione = 'The Indian pond heron or paddybird is a small heron. It is of Old World origins, breeding in southern Iran and east to the Indian subcontinent, Burma, and Sri Lanka. They are widespread and common but can be easily missed when they stalk prey at the edge of small water-bodies or even when they roost close to human habitations.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_pond_heron' where nome_scientifico = 'Ardeola grayii' and descrizione is null;
update specie set descrizione = 'The squacco heron is a small heron, 44–47 cm long, of which the body is 20–23 cm (8–9 in), with 80–92 cm wingspan. It is of Old World origins, breeding in southern Europe and the Greater Middle East.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Squacco_heron' where nome_scientifico = 'Ardeola ralloides' and descrizione is null;
update specie set descrizione = 'La sgarza di Giava è un uccello della famiglia degli Ardeidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ardeola_speciosa' where nome_scientifico = 'Ardeola speciosa' and descrizione is null;
update specie set descrizione = 'Il voltapietre è un uccello che fa parte della famiglia scolopacidae. È un migratore che nidifica nella parte settentrionale dell''Eurasia e del Nord America per poi volare verso sud in inverno lungo le coste di quasi tutto il mondo. Il nome deriva dalla sua capacità di voltare velocemente le pietre per mangiarne gli insetti che vi si annidano sotto.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Arenaria_interpres' where nome_scientifico = 'Arenaria interpres' and descrizione is null;
update specie set descrizione = 'Il voltapietre testa nera è un uccello della famiglia degli Scolopacidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Arenaria_melanocephala' where nome_scientifico = 'Arenaria melanocephala' and descrizione is null;
update specie set descrizione = 'L''argo maggiore, unica specie del genere Argusianus G. R. Gray, 1849, è un uccello della famiglia dei Fasianidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Argusianus_argus' where nome_scientifico = 'Argusianus argus' and descrizione is null;
update specie set descrizione = 'The yellow-billed babbler is a member of the family Leiothrichidae endemic to southern India and Sri Lanka. The yellow-billed babbler is a common resident breeding bird in Sri Lanka and southern India. Its habitat is scrub, cultivation and garden land. This species, like most babblers, is not migratory, and has short rounded wings and a weak flight and is usually seen calling and foraging in groups. It is often mistaken for the jungle babbler, whose range overlaps in parts of southern India, although it has a distinctive call and tends to be found in more vegetated habitats. Its name is also confused with Turdoides leucocephala, which is also known as white-headed babbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-billed_babbler' where nome_scientifico = 'Argya affinis' and descrizione is null;
update specie set descrizione = 'The common babbler is a member of the family of Leiothrichidae. They are found in dry open scrub country mainly in India. Two populations are recognized as subspecies and the populations to the west of the Indus river system are now usually treated as a separate species, the Afghan babbler. The species is distinctly long-tailed, slim with an overall brown or greyish colour, streaked on the upper plumage and having a distinctive whitish throat.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_babbler' where nome_scientifico = 'Argya caudata' and descrizione is null;
update specie set descrizione = 'The striated babbler is a species of bird in the family Leiothrichidae. It is found in southern Asia from Pakistan to Myanmar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Striated_babbler' where nome_scientifico = 'Argya earlei' and descrizione is null;
update specie set descrizione = 'The large grey babbler is a member of the family Leiothrichidae found across India and far western Nepal. They are locally common in the scrub, open forest and gardenland. They are usually seen in small groups and are easily distinguished from other babblers in the region by their nasal call and the whitish outer feathers to their long tail. It is one of the largest babblers in the region.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Large_grey_babbler' where nome_scientifico = 'Argya malcolmi' and descrizione is null;
update specie set descrizione = 'The jungle babbler is a member of the family Leiothrichidae found in the Indian subcontinent. Jungle babblers are gregarious birds that forage in small groups of six to ten birds, a habit that has given them the popular name of "seven sisters" in urban Northern India, and in Bengali, with cognates in other regional languages which also mean "seven brothers".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Jungle_babbler' where nome_scientifico = 'Argya striata' and descrizione is null;
update specie set descrizione = 'The rufous babbler is an endemic species of bird found in the Western Ghats of southern India of the family Leiothrichidae It is dark brown and long tailed, and is usually seen foraging in noisy groups along open hillsides with a mixture of grass, bracken and forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous_babbler' where nome_scientifico = 'Argya subrufa' and descrizione is null;
update specie set descrizione = 'The stripe-cheeked greenbul is a species of the bulbul family of passerine birds. It is found in south-eastern Africa. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Stripe-cheeked_greenbul' where nome_scientifico = 'Arizelocichla milanjensis' and descrizione is null;
update specie set descrizione = 'The black-headed mountain greenbul, also known as the mountain greenbul or eastern mountain greenbul, is a species of the bulbul family of passerine birds. It is native to the eastern Afromontane. Its diet consists of fruit and nectar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_mountain_greenbul' where nome_scientifico = 'Arizelocichla nigriceps' and descrizione is null;
