update specie set descrizione = 'The red-capped forest warbler, also known as the African tailorbird, is a songbird of the family Cisticolidae, formerly part of the "Old World warbler" assemblage. It is found in Mozambique and Tanzania. Its natural habitat is subtropical or tropical moist montane forests from 1600 to 2500 m.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-capped_forest_warbler' where nome_scientifico = 'Artisornis metopias' and descrizione is null;
