update specie set descrizione = 'The ochre-breasted brushfinch (Atlapetes semirufus) is a species of bird in the family Passerellidae. It is endemic to the northern Andes, occurring in Colombia and Venezuela. In Colombia, it inhabits elevations of 1,600–3,500 meters, while in Venezuela it is found between 600–2,700 meters. The species is present in several national parks and is not currently considered to face immediate conservation threats. Although relatively common, its breeding biology and life history remain poorly understood, and the population is believed to be in decline.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ochre-breasted_brushfinch' where nome_scientifico = 'Atlapetes semirufus' and descrizione is null;
