update specie set descrizione = 'The gold-ringed tanager is a species of bird in the family Thraupidae, endemic to Colombia. It is a plump, relatively short-tailed tanager with a distinctive gold ring around its face. It inhabits a narrow band of high-altitude cloud forest on the slopes of the western cordillera of the Andes, where it survives on a diet of fruit and insects. The bird is found in small numbers within a limited geographical area, and much of its breeding biology has yet to be described. It is considered a vulnerable species, threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gold-ringed_tanager' where nome_scientifico = 'Bangsia aureocincta' and descrizione is null;
update specie set descrizione = 'The moss-backed tanager is a species of bird in the family Thraupidae. It is found in Colombia and Ecuador. It is a chunky, large-headed tanager with moss-green upperparts, dark blue-tinged dark green wings, olive green underparts, a bright golden yellow patch on the chest, and black head with shining blue sides. It is endemic to the Western Andes of western Colombia and northwestern Ecuador, where it inhabits dense, humid Pacific slope forests. It feeds on insects and fruit. It is classified as being of least concern on the IUCN Red List due to its sufficiently large range and population.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Moss-backed_tanager' where nome_scientifico = 'Bangsia edwardsi' and descrizione is null;
