update specie set descrizione = 'The golden-browed warbler is a species of bird in the family Parulidae, the New World warblers.
It is found in El Salvador, Guatemala, Honduras, and Mexico.
Its natural habitat is subtropical or tropical moist montane forests.
The species was described by Jacob Post Giraud, Jr. in 1841.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-browed_warbler' where nome_scientifico = 'Basileuterus belli' and descrizione is null;
update specie set descrizione = 'The golden-crowned warbler is a small insectivorous bird in the New World warbler family Parulidae. It has a large geographic range that extends from northeastern Mexico south to northern Argentina. The white-bellied warbler was formerly treated as a separate species but is now considered to be conspecific with the golden-crowned warbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-crowned_warbler' where nome_scientifico = 'Basileuterus culicivorus' and descrizione is null;
update specie set descrizione = 'The chestnut-capped warbler is a New World warbler native from Guatemala to Venezuela. It was split from the rufous-capped warbler as a distinct species by the IOC in 2021.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-capped_warbler' where nome_scientifico = 'Basileuterus delattrii' and descrizione is null;
update specie set descrizione = 'The fan-tailed warbler is a New World warbler in the genus Basileuterus that lives along the Pacific slope from northern Mexico to Nicaragua. Vagrant records exist for Arizona, New Mexico and Texas. It is yellow on its throat and underparts with a tawny wash on its chest. The head is gray with a black-framed yellow crown and white around the eyes. The undertail coverlets are white. It is 5.8-6.3 in (14.5–16 cm) long and has a pleasant, upslurred song. Fan-tailed warblers live in and at the edge of evergreen and semideciduous forest, especially near ravines. They eat insects, and are seen hopping around on either the forest floor or close to it. They are found alone or in pairs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fan-tailed_warbler' where nome_scientifico = 'Basileuterus lachrymosus' and descrizione is null;
update specie set descrizione = 'The black-cheeked warbler is a New World warbler, resident breeding bird endemic to the Talamancan montane forests of Costa Rica and western Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-cheeked_warbler' where nome_scientifico = 'Basileuterus melanogenys' and descrizione is null;
update specie set descrizione = 'The black-eared warbler or Costa Rican warbler is a species of bird in the family Parulidae. It was previously considered conspecific with the three-striped warbler and the Tacarcuna warbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-eared_warbler' where nome_scientifico = 'Basileuterus melanotis' and descrizione is null;
