update specie set descrizione = 'The western black-headed batis or Von Erlanger''s batis, is a species of passerine bird in the wattle-eye family Platysteiridae. It is found over an extensive area of central Africa. Its natural habitats are subtropical or tropical dry forests and moist savanna. It was formerly treated as conspecific with the eastern black-headed batis.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_black-headed_batis' where nome_scientifico = 'Batis erlangeri' and descrizione is null;
