update specie set descrizione = 'The chinspot batis is a small songbird of the genus Batis in the family Platysteiridae which is a common and widespread species in the woodlands of southern Africa from the Eastern Cape north to 3°N in southern Kenya and Gabon. It forms a superspecies with other rather similar members of the genus Batis.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chinspot_batis' where nome_scientifico = 'Batis molitor' and descrizione is null;
