update specie set descrizione = 'The large frogmouth is a species of bird in the family Podargidae. It is found in Brunei, Indonesia, Malaysia, and Thailand, in subtropical or tropical moist lowland forest. Logging of its habitat poses a risk to its survival, and the International Union for Conservation of Nature has listed it as a vulnerable species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Large_frogmouth' where nome_scientifico = 'Batrachostomus auritus' and descrizione is null;
update specie set descrizione = 'The Sunda frogmouth is a medium-sized, old world species of bird within the order Podargiformes. It is also uncommonly referred to as the long-tailed frogmouth or the horned frogmouth. The term "Sunda" is based on the geographical range of the species to regions around the Sunda islands. The genus name, Batrachostomus, is a Greek translation to ''frogmouth'', which comes from the wide shape of the bill and slight gape. The species name cornutus is a Latin word translated to "having horns", referring to the tufts of feathers on the head.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sunda_frogmouth' where nome_scientifico = 'Batrachostomus cornutus' and descrizione is null;
update specie set descrizione = 'The Sri Lanka frogmouth, Sri Lankan frogmouth or Ceylon frogmouth is a small frogmouth found in the Western Ghats of south India and Sri Lanka. Related to the nightjars, it is nocturnal and is found in forest habitats. The plumage coloration resembles that of dried leaves and the bird roosts quietly on branches, making it difficult to see. Each has a favourite roost that it uses regularly unless disturbed. It has a distinctive call that is usually heard at dawn and dusk. The sexes differ slightly in plumage.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sri_Lanka_frogmouth' where nome_scientifico = 'Batrachostomus moniliger' and descrizione is null;
update specie set descrizione = 'The Philippine frogmouth is a nocturnal bird that can be found throughout the Philippine archipelago. It is common in lowland forests and maturing second growth. There is little information about the bird. It feeds on grasshoppers, cicadas, crickets and beetles.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Philippine_frogmouth' where nome_scientifico = 'Batrachostomus septimus' and descrizione is null;
