update specie set descrizione = 'The spot-bellied eagle-owl, also known as the forest eagle-owl is a large bird of prey with a formidable appearance. It is a forest-inhabiting species found in the Indian subcontinent and Southeast Asia. This species is considered part of a superspecies with the barred eagle-owl, which looks quite similar but is allopatric in distribution.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spot-bellied_eagle-owl' where nome_scientifico = 'Bubo nipalensis' and descrizione is null;
update specie set descrizione = 'Il gufo delle nevi (Bubo scandiacus è un uccello della famiglia degli Strigidi. Il gufo delle nevi è l''uccello ufficiale del Québec.
Noto in Italia anche col nome di civetta delle nevi, la sua denominazione scientifica è stata Nyctea scandiaca fino al 2002, quando uno studio sulla sequenza cromosomica ne ha rivelato la vicinanza con gli altri gufi del genere Bubo.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Bubo_scandiacus' where nome_scientifico = 'Bubo scandiacus' and descrizione is null;
update specie set descrizione = 'The barred eagle-owl, also called the Malay eagle-owl, is a species of eagle owl in the family Strigidae. It is a member of the large genus Ketupa, which is found on most of the world''s continents. This relatively little-known species is found from the southern Malay Peninsula down a string of several of the larger southeast Asian islands to as far as Borneo. It forms a superspecies with the physically similar but larger spot-bellied eagle-owl, although the two species appear to be allopatric in distribution.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Barred_eagle-owl' where nome_scientifico = 'Bubo sumatranus' and descrizione is null;
