update specie set descrizione = 'Il bucero maggiore è un uccello della famiglia dei Bucerotidi originario dell''Asia meridionale. Può superare il metro di lunghezza ed è uno degli uccelli di foresta più grandi del mondo. Come tutti i buceri, nidifica anch''esso nelle cavità degli alberi. La femmina trascorre i quattro mesi della stagione riproduttiva murata all''interno della cavità del nido, collegata all''aperto solo attraverso una stretta fessura. Durante questo periodo, lei e in seguito i nidiacei che escono dalle uova vengono nutriti dal maschio.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Buceros_bicornis' where nome_scientifico = 'Buceros bicornis' and descrizione is null;
update specie set descrizione = 'The rufous hornbill, also known as the Philippine hornbill and locally as kalaw, is a large species of hornbill endemic to the Philippines. It is called the "clock-of-the-mountains" by locals, because of its loud booming call which typically occurs every hour. Rufous hornbills inhabit moist tropical lowland forest areas, and are now regarded as a threatened species. Reasons for decline include habitat destruction, hunting and poaching for the illegal pet trade.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous_hornbill' where nome_scientifico = 'Buceros hydrocorax' and descrizione is null;
update specie set descrizione = 'Il bucero rinoceronte è una grande specie di bucero originario del Sud-est asiatico. In cattività questo uccello può vivere fino a 35 anni. Si trova in aree pianeggianti e montane, tropicali e subtropicali e nelle foreste pluviali di montagna fino a 1.400 metri del Borneo, Sumatra, Giava, nella penisola malese, Singapore e nel sud della Thailandia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Buceros_rhinoceros' where nome_scientifico = 'Buceros rhinoceros' and descrizione is null;
update specie set descrizione = 'The helmeted hornbill is a very large bird in the hornbill family. It is found on the Malay Peninsula, Sumatra, Borneo, Thailand and Myanmar. The casque accounts for some 11% of its 3 kg weight. Unlike any other hornbill, the casque is almost solid, and is used in head-to-head combat among males. It is a belief among the Punan Bah that a large helmeted hornbill guards the river between life and death.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Helmeted_hornbill' where nome_scientifico = 'Buceros vigil' and descrizione is null;
