update specie set descrizione = 'L''occhione indiano è un uccello della famiglia dei Burhinidae; precedentemente considerato una sottospecie dell''Occhione comune. Questa specie si trova nelle pianure dell''India, Pakistan, Nepal e Sri Lanka. Presentano grandi occhi e sono di colore marrone con striature bianche o chiare che li rendono particolarmente mimetici.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Burhinus_indicus' where nome_scientifico = 'Burhinus indicus' and descrizione is null;
