update specie set descrizione = 'The white-throated hawk is a bird of prey in subfamily Buteoninae, the "soaring" hawks, of family Accipitridae. It is found in Argentina, Bolivia, Chile, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_hawk' where nome_scientifico = 'Buteo albigula' and descrizione is null;
update specie set descrizione = 'The zone-tailed hawk is a medium-sized hawk of warm, dry parts of the Americas. It is somewhat similar in plumage and flight style to a common scavenger, the turkey vulture, and may benefit from being able to blend into groups of vultures. It feeds on small terrestrial tetrapods of all kinds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Zone-tailed_hawk' where nome_scientifico = 'Buteo albonotatus' and descrizione is null;
update specie set descrizione = 'The augur buzzard is a fairly large African bird of prey. This species is distinct in typical adult plumage for its blackish back, whitish underside and orange-red tail, while juvenile augur buzzards are generally rather brown in colour; however a dark morph is known, which causes the bird''s entire body to become darker. This member of the Buteo genus is distributed in several parts of the central and southern Africa, normally being found from Ethiopia to southern Angola and central Namibia. It is resident and non-migratory throughout its range. This is a species of mountains, and adjacent savannah and grassland. It is a typical buteonine raptor, being a generalist predator which tends to prefer small mammals supplemented by reptiles and birds among various prey items.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Augur_buzzard' where nome_scientifico = 'Buteo augur' and descrizione is null;
update specie set descrizione = 'La poiana del Madagascar è un uccello della famiglia degli Accipitridi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Buteo_brachypterus' where nome_scientifico = 'Buteo brachypterus' and descrizione is null;
update specie set descrizione = 'La poiana codacorta è un uccello della famiglia degli Accipitridi dell''ordine degli Accipitriformi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Buteo_brachyurus' where nome_scientifico = 'Buteo brachyurus' and descrizione is null;
update specie set descrizione = 'La poiana comune, detta anche bozzago, bozzagro, bozzegro, buzzago, buzzagro o abuzzago, è un uccello rapace della famiglia Accipitridae. Il suo areale copre la maggior parte dell''Europa e si estende in Asia. Vive in tutte le zone tranne che in quelle più fredde. Preferisce i boschi e caccia in territori aperti.
Le sue prede sono generalmente insetti e piccoli roditori.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Buteo_buteo' where nome_scientifico = 'Buteo buteo' and descrizione is null;
update specie set descrizione = 'La poiana della Giamaica o poiana codarossa è un uccello rapace della famiglia degli Accipitridi. È il rapace americano più diffuso, e vive dal Canada meridionale al Centro America. Le due principali sottospecie sono quella scura e quella chiara riconoscibili dalla variazione del piumaggio che è rispettivamente: quasi completamente marrone scuro con qualche leggera stiratura bianca sul sottoala e leggermente rossiccia sulla coda; l''altra invece è molto più bianca con striature marrone scuro e marrone rossicce soprattutto sulla coda da dove prende il suo nome comune, assomiglia alla poiana comune soltanto che il marrone è più appunto rossiccio. Possiede un''incredibile capacità di adattamento, che le permette di sopravvivere negli habitat più disparati e di cacciare le prede più diverse: dalle praterie, dove caccia lepri, conigli e cani della prateria, alle giungle dove insegue grandi invertebrati e iguane, alle paludi dove mangia procioni, opossum e moffette, ai cigli delle strade, dove divora le carcasse degli animali investiti, fino alle grandi città, dove caccia gli uccelli. È a sua volta preda di linci rosse, coyote, gufi della Virginia, aquile reali, alligatori, puma e cani; sovente sono anche investite dalle automobili. Nonostante ciò, il loro altissimo numero fa in modo che esse non siano considerate a rischio di estinzione. Deve il suo nome scientifico al luogo dove è stata scoperta e il suo nome comune al colore della coda.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Buteo_jamaicensis' where nome_scientifico = 'Buteo jamaicensis' and descrizione is null;
update specie set descrizione = 'La poiana giapponese è un uccello rapace della famiglia Accipitridae, diffuso in Estremo Oriente.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Buteo_japonicus' where nome_scientifico = 'Buteo japonicus' and descrizione is null;
