update specie set descrizione = 'The hooded mountain tanager is a species of bird in the tanager family Thraupidae. It is the only member of the genus Buthraupis. It is found in the forests and woodlands of the Andean highlands of Bolivia, Colombia, Ecuador, Peru, and Venezuela, at altitudes between 1,800 and 3,000 m. At 23 centimetres (9.1 in) and 96 grams (3.4 oz), it is one of the largest tanagers. It has a black head and thighs, a blue back and bright yellow belly, with red eyes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hooded_mountain_tanager' where nome_scientifico = 'Buthraupis montana' and descrizione is null;
update specie set descrizione = 'The striated heron also known as mangrove heron or little green heron, is a small heron, about 44 cm tall. It is mostly sedentary and noted for some interesting behavioural traits. The breeding habitat is in South America and the Caribbean. The striated heron was formerly considered to be conspecific with the little heron that is found in the Old World tropics from west Africa to Japan and Australia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Striated_heron' where nome_scientifico = 'Butorides striata' and descrizione is null;
