update specie set descrizione = 'The rock sandpiper is a small shorebird in the sandpiper family Scolopacidae. This is a hardy sandpiper that breeds in the arctic and subarctic regions of Alaska and the Chukotka and Kamchatka Peninsulas. It is closely related to the purple sandpiper that breeds in arctic regions of northeast Canada and the northwest Palearctic, and in the past was often considered conspecific with it.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rock_sandpiper' where nome_scientifico = 'Calidris ptilocnemis' and descrizione is null;
update specie set descrizione = 'The ruff is a medium-sized wading bird that breeds in marshes and wet meadows across northern Eurasia. This highly gregarious sandpiper is migratory and sometimes forms huge flocks in its winter grounds, which include southern and western Europe, Africa, southern Asia and Australia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ruff_(bird)' where nome_scientifico = 'Calidris pugnax' and descrizione is null;
update specie set descrizione = 'The semipalmated sandpiper is a very small shorebird. The genus name is from Ancient Greek kalidris or skalidris, a term used by Aristotle for some grey-coloured waterside birds. The specific pusilla is Latin for "very small".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Semipalmated_sandpiper' where nome_scientifico = 'Calidris pusilla' and descrizione is null;
update specie set descrizione = 'The spoon-billed sandpiper is a small wader which breeds on the coasts of the Bering Sea and winters in Southeast Asia. This species is highly threatened, and it is said that since the 1970s the breeding population has decreased significantly. By 2000, the estimated breeding population of the species was 350–500.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spoon-billed_sandpiper' where nome_scientifico = 'Calidris pygmaea' and descrizione is null;
update specie set descrizione = 'The red-necked stint or rufous-necked stint is a small migratory wader that breeds in northeast Russia and spends the non-breeding season along the coastlines of Southeast Asia and Australasia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-necked_stint' where nome_scientifico = 'Calidris ruficollis' and descrizione is null;
