update specie set descrizione = 'The yellow-faced honeyeater is a small to medium-sized bird in the honeyeater family, Meliphagidae. It takes its common and scientific names from the distinctive yellow stripes on the sides of its head. Its loud, clear call often begins twenty or thirty minutes before dawn. It is widespread across eastern and southeastern Australia, in open sclerophyll forests from coastal dunes to high-altitude subalpine areas, and woodlands along creeks and rivers. Comparatively short-billed for a honeyeater, it is thought to have adapted to a diet of flies, spiders, and beetles, as well as nectar and pollen from the flowers of plants, such as Banksia and Grevillea, and soft fruits. It catches insects in flight as well as gleaning them from the foliage of trees and shrubs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-faced_honeyeater' where nome_scientifico = 'Caligavis chrysops' and descrizione is null;
update specie set descrizione = 'The black-throated honeyeater is a species of bird in the family Meliphagidae. It is found in New Guinea. Its natural habitat is subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_honeyeater' where nome_scientifico = 'Caligavis subfrenata' and descrizione is null;
