update specie set descrizione = 'La calliope siberiana è un uccello passeriforme della famiglia dei Muscicapidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Calliope_calliope' where nome_scientifico = 'Calliope calliope' and descrizione is null;
update specie set descrizione = 'The firethroat also known as David''s rubythroat or Père David''s orangethroat is a species of passerine bird in the family Muscicapidae, found in western and central parts of China. It breeds in Sichuan, China, and winters primarily in the Indian subcontinent. Its wintering range spans across Bangladesh, Bhutan, India, Nepal, Tibet and Myanmar. Its natural habitat is temperate forests.
It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Firethroat' where nome_scientifico = 'Calliope pectardens' and descrizione is null;
update specie set descrizione = 'The Himalayan rubythroat is a species of passerine bird in the family Muscicapidae. It is closely related to the Siberian rubythroat which however lacks the distinctive white tail-tips and white tail bases. It was also previously considered conspecific with the Chinese rubythroat, together called the white-tailed rubythroat. It is found along the Tien Shan and Himalayan ranges from Afghanistan to Myanmar. Three subspecies are recognized across its wide range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Himalayan_rubythroat' where nome_scientifico = 'Calliope pectoralis' and descrizione is null;
update specie set descrizione = 'The Chinese rubythroat is a small passerine bird in the family Muscicapidae. It is closely related to the Siberian rubythroat which however lacks the distinctive white tail-tips and white tail bases. It was also previously considered conspecific with the Himalayan rubythroat, together called the white-tailed rubythroat. It is found along the Himalayan ranges from Pakistan to Myanmar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chinese_rubythroat' where nome_scientifico = 'Calliope tschebaiewi' and descrizione is null;
update specie set descrizione = 'La quaglia della California o colino della California è un uccello della famiglia Odontophoridae, originario degli Stati Uniti occidentali. Il suo parente più prossimo è la quaglia di Gambel che ha una distribuzione più meridionale, il ciuffo più lungo (6,4 cm), la testa di un rosso mattone più acceso (maschio) e una parte ventrale priva di piume simili a squame ma con invece una grossa macchia nera (maschio). Le due specie si separarono circa 1-2 milioni di anni fa, tra la fine Pliocene e l''inizio del Pleistocene. Essendosi separate da un tempo relativamente breve, queste due specie sono ancora interfertili, e talvolta producono ibridi anche in natura. Dal 1932 la quaglia californiana è l''uccello di stato della California.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Callipepla_californica' where nome_scientifico = 'Callipepla californica' and descrizione is null;
update specie set descrizione = 'La quaglia elegante, nota anche come quaglia di Douglas o colino di Douglas, è un uccello della famiglia Odontophoridae, endemico del Messico.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Callipepla_douglasii' where nome_scientifico = 'Callipepla douglasii' and descrizione is null;
