update specie set descrizione = 'The green-backed camaroptera, also known as the bleating camaroptera, is a small bird in the family Cisticolidae. This bird is a resident breeder in Africa south of the Sahara Desert. Recent studies suggest this species and the grey-backed camaroptera may be the same species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-backed_camaroptera' where nome_scientifico = 'Camaroptera brachyura' and descrizione is null;
