update specie set descrizione = 'The black cuckooshrike is a species of bird in the cuckooshrike family Campephagidae. The species is closely related to Petit''s cuckooshrike and the red-shouldered cuckooshrike, and forms a superspecies with them. It is also known as the African black cuckooshrike.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_cuckooshrike' where nome_scientifico = 'Campephaga flava' and descrizione is null;
