update specie set descrizione = 'The golden-tailed woodpecker is a species of bird in the family Picidae. Its specific name commemorates the 5th Earl of Abingdon. It belongs to a species complex that includes the Knysna woodpecker to the south of its range, and the mostly allopatric Mombasa woodpecker to the northeast, with which it perhaps hybridizes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-tailed_woodpecker' where nome_scientifico = 'Campethera abingoni' and descrizione is null;
update specie set descrizione = 'The little green woodpecker, or green-backed woodpecker is a species of bird in the family Picidae. It is widely distributed in tropical Africa, living in forest edges, clearings, and forest-shrub mosaics. The International Union for Conservation of Nature (IUCN) has assessed it as a least-concern species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Little_green_woodpecker' where nome_scientifico = 'Campethera cailliautii' and descrizione is null;
update specie set descrizione = 'The Mombasa woodpecker is a species of bird in the family Picidae.
