update specie set descrizione = 'The southern beardless tyrannulet is a small passerine bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Costa Rica, Panama, in every mainland South American country except Chile, and on Trinidad.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_beardless_tyrannulet' where nome_scientifico = 'Camptostoma obsoletum' and descrizione is null;
