update specie set descrizione = 'The cactus wren is a species of wren that is endemic to the deserts of the southwestern United States and northern and central Mexico. It is the state bird of Arizona, and the largest wren in the United States. Its plumage is brown, with black and white spots as markings. It has a distinctive white eyebrow that sweeps to the nape of the neck. The chest is white, whereas the underparts are cinnamon-buff colored. Both sexes appear similar. The tail, as well as flight feathers, are barred in black and white. Their song is a loud raspy chirrup; akin in the description of some ornithologists to the sound of a car engine that will not start. It is well-adapted to its native desert environment, and the birds can meet their water needs from their diet which consists chiefly of insects, but also of some plant matter. The cactus wren is a poor flier and generally forages for food on the ground. Ornithologists generally recognize seven subspecies, with the exact taxonomy under dispute.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cactus_wren' where nome_scientifico = 'Campylorhynchus brunneicapillus' and descrizione is null;
update specie set descrizione = 'The giant wren is a species of bird in the family Troglodytidae. It is found in Mexico and Guatemala.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Giant_wren' where nome_scientifico = 'Campylorhynchus chiapensis' and descrizione is null;
update specie set descrizione = 'The fasciated wren is a species of bird in the family Troglodytidae. It is found in Ecuador and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fasciated_wren' where nome_scientifico = 'Campylorhynchus fasciatus' and descrizione is null;
