update specie set descrizione = 'The gray-barred wren is a species of bird in the family Troglodytidae. It is endemic to Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gray-barred_wren' where nome_scientifico = 'Campylorhynchus megalopterus' and descrizione is null;
update specie set descrizione = 'The stripe-backed wren is a bird found in the savannas of northern Colombia and central Venezuela. It lives in dry, riparian woodland, or farmlands, and is found at heights up to 800 m.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Stripe-backed_wren' where nome_scientifico = 'Campylorhynchus nuchalis' and descrizione is null;
update specie set descrizione = 'The Veracruz wren is a songbird of the family Troglodytidae. It is endemic to Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Veracruz_wren' where nome_scientifico = 'Campylorhynchus rufinucha' and descrizione is null;
update specie set descrizione = 'The thrush-like wren is a South American species of bird in the family Troglodytidae, the wrens. As suggested by its common and scientific name, its size and coloration are vaguely reminiscent of that of a thrush, although the general impression it gives in life is very different and not at all "thrush-like".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Thrush-like_wren' where nome_scientifico = 'Campylorhynchus turdinus' and descrizione is null;
update specie set descrizione = 'The Yucatan wren is a species of bird in the family Troglodytidae. It is endemic to Mexico. Its natural habitat is subtropical or tropical dry shrubland, only found on the narrow coastal strip of the northern Yucatán Peninsula. One of the critical habitats of this species is the Petenes mangroves ecoregion of the Yucatan coast. It is threatened by habitat destruction.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yucatan_wren' where nome_scientifico = 'Campylorhynchus yucatanicus' and descrizione is null;
update specie set descrizione = 'The band-backed wren is a small songbird of the wren family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Band-backed_wren' where nome_scientifico = 'Campylorhynchus zonatus' and descrizione is null;
update specie set descrizione = 'Il tetraone delle peccete è un uccello di medie dimensioni, appartenente alla famiglia dei Fagianidi, diffuso nel Nord America.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Canachites_canadensis' where nome_scientifico = 'Canachites canadensis' and descrizione is null;
update specie set descrizione = 'Il coyote, adattato a volte in coiote, detto anche lupo della prateria, è un canide lupino indigeno del Nord America. In confronto al lupo grigio il coyote è di taglia più piccola e filogeneticamente più antico, paragonabile allo sciacallo dorato dell''Eurasia, benché ne sia più grande e con istinti più predatori. Viene classificato dalla IUCN tra le specie a rischio minimo, dato che ha un vastissimo areale che dal Nord America scende a includere il Messico e l''America centrale. È una specie molto adattabile, il cui areale si è ampliato in mezzo ai cambiamenti ambientali dell''uomo. Questo incremento è ancora in corso ed è probabile che colonizzerà il Sud America, come dimostrato dalla presenza di coyote oltre il Canale di Panama nel 2013. Nel 2005 Mammal Species of the World ne riconosceva 19 sottospecie.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Canis_latrans' where nome_scientifico = 'Canis latrans' and descrizione is null;
update specie set descrizione = 'Il lupo grigio, noto anche come lupo comune o semplicemente lupo, è un canide lupino presente nelle zone remote del Nord America e dell''Eurasia. È il più grande della sua famiglia, con un peso medio di 43-45 kg per i maschi e 36-38,5 kg per le femmine. Oltre che per le dimensioni, il lupo grigio si distingue dagli altri membri del genere Canis per il muso e le orecchie meno appuntite. Il suo mantello invernale è lungo e folto, prevalentemente grigio variegato, ma alcuni esemplari possono presentare colorazioni bianche, rosse, brune o nere.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Canis_lupus' where nome_scientifico = 'Canis lupus' and descrizione is null;
