update specie set descrizione = 'The stripe-throated wren is a species of bird in the family Troglodytidae. It is found in Colombia, Ecuador, and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Stripe-throated_wren' where nome_scientifico = 'Cantorchilus leucopogon' and descrizione is null;
update specie set descrizione = 'The buff-breasted wren is a species of bird in the family Troglodytidae. It is found in the Amazon Basin of northern Brazil and Amazonian Colombia, Ecuador, Peru and northern-border Bolivia, and also the Guianan countries of Guyana, Suriname, and French Guiana. It occurs in non-Amazonian regions of Venezuela and Colombia and its range extends into eastern Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buff-breasted_wren' where nome_scientifico = 'Cantorchilus leucotis' and descrizione is null;
