update specie set descrizione = 'The gilded barbet is a species of bird in the family Capitonidae, the New World barbets, and a close relative of the toucans.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gilded_barbet' where nome_scientifico = 'Capito auratus' and descrizione is null;
