update specie set descrizione = 'The black-spotted barbet is a species of bird in the family Capitonidae, the New World barbets. It is found in Brazil, the Guianas, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-spotted_barbet' where nome_scientifico = 'Capito niger' and descrizione is null;
