update specie set descrizione = 'Il succiacapre di savana o succiacapre della Sonda (Caprimulgus affinis) è una specie di succiacapre che vive in Asia meridionale, solitamente nelle Filippine.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Caprimulgus_affinis' where nome_scientifico = 'Caprimulgus affinis' and descrizione is null;
update specie set descrizione = 'The Indian nightjar is a small nightjar which is a resident breeder in open lands across South Asia and Southeast Asia. Like most nightjars it is crepuscular and is best detected from its characteristic calls at dawn and dusk that have been likened to a stone skipping on a frozen lake - a series of clicks that become shorter and more rapid. They are sometimes spotted on roads when their eyes gleam red in the spotlight of a vehicle. There is considerable plumage variation across its range and can be hard to differentiate from other nightjars in the region especially in the field.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_nightjar' where nome_scientifico = 'Caprimulgus asiaticus' and descrizione is null;
update specie set descrizione = 'The slender-tailed nightjar is a species of nightjar in the family Caprimulgidae. It is found in parts of eastern and central Africa, including the Democratic Republic of the Congo, Ethiopia, Kenya, Somalia, South Sudan, Tanzania, and Uganda.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slender-tailed_nightjar' where nome_scientifico = 'Caprimulgus clarus' and descrizione is null;
update specie set descrizione = 'The long-tailed nightjar is one of 98 species of nightjar in the family Caprimulgidae, the "true nightjars". It is a nocturnal, insectivorous bird characterized by its distinctive long tail. It is found throughout mainland Africa in open areas, arid semi-deserts, and savannas, with common sightings alongside roadways.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-tailed_nightjar' where nome_scientifico = 'Caprimulgus climacurus' and descrizione is null;
update specie set descrizione = 'The European nightjar, common goatsucker, Eurasian nightjar or just nightjar is a crepuscular and nocturnal bird in the nightjar family that breeds across most of Europe and the Palearctic to Mongolia and Northwestern China. The Latin generic name refers to the old myth that the nocturnal nightjar suckled from goats, causing them to cease to give milk. The six subspecies differ clinally, the birds becoming smaller and paler towards the east of the range. All populations are migratory, wintering in sub-Saharan Africa. Their densely patterned grey and brown plumage makes individuals difficult to see in the daytime when they rest on the ground or perch motionless along a branch, although the male shows white patches in the wings and tail as he flies at night.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/European_nightjar' where nome_scientifico = 'Caprimulgus europaeus' and descrizione is null;
update specie set descrizione = 'The square-tailed nightjar is a species of nightjar in the family Caprimulgidae which is native to tropical and subtropical woodlands of the Afrotropics. It has an extensive range south of the African equator. Despite not having a completely "square tail", its naming highlights a distinguishing field mark. The similarly plumaged slender-tailed nightjar, found in dry bush country of the tropics, differs namely by its protruding central tail feathers. It is alternatively known as the Gabon nightjar or Gaboon nightjar or the Mozambique nightjar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Square-tailed_nightjar' where nome_scientifico = 'Caprimulgus fossii' and descrizione is null;
update specie set descrizione = 'The jungle nightjar is a species of nightjar found in the Indian subcontinent. It is found mainly on the edge of forests where it is seen or heard at dusk. The taxonomy of this and related nightjars is complex and a range of treatments have been followed that cover this and several other nightjars in the Asian region. It was formerly called the grey nightjar or Indian jungle nightjar and sometimes included the East Asian grey nightjar as a subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Jungle_nightjar' where nome_scientifico = 'Caprimulgus indicus' and descrizione is null;
update specie set descrizione = 'The grey nightjar is a species of nightjar found in East Asia, breeding from southeastern Russia south through China, the Korean Peninsula and Japan to northern Indochina and westward along the Himalayas. It is largely migratory, wintering in Indochina south to Java in Indonesia, but is resident in warmer areas in the south of its breeding range. It is sometimes treated as a subspecies of the jungle nightjar, its South Asian relative. The grey nightjar breeds and forages in early successional habitats surrounded by forests; its populations have declined since the 1970s in Japan. Like all nightjars, it is crepuscular to nocturnal, feeding on flying insects, including moths, beetles, flying ants, grasshoppers, and others.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey_nightjar' where nome_scientifico = 'Caprimulgus jotaka' and descrizione is null;
update specie set descrizione = 'The large-tailed nightjar is a species of nightjar known for its distinctive long, broad tail and cryptic plumage that allows it to blend into its surroundings. Found along the southern Himalayan foothills, eastern South Asia, Southeast Asia and northern Australia, its natural habitats are subtropical or tropical moist lowland forest, subtropical or tropical mangrove forest, and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Large-tailed_nightjar' where nome_scientifico = 'Caprimulgus macrurus' and descrizione is null;
update specie set descrizione = 'Il succiacapre del Madagascar è un uccello della famiglia Caprimulgidae, diffuso in Madagascar e nelle Seychelles.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Caprimulgus_madagascariensis' where nome_scientifico = 'Caprimulgus madagascariensis' and descrizione is null;
update specie set descrizione = 'The Philippine nightjar is a species of nightjar in the family Caprimulgidae. It is endemic to the Philippines. Its local names are kandarapa (Tagalog) and tagolilong (Cebuano).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Philippine_nightjar' where nome_scientifico = 'Caprimulgus manillensis' and descrizione is null;
update specie set descrizione = 'The swamp nightjar or Natal nightjar is a crepuscular and nocturnal bird in the nightjar family found in Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Swamp_nightjar' where nome_scientifico = 'Caprimulgus natalensis' and descrizione is null;
update specie set descrizione = 'The fiery-necked nightjar is a species of nightjar in the family Caprimulgidae, which is found mostly in Africa south of the equator, though it has been spotted in a few countries north of the equator. It is most often found in woodland savannas or other deciduous woodlands. It is usually distinguished by its tawny coloured collar which gives the species its common name. It has a distinctive call that many have rendered as ''good-lord-deliver-us''. The fiery-necked nightjar is an insectivorous species that mostly eats butterflies, moths and other insects. The fiery-necked nightjar breeds after the dry season and typically produce two clutches with two eggs per clutch.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fiery-necked_nightjar' where nome_scientifico = 'Caprimulgus nigriscapularis' and descrizione is null;
update specie set descrizione = 'The fiery-necked nightjar is a species of nightjar in the family Caprimulgidae, which is found mostly in Africa south of the equator, though it has been spotted in a few countries north of the equator. It is most often found in woodland savannas or other deciduous woodlands. It is usually distinguished by its tawny coloured collar which gives the species its common name. It has a distinctive call that many have rendered as ''good-lord-deliver-us''. The fiery-necked nightjar is an insectivorous species that mostly eats butterflies, moths and other insects. The fiery-necked nightjar breeds after the dry season and typically produce two clutches with two eggs per clutch.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fiery-necked_nightjar' where nome_scientifico = 'Caprimulgus pectoralis' and descrizione is null;
update specie set descrizione = 'The montane nightjar, mountain nightjar or Abyssinian nightjar, is a species of nightjar in the family Caprimulgidae. It is native to upland regions of Central and Eastern Africa where it is a locally common species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Montane_nightjar' where nome_scientifico = 'Caprimulgus poliocephalus' and descrizione is null;
update specie set descrizione = 'Il succiacapre collorosso è un uccello della famiglia Caprimulgidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Caprimulgus_ruficollis' where nome_scientifico = 'Caprimulgus ruficollis' and descrizione is null;
update specie set descrizione = 'The rufous-cheeked nightjar is a species of nightjar in the family Caprimulgidae. It is an intra-African migrant that breeds in the south of its range. It spends the non-breeding season in eastern Nigeria, Cameroon, southern Chad and Sudan, the Republic of the Congo, the D.R.C. and western Central African Republic. Throughout the year it can be found in Southern Africa. It is a nocturnal species that feeds on flying insects, mainly hunting at dusk and the early night. They can hunt at night thanks to their large eyes that are adept at seeing in the dark. They cannot see in complete darkness and most likely cannot see colours either. The rufous-cheeked nightjar forms monogamous pairs and the egg laying period is from September to November. It looks very similar to other African nightjars and they are frequently misidentified during research and studies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-cheeked_nightjar' where nome_scientifico = 'Caprimulgus rufigena' and descrizione is null;
update specie set descrizione = 'The freckled nightjar or freckled rock nightjar is a species of nightjar in the family Caprimulgidae. It has a wide yet patchy distribution throughout the Afrotropics.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Freckled_nightjar' where nome_scientifico = 'Caprimulgus tristigma' and descrizione is null;
update specie set descrizione = 'The yellow tyrannulet is a small passerine bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Costa Rica, Nicaragua, Panama, and in every mainland South American country except Chile and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow_tyrannulet' where nome_scientifico = 'Capsiempis flaveola' and descrizione is null;
update specie set descrizione = 'Il caracara meridionale è un uccello rapace della famiglia dei Falconidi diffuso in Sud America, dove è noto come carcarà o carancho.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Caracara_plancus' where nome_scientifico = 'Caracara plancus' and descrizione is null;
update specie set descrizione = 'The Canada warbler is a small boreal songbird of the New World warbler family (Parulidae). It summers in Canada and northeastern United States and winters in northern South America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Canada_warbler' where nome_scientifico = 'Cardellina canadensis' and descrizione is null;
update specie set descrizione = 'The red warbler is a small passerine bird of the New World warbler family Parulidae endemic to the highlands of Mexico, north of the Isthmus of Tehuantepec. It is closely related to, and forms a superspecies with, the pink-headed warbler of southern Mexico and Guatemala. There are three subspecies, found in disjunct populations, which differ in the color of their ear patch and in the brightness and tone of their body plumage. The adult is bright red, with a white or gray ear patch, depending on the subspecies; young birds are pinkish-brown, with a whitish ear patch and two pale wingbars.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red_warbler' where nome_scientifico = 'Cardellina rubra' and descrizione is null;
update specie set descrizione = 'The red-faced warbler is a species of New World warbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-faced_warbler' where nome_scientifico = 'Cardellina rubrifrons' and descrizione is null;
update specie set descrizione = 'The pink-headed warbler is a small passerine bird found in the southwestern highlands of Guatemala and the central and southeastern highlands of the Mexican state of Chiapas. The adult is primarily red, with a silvery-pink head and chest. It is a fairly common to common resident of humid to semi-humid pine-oak, pine-evergreen and evergreen forest and edge, at altitudes ranging from 1,800–3,500 m (5,900–11,500 ft) above sea level.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pink-headed_warbler' where nome_scientifico = 'Cardellina versicolor' and descrizione is null;
