update specie set descrizione = 'Il seriema crestato è un uccello predatore prevalentemente terrestre appartenente alla famiglia dei Cariamidi (Cariamidae). Questa famiglia, in passato inclusa nei Gruiformi (Gruiformes) nella loro vecchia circoscrizione polifiletica, è oggi collocata in un ordine distinto, i Cariamiformi (Cariamiformes), insieme a tre famiglie estinte.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cariama_cristata' where nome_scientifico = 'Cariama cristata' and descrizione is null;
