update specie set descrizione = 'The pale rockfinch or pale rock sparrow is a small sparrow found in the Middle East and Central Asia. It is the only member of the genus Carpospiza. Some authorities include it in the genus Petronia. Others have placed it in the finch family due to some similarities in behaviour and form, but the anatomy of its tongue exhibits characteristic sparrow features.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale_rockfinch' where nome_scientifico = 'Carpospiza brachydactyla' and descrizione is null;
update specie set descrizione = 'The golden monarch is a species of passerine bird in the family Monarchidae found in New Guinea.
Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forest. The golden monarch displays marked sexual dimorphism, the male a striking golden colour with black mask, wings and tail, the female a golden or golden-olive colour. Both bear a characteristic ''teardrop'' white pattern below the eye.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden_monarch' where nome_scientifico = 'Carterornis chrysomela' and descrizione is null;
update specie set descrizione = 'The white-eared monarch, or white-eared flycatcher, is a species of bird in the family Monarchidae.
It is endemic to north-eastern Australia. Its natural habitat is subtropical or tropical moist lowland forests. The white-eared monarch was originally described in the genus Monarcha until moved to Carterornis in 2009.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-eared_monarch' where nome_scientifico = 'Carterornis leucotis' and descrizione is null;
