update specie set descrizione = 'L''avvoltoio collorosso, noto anche come "avvoltoio tacchino", è il rappresentante più diffuso della famiglia dei Catartidi, gli avvoltoi del Nuovo Mondo. Nelle regioni nordamericane in cui vive è noto anche come Turkey Buzzard, vale a dire «poiana tacchino» o «poiana», mentre in alcune zone dei Caraibi viene chiamato John Crow o Carrion Crow, cioè «John il corvo» o «corvo delle carogne». Questo avvoltoio, una delle tre specie del genere Cathartes, è diffuso dal Canada meridionale all''estremità meridionale del Sudamerica. Occupa una vasta gamma di ambienti aperti e semi-aperti, quali foreste subtropicali, boscaglie, pascoli e deserti.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cathartes_aura' where nome_scientifico = 'Cathartes aura' and descrizione is null;
update specie set descrizione = 'The orange-billed nightingale-thrush is a species of bird in the family Turdidae, the thrushes and allies. It is found from northern Mexico through Central America into northern South America. In addition it has been documented in Brazil and as a vagrant to the United States.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-billed_nightingale-thrush' where nome_scientifico = 'Catharus aurantiirostris' and descrizione is null;
update specie set descrizione = 'The yellow-throated nightingale-thrush or Gould''s nightingale-thrush is a species of bird in the family Turdidae, the thrushes and allies. It is found from Mexico to Nicaragua.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_nightingale-thrush' where nome_scientifico = 'Catharus dryas' and descrizione is null;
