update specie set descrizione = 'The veery is a small North American thrush species, a member of a group of closely related and similar species in the genus Catharus, also including the gray-cheeked thrush, Bicknell''s thrush, Swainson''s thrush, and hermit thrush. Alternate names for this species include Wilson''s thrush and tawny thrush. Up to six subspecies exist, which are grouped into the eastern veery, the western veery or willow thrush, and the Newfoundland veery.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Veery' where nome_scientifico = 'Catharus fuscescens' and descrizione is null;
