update specie set descrizione = 'The speckled nightingale-thrush or Sclater''s nightingale-thrush is a species of bird in the family Turdidae, the thrushes and allies. It is found from Colombia and Venezuela to Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Speckled_nightingale-thrush' where nome_scientifico = 'Catharus maculatus' and descrizione is null;
update specie set descrizione = 'The black-headed nightingale-thrush is a species of bird in the family Turdidae, the thrushes and allies. It is found in Costa Rica, Guatemala, Honduras, Mexico, Nicaragua, and Panama. It has also been recorded as a vagrant in the U. S. state of Texas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_nightingale-thrush' where nome_scientifico = 'Catharus mexicanus' and descrizione is null;
update specie set descrizione = 'The gray-cheeked thrush is a medium-sized thrush. This species is 15–17 cm (5.9–6.7 in) in length, and has the white-dark-white underwing pattern characteristic of Catharus thrushes. It is a member of a close-knit group of migrant species together with the veery and Bicknell''s thrush; it forms a cryptic species pair with the latter. The gray-cheeked thrush is all but indistinguishable from Bicknell''s thrush except by its slightly larger size and different song. The two were formerly considered conspecific. Of all the American spotted thrushes, the gray-cheeked has the most northern breeding range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gray-cheeked_thrush' where nome_scientifico = 'Catharus minimus' and descrizione is null;
update specie set descrizione = 'The russet nightingale-thrush is a species of bird in the family Turdidae, the thrushes and allies. It is endemic to Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Russet_nightingale-thrush' where nome_scientifico = 'Catharus occidentalis' and descrizione is null;
update specie set descrizione = 'The canyon wren is a small North American songbird of the wren family Troglodytidae. A non-migratory species, these birds are found throughout western North America in dry, rocky environments such as cliffs, outcrops, and canyons. It is a small bird that is hard to see on its rocky habitat, and is often located by its loud distinctive song. It is currently in a monotypic taxon and is the only species in the genus Catherpes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Canyon_wren' where nome_scientifico = 'Catherpes mexicanus' and descrizione is null;
