update specie set descrizione = 'The lesser coucal is a species of cuckoo in the family Cuculidae. It has a wide distribution range that overlaps with several other similar species. The habitat in which it is found is often marshy land with grass and tree cover. It is distinguished by its smaller size, less prominent bill, pale shaft streaks on the feathers of the head and back. It has a much longer claw on its hind toe and a distinct call. It is also among the few coucals that show season plumage differences but like in other coucals, the sexes cannot be distinguished in the field.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_coucal' where nome_scientifico = 'Centropus bengalensis' and descrizione is null;
