update specie set descrizione = 'The golden-headed manakin is a small passerine bird which breeds in tropical Central and South America in both wet and dry forests, secondary growth and plantations. It is a small manakin, about 9.4 centimetres (3.7 in) long. Males are entirely black apart from a golden head, yellow bill, white and red thighs and pink legs. Females and juveniles are olive-green with pink legs. At breeding time, males are involved in a cooperative lekking behaviour during which they jump, slide and dart from perch to perch. This is a fairly common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-headed_manakin' where nome_scientifico = 'Ceratopipra erythrocephala' and descrizione is null;
