update specie set descrizione = 'The miombo scrub robin is a species of bird in the family Muscicapidae. It is found in Angola, Burundi, Democratic Republic of the Congo, Malawi, Mozambique, Tanzania, and Zambia. This species was formerly placed in the genus Cercotrichas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Miombo_scrub_robin' where nome_scientifico = 'Cercotrichas barbata' and descrizione is null;
update specie set descrizione = 'The Karoo scrub robin or Karoo robin is a species of bird in the family Muscicapidae. It is found in Lesotho, Namibia, and South Africa. Its natural habitats are dry shrubland and Mediterranean-type shrubby vegetation. This species was formerly placed in the genus Cercotrichas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Karoo_scrub_robin' where nome_scientifico = 'Cercotrichas coryphoeus' and descrizione is null;
update specie set descrizione = 'The rufous-tailed scrub robin is a medium-sized member of the family Muscicapidae. Other common names include the rufous scrub robin, rufous bush chat, rufous bush robin and the rufous warbler. It breeds around the Mediterranean and east to Pakistan. It also breeds south of the Sahara from the Sahel region east to Somalia; these African birds are sometimes considered to be a separate species, the African scrub robin. It is partially migratory, wintering in Africa and India. This is a very rare visitor to northern Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-tailed_scrub_robin' where nome_scientifico = 'Cercotrichas galactotes' and descrizione is null;
update specie set descrizione = 'The brown-backed scrub robin is a species of bird in the family Muscicapidae.
