update specie set descrizione = 'The coal-crested finch is a species of bird in the family Thraupidae. Though previously classified in the bunting and American sparrow family Emberizidae, molecular phylogenetic studies have shown that it is a member of the large tanager family Thraupidae. It is the only member of the genus Charitospiza.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Coal-crested_finch' where nome_scientifico = 'Charitospiza eucosma' and descrizione is null;
