update specie set descrizione = 'The Oʻahu ʻelepaio is a monarch flycatcher endemic to the Hawaiian Island of Oʻahu. It is one of the three distinct, closely related species of ʻelepaio native to the Hawaiian archipelago, including the Hawaiʻi ʻelepaio and the Kauʻi ʻelepaio. They are found in high elevations on the slopes of Oʻahu and primarily consume insects. They are currently listed as vulnerable by the IUCN Red List, and ongoing work is being done to eliminate invasive predators and disease.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/O%CA%BBahu_%CA%BBelepaio' where nome_scientifico = 'Chasiempis ibidis' and descrizione is null;
update specie set descrizione = 'The Hawaiʻi ʻelepaio, also Hawaiian ʻelepaio, is a monarch flycatcher found on the Big Island of Hawaii. Until 2010, all three ʻelepaio species, the Kauaʻi ʻelepaio, the Oʻahu ʻelepaio and this species were considered conspecific.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hawai%CA%BBi_%CA%BBelepaio' where nome_scientifico = 'Chasiempis sandwichensis' and descrizione is null;
update specie set descrizione = 'The Kauaʻi ʻelepaio is a monarch flycatcher found on the Hawaiian Island of Kauaʻi. It numbered 40,000 around 1970, but declined by half in the 1990s. Whether this fluctuation is natural and thus the birds'' numbers will rebound or whether it signifies a novel threat remains to be seen. However, it seems the birds are making a recovery, as population density on the Alakai plateau has increased by 13% in recent years.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Kaua%CA%BBi_%CA%BBelepaio' where nome_scientifico = 'Chasiempis sclateri' and descrizione is null;
