update specie set descrizione = 'The glittering-throated emerald is a species of hummingbird in the "emeralds", tribe Trochilini of subfamily Trochilinae. It is found in Bolivia, Brazil, Colombia, Ecuador, the Guianas, Peru, Trinidad and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Glittering-throated_emerald' where nome_scientifico = 'Chionomesa fimbriata' and descrizione is null;
update specie set descrizione = 'The sapphire-spangled emerald is a species of hummingbird in the "emeralds", tribe Trochilini of subfamily Trochilinae. It is regularly found in Bolivia, Brazil, Peru, and Venezuela; as a vagrant in Argentina; and has possibly occurred in Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sapphire-spangled_emerald' where nome_scientifico = 'Chionomesa lactea' and descrizione is null;
update specie set descrizione = 'The Yungas manakin is a species of bird in the family Pipridae. It is found in Argentina, Bolivia, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yungas_manakin' where nome_scientifico = 'Chiroxiphia boliviana' and descrizione is null;
update specie set descrizione = 'The blue manakin or swallow-tailed manakin is a small species of bird in the family Pipridae. It is found mainly in the Atlantic Forest of south-eastern Brazil, eastern Paraguay and far north-eastern Argentina. Its typical habitat is wet lowland or montane forest and heavily degraded former forest. Males have a bright blue body, black head wings and tail and a red crown. Females and juveniles are olive-green. At breeding time, males are involved in lekking behaviour when they sing and dance to impress females. This is a common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue_manakin' where nome_scientifico = 'Chiroxiphia caudata' and descrizione is null;
update specie set descrizione = 'The lance-tailed manakin is a small passerine bird which breeds in tropical Central and South America from Costa Rica to northern Venezuela. This manakin is a fairly common bird of dry and moist deciduous forests, but not rainforest. It is a small, compact bird about 13 centimetres (5 in) long and similar to the blue-backed manakin, but both sexes have the two central tail feathers elongated to form a spike. Males have black plumage with a blue back, a red crown and orange legs. Females and juveniles are olive-green with paler underparts. At breeding time, males are involved in a cooperative behaviour during which they jump up and down alternately. This is a fairly common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lance-tailed_manakin' where nome_scientifico = 'Chiroxiphia lanceolata' and descrizione is null;
update specie set descrizione = 'The long-tailed manakin is a species of bird in the family Pipridae native to Central America where it inhabits both wet and dry tropical and subtropical forests. It is a small, plump bird about 10 centimetres (4 in) long. Males have black plumage with a blue back and a red crown, and the two central tail feathers are greatly elongated. Females and juveniles are olive-green with paler underparts. At breeding time, males are involved in a cooperative lekking behaviour with a complex coordinated courtship dance. This is a fairly common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-tailed_manakin' where nome_scientifico = 'Chiroxiphia linearis' and descrizione is null;
update specie set descrizione = 'The blue-backed manakin is a small passerine bird which breeds in tropical South America, its range extending from Colombia and Tobago to southeastern Brazil. It is found in deciduous forests but not evergreen rainforests. It is a small, plump bird about 13 centimetres (5 in) long. Males have black plumage with a bright blue back and a red or yellow crown. Females and juveniles are olive-green with paler underparts. At breeding time, males are involved in a cooperative lekking behaviour during which they jump and twirl. This is a fairly common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-backed_manakin' where nome_scientifico = 'Chiroxiphia pareola' and descrizione is null;
