update specie set descrizione = 'The White-chinned sapphire is a small species of hummingbird in the family Trochilidae.
It is found in northern and eastern South America.
It inhabits a variety of environments, including lowland tropical forests, woodland edges, and clearings with scattered trees. This species is known for its distinctive steel-blue tail and sexual dimorphism, with males displaying a violet-blue head and throat and a coral-red bill, while females have subdued green plumage. The White-chinned sapphire feeds primarily on nectar from flowering plants but also consumes small arthropods such as insects and spiders. It is non-migratory species and occurs as a year round resident throughout much of its range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-chinned_sapphire' where nome_scientifico = 'Chlorestes cyanus' and descrizione is null;
update specie set descrizione = 'The blue-throated goldentail, also known as the blue-throated sapphire, is a species of hummingbird in the family Trochilidae. It is found in Belize, Colombia, Costa Rica, El Salvador, Guatemala, Honduras, Mexico, Nicaragua, and Panama. Its natural habitats are subtropical or tropical moist lowland forest and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-throated_goldentail' where nome_scientifico = 'Chlorestes eliciae' and descrizione is null;
