update specie set descrizione = 'The cardinal woodpecker is a widespread and common resident breeder in much of sub-Saharan Africa. It occurs in a wide range of habitats, ranging from dense forest to thorn bush. It is fairly vocal and is easily identified by its call notes. The sexes are distinguishable by their head patterns. They feed primarily on tree-boring insects; using their adhering tongues they extract the insects from holes in wood or bark.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cardinal_woodpecker' where nome_scientifico = 'Chloropicus fuscescens' and descrizione is null;
update specie set descrizione = 'The African grey woodpecker is a species of bird in the woodpecker family Picidae. Is a widespread and frequently common resident breeder in much of Sub-Saharan and equatorial Africa. It is a species associated with forest and bush which nests in a tree hole, often in an oil palm, laying two to four eggs. It is a common bird with a very wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_grey_woodpecker' where nome_scientifico = 'Chloropicus goertae' and descrizione is null;
update specie set descrizione = 'The olive woodpecker is a species of bird in the woodpecker family Picidae. It is in the Dendropicos genus, which comprises small woodpeckers native to Sub-Saharan Africa. There are three described subspecies, all inhabiting various regions of southeast Africa; the red-bellied olive woodpecker, the montane olive woodpecker, and the southern olive woodpecker.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive_woodpecker' where nome_scientifico = 'Chloropicus griseocephalus' and descrizione is null;
update specie set descrizione = 'The bearded woodpecker is a species of bird in the family Picidae. It has a distinctive black and white head and brownish barred body. It is native to tropical central Africa. It has an extremely wide range and is a fairly common species, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern". Some taxonomic authorities place this species in Dendropicos.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bearded_woodpecker' where nome_scientifico = 'Chloropicus namaquus' and descrizione is null;
update specie set descrizione = 'The eastern grey woodpecker, also known as grey-headed woodpecker and mountain gray woodpecker, is a species of bird in the woodpecker family Picidae. It is a resident breeder in eastern Africa. It has a large range and is a fairly common species. No special threats have been recognised and the International Union for Conservation of Nature has rated the bird''s conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_grey_woodpecker' where nome_scientifico = 'Chloropicus spodocephalus' and descrizione is null;
