update specie set descrizione = 'The common chlorospingus, also referred to as common bush tanager, is a small passerine bird. It is a resident breeder in the highlands from central Mexico south to Bolivia and northwest Argentina. C. flavopectus in the loose sense is a notorious cryptic species complex, and several of the up to 25 subspecies recognized in recent times are likely to be distinct species. Some populations in fact appear to be more distinct than several other members of Chlorospingus.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_chlorospingus' where nome_scientifico = 'Chlorospingus flavopectus' and descrizione is null;
update specie set descrizione = 'The sooty-capped chlorospingus or sooty-capped bush tanager, is a small passerine bird in the family Passerellidae, the New World sparrows. It is found in Costa Rica and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sooty-capped_chlorospingus' where nome_scientifico = 'Chlorospingus pileatus' and descrizione is null;
