update specie set descrizione = 'The blue-tailed emerald is a hummingbird in the "emeralds", tribe Trochilini of subfamily Trochilinae. It is found in tropical and subtropical South America east of the Andes from Colombia east to the Guianas and Trinidad, and south to northern Bolivia and central Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-tailed_emerald' where nome_scientifico = 'Chlorostilbon mellisugus' and descrizione is null;
update specie set descrizione = 'The lemon-spectacled tanager is a species of bird in the family Cardinalidae. It is found in Colombia, Ecuador, and Panama where its natural habitats are subtropical or tropical moist lowland forest, subtropical or tropical moist montane forest, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lemon-spectacled_tanager' where nome_scientifico = 'Chlorothraupis olivacea' and descrizione is null;
update specie set descrizione = 'The ochre-breasted tanager is a species of bird in the family Cardinalidae. It is found in Colombia and Ecuador where its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests. As a fairly common species with a stable population, the International Union for Conservation of Nature has rated this bird as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ochre-breasted_tanager' where nome_scientifico = 'Chlorothraupis stolzmanni' and descrizione is null;
update specie set descrizione = 'The brown parrotbill is a parrotbill found in the central and eastern Himalayas. It is also known as the brown suthora. This is a 17–19 cm (6.7–7.5 in) long grey-brown bird with a long tail and a characteristic small, yellowish, parrot-like bill. A dark stripe runs above the eyes and along the sides of the crown. The bird moves in small groups and will sometimes join mixed species foraging flocks. It is found in Bhutan, China, India, Myanmar, and Nepal.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_parrotbill' where nome_scientifico = 'Cholornis unicolor' and descrizione is null;
