update specie set descrizione = 'Il nibbio beccouncinato è un rapace della famiglia degli Accipitridi originario delle Americhe.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Chondrohierax_uncinatus' where nome_scientifico = 'Chondrohierax uncinatus' and descrizione is null;
update specie set descrizione = 'The lesser nighthawk is a nightjar found throughout a large part of the Americas. This bird looks similar to the common nighthawk but is slightly smaller, has a slightly less deeply forked tail, and is more buffy in coloration. Their distinctive mouths are very well adapted for capturing insects mid-flight.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_nighthawk' where nome_scientifico = 'Chordeiles acutipennis' and descrizione is null;
update specie set descrizione = 'The Antillean nighthawk is a nightjar native to the Caribbean, The Bahamas, and Florida Keys.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Antillean_nighthawk' where nome_scientifico = 'Chordeiles gundlachii' and descrizione is null;
update specie set descrizione = 'The common nighthawk or bullbat is a medium-sized crepuscular or nocturnal bird of the Americas within the nightjar (Caprimulgidae) family, whose presence and identity are best revealed by its vocalization. Typically dark, displaying cryptic colouration and intricate patterns, this bird is difficult to spot with the naked eye during the day. This bird is most conspicuous when in its buoyant and erratic flight. The most remarkable feature of this aerial insectivore is its small beak that belies the massiveness of its mouth. Some claim appearance similarities to owls. With its horizontal stance and short legs, the common nighthawk does not travel frequently on the ground, instead preferring to perch horizontally, parallel to branches, on posts, on the ground or on a roof. The males of this species may roost together but the bird is primarily solitary. The common nighthawk shows variability in territory size.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_nighthawk' where nome_scientifico = 'Chordeiles minor' and descrizione is null;
update specie set descrizione = 'The nacunda nighthawk is a species of nightjar in the family Caprimulgidae. It is found in Argentina, Bolivia, Brazil, Chile, Colombia, Ecuador, French Guiana, Guyana, Paraguay, Peru, Suriname, Trinidad and Tobago, Uruguay, and Venezuela. Its natural habitats are dry savanna, subtropical or tropical seasonally wet or flooded lowland grassland, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Nacunda_nighthawk' where nome_scientifico = 'Chordeiles nacunda' and descrizione is null;
update specie set descrizione = 'The least nighthawk is a species of nightjar in the family Caprimulgidae. It is found in Argentina, Bolivia, Brazil, Colombia, Guyana, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Least_nighthawk' where nome_scientifico = 'Chordeiles pusillus' and descrizione is null;
