update specie set descrizione = 'The white-naped woodpecker is woodpecker which is a widespread but a scarce breeder in the Indian subcontinent. 
It is associated with open forest and scrub with some trees. It nests in a tree hole, laying one or two white eggs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-naped_woodpecker' where nome_scientifico = 'Chrysocolaptes festivus' and descrizione is null;
