update specie set descrizione = 'The yellow-eyed babbler is a passerine bird native to South and Southeast Asia. It inhabits shrubland, grassland and wetland habitats. On the IUCN Red List, it is listed as Least Concern because of its wide distribution and stable population.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-eyed_babbler' where nome_scientifico = 'Chrysomma sinense' and descrizione is null;
update specie set descrizione = 'The yellow-hooded blackbird is a species of bird in the family Icteridae. It is found in grassy and brush areas near water in northern South America, and is generally fairly common. It is sexually dimorphic, and the sexes resemble the respective sexes of the larger yellow-headed blackbird of North America, though the male yellow-hooded blackbird lacks white in the wings.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-hooded_blackbird' where nome_scientifico = 'Chrysomus icterocephalus' and descrizione is null;
update specie set descrizione = 'The chestnut-capped blackbird is a species of bird in the family Icteridae. It is found in Argentina, Bolivia, Brazil, French Guiana, Paraguay, and Uruguay, where its natural habitats are swamps, ricefields and pastureland. The International Union for Conservation of Nature rates its conservation status as "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-capped_blackbird' where nome_scientifico = 'Chrysomus ruficapillus' and descrizione is null;
