update specie set descrizione = 'The checker-throated woodpecker, checker-throated yellownape, or Javan yellownape is a species of bird in the family Picidae native to Southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Checker-throated_woodpecker' where nome_scientifico = 'Chrysophlegma mentale' and descrizione is null;
update specie set descrizione = 'The banded woodpecker or the banded red woodpecker is a species of bird in the family Picidae. It is found in Brunei, Indonesia, Malaysia, Myanmar, Singapore, and Thailand. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical mangrove forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Banded_woodpecker' where nome_scientifico = 'Chrysophlegma miniaceum' and descrizione is null;
update specie set descrizione = 'The black-and-yellow tanager is a fairly small passerine bird. This tanager resides in the hills of Costa Rica and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-and-yellow_tanager' where nome_scientifico = 'Chrysothlypis chrysomelas' and descrizione is null;
update specie set descrizione = 'The scarlet-and-white tanager is a species of bird in the family Thraupidae. It is found in Colombia and northern Ecuador. Its natural habitats are subtropical or tropical moist lowland forests and heavily degraded former forest. The male is highly distinctive and has bright scarlet upperparts, darker red wings and undertail coverts, and white underparts with a scarlet median stripe running down the throat and belly. Females are patterned like the males, but are olive-brown instead of scarlet.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet-and-white_tanager' where nome_scientifico = 'Chrysothlypis salmoni' and descrizione is null;
