update specie set descrizione = 'The rufous-banded owl is a species of owl in the family Strigidae. It is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-banded_owl' where nome_scientifico = 'Ciccaba albitarsis' and descrizione is null;
update specie set descrizione = 'The black-banded owl is a species of owl in the family Strigidae. Entirely nocturnal, this midsized black and white neotropical bird is a resident species, and therefore never migrates out of its native South America. Its natural habitats are varied subtropical or tropical forests ranging from lowlands to areas of medium altitude, and it has been found in Argentina, Bolivia, Brazil, Colombia, Ecuador, French Guiana, Guyana, Paraguay, Peru, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-banded_owl' where nome_scientifico = 'Ciccaba huhula' and descrizione is null;
update specie set descrizione = 'The black-and-white owl is a species of owl in the family Strigidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-and-white_owl' where nome_scientifico = 'Ciccaba nigrolineata' and descrizione is null;
update specie set descrizione = 'The mottled owl is a medium-sized owl found in Central and South America from Mexico to Brazil and Argentina. The head and back are mottled brown and the underparts whitish, with vertical bars on the chest and throat. The eyes are dark and the head is round and they do not have ear tufts. They are territorial and found in dry forests and jungles at altitudes of up to 2,500 m (8,200 ft) above sea level.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mottled_owl' where nome_scientifico = 'Ciccaba virgata' and descrizione is null;
update specie set descrizione = 'The collared palm thrush is a species of bird in the family Muscicapidae.
It is found in Botswana, Burundi, Democratic Republic of the Congo, Kenya, Malawi, Mozambique, Rwanda, Tanzania, Uganda, Zambia, and Zimbabwe.
Its natural habitats are dry savannah and subtropical or tropical moist shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Collared_palm_thrush' where nome_scientifico = 'Cichladusa arquata' and descrizione is null;
update specie set descrizione = 'The spotted palm thrush, also known as the spotted morning-thrush, is a species of bird in the Muscicapidae family. They are small birds mostly consisting of the colors brown, black, and cream. They can be found in eastern African countries such as Ethiopia, Kenya, Somalia, Sudan, Tanzania, and Uganda. Their natural habitats are subtropical or tropical dry forests, dry savanna, and subtropical or tropical moist shrubland. This bird is a forager that has a diet consisting of invertebrates. These birds create a variety of different vocal duets as a form of communication.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spotted_palm_thrush' where nome_scientifico = 'Cichladusa guttata' and descrizione is null;
update specie set descrizione = 'The pale-browed treehunter is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is endemic to Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale-browed_treehunter' where nome_scientifico = 'Cichlocolaptes leucophrus' and descrizione is null;
