update specie set descrizione = 'La paradisea reale è un uccello passeriforme della famiglia Paradisaeidae: rappresenta l''unica specie in seno al genere Cicinnurus Vieillot, 1816.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cicinnurus_regius' where nome_scientifico = 'Cicinnurus regius' and descrizione is null;
update specie set descrizione = 'La cicogna bianca è un grande uccello della famiglia delle cicogne, i Ciconiidae, facilmente riconoscibile per il suo candido piumaggio prevalentemente bianco, con penne nere sulle ali. Gli adulti hanno lunghe zampe rosse e un lungo becco appuntito anch''esso rosso, misurando in media 100–115 centimetri dalla punta del becco all''estremità della coda, con un''apertura alare di 155–215 centimetri. Le due sottospecie riconosciute, che differiscono leggermente per dimensioni, si riproducono in Europa, Africa nord-occidentale, Asia sud-occidentale e in Africa meridionale. La cicogna bianca è un uccello migratore in grado di percorrere enormi distanze, svernando in Africa dall''Africa subsahariana fino all''estremo sud del Sud Africa o nel subcontinente indiano. Durante le migrazioni tra Europa e Africa, questi uccelli evitano di attraversare il Mar Mediterraneo deviando sul Levante a est o sullo Stretto di Gibilterra a ovest, poiché le correnti termiche d''aria da cui dipendono per il volo non si formano sull''acqua.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ciconia_ciconia' where nome_scientifico = 'Ciconia ciconia' and descrizione is null;
update specie set descrizione = 'La cicogna nera è un uccello della famiglia delle Ciconiidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ciconia_nigra' where nome_scientifico = 'Ciconia nigra' and descrizione is null;
update specie set descrizione = 'The blue-fronted robin is a species of bird in the family Muscicapidae. It is the only species in the monotypic genus Cinclidium. It is found in Bhutan, China, Northeast India, Laos, Thailand, Vietnam, and possibly Nepal. Its natural habitat is temperate forests. As of June 12th,2024 this species is categorized as of least concern on the IUCN red list, with a stable population trend, though Birds of the World notes that it is uncommon in parts of its range. Blue-fronted robins are a bird species with limited published research.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-fronted_robin' where nome_scientifico = 'Cinclidium frontale' and descrizione is null;
update specie set descrizione = 'The grey trembler is a songbird species in the family Mimidae, the mockingbirds and thrashers. It is found only on Martinique and Saint Lucia in the Lesser Antilles of the Caribbean Sea.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey_trembler' where nome_scientifico = 'Cinclocerthia gutturalis' and descrizione is null;
update specie set descrizione = 'The chestnut-winged cinclodes is a species of bird in the family Furnariidae. It is found in Colombia, Venezuela, Ecuador, and Peru. It was formerly considered a subspecies of the bar-winged cinclodes. Its natural habitats are subtropical or tropical high-altitude shrubland and grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-winged_cinclodes' where nome_scientifico = 'Cinclodes albidiventris' and descrizione is null;
