update specie set descrizione = 'The dark-bellied cinclodes is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Argentina and Chile.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dark-bellied_cinclodes' where nome_scientifico = 'Cinclodes patagonicus' and descrizione is null;
update specie set descrizione = 'The brown songlark, also Australian songlark, is a small passerine bird found throughout much of Australia. A member of the family Locustellidae, this species is notable for sexual size dimorphism, among the most pronounced in any bird. It is a moderate-sized bird of nondescript plumage; the female brownish above and paler below, the larger male a darker brown.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_songlark' where nome_scientifico = 'Cincloramphus cruralis' and descrizione is null;
update specie set descrizione = 'The Papuan grassbird is a species of typical grassbird in the family Locustellidae. The species was once treated as several subspecies of the tawny grassbird, but the two do not interbreed where their ranges are sympatric. The species is endemic to New Guinea and its satellite islands. There are seven subspecies ranging across montane areas of New Guinea, New Britain and New Ireland. It is a fairly large typical grassbird, 20–23 cm (7.9–9.1 in) long and weighing 40 g (1.4 oz).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Papuan_grassbird' where nome_scientifico = 'Cincloramphus macrurus' and descrizione is null;
update specie set descrizione = 'The rufous songlark is a species in the family Locustellidae endemic to Australia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous_songlark' where nome_scientifico = 'Cincloramphus mathewsi' and descrizione is null;
update specie set descrizione = 'The tawny grassbird is a large songbird that is a member of the family Locustellidae commonly found in grassland and reedbed habitats. It is streaked above and has a distinctive rich brown cap. Its underside is paler and it has a long graduated tail. They call often with "loud, grumpy churring calls and a longer call that starts tick-tick-tick-tick and ends with an explosive descending trill".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tawny_grassbird' where nome_scientifico = 'Cincloramphus timoriensis' and descrizione is null;
