update specie set descrizione = 'The violet-backed starling, also known as the plum-coloured starling or amethyst starling, or Ndambamukula in the Venda language, is a relatively small species (17 cm) of starling in the family Sturnidae. It is the only member of the genus Cinnyricinclus. This strongly sexually dimorphic species is found widely in the woodlands and savannah forest edges of mainland sub-Saharan Africa. It is rarely seen on the ground, but instead found in trees and other locations away from the ground.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Violet-backed_starling' where nome_scientifico = 'Cinnyricinclus leucogaster' and descrizione is null;
update specie set descrizione = 'The greater double-collared sunbird is a small bird in the sunbird family. It was formerly placed in genus Nectarinia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greater_double-collared_sunbird' where nome_scientifico = 'Cinnyris afer' and descrizione is null;
update specie set descrizione = 'The purple sunbird is a small bird in the sunbird family. It occurs in parts of the Arabian peninsula and South and Southeast Asia. It has a fast and direct flight and can take nectar by hovering like a hummingbird but often perches at the base of flowers. It feeds mainly on nectar and insects, especially when feeding young. The males can appear all black in harsh sunlight but the purple iridescence is visible on closer observation or under good light conditions. Females are olive above and yellowish below.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Purple_sunbird' where nome_scientifico = 'Cinnyris asiaticus' and descrizione is null;
update specie set descrizione = 'The purple-banded sunbird is a species of bird in the family Nectariniidae.
It is found in Angola, Botswana, Republic of the Congo, Democratic Republic of the Congo, Ethiopia, Eswatini, Gabon, Kenya, Malawi, Mozambique, Namibia, Rwanda, Somalia, South Africa, Tanzania, Uganda, Zambia, and Zimbabwe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Purple-banded_sunbird' where nome_scientifico = 'Cinnyris bifasciatus' and descrizione is null;
update specie set descrizione = 'The southern double-collared sunbird or lesser double-collared sunbird is a small passerine bird which breeds in southern Africa. It is mainly resident, but partially migratory in the north-east of its range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_double-collared_sunbird' where nome_scientifico = 'Cinnyris chalybeus' and descrizione is null;
update specie set descrizione = 'The olive-bellied sunbird is a species of bird in the family Nectariniidae. It is widely spread across the African tropical rainforest primarily throughout West and Central Africa, but is also found in Southern and East Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive-bellied_sunbird' where nome_scientifico = 'Cinnyris chloropygius' and descrizione is null;
update specie set descrizione = 'The splendid sunbird is a sunbird. The sunbirds are a group of very small Old World passerine birds which feed largely on nectar, although they will also feed on insects, especially when feeding young.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Splendid_sunbird' where nome_scientifico = 'Cinnyris coccinigastrus' and descrizione is null;
update specie set descrizione = 'The copper sunbird is a species of passerine bird in the family Nectariniidae. It is native to tropical Africa, its range extending from Senegal and Guinea in the west to South Sudan and Kenya in the east, and southwards to Angola, Zambia, Zimbabwe and Mozambique.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Copper_sunbird' where nome_scientifico = 'Cinnyris cupreus' and descrizione is null;
