update specie set descrizione = 'The variable sunbird or yellow-bellied sunbird, formerly Nectarinia venusta, is a sunbird. The sunbirds are a group of small Old World passerine birds which feed largely on nectar, although they will also take insects, especially when feeding young. Flight is fast and direct on their short wings. Most species can take nectar by hovering like a hummingbird, but usually perch to feed most of the time.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Variable_sunbird' where nome_scientifico = 'Cinnyris venustus' and descrizione is null;
