update specie set descrizione = 'The magpie tanager is a South American species of tanager. It is the only member of the monotypic genus Cissopis. As suggested by its common name, this blue-black and white species is superficially reminiscent of a European magpie. With a total length of 25–30 cm (9.8–11.8 in), a large percentage of which is tail, it is the longest species of tanager. It weighs 69–76 g (2.4–2.7 oz).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Magpie_tanager' where nome_scientifico = 'Cissopis leverianus' and descrizione is null;
update specie set descrizione = 'The rock-loving cisticola, also known as the lazy cisticola, is a species of bird in the family Cisticolidae. It is widespread throughout sub-Saharan Africa and is usually associated with rocky wooded terrain with interspersed patchy grass tussocks. It was formerly considered to be conspecific with the Huambo cisticola.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rock-loving_cisticola' where nome_scientifico = 'Cisticola aberrans' and descrizione is null;
update specie set descrizione = 'The chattering cisticola is a species of bird in the family Cisticolidae.
It is native to the African tropical rainforest.
Its natural habitats are dry savanna and swamps.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chattering_cisticola' where nome_scientifico = 'Cisticola anonymus' and descrizione is null;
update specie set descrizione = 'The desert cisticola is a species of bird in the family Cisticolidae.
It is present throughout much of sub-Saharan Africa, although relatively absent from central and coastal western areas of the continent.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Desert_cisticola' where nome_scientifico = 'Cisticola aridulus' and descrizione is null;
update specie set descrizione = 'The wing-snapping cisticola, also known as Ayres'' cisticola, is a species of bird in the family Cisticolidae. Its scientific name honours South African ornithologist Thomas Ayres.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Wing-snapping_cisticola' where nome_scientifico = 'Cisticola ayresii' and descrizione is null;
update specie set descrizione = 'The short-winged cisticola, also known as the siffling cisticola, is a species of bird in the family Cisticolidae. It is found in Angola, Benin, Burkina Faso, Burundi, Cameroon, Central African Republic, Chad, Republic of the Congo, Democratic Republic of the Congo, Ivory Coast, Eritrea, Ethiopia, Gabon, Gambia, Ghana, Guinea, Guinea-Bissau, Kenya, Liberia, Malawi, Mali, Mozambique, Niger, Nigeria, Rwanda, Senegal, Sierra Leone, Somalia, South Sudan, Tanzania, Togo, Uganda, Zambia, and Zimbabwe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Short-winged_cisticola' where nome_scientifico = 'Cisticola brachypterus' and descrizione is null;
update specie set descrizione = 'The singing cisticola is a species of bird in the family Cisticolidae.
