update specie set descrizione = 'Il beccamoschino del Madagascar è un uccello della famiglia Cisticolidae, endemico del Madagascar e delle isole Seychelles.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cisticola_cherina' where nome_scientifico = 'Cisticola cherina' and descrizione is null;
update specie set descrizione = 'The rattling cisticola is a species of bird in the family Cisticolidae which is native to Africa south of the equator, and parts of East Africa. It is a common to abundant species in open savanna and scrubland habitats, whether in arid, moist or upland regions. Especially during summer, it is highly conspicuous due to its strident and repetitive call-notes from prominent perches.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rattling_cisticola' where nome_scientifico = 'Cisticola chiniana' and descrizione is null;
update specie set descrizione = 'The ashy cisticola is a species of bird in the family Cisticolidae. It is found in Ethiopia, Kenya, Somalia, South Sudan, and Tanzania. Its natural habitats are dry savanna, subtropical or tropical dry shrubland, and subtropical or tropical dry lowland grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ashy_cisticola' where nome_scientifico = 'Cisticola cinereolus' and descrizione is null;
update specie set descrizione = 'The red-faced cisticola is a species of bird in the family Cisticolidae. It is widely present across sub-Saharan Africa. Its natural habitats are subtropical or tropical seasonally wet or flooded lowland grassland and swamps.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-faced_cisticola' where nome_scientifico = 'Cisticola erythrops' and descrizione is null;
update specie set descrizione = 'The golden-headed cisticola, also known as the bright-capped cisticola, is a species of warbler in the family Cisticolidae, found in Australia and thirteen Asian countries. Growing to 9–11.5 cm (3.5–4.5 in) long, it is usually brown and cream in colour, but has a different appearance during the mating season, with a gold-coloured body and a much shorter tail. It is an omnivore and frequently makes a variety of vocalizations. Known as the "finest tailor of all birds", it constructs nests out of plants and spider threads. It mates in the rainy season. It has a very large range and population, which is thought to be increasing.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-headed_cisticola' where nome_scientifico = 'Cisticola exilis' and descrizione is null;
update specie set descrizione = 'The neddicky, or piping cisticola, is a small passerine bird in the family Cisticolidae, which is native to Africa, southwards of the equator. Its strongholds are the light woodlands and shrublands of the subtropics and temperate regions of southern Africa. The common name, neddicky, is the Afrikaans name for the species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Neddicky' where nome_scientifico = 'Cisticola fulvicapilla' and descrizione is null;
update specie set descrizione = 'The coastal cisticola, also known as the umbabird, is a species of bird in the family Cisticolidae. It is found on the coastal plain of East Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Coastal_cisticola' where nome_scientifico = 'Cisticola haematocephalus' and descrizione is null;
update specie set descrizione = 'Il beccamoschino è un uccello passeriforme appartenente alla famiglia Cisticolidae, diffuso in Eurasia, Africa e Oceania.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cisticola_juncidis' where nome_scientifico = 'Cisticola juncidis' and descrizione is null;
update specie set descrizione = 'The wailing cisticola is a species of bird in the family Cisticolidae. It is found in Angola, Eswatini, Lesotho, Malawi, Mozambique, South Africa, Tanzania, Zambia, and Zimbabwe. Its natural habitat is subtropical or tropical high-altitude grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Wailing_cisticola' where nome_scientifico = 'Cisticola lais' and descrizione is null;
update specie set descrizione = 'The whistling cisticola is a species of bird in the Cisticolidae family. It is native to the African tropical rainforest and adjacent areas. Its natural habitats include subtropical or tropical dry forests, dry savanna, and moist savanna.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Whistling_cisticola' where nome_scientifico = 'Cisticola lateralis' and descrizione is null;
update specie set descrizione = 'The winding cisticola is a species of bird in the family Cisticolidae. It has a scattered distribution across Africa south of the Sahara, and north of 11°S.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Winding_cisticola' where nome_scientifico = 'Cisticola marginatus' and descrizione is null;
update specie set descrizione = 'The croaking cisticola is an Old World warbler in the family Cisticolidae. It is a resident breeder in Africa south of the Sahara. The croaking cisticola is an insectivorous passerine that is found in rank grassland habitats, often near swamps or water. Male cisticolas are polygamous; the female builds a discreet nest deep in the grasses, often binding living leaves into the soft fabric of felted plant-down, cobwebs, and grass. The croaking cisticola''s nest is a ball shape with a side entrance; 2-4 eggs are laid.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Croaking_cisticola' where nome_scientifico = 'Cisticola natalensis' and descrizione is null;
update specie set descrizione = 'The black-lored cisticola is a species of bird in the family Cisticolidae. It is found in Malawi, Tanzania, and Zambia. Its natural habitat is subtropical or tropical dry shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-lored_cisticola' where nome_scientifico = 'Cisticola nigriloris' and descrizione is null;
update specie set descrizione = 'The churring cisticola is a species of bird in the family Cisticolidae.
