update specie set descrizione = 'The chirping cisticola is a species of bird in the family Cisticolidae.
It is found in Angola, Botswana, Burundi, Democratic Republic of the Congo, Namibia, Tanzania, Zambia, and Zimbabwe.
Its natural habitats are subtropical or tropical seasonally wet or flooded lowland grassland and swamps.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chirping_cisticola' where nome_scientifico = 'Cisticola pipiens' and descrizione is null;
update specie set descrizione = 'The stout cisticola is a species of bird in the family Cisticolidae. It is found in Angola, Burundi, Cameroon, Republic of the Congo, Democratic Republic of the Congo, Eritrea, Ethiopia, Kenya, Nigeria, Rwanda, South Sudan, Tanzania, Uganda, and Zambia. Its natural habitats are boreal forest, moist savanna, and subtropical or tropical high-altitude grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Stout_cisticola' where nome_scientifico = 'Cisticola robustus' and descrizione is null;
update specie set descrizione = 'The grey-backed cisticola or red-headed cisticola is a small passerine bird. This cisticola is a resident breeder in southernmost Angola, Namibia and western South Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-backed_cisticola' where nome_scientifico = 'Cisticola subruficapilla' and descrizione is null;
update specie set descrizione = 'The cloud cisticola or tink-tink cisticola is a species of bird in the family Cisticolidae. It is found in Angola, Eswatini, Lesotho, Mozambique, South Africa, and Zambia, and its natural habitat is subtropical or tropical dry lowland grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cloud_cisticola' where nome_scientifico = 'Cisticola textrix' and descrizione is null;
