update specie set descrizione = 'The marsh wren is a small North American songbird of the wren family. It was formerly called the long-billed marsh wren to distinguish it from the sedge wren, then known as the short-billed marsh wren.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Marsh_wren' where nome_scientifico = 'Cistothorus palustris' and descrizione is null;
