update specie set descrizione = 'The sedge wren is a small and secretive passerine bird in the family Troglodytidae. It is widely distributed in North America. It is often found in wet grasslands and meadows where it nests in the tall grasses and sedges and feeds on insects. The sedge wren was formerly considered as conspecific with the non-migratory grass wren of central and South America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sedge_wren' where nome_scientifico = 'Cistothorus stellaris' and descrizione is null;
