update specie set descrizione = 'The brown treecreeper is the largest Australasian treecreeper. The bird, endemic to eastern Australia, has a broad distribution, occupying areas from Cape York, Queensland, throughout New South Wales and Victoria to Port Augusta and the Flinders Ranges, South Australia. Prevalent nowadays between 16˚S and 38˚S, the population has contracted from the edges of its pre-European range, declining in Adelaide and Cape York. Found in a diverse range of habitats varying from coastal forests to mallee shrub-lands, the brown treecreeper often occupies eucalypt-dominated woodland habitats up to 1,000 metres (3,300 ft), avoiding areas with a dense shrubby understorey.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_treecreeper' where nome_scientifico = 'Climacteris picumnus' and descrizione is null;
update specie set descrizione = 'The recurve-billed bushbird is an Endangered species of Thamnophilid antbird that inhabits dense stands of secondary vegetation at the northern end of the Andes in Colombia and Venezuela. It is named for its extraordinary bill, which curves upwards. Until 2007, the bird was almost unknown in life and apart from earlier specimens it had only been seen in life once at an army ant swarm in Colombia in 1965.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Recurve-billed_bushbird' where nome_scientifico = 'Clytoctantes alixii' and descrizione is null;
