update specie set descrizione = 'The sparkling violetear is a species of hummingbird widespread in highlands of northern and western South America, including a large part of the Andes, the Venezuelan Coastal Range, and the Tepuis. It occurs in a wide range of semi-open habitats, even in gardens and parks within major cities such as Quito, and is often the most common species of hummingbird in its range. It is highly vocal and territorial.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sparkling_violetear' where nome_scientifico = 'Colibri coruscans' and descrizione is null;
