update specie set descrizione = 'The African olive pigeon or Rameron pigeon is a pigeon which is a resident breeding bird in much of eastern and southern Africa from Ethiopia to the Cape. Populations also are found in western Angola, southwestern Saudi Arabia and northern Yemen. It is locally common, although sizeable gaps in its distribution occur due to its habitat requirements. Despite this, the species is monotypic, with no substantive variation between birds in the different areas it occurs in.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_olive_pigeon' where nome_scientifico = 'Columba arquatrix' and descrizione is null;
update specie set descrizione = 'Il piccione di Guinea, anche piccione marezzato, colomba di Guinea, colomba della Guinea o colomba guinea, è un uccello appartenente alla famiglia Columbidae diffuso nel continente africano.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Columba_guinea' where nome_scientifico = 'Columba guinea' and descrizione is null;
update specie set descrizione = 'The western bronze-naped pigeon is a species of bird in the family Columbidae, part of the subgenus Turturoena. A medium sized bird, it has a pale, broad terminal tail band which is noticeable on landing. It is found in most countries of Africa. The IUCN Red List classifies it as a species of least concern.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_bronze-naped_pigeon' where nome_scientifico = 'Columba iriditorques' and descrizione is null;
update specie set descrizione = 'The black wood pigeon or Japanese wood pigeon is a species of bird in the family Columbidae. It is found in East Asia, occurring mainly on offshore islands of the Pacific''s Korea Strait, Philippine Sea and East China Sea around Japan, Korea, China, and Taiwan. Its natural habitats are temperate forests and subtropical or tropical moist lowland forests. The species is in decline owing to habitat loss, habitat degradation, deforestation and hunting. This wood pigeon is endemic to laurel forest habitat.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_wood_pigeon' where nome_scientifico = 'Columba janthina' and descrizione is null;
update specie set descrizione = 'The lemon dove or cinnamon dove is a species of bird in the pigeon family Columbidae found in montane forests of sub-Saharan Africa. The lemon dove has a generally brownish-grey plumage with a cinnamon brown breast. Adults have a greenish-glossed neck and white markings on the head, and juveniles are rather more brown with pale feather fringe barring and have greyer facial markings. This dove is a common species, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lemon_dove' where nome_scientifico = 'Columba larvata' and descrizione is null;
update specie set descrizione = 'Il piccione selvatico occidentale è una specie di uccello appartenente alla famiglia Columbidae. La forma addomesticata che include i piccioni viaggiatori e numerose altre razze è detta piccione domestico, da essa discendono i piccioni semi-selvatici diffusi nelle città di quasi tutto il mondo.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Columba_livia' where nome_scientifico = 'Columba livia' and descrizione is null;
update specie set descrizione = 'La colombella, chiamata anche palombella, è un uccello della famiglia dei Columbidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Columba_oenas' where nome_scientifico = 'Columba oenas' and descrizione is null;
update specie set descrizione = 'Il colombaccio, chiamato anche palombo o palombaccio, è una specie di uccello della famiglia dei Columbidi. È la più grande, più frequente e più diffusa specie di columbidi in Europa.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Columba_palumbus' where nome_scientifico = 'Columba palumbus' and descrizione is null;
