update specie set descrizione = 'The Ecuadorian ground dove is a species of bird in the family Columbidae. It is found in Ecuador and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ecuadorian_ground_dove' where nome_scientifico = 'Columbina buckleyi' and descrizione is null;
