update specie set descrizione = 'The Inca dove or Mexican dove is a small New World dove. The species was first described by French surgeon and naturalist René Lesson in 1847. It reaches a length of 16.5–23 cm (6.5–9.1 in) and weighs 30–58 g (1.1–2.0 oz). The Inca dove has an average wingspan of 28.5 cm and a max wingspan of 32 cm. It is a slender species, with a gray-brown body covered in feathers that resemble a scaled pattern. The tail is long and square and edged with white feathers that may flare out in flight. The underwings are reddish, like other ground doves, and upon takeoff, the wings produce a distinctive, quiet rattling noise.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Inca_dove' where nome_scientifico = 'Columbina inca' and descrizione is null;
update specie set descrizione = 'The plain-breasted ground dove is a species of bird in the family Columbidae. It lacks the scaled appearance to the feathers of the similar and typically more abundant common ground dove.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plain-breasted_ground_dove' where nome_scientifico = 'Columbina minuta' and descrizione is null;
