update specie set descrizione = 'The rufous-banded honeyeater is a species of bird in the family Meliphagidae. It is found in the Aru Islands, New Guinea and northern Australia. Its natural habitat is subtropical or tropical mangrove forests. The rufous-banded honeyeater is considered one of the most common small birds in the suburban ecosystem of Darwin, Australia, notable because its lack of introduced bird species. It is also native to Queensland, Australia. Ornithologist F. Salomonsen recognized two subspecies of rufous-banded honeyeater, Conopophila albogularis and Conopophila mimikae but J. Ford disagreed with this subspeciation.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-banded_honeyeater' where nome_scientifico = 'Conopophila albogularis' and descrizione is null;
update specie set descrizione = 'The great parrotbill is a bird species the Paradoxornithidae family. It is found in Bhutan, China, India, Myanmar, and Nepal. It was previously placed in a monotypic genus, the Conostoma.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Great_parrotbill' where nome_scientifico = 'Conostoma aemodium' and descrizione is null;
update specie set descrizione = 'The black-and-white tanager is a tanager found in the Tumbes region of southwestern Ecuador and northwestern Peru; it migrates eastwards as far as Acre. The only other member of its genus is the recently rediscovered cone-billed tanager.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-and-white_tanager' where nome_scientifico = 'Conothraupis speculigera' and descrizione is null;
