update specie set descrizione = 'The greater pewee, formerly known as Coues''s flycatcher, is a passerine bird in the family Tyrannidae, the tyrant flycatchers. It is found from Arizona and New Mexico to Nicaragua.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greater_pewee' where nome_scientifico = 'Contopus pertinax' and descrizione is null;
update specie set descrizione = 'The western wood pewee is a small tyrant flycatcher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_wood_pewee' where nome_scientifico = 'Contopus sordidulus' and descrizione is null;
update specie set descrizione = 'The eastern wood pewee is a small tyrant flycatcher from North, Central and South America. This bird and the western wood pewee were formerly considered a single species. The two species are virtually identical in appearance, and can be distinguished most easily by their calls.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_wood_pewee' where nome_scientifico = 'Contopus virens' and descrizione is null;
update specie set descrizione = 'The Andaman shama is a species of bird in the family Muscicapidae. It is endemic to the Andaman Islands. It is considered a restricted-range species because it occurs only within this island group. It was previously considered a subspecies of the white-rumped shama. Its natural habitats are subtropical or tropical dry forests and subtropical or tropical moist lowland forests. Although precise global population estimates are not available, the species is reported to be common within its limited range. The Andaman Shama inhabits forested and semi-open habitats across several islands in the Andaman archipelago and is considered non-migratory.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Andaman_shama' where nome_scientifico = 'Copsychus albiventris' and descrizione is null;
update specie set descrizione = 'Il merlo gazza del Madagascar è un uccello della famiglia Muscicapidae, endemico del Madagascar.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Copsychus_albospecularis' where nome_scientifico = 'Copsychus albospecularis' and descrizione is null;
update specie set descrizione = 'The Black shama is a species of bird in the family Muscicapidae.
It is endemic to the island of Cebu, Philippines where it is known locally as "Siloy".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_shama' where nome_scientifico = 'Copsychus cebuensis' and descrizione is null;
update specie set descrizione = 'The Indian robin is a species of passerine bird in the family Muscicapidae. It is widespread in the Indian subcontinent and ranges across Bangladesh, Bhutan, India, Nepal, Pakistan and Sri Lanka. The males of the northern subspecies have brown backs whose extent gradually reduces southwards, with the males of the southern subspecies having all-black backs. They are commonly found in open scrub areas and often seen running along the ground or perching on low thorny shrubs and rocks. The long tail is usually held up and the chestnut undertail coverts and dark body make them easily distinguishable from pied bushchats and Oriental magpie-robins.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_robin' where nome_scientifico = 'Copsychus fulicatus' and descrizione is null;
update specie set descrizione = 'The white-browed shama is a species of bird in the family Muscicapidae.
It is endemic to the Philippines found only on the islands of Luzon, Marinduque and the Polillo Islands. The Visayan shama, formerly considered a subspecies, was split as a distinct species in 2021.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-browed_shama' where nome_scientifico = 'Copsychus luzoniensis' and descrizione is null;
update specie set descrizione = 'Lo shama groppabianca è un uccello passeriforme della famiglia Muscicapidae del Vecchio Mondo. Originario di habitat densamente vegetati nel subcontinente indiano e nel sud-est asiatico, la sua popolarità come uccello canoro da gabbia ha portato alla sua introduzione altrove. Lo shama di Larwo, lo shama di Kangean e lo shama dello Sri Lanka erano in passato considerati conspecifici dello shama groppabianca.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Copsychus_malabaricus' where nome_scientifico = 'Copsychus malabaricus' and descrizione is null;
update specie set descrizione = 'The Philippine magpie-robin is a species of bird in the family Muscicapidae.
It is endemic to the Philippines. It was formerly a subspecies of Oriental magpie-robin but was designated as its own species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Philippine_magpie-robin' where nome_scientifico = 'Copsychus mindanensis' and descrizione is null;
update specie set descrizione = 'The white-vented shama is a species of bird in the chat and flycatcher family Muscicapidae. It is endemic to the Palawan, Balabac and Calamian islands in the Philippines. Along with the Black shama, White-browed shama and Visayan shama are the four endemic shamas of the country.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-vented_shama' where nome_scientifico = 'Copsychus niger' and descrizione is null;
update specie set descrizione = 'The rufous-tailed shama is a species of passerine bird in the Old World flycatcher family Muscicapidae. It is found in extreme southern Thailand, Malaysia, Sumatra, and Borneo, where its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical swamps. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-tailed_shama' where nome_scientifico = 'Copsychus pyrropygus' and descrizione is null;
update specie set descrizione = 'The Oriental magpie-robin is a small passerine bird that was formerly classed as a member of the thrush family Turdidae, but now considered an Old World flycatcher. The males are distinctive black and white birds with a long tail that is held upright as they forage on the ground or perch conspicuously. Occurring across most of the Indian subcontinent and parts of Southeast Asia, they are common birds in urban gardens as well as forests. They are particularly well known for their songs and were once popular as cagebirds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Oriental_magpie-robin' where nome_scientifico = 'Copsychus saularis' and descrizione is null;
update specie set descrizione = 'La ghiandaia marina abissina è un uccello della famiglia Coraciidae, ampiamente diffuso in parte dell''Africa subsahariana e in una piccola porzione della Penisola araba.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Coracias_abyssinicus' where nome_scientifico = 'Coracias abyssinicus' and descrizione is null;
