update specie set descrizione = 'The grey cuckooshrike is a species of bird in the cuckooshrike family Campephagidae. It is a medium-sized forest bird, with grey to blue-grey plumage and large black eyes. There are two subspecies that occur in forest patches of southern and central Africa respectively.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey_cuckooshrike' where nome_scientifico = 'Coracina caesia' and descrizione is null;
update specie set descrizione = 'La coracina del Madagascar è un uccello della famiglia Campephagidae, endemico del Madagascar.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ceblepyris_cinereus' where nome_scientifico = 'Coracina cinerea' and descrizione is null;
update specie set descrizione = 'The barred cuckooshrike, also called the yellow-eyed cuckooshrike, is a species of bird in the family Campephagidae. It is found in eastern Australia, Indonesia, Papua New Guinea, and Solomon Islands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Barred_cuckooshrike' where nome_scientifico = 'Coracina lineata' and descrizione is null;
update specie set descrizione = 'The hooded cuckooshrike is a species of bird in the family Campephagidae. It is found in the New Guinea Highlands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hooded_cuckooshrike' where nome_scientifico = 'Coracina longicauda' and descrizione is null;
update specie set descrizione = 'The Indian cuckooshrike is a species of bird in the cuckooshrike family Campephagidae that is found on the Indian subcontinent. Formerly under the English name "large cuckooshrike" this species included many subspecies and had a large range that included Southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_cuckooshrike' where nome_scientifico = 'Coracina macei' and descrizione is null;
update specie set descrizione = 'The black-faced cuckooshrike is a common omnivorous passerine bird native to Australia and southern New Guinea. It has a protected status in New South Wales, under the National Parks and Wildlife Act, 1974.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-faced_cuckooshrike' where nome_scientifico = 'Coracina novaehollandiae' and descrizione is null;
update specie set descrizione = 'The white-bellied cuckooshrike is a species of bird in the family Campephagidae. It is found in Australia, the Moluccas, New Guinea and the Solomon Islands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-bellied_cuckooshrike' where nome_scientifico = 'Coracina papuensis' and descrizione is null;
update specie set descrizione = 'The white-breasted cuckooshrike is a species of bird in the family Campephagidae.
It is found in Angola, Benin, Botswana, Burkina Faso, Burundi, Cameroon, Central African Republic, Democratic Republic of the Congo, Ivory Coast, Eswatini, Ethiopia, Gambia, Ghana, Guinea, Guinea-Bissau, Kenya, Malawi, Mali, Mauritania, Mozambique, Namibia, Nigeria, Rwanda, Senegal, Sierra Leone, South Africa, Sudan, Tanzania, Togo, Uganda, Zambia, and Zimbabwe.
Its natural habitats are subtropical or tropical dry forest and dry savanna. The species forages at mid-canopy level and is typically found alone or in pairs. It is insectivorous, feeding primarily on insects and caterpillars.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-breasted_cuckooshrike' where nome_scientifico = 'Coracina pectoralis' and descrizione is null;
update specie set descrizione = 'The bar-bellied cuckooshrike is a species of bird in the family Campephagidae. It is found in Thailand, Malaysia, Indonesia, and the Philippines, and its natural habitats include mangrove forest, dry forest, swamp forest, and secondary forest. The plumage varies among the subspecies, with different amounts of barring on the underparts. The International Union for Conservation of Nature (IUCN) has assessed the species as one of least-concern.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bar-bellied_cuckooshrike' where nome_scientifico = 'Coracina striata' and descrizione is null;
