update specie set descrizione = 'The white-ruffed manakin is a sub-oscine (Tyranni), passerine bird in the manakin family. It is a resident breeder in the tropical New World from eastern Honduras to northwestern Colombia. Its typical habitat is wet forest, adjacent clearings and tall secondary growth. It is a small, plump bird about 10 centimetres (4 in) long. Males have glossy blue-black plumage with a white erectile ruff on the throat and females are green. At breeding time, males are involved in lekking behaviour on the forest floor during which they puff out their neck feathers. This is a fairly common species with a wide range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-ruffed_manakin' where nome_scientifico = 'Corapipo altera' and descrizione is null;
