update specie set descrizione = 'The Cape crow or black crow is slightly larger than the carrion crow and is completely black with a slight gloss of purple in its feathers. It also has proportionately longer legs, wings, and tail, and has a much longer, slimmer bill that seems to be adapted for probing into the ground for invertebrates. The head feathers have a coppery-purple gloss and the throat feathers are quite long and fluffed out in some calls and displays.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cape_crow' where nome_scientifico = 'Corvus capensis' and descrizione is null;
