update specie set descrizione = 'The Torresian crow, also called the Australian crow or Papuan crow, is a passerine bird in the crow family native to the north and west of Australia and nearby islands in Indonesia and Papua New Guinea. The species has a black plumage, beak and mouth with white irises. The base of the feathers on the head and neck are white. The Torresian crow is slightly larger with a more robust bill than the morphologically similar little crow.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Torresian_crow' where nome_scientifico = 'Corvus orru' and descrizione is null;
