update specie set descrizione = 'The black-masked finch is a species of South American bird in the tanager family Thraupidae. It is the only member of the genus Coryphaspiza. It is found in Argentina, Bolivia, Brazil, Paraguay, and Peru.
Its natural habitats are subtropical or tropical moist shrubland, subtropical or tropical dry lowland grassland, and subtropical or tropical seasonally wet or flooded lowland grassland.
It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-masked_finch' where nome_scientifico = 'Coryphaspiza melanotis' and descrizione is null;
update specie set descrizione = 'The lark-like brushrunner is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Argentina, Bolivia, Brazil, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lark-like_brushrunner' where nome_scientifico = 'Coryphistera alaudina' and descrizione is null;
update specie set descrizione = 'Il fringuello rosso pileato, noto anche come fringuello dalla cresta rossa, è una specie di fringuello della famiglia Thraupidae. È originario dell''Argentina, Bolivia, Brasile, Ecuador, Guyana francese, Guyana, Paraguay, Perù, sul lato orientale delle Ande. Il suo habitat naturale sono le foreste subtropicali asciutte e tropicali, i boschi di pianura umide subtropicali e tropicali. È una specie comune e l''Unione internazionale per la conservazione della natura ha valutato il suo stato di conservazione come "a Rischio minimo".', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Coryphospingus_cucullatus' where nome_scientifico = 'Coryphospingus cucullatus' and descrizione is null;
update specie set descrizione = 'The grey pileated finch, also known as the pileated finch, is a species of bird in the family Thraupidae, where it has recently been moved to from the Emberizidae. It is found in Brazil, Colombia, French Guiana, and Venezuela in subtropical or tropical dry forests, subtropical or tropical moist lowland forests, subtropical or tropical dry shrubland, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey_pileated_finch' where nome_scientifico = 'Coryphospingus pileatus' and descrizione is null;
