update specie set descrizione = 'The black cuckoo is a species of cuckoo in the family Cuculidae. The species is distributed widely across sub-Saharan Africa. There are two subspecies. This cuckoo has a very wide range and is quite common so it is classified as a least-concern species by the International Union for Conservation of Nature.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_cuckoo' where nome_scientifico = 'Cuculus clamosus' and descrizione is null;
update specie set descrizione = 'The African cuckoo or African grey cuckoo is a species of cuckoo in the family Cuculidae. It is found in Sub-Saharan Africa where it migrates within the continent, generally arriving and breeding in any one locality during the rainy season. A fairly common bird, the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_cuckoo' where nome_scientifico = 'Cuculus gularis' and descrizione is null;
update specie set descrizione = 'The Sunda cuckoo or Sunda lesser cuckoo is a South-east Asian bird belonging to the genus Cuculus in the cuckoo family, Cuculidae. It was formerly classified with the Himalayan cuckoo and Oriental cuckoo in a single species, C. saturatus, but is now often regarded as a separate species based on differences in voice, size and plumage.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sunda_cuckoo' where nome_scientifico = 'Cuculus lepidus' and descrizione is null;
update specie set descrizione = 'The  Indian cuckoo or short-winged cuckoo is a member of the cuckoo order of birds, the Cuculiformes, that is found in the Indian subcontinent and Southeast Asia. It ranges from India, Bangladesh, Bhutan, Nepal and Sri Lanka east to Indonesia and north to China and Russia. It is a solitary and shy bird, found in forests and open woodland at up to 3,600 m (11,800 ft).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_cuckoo' where nome_scientifico = 'Cuculus micropterus' and descrizione is null;
