update specie set descrizione = 'The grey-headed canary-flycatcher, sometimes known as the grey-headed flycatcher, is a species of small flycatcher-like bird found in tropical Asia. It has a square crest, a grey hood and yellow underparts. They are found mainly in forested habitats where they often join other birds in mixed-species foraging flocks. Pairs are often seen as they forage for insects by making flycatcher-like sallies and calling aloud. Several subspecies are recognized within their wide distribution range. In the past the genus Culicicapa was considered to be an Old World flycatcher but studies have found them to belong to a new family designated as the Stenostiridae or fairy flycatchers that include the African genera Stenostira and Elminia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-headed_canary-flycatcher' where nome_scientifico = 'Culicicapa ceylonensis' and descrizione is null;
update specie set descrizione = 'The citrine canary-flycatcher is a species of bird in the family Stenostiridae. The term citrine refers to its yellowish colouration. It is found in Sulawesi and the Philippines. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Citrine_canary-flycatcher' where nome_scientifico = 'Culicicapa helianthea' and descrizione is null;
update specie set descrizione = 'The sharp-tailed grass tyrant or sharp-tailed tyrant is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Bolivia, Brazil, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sharp-tailed_grass_tyrant' where nome_scientifico = 'Culicivora caudacuta' and descrizione is null;
update specie set descrizione = 'The austral blackbird is a species of bird in the family Icteridae. It is found in Argentina and Chile, and it migrates to regions close by. Its natural habitats are temperate forests, subtropical or tropical high-altitude shrubland, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Austral_blackbird' where nome_scientifico = 'Curaeus curaeus' and descrizione is null;
update specie set descrizione = 'The banded parisoma, banded tit warbler or banded warbler, is a species of Old World warbler in the family Sylviidae. It is found in Ethiopia, Kenya, Somalia, and Tanzania. Its natural habitat is dry savanna.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Banded_parisoma' where nome_scientifico = 'Curruca boehmi' and descrizione is null;
update specie set descrizione = 'La sterpazzola è un uccello della famiglia dei Silvidi appartenente al genere dei Sylvia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sylvia_communis' where nome_scientifico = 'Curruca communis' and descrizione is null;
update specie set descrizione = 'The spectacled warbler is a species of passerine bird in the warbler genus Curruca in the family Sylviidae. The specific conspicillata is from Latin conspicillum, a place to look from, equivalent to "spectacled".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spectacled_warbler' where nome_scientifico = 'Curruca conspicillata' and descrizione is null;
update specie set descrizione = 'The eastern Orphean warbler is an Old World warbler of the genus Curruca. This species occurs in summer around the Mediterranean, through the Balkans via Turkey, the Caucasus and surrounding regions to Central Asia. It is migratory, wintering in sub-Saharan Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_Orphean_warbler' where nome_scientifico = 'Curruca crassirostris' and descrizione is null;
update specie set descrizione = 'The lesser whitethroat is a common and widespread Old World warbler which breeds in temperate Europe, except the southwest, and in the western and central Palearctic. This small passerine bird is strongly migratory, wintering in Africa just south of the Sahara, Arabia and India.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_whitethroat' where nome_scientifico = 'Curruca curruca' and descrizione is null;
update specie set descrizione = 'The western Orphean warbler is an Old World warbler of the genus Curruca. This species occurs in summer around the Mediterranean, through western Europe and extending into northwest Africa. It is migratory, wintering in Sub-Saharan Africa. It is a rare vagrant to northern and north-western Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_Orphean_warbler' where nome_scientifico = 'Curruca hortensis' and descrizione is null;
update specie set descrizione = 'The western subalpine warbler is a small Sylviidae warbler which breeds in the southernmost areas of Europe and north-western Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_subalpine_warbler' where nome_scientifico = 'Curruca iberiae' and descrizione is null;
update specie set descrizione = 'The Sardinian warbler is a common and widespread Sylviidae warbler from the Mediterranean region. Like most Curruca species, it has distinct male and female plumages. The adult male has a grey back, whitish underparts, black head, white throat and red eyes. Plumages are somewhat variable even in the same locality, with the intensity of a reddish hue on upper- and/or underside that varies from absent to pronounced. The female is mainly brown above and buff below, with a grey head. The Sardinian warbler''s song is fast and rattling, and is very characteristic of the Mediterranean areas where this bird breeds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sardinian_warbler' where nome_scientifico = 'Curruca melanocephala' and descrizione is null;
update specie set descrizione = 'The barred warbler is a species of bird in the warbler family Sylviidae which breeds across temperate regions of central and eastern Europe and western and central Asia. This passerine bird is strongly migratory, and winters in tropical eastern Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Barred_warbler' where nome_scientifico = 'Curruca nisoria' and descrizione is null;
update specie set descrizione = 'The chestnut-vented warbler, chestnut-vented tit-babbler or rufous-vented warbler is an Old World warbler of the family Sylviidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-vented_warbler' where nome_scientifico = 'Curruca subcoerulea' and descrizione is null;
update specie set descrizione = 'The Dartford warbler is a Sylviid warbler from the warmer parts of western Europe and northwestern Africa. It is a small warbler with a long thin tail and a thin pointed bill. The adult male has grey-brown upperparts and is dull reddish-brown below except for the centre of the belly which has a dirty white patch. It has light speckles on the throat and a red eye-ring. The sexes are similar but the adult female is usually less grey above and paler below.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dartford_warbler' where nome_scientifico = 'Curruca undata' and descrizione is null;
update specie set descrizione = 'The Vietnamese cutia is a bird species in the family Leiothrichidae. It is found in Laos and Vietnam.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Vietnamese_cutia' where nome_scientifico = 'Cutia legalleni' and descrizione is null;
update specie set descrizione = 'The Himalayan cutia is a bird species in the family Leiothrichidae. Its scientific name ultimately means "the khutya from Nepal", as Cutia is derived from the Nepali name for these birds, and nipalensis is Latin for "from Nepal".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Himalayan_cutia' where nome_scientifico = 'Cutia nipalensis' and descrizione is null;
update specie set descrizione = 'The purple honeycreeper is a small Neotropical bird in the tanager family Thraupidae. It is found in the tropical New World from Colombia and Venezuela south to Brazil, and on Trinidad. A few, possibly introduced, birds have been recorded on Tobago.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Purple_honeycreeper' where nome_scientifico = 'Cyanerpes caeruleus' and descrizione is null;
update specie set descrizione = 'The red-legged honeycreeper is a small songbird species in the tanager family (Thraupidae). It is found in the tropical New World from southern Mexico south to Peru, Bolivia and central Brazil, Trinidad and Tobago, and on Cuba, where possibly introduced. It is also rarely found in southern Texas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-legged_honeycreeper' where nome_scientifico = 'Cyanerpes cyaneus' and descrizione is null;
update specie set descrizione = 'The blue-backed tanager is a species of South American bird in the tanager family Thraupidae. It is the only member of the genus Cyanicterus. It is found in Brazil, French Guiana, Guyana, Suriname, and Venezuela. Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-backed_tanager' where nome_scientifico = 'Cyanicterus cyanicterus' and descrizione is null;
