update specie set descrizione = 'The rufous-fronted babbler is a babbler species in the Old World babbler family. It occurs in the Eastern Himalayan foothills, Myanmar, Thailand, northern Indochina and south to the Malay Peninsula and the islands of Sumatra and Borneo. The buff-chested babbler is now subsumed into this species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-fronted_babbler' where nome_scientifico = 'Cyanoderma ambiguum' and descrizione is null;
update specie set descrizione = 'The golden babbler is a babbler species in the family Timaliidae. It occurs from the foothills of the Eastern Himalayas to Southeast Asia and inhabits subtropical lowland and montane forests. It is listed as Least Concern on the IUCN Red List because of its wide distribution.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden_babbler' where nome_scientifico = 'Cyanoderma chrysaeum' and descrizione is null;
