update specie set descrizione = 'The crescent-chested babbler is a babbler species in the family Timaliidae and is native to the Indonesian islands of Java and Bali. It inhabits subtropical or tropical moist lowland forest, montane forest and shrubland. It is listed as Least Concern on the IUCN Red List.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crescent-chested_babbler' where nome_scientifico = 'Cyanoderma melanothorax' and descrizione is null;
update specie set descrizione = 'The black-chinned babbler is a babbler species in the family Timaliidae. It occurs in the foothills of the Himalayas from the Murree Hills in Pakistan to eastern Nepal. It inhabits subtropical and temperate forest at 245–2,750 m (804–9,022 ft) altitudes. It is terrestrial. It is listed as Least Concern on the IUCN Red List.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-chinned_babbler' where nome_scientifico = 'Cyanoderma pyrrhops' and descrizione is null;
update specie set descrizione = 'The rufous-capped babbler is a babbler species in the family Timaliidae. It occurs from the Eastern Himalayas to northern Thailand, Laos, eastern China to Vietnam and Taiwan. It inhabits temperate forest with dense bushes or bamboo and is listed as Least Concern on the IUCN Red List.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-capped_babbler' where nome_scientifico = 'Cyanoderma ruficeps' and descrizione is null;
