update specie set descrizione = 'The blue-and-white flycatcher is a migratory songbird in the Old World flycatcher family Muscicapidae. The species is also known as the Japanese flycatcher. It breeds in Japan, Korea, and in parts of north eastern China and the Russian Far East. It winters in South East Asia, especially in Vietnam, Cambodia, Thailand, Sumatra and Borneo. This species has been recorded as a vagrant from the Sinharaja Rainforest in Sri Lanka in 2014.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-and-white_flycatcher' where nome_scientifico = 'Cyanoptila cyanomelana' and descrizione is null;
