update specie set descrizione = 'The rufous-browed peppershrike is a passerine bird in the vireo family. It is widespread and often common in woodland, forest edge, and cultivation with some tall trees from Mexico and Trinidad south to Argentina and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-browed_peppershrike' where nome_scientifico = 'Cyclarhis gujanensis' and descrizione is null;
update specie set descrizione = 'The black-billed peppershrike is a species of bird in the family Vireonidae. It is found in the Andes of Colombia and northern Ecuador. It inhabits subtropical or tropical moist montane forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-billed_peppershrike' where nome_scientifico = 'Cyclarhis nigrirostris' and descrizione is null;
update specie set descrizione = 'The black swan is a large waterbird, a species of swan which breeds mainly in the southeast and southwest regions of Australia. Within Australia, the black swan is nomadic, with erratic migration patterns dependent on climatic conditions. It is a large bird with black plumage and a red bill. It is a monogamous breeder, with both partners sharing incubation and cygnet-rearing duties.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_swan' where nome_scientifico = 'Cygnus atratus' and descrizione is null;
update specie set descrizione = 'The trumpeter swan, or simply the trumpeter, is a species of swan found in North America. The heaviest living bird native to North America, it is also the largest extant species of waterfowl, with a wingspan of 185 to 304.8 cm. It is the American counterpart and a close relative of the whooper swan of Eurasia and has even been considered the same species by some authorities. By 1933, fewer than 70 wild individuals were known to exist; extinction seemed imminent until aerial surveys discovered a Pacific population of several thousand trumpeter swans around Alaska''s Copper River. Careful reintroductions by wildlife agencies and the Trumpeter Swan Society gradually restored the North American wild population to over 46,000 birds by 2010.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Trumpeter_swan' where nome_scientifico = 'Cygnus buccinator' and descrizione is null;
update specie set descrizione = 'Il cigno minore è il più piccolo tra i cigni, distribuito in tutti i paesi nordici.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cygnus_columbianus' where nome_scientifico = 'Cygnus columbianus' and descrizione is null;
update specie set descrizione = 'Il cigno selvatico, più raramente noto come "cigno canoro" o "cigno musico", è un uccello appartenente alla famiglia Anatidae. In inglese è comunemente chiamato Whooper Swan, mentre in tempi passati veniva chiamato "Elk".', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cygnus_cygnus' where nome_scientifico = 'Cygnus cygnus' and descrizione is null;
