update specie set descrizione = 'The bamboo antshrike is a species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Bolivia, Brazil, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bamboo_antshrike' where nome_scientifico = 'Cymbilaimus sanctaemariae' and descrizione is null;
update specie set descrizione = 'Il beccolargo rossonero, beccolargo nero e rosso od eurilaimo nero e rosso è un uccello passeriforme della famiglia degli Eurilaimidi. Si tratta dell''unica specie ascritta al genere Cymbirhynchus Vigors, 1830.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cymbirhynchus_macrorhynchos' where nome_scientifico = 'Cymbirhynchus macrorhynchos' and descrizione is null;
update specie set descrizione = 'The broad-billed hummingbird is a small hummingbird that resides in Mexico and the southwestern United States. Males and females have different features. The juveniles resemble the female adult more than the male adult. The broad-billed hummingbird is a bright green bird. The broad, red bill in both sexes and the male''s blue gorget are useful for identification. The bird is also known for its other common names – the Colibrí Pico Ancho in Spanish and Colibri circé in French. It is more active during the day and less active during the night.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Broad-billed_hummingbird' where nome_scientifico = 'Cynanthus latirostris' and descrizione is null;
update specie set descrizione = 'The Sunda blue flycatcher, also known as the large-billed blue-flycatcher, is a species of bird in the family Muscicapidae. It is found in Sumatra and Borneo.
Its natural habitat is subtropical or tropical moist lowland forests. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sunda_blue_flycatcher' where nome_scientifico = 'Cyornis caerulatus' and descrizione is null;
update specie set descrizione = 'The white-tailed flycatcher is a species of bird in the family Muscicapidae. It is the only member of the monotypic genus Leucoptilon. It is found in submountain forests from the eastern Himalayas and northern Myanmar to southern China, western and southern Thailand, the Malay Peninsula, Sumatra and Borneo.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-tailed_flycatcher' where nome_scientifico = 'Cyornis concretus' and descrizione is null;
update specie set descrizione = 'The Chinese blue flycatcher is a small passerine bird in the flycatcher family, Muscicapidae. The Chinese blue flycatcher is native to mid-southern China; it winters to the Tenasserim Hills and the Malay Peninsula. It previously was considered a subspecies of the blue-throated blue flycatcher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chinese_blue_flycatcher' where nome_scientifico = 'Cyornis glaucicomans' and descrizione is null;
update specie set descrizione = 'The Hainan blue flycatcher is a bird in the family Muscicapidae. The species was first described by William Robert Ogilvie-Grant in 1900. It is native to southern China, Hainan and Indochina.
Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hainan_blue_flycatcher' where nome_scientifico = 'Cyornis hainanus' and descrizione is null;
update specie set descrizione = 'The blue-fronted blue flycatcher, also known as the blue-fronted flycatcher, is a species of bird in the family Muscicapidae. It is endemic to Indonesia. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-fronted_blue_flycatcher' where nome_scientifico = 'Cyornis hoevelli' and descrizione is null;
update specie set descrizione = 'The fulvous-chested jungle flycatcher is a species of bird in the Old World flycatcher family Muscicapidae.
It is found in Brunei, Indonesia, Malaysia, Myanmar, and Thailand.
Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fulvous-chested_jungle_flycatcher' where nome_scientifico = 'Cyornis olivaceus' and descrizione is null;
update specie set descrizione = 'Il pigliamosche blu di Sulawesi è un uccello della famiglia Muscicapidae, endemico dell''isola di Sulawesi (Indonesia).', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cyornis_omissus' where nome_scientifico = 'Cyornis omissus' and descrizione is null;
update specie set descrizione = 'Il pigliamosche blu dal ventre bianco è un uccello passeriforme appartenente alla famiglia Muscicapidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cyornis_pallipes' where nome_scientifico = 'Cyornis pallidipes' and descrizione is null;
update specie set descrizione = 'The pale-chinned flycatcher is a species of bird in the family Muscicapidae. It has also been known in the past as pale-chinned blue flycatcher, and Brook''s flycatcher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale-chinned_flycatcher' where nome_scientifico = 'Cyornis poliogenys' and descrizione is null;
update specie set descrizione = 'The blue-throated blue flycatcher is a small passerine bird in the flycatcher family, Muscicapidae. It resembles Cyornis tickelliae but easily separated by the blue throat. The habitat of this species is a thicker forest than other species of flycatchers. The blue-throated flycatcher is found in much of the Indian subcontinent, all through the Himalayas, the plains and Western Ghats of India in the cold months, and also extends eastwards into Bangladesh, and to Arakan and the Tenasserim Hills in Myanmar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-throated_blue_flycatcher' where nome_scientifico = 'Cyornis rubeculoides' and descrizione is null;
update specie set descrizione = 'The mangrove blue flycatcher is a species of bird in the family Muscicapidae.
It is native to Brunei, Indonesia, Malaysia, the Philippines, Sri Lanka, Singapore, and Thailand.
Its natural habitat is subtropical or tropical mangrove forests. Clements splits the Kalao blue flycatcher, Cyornis kalaoensis into a distinct species. The IOC still lists it as a subspecies of the mangrove blue flycatcher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mangrove_blue_flycatcher' where nome_scientifico = 'Cyornis rufigastra' and descrizione is null;
update specie set descrizione = 'The Indochinese blue flycatcher is a species of bird in the family Muscicapidae.
It is found from southern Myanmar and the Malay Peninsula to Indochina and northeastern Sumatra. It was previously considered conspecific with Tickell''s blue flycatcher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indochinese_blue_flycatcher' where nome_scientifico = 'Cyornis sumatrensis' and descrizione is null;
update specie set descrizione = 'The Bornean blue flycatcher is a species of bird in the family Muscicapidae. It is found in Brunei, Indonesia, and Malaysia, where it is endemic to the island of Borneo. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bornean_blue_flycatcher' where nome_scientifico = 'Cyornis superbus' and descrizione is null;
update specie set descrizione = 'The Malaysian blue flycatcher is a species of bird in the family Muscicapidae. It has a brilliant blue upperparts, a pale orange throat and chest, and a white belly. A slightly paler female has a whitish throat, while a male''s is blue; the sexes are otherwise quite similar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Malaysian_blue_flycatcher' where nome_scientifico = 'Cyornis turcosus' and descrizione is null;
update specie set descrizione = 'The grey-chested jungle flycatcher is a species of bird in the Old World flycatcher family Muscicapidae. It is found in Brunei, Indonesia, Malaysia, and Thailand. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical swamps. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-chested_jungle_flycatcher' where nome_scientifico = 'Cyornis umbratilis' and descrizione is null;
update specie set descrizione = 'Il pigliamosche blu chiaro è un uccello della famiglia Muscicapidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Cyornis_unicolor' where nome_scientifico = 'Cyornis unicolor' and descrizione is null;
