update specie set descrizione = 'The forest wagtail is a medium-sized passerine bird in the wagtail family Motacillidae. It has a distinctive plumage that sets it apart from other wagtails and has the habit of wagging its tail sideways unlike the usual up and down movements of the other wagtail species. It is the only wagtail species that nests in trees. It is found mainly in forested habitats, breeding in the temperate parts of east Asia and wintering across tropical Asia from India to Indonesia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Forest_wagtail' where nome_scientifico = 'Dendronanthus indicus' and descrizione is null;
update specie set descrizione = 'The straight-billed woodcreeper is a species of bird in the subfamily Dendrocolaptinae of the ovenbird family Furnariidae. It is found in Panama, Trinidad, and in every mainland South American country except Chile, Argentina, Paraguay and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Straight-billed_woodcreeper' where nome_scientifico = 'Dendroplex picus' and descrizione is null;
update specie set descrizione = 'La pernice boschereccia barbuta o pernice di bosco barbuta è una delle tre specie di quaglie del Nuovo Mondo del genere Dendrortyx. Questa specie è endemica del Messico dove abita le foreste umide subtropicali, tropicali o le piantagioni. 
La pernice boschereccia barbuta è resa vulnerabile principalmente dalla perdita di habitat.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Dendrortyx_barbatus' where nome_scientifico = 'Dendrortyx barbatus' and descrizione is null;
update specie set descrizione = 'La pernice boschereccia capocamoscio o pernice di bosco di montagna è una delle tre specie di quaglie del Nuovo Mondo del genere Dendrortyx.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Dendrortyx_leucophrys' where nome_scientifico = 'Dendrortyx leucophrys' and descrizione is null;
update specie set descrizione = 'La pernice boschereccia codalunga o pernice di bosco codalunga è una delle tre specie di quaglie del Nuovo Mondo del genere Dendrortyx. Questa specie è endemica degli altopiani ricchi foreste del centro-sud messicano. Nonostante questo uccello non sia a rischio di estinzione è protetto dalla legge messicana.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Dendrortyx_macroura' where nome_scientifico = 'Dendrortyx macroura' and descrizione is null;
update specie set descrizione = 'Il pappagallo dal ventaglio è un uccello della famiglia degli Psittacidi. È l''unica specie del genere Deroptyus Wagler, 1832.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Deroptyus_accipitrinus' where nome_scientifico = 'Deroptyus accipitrinus' and descrizione is null;
update specie set descrizione = 'The midget flowerpecker is a species of bird in the family Dicaeidae. It is found in the Solomon Islands archipelago. Its natural habitats are subtropical or tropical moist lowland forest, subtropical or tropical mangrove forest, and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Midget_flowerpecker' where nome_scientifico = 'Dicaeum aeneum' and descrizione is null;
update specie set descrizione = 'The thick-billed flowerpecker is a tiny bird in the flowerpecker group. They feed predominantly on fruits and are active birds that are mainly seen in the tops of trees in forests. It is a resident bird with a wide distribution across tropical southern Asia from India east to Indonesia and Timor with several populations recognized as subspecies some of which are sometimes treated as full species. This species was formerly placed in the genus Dicaeum.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Thick-billed_flowerpecker' where nome_scientifico = 'Dicaeum agile' and descrizione is null;
update specie set descrizione = 'The red-keeled flowerpecker or red-striped flowerpecker is a species of bird in the family Dicaeidae. It is endemic to the Philippines. It is one of the more common birds in the Philippines as it is able to thrive in a wide array of habitats. The black-belted flowerpecker was formerly regarded as a subspecies of this bird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-keeled_flowerpecker' where nome_scientifico = 'Dicaeum australe' and descrizione is null;
update specie set descrizione = 'The yellow-vented flowerpecker is a species of bird in the family Dicaeidae. It is found in Bangladesh, Bhutan, Brunei, Cambodia, China, India, Indonesia, Laos, Malaysia, Myanmar, Nepal, Singapore, Thailand, and Vietnam. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest. While most species have vestigial outermost primary feathers, those of the yellow-vented flowerpecker are elongated. This species was formerly placed in the genus Dicaeum.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-vented_flowerpecker' where nome_scientifico = 'Dicaeum chrysorrheum' and descrizione is null;
update specie set descrizione = 'The Nilgiri flowerpecker is a tiny bird in the flowerpecker family. Formerly a subspecies of what used to be termed as the plain flowerpecker although that name is now reserved for Dicaeum minullum. Like others of the group, it feeds predominantly on nectar and fruits. They forage within the canopy of forests and are found in India. They are non-migratory and the widespread distribution range includes several populations that are non-overlapping and morphologically distinct, some of which are recognized as full species. They are important pollinators and dispersers of mistletoes in forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Nilgiri_flowerpecker' where nome_scientifico = 'Dicaeum concolor' and descrizione is null;
update specie set descrizione = 'The scarlet-backed flowerpecker is a species of passerine bird in the flowerpecker family Dicaeidae. Sexually dimorphic, the male has navy blue upperparts with a bright red streak down its back from its crown to its tail coverts, while the female and juvenile are predominantly olive green. It is found in subtropical or tropical moist lowland forests and occasionally gardens in a number of countries throughout South and East Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet-backed_flowerpecker' where nome_scientifico = 'Dicaeum cruentatum' and descrizione is null;
update specie set descrizione = 'The pale-billed flowerpecker or Tickell''s flowerpecker is a tiny bird that feeds on nectar and berries, found in India, Sri Lanka, Bangladesh and western Myanmar. The bird is common especially in urban gardens with berry bearing trees. They have a rapid chipping call and the pinkish curved beak separates it from other species in the region.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale-billed_flowerpecker' where nome_scientifico = 'Dicaeum erythrorhynchos' and descrizione is null;
update specie set descrizione = 'The mistletoebird, also known as the mistletoe flowerpecker, is a species of flowerpecker native to most of Australia and also to the eastern Maluku Islands of Indonesia in the Arafura Sea between Australia and New Guinea. The mistletoebird eats mainly the berries of the parasitic mistletoe and is a vector for the spread of the mistletoe''s seeds through its digestive system.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mistletoebird' where nome_scientifico = 'Dicaeum hirundinaceum' and descrizione is null;
update specie set descrizione = 'The fire-breasted flowerpecker is a species of bird in the family Dicaeidae found in the Indian subcontinent and Southeast Asia. Like other flowerpeckers, this tiny bird feeds on fruits and plays an important role in the dispersal of fruiting plants. Unlike many other species in the genus, this species has marked sexual dimorphism with the male having contrasting upper and lower parts with a distinctive bright orange breast patch. The female is dull coloured.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fire-breasted_flowerpecker' where nome_scientifico = 'Dicaeum ignipectus' and descrizione is null;
update specie set descrizione = 'The plain flowerpecker is a bird in the family Dicaeidae. The species was described and given its binomial name by Robert Swinhoe in 1870. It is found in the central Himalayas, through western Indonesia to Taiwan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plain_flowerpecker' where nome_scientifico = 'Dicaeum minullum' and descrizione is null;
update specie set descrizione = 'The pygmy flowerpecker is a species of bird in the family Dicaeidae.
