update specie set descrizione = 'Il beccafiori ventrearancio è un uccello passeriforme della famiglia Dicaeidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Dicaeum_trigonostigma' where nome_scientifico = 'Dicaeum trigonostigma' and descrizione is null;
update specie set descrizione = 'The mottled flowerpecker or white-mottled flowerpecker is a species of bird in the family Dicaeidae. It is endemic to Makira in the Solomon Islands. It inhabits primary forest and secondary growth, most commonly in the mountains.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mottled_flowerpecker' where nome_scientifico = 'Dicaeum tristrami' and descrizione is null;
update specie set descrizione = 'The banded antbird – sometimes called banded antwren despite not being close to the true antwrens – is a species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Bolivia, Brazil, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Banded_antbird' where nome_scientifico = 'Dichrozona cincta' and descrizione is null;
