update specie set descrizione = 'The fork-tailed drongo, also called the common drongo or African drongo, is a small bird found from the Sahel to South Africa that lives in wooded habitats, particularly woodlands and savannas. It is part of the family Dicruridae and has four recognized subspecies, D. a adsimilis, D. a. apivorus, D. a. fugax and D. a. jubaensis. Like other drongos, the fork-tailed is mostly insectivorous; its diet mainly consists of butterflies, termites, and grasshoppers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fork-tailed_drongo' where nome_scientifico = 'Dicrurus divaricatus' and descrizione is null;
