update specie set descrizione = 'Il drongo coda a racchetta minore, o semplicemente drongo coda a racchetta è un uccello passeriforme appartenente alla famiglia Dicruridae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Dicrurus_remifer' where nome_scientifico = 'Dicrurus remifer' and descrizione is null;
update specie set descrizione = 'The white-sided flowerpiercer is a fairly common and widespread species of flowerpiercer. Flowerpiercers are a genus of birds within the tanager family Thraupidae, with specially adapted bills that enable them to pierce the sides of flower blossoms to access the nectar. 
The white-sided flowerpiercer is found in Colombia, Ecuador, Peru, and Venezuela. Its natural habitats are subtropical or tropical moist montane forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-sided_flowerpiercer' where nome_scientifico = 'Diglossa albilatera' and descrizione is null;
update specie set descrizione = 'The cinnamon-bellied flowerpiercer is a species of bird in the family Thraupidae. It is found in El Salvador, Guatemala, Honduras, and Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cinnamon-bellied_flowerpiercer' where nome_scientifico = 'Diglossa baritula' and descrizione is null;
update specie set descrizione = 'The black-throated flowerpiercer is a species of bird in the family Thraupidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_flowerpiercer' where nome_scientifico = 'Diglossa brunneiventris' and descrizione is null;
update specie set descrizione = 'The bluish flowerpiercer is a species of bird in the family Thraupidae. It is found in humid montane forest in Bolivia, Colombia, Ecuador, Peru and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bluish_flowerpiercer' where nome_scientifico = 'Diglossa caerulescens' and descrizione is null;
update specie set descrizione = 'The masked flowerpiercer is a species of bird in the tanager family, Thraupidae. It is found in humid montane forest and scrub in Venezuela, Colombia, Ecuador, Peru and Bolivia. Flowerpiercers got their name from the fact that they have a sharp hook on the tip of their upper mandible which they use to slice open the base of flowers to get at the nectar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Masked_flowerpiercer' where nome_scientifico = 'Diglossa cyanea' and descrizione is null;
update specie set descrizione = 'The golden-eyed flowerpiercer, also known as the deep-blue flowerpiercer, is a species of bird in the tanager family Thraupidae. It is found in humid Andean forests in Colombia, Ecuador, Peru and Bolivia. It is the only species of flowerpiercer with bright yellow eyes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-eyed_flowerpiercer' where nome_scientifico = 'Diglossa glauca' and descrizione is null;
update specie set descrizione = 'The chestnut-bellied flowerpiercer is a species of bird in the family Thraupidae. It is endemic to Colombia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-bellied_flowerpiercer' where nome_scientifico = 'Diglossa gloriosissima' and descrizione is null;
update specie set descrizione = 'The black flowerpiercer is a species of bird in the family Thraupidae of the order Passeriformes. The family Thraupidae is known for tanagers and other very similar species of birds, but it is still facing classification issues. The black flowerpiercer is found in Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_flowerpiercer' where nome_scientifico = 'Diglossa humeralis' and descrizione is null;
update specie set descrizione = 'The indigo flowerpiercer is a species of bird in the family Thraupidae. It is found in humid forest on the lower west Andean slopes in northern Ecuador and Colombia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indigo_flowerpiercer' where nome_scientifico = 'Diglossa indigotica' and descrizione is null;
update specie set descrizione = 'The glossy flowerpiercer is a species of bird in the family Thraupidae. It is found in Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Glossy_flowerpiercer' where nome_scientifico = 'Diglossa lafresnayii' and descrizione is null;
update specie set descrizione = 'The moustached flowerpiercer is a species of bird in the family Thraupidae. It was first described by French ornithologist Frédéric de Lafresnaye in 1846. It is found in Bolivia and Peru. Its natural habitats are subtropical or tropical moist montane forests, subtropical or tropical high-altitude grassland, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Moustached_flowerpiercer' where nome_scientifico = 'Diglossa mystacalis' and descrizione is null;
update specie set descrizione = 'The slaty flowerpiercer is a passerine bird endemic to the Talamancan montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slaty_flowerpiercer' where nome_scientifico = 'Diglossa plumbea' and descrizione is null;
update specie set descrizione = 'The rusty flowerpiercer is a species of bird in the family Thraupidae. It is found in Argentina, Bolivia, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rusty_flowerpiercer' where nome_scientifico = 'Diglossa sittoides' and descrizione is null;
update specie set descrizione = 'The white-headed buffalo weaver or white-faced buffalo-weaver is a species of passerine bird in the family Ploceidae native to East Africa. The buffalo part of its name derives from its habit of following the African buffalo, feeding on disturbed insects. Two subspecies are recognized.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-headed_buffalo_weaver' where nome_scientifico = 'Dinemellia dinemelli' and descrizione is null;
update specie set descrizione = 'The black-rumped flameback, also known as the lesser golden-backed woodpecker or lesser goldenback, is a woodpecker found widely distributed in the Indian subcontinent. It is one of the few woodpeckers that are seen in urban areas. It has a characteristic rattling-whinnying call and an undulating flight. It is the only golden-backed woodpecker with a black throat and a black rump.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-rumped_flameback' where nome_scientifico = 'Dinopium benghalense' and descrizione is null;
update specie set descrizione = 'The common flameback, also referred to as the common goldenback, is a small (28–30 cm), three-toed woodpecker in the family Picidae, found throughout South and Southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_flameback' where nome_scientifico = 'Dinopium javanense' and descrizione is null;
update specie set descrizione = 'The olive-backed woodpecker is a species of bird in the woodpecker family Picidae that is found in Southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive-backed_woodpecker' where nome_scientifico = 'Dinopium rafflesii' and descrizione is null;
update specie set descrizione = 'L''albatro urlatore è un uccello appartenente alla famiglia dei Diomedeidae. È l’uccello attualmente vivente con apertura alare più ampia, seguito dal congenere albatro reale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Diomedea_exulans' where nome_scientifico = 'Diomedea exulans' and descrizione is null;
update specie set descrizione = 'L''ara spallerosse è un uccello della famiglia degli Psittacidi. È l''unica specie del genere Diopsittaca.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Diopsittaca_nobilis' where nome_scientifico = 'Diopsittaca nobilis' and descrizione is null;
update specie set descrizione = 'The diuca finch is a species of bird in the tanager family Thraupidae. It is the only member of the genus Diuca. It is found in Argentina, Bolivia, Brazil, Chile, and Uruguay. Its natural habitats are subtropical or tropical dry shrubland, subtropical or tropical high-altitude shrubland, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Diuca_finch' where nome_scientifico = 'Diuca diuca' and descrizione is null;
update specie set descrizione = 'The melodious blackbird is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found from Mexico to Costa Rica.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Melodious_blackbird' where nome_scientifico = 'Dives dives' and descrizione is null;
update specie set descrizione = 'The scrub blackbird is a species of bird in the family Icteridae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scrub_blackbird' where nome_scientifico = 'Dives warczewiczi' and descrizione is null;
update specie set descrizione = 'The bobolink is a small New World blackbird and the only member of the genus Dolichonyx. An old name for this species is the "rice bird", from its tendency to feed on cultivated grains during winter and migration. The bobolink breeds in the summer in the United States and Canada, with most of the summer range in the northern U.S. Bobolinks winter in southern South America, primarily Paraguay, Argentina, and Bolivia. Bobolink numbers are rapidly declining due to factors such as agricultural intensification and habitat loss; they are considered threatened in Canada, and are at risk throughout their range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bobolink' where nome_scientifico = 'Dolichonyx oryzivorus' and descrizione is null;
