update specie set descrizione = 'The crimson-naped woodpecker, crimson-breasted woodpecker or scarlet-breasted woodpecker is a species of bird in the family Picidae. It is found in Bhutan, China, India, Myanmar and Nepal. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests. It was previously considered conspecific with necklaced woodpecker.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-naped_woodpecker' where nome_scientifico = 'Dryobates cathpharius' and descrizione is null;
update specie set descrizione = 'The smoky-brown woodpecker is a species of bird in subfamily Picinae of the woodpecker family Picidae. It is found in Argentina, Belize, Bolivia, Colombia, Costa Rica, Ecuador, El Salvador, Guatemala, Honduras, Mexico, Nicaragua, Panama, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Smoky-brown_woodpecker' where nome_scientifico = 'Dryobates fumigatus' and descrizione is null;
update specie set descrizione = 'The red-rumped woodpecker is a species of bird in the subfamily Picinae of the woodpecker family Picidae. It is found from Costa Rica south to Peru and east to Brazil, Guyana, and Trinidad and Tobago.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-rumped_woodpecker' where nome_scientifico = 'Dryobates kirkii' and descrizione is null;
