update specie set descrizione = 'The little woodpecker is a species of bird in subfamily Picinae of the woodpecker family Picidae. It is found in every mainland South American country except Chile, Suriname, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Little_woodpecker' where nome_scientifico = 'Dryobates passerinus' and descrizione is null;
update specie set descrizione = 'The downy woodpecker is a species of woodpecker, the smallest in North America. Length ranges from 14 to 18 cm. Downy woodpeckers primarily live in forested areas throughout the United States and Canada, with the exception of deserts in the southwest and the northern tundra. The bird nests in tree cavities and feeds primarily on insects, although it supplements its diet with seeds and berries. The downy woodpecker is very similar in appearance to the hairy woodpecker, although they are not closely related.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Downy_woodpecker' where nome_scientifico = 'Dryobates pubescens' and descrizione is null;
update specie set descrizione = 'The ladder-backed woodpecker is a North American woodpecker.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ladder-backed_woodpecker' where nome_scientifico = 'Dryobates scalaris' and descrizione is null;
update specie set descrizione = 'The hairy woodpecker is a medium-sized woodpecker that is found over a large area of North America. It is approximately 250 mm (9.8 in) in length with a 380 mm (15 in) wingspan. With an estimated population in 2020 of almost nine million individuals, the hairy woodpecker is listed by the IUCN as a species of least concern. The species was previously placed in the genus Dryobates.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hairy_woodpecker' where nome_scientifico = 'Dryobates villosus' and descrizione is null;
update specie set descrizione = 'Il picchio nero di Giava è una specie di uccello appartenente alla famiglia dei Picidae. Questa specie di grandi dimensioni è diffusa, con numerose popolazioni disgiunte, in vaste aree dell''Asia meridionale e sud-orientale. Abita un ampio ventaglio di ambienti forestali caratterizzati dalla presenza di alberi maturi, tra cui foreste primarie sempreverdi e decidue, foreste secondarie, mangrovieti con grandi alberi e persino pinete. Si nutre principalmente di grandi formiche e della loro covata, termiti, coleotteri e loro larve, altri insetti, oltre che di frutti.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Dryocopus_javensis' where nome_scientifico = 'Dryocopus javensis' and descrizione is null;
update specie set descrizione = 'The lineated woodpecker is a very large woodpecker which is a resident breeding bird from southern Mexico to northern Argentina and Trinidad in the Caribbean.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lineated_woodpecker' where nome_scientifico = 'Dryocopus lineatus' and descrizione is null;
