update specie set descrizione = 'The canyon tree frog is a species of tree frog native to the rocky plateau areas of southern United States, primarily in New Mexico and Arizona, but it also ranges to Utah, Texas, and Colorado, and as far south as the Mexican states of Michoacán, México, Guanajuato, Guerrero, and Oaxaca.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Canyon_tree_frog' where nome_scientifico = 'Dryophytes arenicolor' and descrizione is null;
update specie set descrizione = 'The bird-voiced tree frog is a species of frog in the family Hylidae, endemic to the United States. Its natural habitats are temperate forests, shrub-dominated wetlands, and swamps.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bird-voiced_tree_frog' where nome_scientifico = 'Dryophytes avivoca' and descrizione is null;
update specie set descrizione = 'La raganella americana, detta anche raganella verde americana, è un anfibio della famiglia Hylidae, molto diffuso nel sud degli Stati Uniti d''America. Comune nei cortili, è popolare come animale domestico ed è l''anfibio simbolo degli stati della Georgia e della Louisiana.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Dryophytes_cinereus' where nome_scientifico = 'Dryophytes cinereus' and descrizione is null;
update specie set descrizione = 'The pine woods tree frog is a species of frog in the family Hylidae, endemic to the southeastern United States.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pine_woods_tree_frog' where nome_scientifico = 'Dryophytes femoralis' and descrizione is null;
update specie set descrizione = 'Dryophytes gratiosus, commonly known as the barking tree frog, is a species of tree frog endemic to the south-eastern United States. Formerly known as Hyla gratiosa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dryophytes_gratiosus' where nome_scientifico = 'Dryophytes gratiosus' and descrizione is null;
update specie set descrizione = 'The squirrel tree frog is a small species of tree frog found in the southeastern United States, from Texas to Virginia. It is an introduced species to the Bahamas. Squirrel tree frogs are small frogs, about 1.5 inches in length as adults. There are several color variations, but most commonly they are green and look very much like the American green tree frog. They can also be varying shades of yellow or brown, sometimes with white or brown blotching. Males may also possess a relatively large, conspicuous lateral body stripe, with thicker stripes being more attractive to female frogs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Squirrel_tree_frog' where nome_scientifico = 'Dryophytes squirellus' and descrizione is null;
update specie set descrizione = 'L''ila grigia nordamericana è un anfibio della famiglia Hylidae, nativo di gran parte degli Stati Uniti d''America orientali e del Canada sudorientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Dryophytes_versicolor' where nome_scientifico = 'Dryophytes versicolor' and descrizione is null;
update specie set descrizione = 'The black-backed puffback is a species of passerine bird in the family Malaconotidae. They are common to fairly common sedentary bushshrikes in various wooded habitats in Africa south of the equator. They restlessly move about singly, in pairs or family groups, and generally frequent tree canopies. Like others of its genus, the males puff out the loose rump and lower back feathers in display, to assume a remarkable ball-like appearance. They draw attention to themselves by their varied repertoire of whistling, clicking and rasping sounds. Their specific name cubla, originated with Francois Levaillant, who derived it from a native southern African name, where the "c" is an onomatopoeic click sound. None of the other five puffback species occur in southern Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-backed_puffback' where nome_scientifico = 'Dryoscopus cubla' and descrizione is null;
update specie set descrizione = 'The northern puffback is a species of bird in the family Malaconotidae.
It is found in northern sub-Saharan Africa. It forms a superspecies with the black-backed puffback, which replaces it in eastern equatorial and southern Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_puffback' where nome_scientifico = 'Dryoscopus gambensis' and descrizione is null;
