update specie set descrizione = 'The gray catbird, also spelled grey catbird, is a medium-sized North American and Central American perching bird of the mimid family. It is the only member of the "catbird" genus Dumetella. Like the black catbird, it is among the basal lineages of the Mimidae, probably a closer relative of the Caribbean thrasher and trembler assemblage than of the mockingbirds and Toxostoma thrashers. In some areas it is known as the slate-colored mockingbird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gray_catbird' where nome_scientifico = 'Dumetella carolinensis' and descrizione is null;
update specie set descrizione = 'The dark-fronted babbler is an Old World babbler found in the Western Ghats of India and the forests of Sri Lanka. They are small chestnut brown birds with a dark black cap, a whitish underside and pale yellow iris. They forage in flocks in the undergrowth of forests constantly making calls and uttering alarm calls when disturbed.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dark-fronted_babbler' where nome_scientifico = 'Dumetia atriceps' and descrizione is null;
update specie set descrizione = 'The tawny-bellied babbler also known in older Indian works as the rufous-bellied babbler is a small babbler that forages in small groups in low scrub forests. Like other members of the large Old World babbler family they are passerine birds characterised by soft fluffy plumage. There are three subspecies within the Indian subcontinent. The nominate hyperythra found in northern and eastern India is uniformly brown underneath while albogularis of the western Indian peninsula is white throated. The population in Sri Lanka, phillipsi, is also white throated but is paler underneath and has a larger bill.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tawny-bellied_babbler' where nome_scientifico = 'Dumetia hyperythra' and descrizione is null;
update specie set descrizione = 'The white-streaked antvireo or white-spotted antvireo is a species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Colombia, Ecuador, Peru, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-streaked_antvireo' where nome_scientifico = 'Dysithamnus leucostictus' and descrizione is null;
update specie set descrizione = 'The plain antvireo is a passerine bird species in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Mexico, every Central American country except El Salvador, on both Trinidad and Tobago, and in every mainland South American country except Chile, French Guiana, Suriname, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plain_antvireo' where nome_scientifico = 'Dysithamnus mentalis' and descrizione is null;
