update specie set descrizione = 'Il pappagallo eclettico o ecletto, ecletto maggiore o ecletto delle Molucche(Eclectus roratus Müller, 1776) è un pappagallo appartenente alla famiglia degli Psittaculidi e al genere Eclectus. È endemico delle isole Molucche, dove la popolazione stimata oscilla tra i 7300 e i 51000 individui.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Eclectus_roratus' where nome_scientifico = 'Eclectus roratus' and descrizione is null;
update specie set descrizione = 'The black-bellied cuckooshrike or black-bellied cicadabird is a species of bird in the family Campephagidae.
It is found in New Guinea.
Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-bellied_cuckooshrike' where nome_scientifico = 'Edolisoma montanum' and descrizione is null;
update specie set descrizione = 'The Sahul cicadabird, previously known as the common cicadabird or slender-billed cicadabird, is a species of passerine bird in the family Campephagidae. It is found in Australia, New Guinea and the Bismarck Archipelago. Its natural habitats are temperate forest and subtropical or tropical moist lowland forest. The species is placed in the reinstated genus Edolisoma by most authors. The common cicadabird was described as a "great speciator" by Mayr & Diamond (2001); and Pedersen et al. (2018) described how this species rapidly colonized and diversified across the Indo-Pacific island region and Australia in the Pleistocene.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sahul_cicadabird' where nome_scientifico = 'Edolisoma tenuirostre' and descrizione is null;
