update specie set descrizione = 'La garzetta è un uccello pelecaniforme della famiglia degli ardeidi. Uccello di colore bianco con un sottile becco nero, presenta lunghe gambe nere e, nella sua versione occidentale, piedi gialli. Come il grosso degli uccelli acquatici si nutre in specchi poco profondi e sulla terraferma, cibandosi di animali di piccola taglia. Si riproduce in colonie, spesso con altre specie di uccelli acquatici, costruendo il proprio nido con rami di alberi, cespugli o canne da palude. In media deposita dalle tre alle cinque uova di colore verde-bluastro e la coppia si preoccupa dei nascituri per circa tre settimane. I giovani esemplari abbandonano il nido e raggiungono l''autosufficienza a circa sei settimane di età.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Egretta_garzetta' where nome_scientifico = 'Egretta garzetta' and descrizione is null;
update specie set descrizione = 'L''airone schistaceo è un uccello appartenente alla famiglia Ardeidae, diffuso in Africa, Asia ed occasionalmente in Europa e America centrale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Egretta_gularis' where nome_scientifico = 'Egretta gularis' and descrizione is null;
