update specie set descrizione = 'The keel-billed motmot is a Vulnerable species of bird in the motmot family Momotidae. It is found in Belize, Costa Rica, Guatemala, Honduras, Mexico, and Nicaragua.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Keel-billed_motmot' where nome_scientifico = 'Electron carinatum' and descrizione is null;
update specie set descrizione = 'The broad-billed motmot is a fairly common Central and South American bird of the Momotidae family. They are nonmigratory, sedentary birds that are most frequently seen in singles or pairs. There exist six subspecies of the broad-billed motmot.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Broad-billed_motmot' where nome_scientifico = 'Electron platyrhynchum' and descrizione is null;
