update specie set descrizione = 'The sickle-winged nightjar is a species of nightjar in the family Caprimulgidae. It is found in Argentina, Brazil, Paraguay and possibly Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sickle-winged_nightjar' where nome_scientifico = 'Eleothreptus anomalus' and descrizione is null;
