update specie set descrizione = 'The white-tailed crested flycatcher is a species of bird in the flycatcher family Stenostiridae. It has a discontinuous distribution in eastern Africa. There are three subspecies, E. a. albonotata of central Kenya, and Uganda through to south west Tanzania; E. a. subvaerulea, which ranges from southern Kenya to Malawi and E. a. swynnertoni of Zimbabwe and Mozambique.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-tailed_crested_flycatcher' where nome_scientifico = 'Elminia albonotata' and descrizione is null;
