update specie set descrizione = 'Il corriere frontenera, è un uccello della famiglia dei Charadriidae e unico rappresentante del genere Elseyornis.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Elseyornis_melanops' where nome_scientifico = 'Elseyornis melanops' and descrizione is null;
update specie set descrizione = 'The sickle-winged chat or sicklewing chat is a small passerine bird of the Old World flycatcher family Muscicapidae endemic to southern Africa. It is a common resident breeder in South Africa and Lesotho, and is also found in southernmost areas of Botswana and Namibia. Its habitat is Karoo scrub, short grassland, and barren sandy or stony areas. In western coastal areas, it also occurs on agricultural land.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sickle-winged_chat' where nome_scientifico = 'Emarginata sinuata' and descrizione is null;
update specie set descrizione = 'The yellow-breasted bunting is a passerine bird in the bunting family Emberizidae that is found across the Boreal and East Palearctic. The genus name Emberiza is from Old German Embritz, a bunting. The specific aureola is Latin for "golden". The bird''s call is a distinctive zick, and the song is a clear tru-tru, tri-tri.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-breasted_bunting' where nome_scientifico = 'Emberiza aureola' and descrizione is null;
update specie set descrizione = 'The red-headed bunting is a passerine bird in the bunting family Emberizidae. It breeds in central Asia, including Afghanistan, Iran, Kazakhstan, Kyrgyzstan, Mongolia; Russia, Tajikistan, Turkmenistan, Uzbekistan and China. It is migratory, wintering in India and Bangladesh. Its status in western Europe, where it is a vagrant, has been confused by escapes, especially as this species has been more commonly recorded than the closely related black-headed bunting, despite the latter having a more westerly breeding range. Reports in Britain have declined dramatically over recent years, coinciding with the decline in some Emberizidae species from the impact of illegal trade. An individual found on Shetland in 2010 was deemed to be wild in origin.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-headed_bunting' where nome_scientifico = 'Emberiza bruniceps' and descrizione is null;
update specie set descrizione = 'The grey-necked bunting, sometimes referred to as grey-hooded bunting is a species of bird in the family Emberizidae. It breeds along a wide distribution range from the Caspian Sea to the Altai Mountains in Central Asia and winters in parts of Southern Asia. Like other buntings it is found in small flocks.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-necked_bunting' where nome_scientifico = 'Emberiza buchanani' and descrizione is null;
