update specie set descrizione = 'Lo zigolo dai sopraccigli gialli è un uccello passeriforme appartenente alla famiglia degli Emberizidi, un gruppo che la maggior parte dei tassonomi moderni considera separato dai Fringillidi. Il nome del genere Emberiza deriva dall''antico tedesco Embritz, che indicava uno zigolo. L''epiteto specifico chrysophrys proviene invece dal greco antico khrusophrus e significa «dalle sopracciglia dorate».', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Emberiza_chrysophrys' where nome_scientifico = 'Emberiza chrysophrys' and descrizione is null;
