update specie set descrizione = 'The white-capped bunting or chestnut-breasted bunting is a species of bird in the family Emberizidae. It is found in Afghanistan, India, Iran, Kazakhstan, Kyrgyzstan, Nepal, Pakistan, Tajikistan, Turkmenistan, and Uzbekistan. Its natural habitats are boreal forests, boreal shrubland, and temperate grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-capped_bunting' where nome_scientifico = 'Emberiza stewarti' and descrizione is null;
