update specie set descrizione = 'The ochre-rumped bunting, also known as the Japanese reed bunting, is a bird in the family Emberizidae. It is found in Manchuria, Korea and Japan. Its natural habitats are temperate grassland and swamps. It is threatened by habitat loss. In South Korea it is classified as an endangered species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ochre-rumped_bunting' where nome_scientifico = 'Emberiza yessoensis' and descrizione is null;
update specie set descrizione = 'The wedge-tailed grass finch is a species of bird in the family Thraupidae; it was formerly placed in the Emberizidae. It is found in Argentina, Bolivia, Brazil, Colombia, Costa Rica, Ecuador, French Guiana, Guyana, Panama, Paraguay, Peru, Suriname, Uruguay, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Wedge-tailed_grass_finch' where nome_scientifico = 'Emberizoides herbicola' and descrizione is null;
update specie set descrizione = 'The lesser grass finch, also known as the grey-cheeked grass-finch, is a species of bird in the family Thraupidae; it was formerly placed in the Emberizidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_grass_finch' where nome_scientifico = 'Emberizoides ypiranganus' and descrizione is null;
update specie set descrizione = 'The serra finch, also known as the pale-throated Pampa-finch, is a species of bird traditionally placed in the family Emberizidae, though recent research suggests it is either very close to the Thraupidae or even part thereof. It is endemic to Brazil. Its natural habitats are dry savanna and subtropical or tropical high-altitude shrubland. It is becoming rare due to habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Serra_finch' where nome_scientifico = 'Embernagra longicauda' and descrizione is null;
update specie set descrizione = 'The Pampa finch, also known as the great Pampa-finch, is a species of bird. It was traditionally placed in the family Emberizidae but molecular phylogenetic studies have shown that it is a member of the tanager family Thraupidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pampa_finch' where nome_scientifico = 'Embernagra platensis' and descrizione is null;
update specie set descrizione = 'The grey-capped warbler is a species of bird in the family Cisticolidae. It is monotypic in the genus Eminia. The grey-capped warbler is found in Burundi, Democratic Republic of the Congo, Kenya, Rwanda, South Sudan, Tanzania, and Uganda. It is a large, chunky, thin-tailed-warbler with a distinctive grey cap, a black band around its head, and a chestnut throat wrapping its neck. Grey-capped warblers maintain a diet of insects and other invertebrates, including caterpillars, moths, grasshoppers, and mantids.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-capped_warbler' where nome_scientifico = 'Eminia lepida' and descrizione is null;
update specie set descrizione = 'The pine flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Guatemala and Mexico. It has also been recorded as a vagrant to Arizona in the U.S.A.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pine_flycatcher' where nome_scientifico = 'Empidonax affinis' and descrizione is null;
update specie set descrizione = 'The white-throated flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Mexico and every country in Central America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_flycatcher' where nome_scientifico = 'Empidonax albigularis' and descrizione is null;
update specie set descrizione = 'The alder flycatcher is a small insect-eating bird in the tyrant flycatcher family. The genus name Empidonax is from Ancient Greek empis, "gnat", and anax, "master". The specific alnorum is Latin and means "of the alders".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Alder_flycatcher' where nome_scientifico = 'Empidonax alnorum' and descrizione is null;
