update specie set descrizione = 'The western flycatcher is a small insectivorous bird in the family Tyrannidae. It is native to western North America, where it breeds in the Rocky Mountains and Pacific Coast forests and mountain ranges from California to Alaska and south to central Mexico; northern populations migrate south to Mexico for the winter.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_flycatcher' where nome_scientifico = 'Empidonax difficilis' and descrizione is null;
