update specie set descrizione = 'The American dusky flycatcher, or simply dusky flycatcher, is a small insectivorous passerine of the tyrant flycatcher family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/American_dusky_flycatcher' where nome_scientifico = 'Empidonax oberholseri' and descrizione is null;
update specie set descrizione = 'The western flycatcher is a small insectivorous bird in the family Tyrannidae. It is native to western North America, where it breeds in the Rocky Mountains and Pacific Coast forests and mountain ranges from California to Alaska and south to central Mexico; northern populations migrate south to Mexico for the winter.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_flycatcher' where nome_scientifico = 'Empidonax occidentalis' and descrizione is null;
update specie set descrizione = 'The willow flycatcher is a small insect-eating, migrant bird of the tyrant flycatcher family native to North America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Willow_flycatcher' where nome_scientifico = 'Empidonax traillii' and descrizione is null;
update specie set descrizione = 'The Acadian flycatcher is a small insect-eating bird of the tyrant flycatcher family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Acadian_flycatcher' where nome_scientifico = 'Empidonax virescens' and descrizione is null;
update specie set descrizione = 'The American gray flycatcher, American grey flycatcher, or just gray flycatcher as it is known in North America, is a small, insectivorous passerine in the tyrant flycatcher family. It is common in the arid regions of western North America, especially the Great Basin. From sagebrush steppes to pinyon-juniper woodlands and ponderosa pine forests, this flycatcher forages for insects from shrubs or low tree branches.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/American_gray_flycatcher' where nome_scientifico = 'Empidonax wrightii' and descrizione is null;
update specie set descrizione = 'The crowned slaty flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in every mainland South American country except Suriname though only as a vagrant to Chile, French Guiana, and Venezuela. There are also single records of it in Panama and the U.S. state of Louisiana.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crowned_slaty_flycatcher' where nome_scientifico = 'Empidonomus aurantioatrocristatus' and descrizione is null;
update specie set descrizione = 'The variegated flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found on Trinidad and in every mainland South American country except Chile. In addition it has been documented as a vagrant in several U.S. states and the Canadian province of Ontario.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Variegated_flycatcher' where nome_scientifico = 'Empidonomus varius' and descrizione is null;
update specie set descrizione = 'Il parrocchetto australe è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Enicognathus_ferrugineus' where nome_scientifico = 'Enicognathus ferrugineus' and descrizione is null;
update specie set descrizione = 'Il parrocchetto beccosottile è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Enicognathus_leptorhynchus' where nome_scientifico = 'Enicognathus leptorhynchus' and descrizione is null;
update specie set descrizione = 'The white-crowned forktail is a species of forktail in the family Muscicapidae. Formally described in 1818, it has five subspecies, each occupying a different geographic range. The largest of the forktails, Enicurus leschenaulti, is between 25 and 28 centimetres long. It has a black throat and breast, black mantle, and largely black wings. The rump and lower back are white, and the bird has a prominent white crown, from which it gets its name. As with other forktails, the tail is long, deeply forked, and banded in black and white. A variety of whistling and clicking calls have been described. Slight morphological differences have been observed between subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-crowned_forktail' where nome_scientifico = 'Enicurus leschenaulti' and descrizione is null;
update specie set descrizione = 'The spotted forktail is a species of bird in the family Muscicapidae. It is found in the Himalayas and the hills of Northeast India, Bangladesh, Myanmar, and southern China including Yunnan. Birds of this species are 25 cm with a long tail. The sexes are alike, having a white forehead and a black crown and nape, a black back spotted white, and a broad white wing bar. The tail is deeply forked, graduated black and white. The white spotted back easily identifies this species from other similar sized forktail. Its call is a shrill, screechy KREE, mostly given in flight; it also makes some shrill, squeaky notes while perched. It breeds mostly at 1200–3600 m, and descends to about 600 m in winter. Its natural habitat is subtropical or tropical moist montane forests, where it is found in boulder-strewn torrents, forest streams, and roadside canals.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spotted_forktail' where nome_scientifico = 'Enicurus maculatus' and descrizione is null;
update specie set descrizione = 'The slaty-backed forktail is a species of forktail in the family Muscicapidae. A slim, medium-sized forktail, it is distinguished from similar species by its slate grey forehead, crown, and mantle. It has a long and deeply forked tail banded in black and white, a white rump, and a white bar across its primary feathers; the rest of the plumage is predominantly white. The sexes look alike. The bird frequents the edges of fast-flowing streams and rivers, where it hunts small invertebrates by hopping among rocks or flying out over the water. It breeds between February and July, laying 3–4 pinkish, bluish, or white eggs; both sexes incubate the eggs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slaty-backed_forktail' where nome_scientifico = 'Enicurus schistaceus' and descrizione is null;
update specie set descrizione = 'The black solitaire is a species of bird in the family Turdidae, the thrushes. It is found in Colombia and Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_solitaire' where nome_scientifico = 'Entomodestes coracinus' and descrizione is null;
update specie set descrizione = 'The white-eared solitaire is a species of bird in the family Turdidae, the thrushes. It is found in Bolivia and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-eared_solitaire' where nome_scientifico = 'Entomodestes leucotis' and descrizione is null;
update specie set descrizione = 'Il succiamiele guanceblu, anche noto colloquialmente come melifago facciablu o uccello banana, è un uccello passeriforme della famiglia Meliphagidae. È l''unico membro del genere Entomyzon ed è strettamente imparentato con i melifagi del genere Melithreptus. Sono riconosciute tre sottospecie. Con una lunghezza di circa 29,5 centimetri, è una delle specie più grandi di melifago. Il suo piumaggio è caratteristico, con il piumaggio dorsale olivastro, il ventre bianco e testa e gola nere con nuca e guance bianche. Maschi e femmine sono simili nell''aspetto. Gli adulti presentano una zona blu di pelle nuda su ciascun lato del viso, che li distingue facilmente dai giovani, i quali hanno macchie di pelle nuda gialle o verdi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Entomyzon_cyanotis' where nome_scientifico = 'Entomyzon cyanotis' and descrizione is null;
update specie set descrizione = 'Il galah o cacatua rosa è un uccello della famiglia dei Cacatuidi, diffuso in Australia. In passato era stato classificato sotto il genere Cacatua.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Eolophus_roseicapilla' where nome_scientifico = 'Eolophus roseicapilla' and descrizione is null;
update specie set descrizione = 'Il frosone codanera o frosone cinese è un uccello passeriforme della famiglia dei Fringillidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Eophona_migratoria' where nome_scientifico = 'Eophona migratoria' and descrizione is null;
update specie set descrizione = 'The Japanese grosbeak or Ikaru is a finch native to the East Palearctic. It is also sometimes referred to as the Japanese or masked hawfinch due to superficial similarities to the well-known Eurasian species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Japanese_grosbeak' where nome_scientifico = 'Eophona personata' and descrizione is null;
