update specie set descrizione = 'The Rio Madeira stipplethroat is a species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Bolivia, Brazil, and Peru. In the past it has also been called eastern stipple-throated antwren, Madeira stipple-throated antwren, Rio Madeira antwren, and Madeira antwren.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rio_Madeira_stipplethroat' where nome_scientifico = 'Epinecrophylla amazonica' and descrizione is null;
update specie set descrizione = 'The rufous-tailed stipplethroat, formerly called the rufous-tailed antwren, is a species of insectivorous bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Brazil, Colombia, Ecuador, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-tailed_stipplethroat' where nome_scientifico = 'Epinecrophylla erythrura' and descrizione is null;
