update specie set descrizione = 'The Nilgiri flycatcher is an Old World flycatcher with a very restricted range in the hills of southern India. It was formerly referred to as the Nilgiri verditer flycatcher because of its similarity to the verditer flycatcher, a winter migrant to the Nilgiris, which, however, has distinct dark lores and a lighter shade of blue. There are two small white patches at the base of the tail. It is found mainly in the higher altitude shola forests of the Western Ghats and the Nilgiris.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Nilgiri_flycatcher' where nome_scientifico = 'Eumyias albicaudatus' and descrizione is null;
