update specie set descrizione = 'The yellow-crowned bishop is a species of passerine bird in the family Ploceidae native to Africa south of the Sahara. It is highly sexually dimorphic in its breeding season, during which the male adopts a distinctive yellow and black plumage, contrasting with the female''s predominantly brown coloration. Four subspecies are recognised.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-crowned_bishop' where nome_scientifico = 'Euplectes afer' and descrizione is null;
update specie set descrizione = 'The red-collared widowbird is a species of bird in the family Ploceidae. Red-collared widowbirds are found in grasslands and bush clearings in western and southern Africa. They are known for their long tails and brilliant red badges, both of which act as sexual ornaments. They are often associated with other widowbird and bishop species. They are polygynous, where males acquisition of territory is an important determinant in their access to mates. Red-collared widowbirds have a wide range and there is little concern in terms of conservation status.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-collared_widowbird' where nome_scientifico = 'Euplectes ardens' and descrizione is null;
update specie set descrizione = 'The yellow bishop, also known as Cape bishop, Cape widow or yellow-rumped widow, is a resident breeding Afromontane bird species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow_bishop' where nome_scientifico = 'Euplectes capensis' and descrizione is null;
