update specie set descrizione = 'The black-winged red bishop, formerly known in southern Africa as the fire-crowned bishop, is a resident breeding bird species in tropical Africa from Senegal to Sudan and south to Angola, Tanzania, Zimbabwe and Mozambique.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-winged_red_bishop' where nome_scientifico = 'Euplectes hordeaceus' and descrizione is null;
update specie set descrizione = 'The southern red bishop or red bishop is a small passerine bird belonging to the bishop and widowbird genus Euplectes in the weaver family, the Ploceidae. It is common in wetlands and grassland in Africa south of the Equator. North of the Equator, it is replaced by the northern red bishop or orange bishop which was formerly regarded as a subspecies of this species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_red_bishop' where nome_scientifico = 'Euplectes orix' and descrizione is null;
