update specie set descrizione = 'The broad-billed roller is a member of the roller family of birds which breeds across tropical Africa and Madagascar in all but the driest regions. It is a wet season breeder, which migrates from the northern and southern areas of its range towards the moister equatorial belt in the dry season.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Broad-billed_roller' where nome_scientifico = 'Eurystomus glaucurus' and descrizione is null;
