update specie set descrizione = 'The fulvous-faced scrub tyrant, or tawny-fronted pygmy-tyrant is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Ecuador, Peru, and possibly Colombia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fulvous-faced_scrub_tyrant' where nome_scientifico = 'Euscarthmus fulviceps' and descrizione is null;
update specie set descrizione = 'The fulvous-crowned scrub tyrant, or tawny-crowned pygmy-tyrant, is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Bolivia, Brazil, Colombia, Paraguay, Peru, Uruguay, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fulvous-crowned_scrub_tyrant' where nome_scientifico = 'Euscarthmus meloryphus' and descrizione is null;
