update specie set descrizione = 'Il falcetto codabianca è un uccello della famiglia Trochilidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Eutoxeres_aquila' where nome_scientifico = 'Eutoxeres aquila' and descrizione is null;
update specie set descrizione = 'Il falco dell''Amur è un uccello falconiforme della famiglia dei Falconidi. Nidifica in Siberia sud-orientale e Cina settentrionale e sverna nell''Africa meridionale. La sua dieta è costituita in gran parte da insetti, soprattutto termiti.
Nel nome scientifico la parola "amurensis" fa riferimento alla foce del fiume Amur dove fu catalogato per la prima volta.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_amurensis' where nome_scientifico = 'Falco amurensis' and descrizione is null;
update specie set descrizione = 'Il falco bruno è un membro dei genere dei falchi che vive nelle regioni asciutte dell''Australia. Il nome specifico berigora deriva dal termine con cui veniva indicato dagli aborigeni.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_berigora' where nome_scientifico = 'Falco berigora' and descrizione is null;
update specie set descrizione = 'Lo smeriglio è un uccello falconiforme della famiglia dei Falconidi. Questa piccola specie di falco dell''emisfero boreale, nota colloquialmente in Nordamerica come pigeon hawk, nidifica nelle regioni olartiche settentrionali; alcuni esemplari migrano in inverno verso le regioni subtropicali e quelle tropicali più settentrionali.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_columbarius' where nome_scientifico = 'Falco columbarius' and descrizione is null;
update specie set descrizione = 'Il falco pettoarancio è un uccello falconiforme della famiglia dei Falconidi. Somiglia molto ad una versione più grande del falco dei pipistrelli, specie con la quale è molto probabilmente imparentato. Entrambe le specie, a loro volta, sono strette parenti del falco aplomado e costituiscono una linea evolutiva americana piuttosto antica di specie del genere Falco.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_deiroleucus' where nome_scientifico = 'Falco deiroleucus' and descrizione is null;
update specie set descrizione = 'Il falco aplomado è un uccello falconiforme della famiglia dei Falconidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_femoralis' where nome_scientifico = 'Falco femoralis' and descrizione is null;
update specie set descrizione = 'Il falco di prateria è un uccello falconiforme della famiglia dei Falconidi. Di medie dimensioni, questo falco è originario delle regioni occidentali del Nordamerica.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_mexicanus' where nome_scientifico = 'Falco mexicanus' and descrizione is null;
update specie set descrizione = 'Il grillaio è un uccello rapace della famiglia dei Falconidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_naumanni' where nome_scientifico = 'Falco naumanni' and descrizione is null;
update specie set descrizione = 'Il falco pellegrino è un uccello rapace della famiglia dei Falconidi diffuso quasi in tutto il mondo: Europa, Asia, Africa, Nordamerica, Sudamerica e Oceania. Nel nome scientifico la parola peregrinus fa riferimento alla colorazione scura delle penne del capo, che ricordano un cappuccio nero simile a quello che erano soliti indossare i pellegrini.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_peregrinus' where nome_scientifico = 'Falco peregrinus' and descrizione is null;
update specie set descrizione = 'Il falco dei pipistrelli è un uccello falconiforme della famiglia dei Falconidi. È una specie stanziale che vive nelle regioni tropicali di Messico, Centro e Sudamerica e a Trinidad. Per lungo tempo è stato noto come Falco albigularis; adesso si ritiene che anche il vecchio nome Falco fusco-coerulescens o Falco fuscocaerulescens, a lungo usato per indicare il falco aplomado, si riferisse in passato a questa specie.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_rufigularis' where nome_scientifico = 'Falco rufigularis' and descrizione is null;
