update specie set descrizione = 'Il gheppio comune è un rapace della famiglia Falconidae ampiamente diffuso in Europa, Africa e Asia. Molti conoscono il gheppio poiché ha conquistato le città come proprio ambiente e si caratterizza per il suo originale volo oscillante.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Falco_tinnunculus' where nome_scientifico = 'Falco tinnunculus' and descrizione is null;
