update specie set descrizione = 'Lo scricciolo di Zapata è un uccello della famiglia dei Trogloditidi originario di Cuba. È l''unica specie nota del genere Ferminia Barbour, 1926..', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ferminia_cerverai' where nome_scientifico = 'Ferminia cerverai' and descrizione is null;
update specie set descrizione = 'The taiga flycatcher or red-throated flycatcher is a migratory bird in the family Muscicapidae. The species was first described by Peter Simon Pallas in 1811. The female has brown upper parts with a blackish tail flanked by white. The breast is buffish with underparts mostly white. The male has ear coverts and sides of the neck blue-tinged grey with breeding males having orange-red coloration on the throats. Unlike the taiga flycatcher, the female of the similar red-breasted flycatcher has a brown tail while the red colour in breeding males extends to the breast in the red-breasted flycatcher. It breeds in northern Eurasia from eastern Russia to Siberia and Mongolia. It is a winter visitor to South and South-east Asia in Bangladesh, Bhutan, India, Cambodia, Laos, Myanmar, Nepal, Malaysia, Thailand, China, Vietnam, and Japan. Its natural habitat is taiga forest. It is a rare vagrant to western Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Taiga_flycatcher' where nome_scientifico = 'Ficedula albicilla' and descrizione is null;
update specie set descrizione = 'La balia dal collare è un uccello passeriforme della famiglia Muscicapidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ficedula_albicollis' where nome_scientifico = 'Ficedula albicollis' and descrizione is null;
update specie set descrizione = 'The little slaty flycatcher is a species of bird in the family Muscicapidae.
It is found on the islands of Mindanao, Leyte and Samar in the Philippines.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Little_slaty_flycatcher' where nome_scientifico = 'Ficedula basilanica' and descrizione is null;
update specie set descrizione = 'The rufous-chested flycatcher is a species of bird in the family Muscicapidae. It is found in Brunei, Indonesia, Malaysia, and Thailand.
Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-chested_flycatcher' where nome_scientifico = 'Ficedula dumetoria' and descrizione is null;
update specie set descrizione = 'The green-backed flycatcher is a bird in the family Muscicapidae, which contains the Old World flycatchers. It was long considered to be a subspecies of the narcissus flycatcher, but morphological and acoustical differences between the two indicate they are instead separate species. It breeds in northeastern China and winters in southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-backed_flycatcher' where nome_scientifico = 'Ficedula elisae' and descrizione is null;
update specie set descrizione = 'The slaty-backed flycatcher is a species of bird in the family Muscicapidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slaty-backed_flycatcher' where nome_scientifico = 'Ficedula erithacus' and descrizione is null;
update specie set descrizione = 'The pygmy flycatcher, also known as the pygmy blue-flycatcher, is a bird species of the family Muscicapidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pygmy_flycatcher' where nome_scientifico = 'Ficedula hodgsoni' and descrizione is null;
update specie set descrizione = 'The snowy-browed flycatcher is a species of bird in the Old World flycatcher family Muscicapidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Snowy-browed_flycatcher' where nome_scientifico = 'Ficedula hyperythra' and descrizione is null;
update specie set descrizione = 'La balia nera è un uccello appartenente alla famiglia Muscicapidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ficedula_hypoleuca' where nome_scientifico = 'Ficedula hypoleuca' and descrizione is null;
update specie set descrizione = 'The mugimaki flycatcher is a small passerine bird of eastern Asia belonging to the genus Ficedula in the Old World flycatcher family, Muscicapidae. The name "mugimaki" comes from Japanese and means "wheat-sower". The bird is also known as the robin flycatcher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mugimaki_flycatcher' where nome_scientifico = 'Ficedula mugimaki' and descrizione is null;
update specie set descrizione = 'The narcissus flycatcher is a passerine bird in the Old World flycatcher family. It is native to the East Palearctic, from Sakhalin to the north, through Japan across through Korea, mainland China, and Taiwan, wintering in southeast Asia, including the Philippines, Vietnam and Borneo. It is highly migratory, and has been found as a vagrant from Australia in the south to Alaska in the north Archived 2006-01-10 at the Wayback Machine.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Narcissus_flycatcher' where nome_scientifico = 'Ficedula narcissina' and descrizione is null;
update specie set descrizione = 'The black-and-orange flycatcher or black-and-rufous flycatcher is a species of flycatcher endemic to the central and southern Western Ghats, the Nilgiris and Palni hill ranges in southern India. It is unique among the Ficedula flycatchers in having rufous coloration on its back and prior to molecular studies was suggested to be related to the chats and thrushes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-and-orange_flycatcher' where nome_scientifico = 'Ficedula nigrorufa' and descrizione is null;
update specie set descrizione = 'The red-breasted flycatcher is a small passerine bird in the Old World flycatcher family. It breeds in eastern Europe and across Central Asia and is migratory, wintering in south Asia. The breeding male is mainly muted brown above and white below, with a grey head and an orange throat. Females and immatures are similarly colored but lack the orange throat patch. The red-breasted flycatcher is a regular passage migrant in western Europe, whereas the collared flycatcher, which has a different migration route, is scarce. It forms a superspecies with the closely related taiga flycatcher and Kashmir flycatcher and can be distinguished from the former by its different song, warmer-toned plumage and the more extensive orange throat patch.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-breasted_flycatcher' where nome_scientifico = 'Ficedula parva' and descrizione is null;
update specie set descrizione = 'The rusty-tailed flycatcher is a small passerine bird in the flycatcher family Muscicapidae. It is found mainly in the northern regions of the Indian subcontinent and some parts of southwest India, as well as pockets of Central Asia including Uzbekistan and Tajikistan. The species is partially migratory, with the Central Asian populations migrating to India, as far as the southwest Indian coast along the Arabian Sea, to Karnataka and Kerala.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rusty-tailed_flycatcher' where nome_scientifico = 'Ficedula ruficauda' and descrizione is null;
update specie set descrizione = 'The semicollared flycatcher is a small passerine bird in the Old World flycatcher family, one of the four species of Western Palearctic black-and-white flycatchers. It breeds in montane forests of the southeastern corner of Europe to Northwest Iran. It is migratory, wintering in Central and Eastern Africa. It is a rare vagrant in western Europe. Tracking studies using geolocators have revealed that weather conditions during spring migration can have a large impact on the timing of Semicollared flycatcher migration and survival of adult birds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Semicollared_flycatcher' where nome_scientifico = 'Ficedula semitorquata' and descrizione is null;
update specie set descrizione = 'The rufous-gorgeted flycatcher is a species of bird in the family Muscicapidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-gorgeted_flycatcher' where nome_scientifico = 'Ficedula strophiata' and descrizione is null;
update specie set descrizione = 'The Kashmir flycatcher is a small passerine bird in the flycatcher family Muscicapidae. It breeds in the Northwest Himalayas and winters in southern India and Sri Lanka. It was formerly considered to be a subspecies of the red-breasted flycatcher, Ficedula parva, which is its closest living relative. Males are distinctive in having a blackish border to the reddish throat while the females can easily be confused with those of F. parva.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Kashmir_flycatcher' where nome_scientifico = 'Ficedula subrubra' and descrizione is null;
update specie set descrizione = 'The ultramarine flycatcher or the white-browed blue flycatcher is a small arboreal Old World flycatcher in the Ficedula genus. Its breeding range extends from eastern Afghanistan to the Hengduan Mountains; it winters in India and northwestern Indochina.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ultramarine_flycatcher' where nome_scientifico = 'Ficedula superciliaris' and descrizione is null;
update specie set descrizione = 'The slaty-blue flycatcher is a species of bird in the family Muscicapidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slaty-blue_flycatcher' where nome_scientifico = 'Ficedula tricolor' and descrizione is null;
update specie set descrizione = 'The little pied flycatcher is a species of bird in the family Muscicapidae. It is native to the Himalayas and Southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Little_pied_flycatcher' where nome_scientifico = 'Ficedula westermanni' and descrizione is null;
update specie set descrizione = 'The yellow-rumped flycatcher, also known as Korean flycatcher or tricolor flycatcher, is a species of flycatcher found in eastern Asia. A distinctive species with almost no look-alike other than the narcissus flycatcher. It breeds in eastern Asia including parts of Mongolia, Transbaikal, southern China, Korea and western Japan. They winter in parts of the Malay Peninsula and South Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-rumped_flycatcher' where nome_scientifico = 'Ficedula zanthopygia' and descrizione is null;
update specie set descrizione = 'Fireworks are low explosive pyrotechnic devices used for aesthetic and entertainment purposes. They are most commonly used in fireworks displays, combining a large number of devices in an outdoor setting. Such displays are the focal point of many cultural and religious celebrations, though mismanagement can lead to fireworks accidents.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fireworks' where nome_scientifico = 'Fireworks' and descrizione is null;
