update specie set descrizione = 'Il pappagallino aliblu è un uccello della famiglia degli Psittacidi. Del tutto simile, anche nelle abitudini, al pappagallino groppaverde, si caratterizza per la colorazione blu intensa di ali e groppone; ha taglia attorno ai 12 cm ed è classificato in sei sottospecie molto simili. Vive in un vasto areale che comprende Colombia nord-occidentale, Perù centrale e nord-occidentale, bacino del Rio delle Amazzoni, Brasile nord-orientale, Argentina nord-orientale, Paraguay e Bolivia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Forpus_xanthopterygius' where nome_scientifico = 'Forpus xanthopterygius' and descrizione is null;
