update specie set descrizione = 'The painted francolin or painted partridge is a species of francolin found in grassy areas in central and southern India and in the lowlands of southeastern Sri Lanka. Thomas C. Jerdon noted that the species was found mainly in Central India south of the Narmada and to the east of the Western Ghats as well as the Chota Nagpur and Northern Circars. It partly overlaps with the black francolin with which it partly overlaps and is said to sometimes hybridize. This species can be so distinguished from a black francolin female by the lack of a rufous hind collar and the white spots on the underside. The face is rufous and there is no dark stripe running behind the eye.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Painted_francolin' where nome_scientifico = 'Francolinus pictus' and descrizione is null;
