update specie set descrizione = 'The ashy flycatcher is a species of bird in the Old World flycatcher family Muscicapidae. It is found throughout sub-Saharan Africa, excluding the drier areas of South Africa, Botswana, and Namibia, where it inhabits subtropical or tropical dry forest, subtropical or tropical moist lowland forest, and savanna. It has a disputed generic placement, with different authorities variously putting it in Muscicapa, Fraseria, or other genera. Ashy flycatchers are mostly grey in colour, with pale grey or white underparts, and display no sexual dimorphism.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ashy_flycatcher' where nome_scientifico = 'Fraseria caerulescens' and descrizione is null;
