update specie set descrizione = 'The pale-legged hornero is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Bolivia, Brazil, Guyana, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale-legged_hornero' where nome_scientifico = 'Furnarius leucopus' and descrizione is null;
