update specie set descrizione = 'Sykes''s lark is a species of lark found in the dry open country of India. Its distribution is mainly restricted to central India, although stray records have been found elsewhere on the sub-continent. It is identified by its prominent crest and its overall rufous colouration. It has streaks on its breast which are less prominent than those found in the Oriental skylark.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sykes''s_lark' where nome_scientifico = 'Galerida deva' and descrizione is null;
