update specie set descrizione = 'The common gallinule is a bird in the family Rallidae. It was split from the common moorhen by the American Ornithologists'' Union in July 2011. It lives around well-vegetated marshes, ponds, canals, and other wetlands in the Americas. The common gallinule is one of the most conspicuous rail species in North America, along with the American coot.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_gallinule' where nome_scientifico = 'Gallinula galeata' and descrizione is null;
update specie set descrizione = 'The dusky moorhen is a bird species in the rail family and is one of the eight extant species in the moorhen genus. It occurs in Australia, New Guinea, Borneo and Indonesia. It is often confused with the purple swamphen and the Eurasian coot due to similar appearance and overlapping distributions. They often live alongside birds in the same genus, such as the Tasmanian nativehen and the common moorhen.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky_moorhen' where nome_scientifico = 'Gallinula tenebrosa' and descrizione is null;
