update specie set descrizione = 'The Chinese hwamei or melodious laughingthrush is a passerine bird of eastern Asia in the laughingthrush family Leiothrichidae. The name "hwamei" comes from its Chinese name huà méi, which means "painted eyebrow", referring to the distinctive marking around the bird''s eyes. The species is a popular cagebird because of its attractive song.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chinese_hwamei' where nome_scientifico = 'Garrulax canorus' and descrizione is null;
