update specie set descrizione = 'The white-necked laughingthrush is a species of bird in the family Leiothrichidae. It is found in Yunnan, Laos, Myanmar and Thailand. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-necked_laughingthrush' where nome_scientifico = 'Garrulax strepitans' and descrizione is null;
update specie set descrizione = 'The Taiwan hwamei is a passerine bird in the family Leiothrichidae. The species was first described by Robert Swinhoe in 1859. It is endemic to the island of Taiwan. It was formerly regarded as a subspecies of the Chinese hwamei but has since been split as a separate species. It is estimated to have diverged from the Chinese hwamei about 1.5 million years ago.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Taiwan_hwamei' where nome_scientifico = 'Garrulax taewanus' and descrizione is null;
update specie set descrizione = 'La ghiandaia è un uccello passeriforme appartenente alla famiglia dei Corvidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Garrulus_glandarius' where nome_scientifico = 'Garrulus glandarius' and descrizione is null;
