update specie set descrizione = 'Gastrophryne carolinensis, the eastern narrow-mouthed toad, is a species of microhylid frog. It is a relatively small, toad-like amphibian found in damp, shady habitats. The species is highly fossorial, and feeds primarily on ants. These North American microhylids are distinguished from true toads, and other anurans by their moist, smooth skin, their lack of eardrums or tympana, their distinguishable squat body shape, and the unique fold of skin superior to their eyes. It is found in the United States, from southern Maryland to the Florida Keys, west to Missouri, Arkansas and Texas. While not a true toad, it is so called because it is terrestrial.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gastrophryne_carolinensis' where nome_scientifico = 'Gastrophryne carolinensis' and descrizione is null;
update specie set descrizione = 'Gastrophryne olivacea, the Great Plains narrow-mouthed toad or western narrow-mouthed toad, is a species of microhylid frog found throughout much of the south-central United States from Nebraska south through Texas, and into northern Mexico. Though not a true toad, evidenced by the smooth, moist skin, its common name is due to its terrestrial habit.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gastrophryne_olivacea' where nome_scientifico = 'Gastrophryne olivacea' and descrizione is null;
update specie set descrizione = 'The yellow-billed loon, also known as the white-billed diver, is the largest member of the loon or diver family. Breeding adults have a black head, white underparts and a chequered black-and-white mantle. Non-breeding plumage is drabber with the chin and foreneck white. Its main distinguishing feature is the long straw-yellow bill, which, because the culmen is straight, appears slightly uptilted.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-billed_loon' where nome_scientifico = 'Gavia adamsii' and descrizione is null;
update specie set descrizione = 'The black-throated loon, also known as the Arctic loon and the black-throated diver, is a migratory aquatic bird found in the Northern Hemisphere, primarily breeding in freshwater lakes in northern Europe and Asia. It winters along sheltered, ice-free coasts of the north-east Atlantic Ocean and the eastern and western Pacific Ocean. This loon was first described by Carl Linnaeus in 1758 and has two subspecies. It was previously considered to be the same species as the Pacific loon, of which it is traditionally considered to be a sister species, although this is debated. In a study that used mitochondrial and nuclear intron DNA, the black-throated loon was found to be sister to a clade consisting of the Pacific loon and two sister species, the common loon and the yellow-billed loon.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_loon' where nome_scientifico = 'Gavia arctica' and descrizione is null;
update specie set descrizione = 'The common loon or great northern diver is a large member of the loon, or diver, family of birds. Breeding adults have a plumage that includes a broad black head and neck with a greenish, purplish, or bluish sheen, blackish or blackish-grey upperparts, and pure white underparts except some black on the undertail coverts and vent. Non-breeding adults are brownish with a dark neck and head marked with dark grey-brown. Their upperparts are dark brownish-grey with an unclear pattern of squares on the shoulders, and the underparts, lower face, chin, and throat are whitish. The sexes look alike, though males are significantly heavier than females. During the breeding season, loons live on lakes and other waterways in Canada, the northern United States, and southern parts of Greenland and Iceland. Small numbers breed on Svalbard and sporadically elsewhere in Arctic Eurasia. Common loons winter on both coasts of North America as far north as Newfoundland and Alaska, and as far south as Mexico, as well as on the Atlantic coast of Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_loon' where nome_scientifico = 'Gavia immer' and descrizione is null;
