update specie set descrizione = 'The singing honeyeater is a small bird found in Australia, and is part of the honeyeater family Meliphagidae. The bird lives in a wide range of shrubland, woodland, and coastal habitat. It is relatively common and is widespread right across Australia west of the Great Dividing Range, through to the west coast and on Western Australian coastal islands. It does not occur in other countries.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Singing_honeyeater' where nome_scientifico = 'Gavicalis virescens' and descrizione is null;
