update specie set descrizione = 'The ruddy quail-dove is a species of bird in the dove and pigeon family Columbidae. It breeds throughout the West Indies, Central America, and tropical South America. It has appeared as a vagrant in Florida and southern Texas. It lays two buff-colored eggs on a flimsy platform built on a shrub. Some nests are built on the ground.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ruddy_quail-dove' where nome_scientifico = 'Geotrygon montana' and descrizione is null;
