update specie set descrizione = 'The fan-tailed gerygone is a species of bird in the family Acanthizidae. It is found in New Caledonia and Vanuatu. The Rennell gerygone of the Solomon Islands was formerly considered conspecific, but was split as a distinct species by the IOC in 2021.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fan-tailed_gerygone' where nome_scientifico = 'Gerygone flavolateralis' and descrizione is null;
update specie set descrizione = 'The western gerygone is a small, brownish-grey species of passerine bird, which is found in inland and south-west Australia. It is an arboreal, insectivore of open forest, woodland and dry shrubland. It is not currently threatened with extinction.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_gerygone' where nome_scientifico = 'Gerygone fusca' and descrizione is null;
update specie set descrizione = 'The grey warbler, also known by its Māori name riroriro or outside New Zealand as the grey gerygone, is an insectivorous bird in the family Acanthizidae endemic to New Zealand. It is sometimes known as the rainbird. Its natural habitat is forests, but also tends to occupy lower vegetation habitats. These insectivorous birds feed on insects living in shrubs, and often feed on the wing. They are found throughout New Zealand, as well as offshore islands where shrub exists. They also flourish in suburban areas where there is vegetation present.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey_warbler' where nome_scientifico = 'Gerygone igata' and descrizione is null;
update specie set descrizione = 'The mangrove gerygone is a species of bird in the Australian warbler family Acanthizidae. The species is also known as the mangrove warbler. The species is thought to form a superspecies with the closely related fan-tailed gerygone of Melanesia and the Australian western gerygone. There are three subspecies of mangrove gerygone, G. l. pallida, found in southern New Guinea, the nominate race G. l. levigaster, which is found from coastal Western Australia to coastal north Queensland and is known as Buff-breasted Flyeater, and G. l. cantator, which is found from coastal Queensland to New South Wales. The species is uncommon in New Guinea and has suffered some declines due to mangrove clearances but is not considered threatened by the IUCN.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mangrove_gerygone' where nome_scientifico = 'Gerygone levigaster' and descrizione is null;
