update specie set descrizione = 'The Asian barred owlet, also known as the cuckoo owlet, is a species of pygmy owl native to the forests and shrublands of mainland Southeast Asia to the foothills of the Himalayas of northern Pakistan. It is a smaller owl, measuring 22–25 cm (8.7–9.8 in), making it one of the larger pygmy owls. They are primarily insectivorous but will eat lizards, small rodents and birds as well.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Asian_barred_owlet' where nome_scientifico = 'Glaucidium cuculoides' and descrizione is null;
