update specie set descrizione = 'The cloud-forest pygmy owl or cloudforest pygmy owl is a short, muscular, small-sized species of owl found throughout the Andes of western Colombia and north-western Ecuador, being confined to cloud forests between 900–2000 m a.s.l. Below this altitudinal range the Central American pygmy owl occurs; above it, the Andean pygmy owl occurs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cloud-forest_pygmy_owl' where nome_scientifico = 'Glaucidium nubicola' and descrizione is null;
