update specie set descrizione = 'The pearl-spotted owlet is a small bird of prey found in sub-Saharan Africa. They belong to the Strigidae family, otherwise known as the typical owls or the true owls, which contains most species of owl. As part of the genus Glaucidium, or pygmy owls, they are commonly referred to as ''owlets'' due to their diminutive size. Pearl-spotted owlets are brownish and heavily spotted white, with two distinct black false ''eyes'' at the back of their head. They are often confused with an African barred owlet.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pearl-spotted_owlet' where nome_scientifico = 'Glaucidium perlatum' and descrizione is null;
