update specie set descrizione = 'The giant antpitta is a perching bird species in the antpitta family (Grallariidae). Rare and somewhat enigmatic, it is known only from Colombia and Ecuador. It is presumably a close relative of the similar undulated antpitta, G. squamigera, which occurs to the south of G. gigantea. The giant antpitta has three subspecies, one of which might be extinct.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Giant_antpitta' where nome_scientifico = 'Grallaria gigantea' and descrizione is null;
