update specie set descrizione = 'The Urubamba antpitta is a bird in the family Grallariidae. The species was first described as a subspecies by Frank Chapman in 1923. It is endemic to Peru. It is a member of the rufous antpitta species complex and was elevated from subspecies to species in 2020 on the basis of differences in plumage and vocalization. The same study also described a new subspecies of Urubamba antpitta.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Urubamba_antpitta' where nome_scientifico = 'Grallaria occabambae' and descrizione is null;
