update specie set descrizione = 'The Muisca antpitta is a bird in the family Grallariidae. The species was first described by Frédéric de Lafresnaye in 1843. It was formerly called the rufous antpitta, which in 2020 was found to be a species complex composed of as many as 15 species, some of which were newly described. It is found in the Andes of northern Colombia and western Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Muisca_antpitta' where nome_scientifico = 'Grallaria rufula' and descrizione is null;
