update specie set descrizione = 'The Urrao antpitta, also known as Fenwick''s antpitta, is a highly threatened species of bird found in the understory of cloud forest in the Andean highlands of Colombia. The first published description used the scientific name Grallaria fenwickorum ; shortly afterward, a second description using the name Grallaria urraoensis was published. The editors of the latter recognized that the name likely was a junior synonym, but others have questioned the validity of the first description, and various authorities, including the International Ornithological Congress, have adopted G. urraoensis. Antioquia antpitta has been suggested as an English-language name compromise.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Urrao_antpitta' where nome_scientifico = 'Grallaria urraoensis' and descrizione is null;
