update specie set descrizione = 'The magpie-lark, also known as wee magpie, peewee, peewit, mudlark or Murray magpie, is a passerine bird native to Australia, Timor, and southern New Guinea. The male and female both have black and white plumage, though with different patterns. John Latham described the species in 1801. Long thought to be a member of the mudnest builder family Corcoracidae, it has been reclassified in the family Monarchidae. Two subspecies are recognized.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Magpie-lark' where nome_scientifico = 'Grallina cyanoleuca' and descrizione is null;
