update specie set descrizione = 'La gru americana è un uccello della famiglia dei Gruidi, originaria del Nordamerica; per il grido sonoro che emette viene chiamata anche gru urlatrice. In natura può vivere fino a 22 - 24 anni. Si stima che in libertà ne esistano meno di 400 esemplari.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Grus_americana' where nome_scientifico = 'Grus americana' and descrizione is null;
