update specie set descrizione = 'Gryllus assimilis, commonly known as the Jamaican field cricket and sometimes referred to as the silent cricket among other names, is one of many cricket species known as a field cricket. Its natural habitats are the West Indies and parts of the southern United States, Mexico, and South America, though as a result of widespread breeding programs to supply feeder insects to the pet industry since 2010, it has become available commercially throughout North America and Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gryllus_assimilis' where nome_scientifico = 'Gryllus assimilis' and descrizione is null;
update specie set descrizione = 'Gryllus fultoni, the southern wood cricket, is a species of cricket in the subfamily Gryllinae. It is found in North America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gryllus_fultoni' where nome_scientifico = 'Gryllus fultoni' and descrizione is null;
update specie set descrizione = 'Gryllus pennsylvanicus is known as the fall field cricket. G. pennsylvanicus is widespread across much of North America from southern Ontario into parts of northern Mexico. It tends to be absent in most of the southwestern United States including southern California. Within its geographic range this field cricket will burrow into soil in fields and forest edges. Individuals inhabit grassy disturbed areas and are often found around areas of human habitation.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gryllus_pennsylvanicus' where nome_scientifico = 'Gryllus pennsylvanicus' and descrizione is null;
update specie set descrizione = 'Gryllus rubens, commonly known as the southeastern field cricket, is one of many cricket species known as a field cricket. It occurs throughout most of the Southeastern United States. Its northern range spans from southern Delaware to the extreme southeastern corner of Kansas, with a southern range stretching from Florida to eastern Texas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gryllus_rubens' where nome_scientifico = 'Gryllus rubens' and descrizione is null;
