update specie set descrizione = 'The yellow-throated bush sparrow, also known as the yellow-throated petronia, is a species of bird in the sparrow family Passeridae. It is found in south-central and southern Africa in its natural habitats of subtropical or tropical dry forests, dry savanna, and subtropical or tropical dry shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_bush_sparrow' where nome_scientifico = 'Gymnoris superciliaris' and descrizione is null;
update specie set descrizione = 'The yellow-throated sparrow or chestnut-shouldered petronia is a species of sparrow found in southern Asia. It is a species mostly of the dry savannah. They forage on the ground for grain and for berries in bushes. They are often seen perched atop bare branches on trees while calling.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_sparrow' where nome_scientifico = 'Gymnoris xanthocollis' and descrizione is null;
