update specie set descrizione = 'Il grifone dell''Himalaya è un avvoltoio del Vecchio Mondo della famiglia degli Accipitridi. Strettamente imparentato con il grifone eurasiatico, tanto da essere un tempo considerato una sua sottospecie, è presente lungo tutta la catena dell''Himalaya e nell''altopiano tibetano a essa adiacente. È una delle due specie più grandi di avvoltoi del Vecchio Mondo, nonché della famiglia degli Accipitridi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Gyps_himalayensis' where nome_scientifico = 'Gyps himalayensis' and descrizione is null;
update specie set descrizione = 'The streaked wren-babbler is a species of bird in the family Pellorneidae.
It is found in Bangladesh, Cambodia, China, India, Laos, Malaysia, Myanmar, Thailand and Vietnam.
Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Streaked_wren-babbler' where nome_scientifico = 'Gypsophila brevicaudata' and descrizione is null;
