update specie set descrizione = 'The black-cheeked ant tanager is a species of bird in the family Cardinalidae. It is endemic to Costa Rica. It was formerly placed with the red-crowned ant tanager in the genus Habia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-cheeked_ant_tanager' where nome_scientifico = 'Habia atrimaxillaris' and descrizione is null;
update specie set descrizione = 'The crested ant tanager is a bird in the family Cardinalidae that is endemic to Colombia. It was formerly placed with the red-crowned ant tanager in the genus Habia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crested_ant_tanager' where nome_scientifico = 'Habia cristata' and descrizione is null;
update specie set descrizione = 'The red-throated ant tanager is a medium-sized passerine bird. This species is a resident breeder on the Caribbean slopes from southeastern Mexico to eastern Panama. It was formerly placed with the red-crowned ant tanager in the genus Habia. It was usually considered an aberrant kind of tanager and placed in the Thraupidae, but is actually closer to the cardinals (Cardinalidae). Consequently, it can be argued that referring to the members of this genus as ant tanagers is misleading, but no other common name has gained usage.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-throated_ant_tanager' where nome_scientifico = 'Habia fuscicauda' and descrizione is null;
update specie set descrizione = 'The sooty ant tanager is a species of bird in the cardinal family (Cardinalidae). It was formerly placed with the true tanagers in the family Thraupidae and was assigned to the genus Habia with the red-crowned ant tanager.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sooty_ant_tanager' where nome_scientifico = 'Habia gutturalis' and descrizione is null;
update specie set descrizione = 'The red-crowned ant tanager is a medium-sized passerine bird from tropical America. It is the only species now placed in the genus Habia. This species was long placed with the tanagers (Thraupidae), but it is actually closer to the cardinals (Cardinalidae).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-crowned_ant_tanager' where nome_scientifico = 'Habia rubica' and descrizione is null;
