update specie set descrizione = 'The crimson-headed partridge is a species of bird in the pheasant, partridge, and francolin family Phasianidae. Described by the British ornithologist Richard Bowdler Sharpe in 1879, it is the only species in the genus Haematortyx. It is endemic to Borneo, where it inhabits lower montane forest in the northern and central parts of the island. It is mainly found at elevations of 1,000–1,700 m (3,300–5,600 ft), but can be seen as low as 185 m (607 ft) and as high as 3,050 m (10,010 ft). Adult males have a striking appearance, with a dark blackish body and crimson red heads, necks, breasts, and undertail coverts. Females have a similar pattern, but with duller brownish-black colouration, orangish-red heads and breasts, and a brownish-black bill instead of a yellowish one. Juveniles are duller and have the crimson restricted to the top of the head.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-headed_partridge' where nome_scientifico = 'Haematortyx sanguiniceps' and descrizione is null;
update specie set descrizione = 'The house finch is a North American bird in the finch family. It is native to Mexico and southwestern United States, but has since been introduced to the eastern part of North America and Hawaiʻi; it is now found year-round in almost all parts of the United States and most of Mexico, with breeding grounds well into Canada as far north as northern Alberta. There are estimated to be 40 million house finches across North America, making it the second-most populous finch, just behind the American goldfinch. The house finch and the other two American rosefinches are placed in the genus Haemorhous.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/House_finch' where nome_scientifico = 'Haemorhous mexicanus' and descrizione is null;
