update specie set descrizione = 'The grey-headed kingfisher is a species of bird in the kingfisher family, Alcedinidae. It is found across large parts of Africa and southern Arabia, from Mauritania through Senegal and the Gambia, east to Ethiopia, Somalia, Yemen, Oman and Saudi Arabia, and south all the way through to South Africa. It is also found in islands off the African coast such as the Cape Verde islands and Zanzibar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-headed_kingfisher' where nome_scientifico = 'Halcyon leucocephala' and descrizione is null;
