update specie set descrizione = 'L''aquila di mare o aquila di mare codabianca, talvolta nota come "aquila di mare", è un grande rapace, ampiamente diffuso nell''Eurasia temperata. Come altre aquile, è un membro della famiglia Accipitridae che comprende anche altri rapaci diurni come poiane, nibbi e albanelle. È uno degli undici membri del genere Haliaeetus, comunemente chiamati aquile di mare. È anche conosciuta con i nomi anglosassoni ern o erne, aquila di mare grigia e aquila di mare eurasiatica.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Haliaeetus_albicilla' where nome_scientifico = 'Haliaeetus albicilla' and descrizione is null;
update specie set descrizione = 'L''aquila pescatrice minore è un uccello rapace della famiglia degli Accipitridi originario dell''intera regione orientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Icthyophaga_humilis' where nome_scientifico = 'Haliaeetus humilis' and descrizione is null;
update specie set descrizione = 'L''aquila pescatrice testagrigia è un uccello rapace della famiglia degli Accipitridi originario dell''intera regione orientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Icthyophaga_ichthyaetus' where nome_scientifico = 'Haliaeetus ichthyaetus' and descrizione is null;
update specie set descrizione = 'L''aquila di mare testabianca, detta anche erroneamente "aquila calva" dalla traduzione del termine inglese bald, è un rapace della famiglia Accipitridae, diffuso in America settentrionale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Haliaeetus_leucocephalus' where nome_scientifico = 'Haliaeetus leucocephalus' and descrizione is null;
update specie set descrizione = 'L''aquila pescatrice panciabianca è un uccello rapace diurno della famiglia Accipitridae, diffuso in Asia e Oceania. Descritta originariamente da Johann Friedrich Gmelin nel 1788, è strettamente imparentata con l''aquila pescatrice di Sanford delle isole Salomone, tant''è che le due sono considerate una superspecie.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Icthyophaga_leucogaster' where nome_scientifico = 'Haliaeetus leucogaster' and descrizione is null;
update specie set descrizione = 'L''aquila urlatrice è un uccello rapace della famiglia degli Accipitridi originario dell''Africa subsahariana.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Icthyophaga_vocifer' where nome_scientifico = 'Haliaeetus vocifer' and descrizione is null;
update specie set descrizione = 'The brahminy kite, also known as the red-backed sea-eagle in India, is a medium-sized bird of prey in the family Accipitridae, which also includes many other diurnal raptors, such as eagles, buzzards, and harriers, found in the Indian subcontinent, Southeast Asia, and Australia. The brahminy kite is found mainly on the coast and in inland wetlands, where it feeds on dead fish and other prey. Adults have a reddish-brown body plumage contrasting with their white head and breast which make them easy to distinguish from other birds of prey.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brahminy_kite' where nome_scientifico = 'Haliastur indus' and descrizione is null;
update specie set descrizione = 'Il nibbio fischiatore è un uccello rapace di grandi dimensioni presente nel territorio dell''Australasia. Appartiene alla famiglia degli Accipitridae e viene anche chiamato aquila fischiatrice o falco fischiatore.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Haliastur_sphenurus' where nome_scientifico = 'Haliastur sphenurus' and descrizione is null;
update specie set descrizione = 'The yellow-breasted crake is a species of bird in the subfamily Rallinae of family Rallidae, the rails, gallinules, and coots. It is found on several Caribbean islands and in most of Central America and South America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-breasted_crake' where nome_scientifico = 'Hapalocrex flaviventer' and descrizione is null;
update specie set descrizione = 'Il pappagallo facciaruggine è un uccello della famiglia degli Psittacidi. Di taglia attorno ai 23 cm, ha piumaggio base verde intenso, spalla rossa, remiganti blu, timoniere rosse con parte apicale rossa. Il becco è giallastro, l''occhio cerchiato di azzurro con iride gialla chiara, le zampe grigie. Sono state classificate tre sottospecie caratterizzate per la diversa colorazione del capo:H. a. amazonina, sottospecie nominale, con corona, fronte e guance rosse sfumate in color ruggine, zona tra becco e occhio gialla, qualche «pagliuzza» giallo oro sull''orecchio;
H. a. velezi, con il rosso ridotto alla corona e al bordo del becco;
H. a. theresae, con la maschera facciale color ruggine molto ampia e con il rosso presente solo all''attaccatura del becco.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Hapalopsittaca_amazonina' where nome_scientifico = 'Hapalopsittaca amazonina' and descrizione is null;
update specie set descrizione = 'Il pappagallo alindaco è un uccello della famiglia degli Psittacidi. Rarissimo, è endemico delle pendici di un vulcano sulle Ande colombiane. Visto l''ultima volta nel 1911 dal personale dell''American Museum of Natural History che si occupava di procurare esemplari, il pappagallo alindaco non fu mai fotografato, fino al 28 luglio 2002. A quella data, i ricercatori Jorge Velasquez e Alonso Quevedo rimasero attoniti nel vedere uno stormo di quattordici di questi uccelli dalle lunghe zampe scendere a spirale dagli alberi per posarsi al suolo vicino a loro. Essi presero appunti, scattarono fotografie e girarono filmati per documentare la loro notevole scoperta. Conosciuto localmente come loro multicolor, il pappagallo alindaco è verde, con ali di color indaco, spalle rosse, sommo della testa blu e una macchia di color castagna alla base del becco, di un avorio pallido. Non essendo stato visto da molto tempo, questo pappagallo era considerato estinto. Una regola empirica, non necessariamente valida, è quella di considerare estinta una specie se non è stata vista da cinquant''anni, ma questa norma non tiene conto delle inaccessibili foreste coperte di nuvole della Colombia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Hapalopsittaca_fuertesi' where nome_scientifico = 'Hapalopsittaca fuertesi' and descrizione is null;
update specie set descrizione = 'La monaca facciabianca è un uccello piciforme della famiglia Bucconidae. È l''unica specie del genere Hapaloptila.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Hapaloptila_castanea' where nome_scientifico = 'Hapaloptila castanea' and descrizione is null;
update specie set descrizione = 'The greenish puffleg is a species of hummingbird in the "brilliants", tribe Heliantheini in subfamily Lesbiinae. It is found in Colombia, Ecuador, Panama, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greenish_puffleg' where nome_scientifico = 'Haplophaedia aureliae' and descrizione is null;
update specie set descrizione = 'The uniform finch is a species of bird in the family Thraupidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Uniform_finch' where nome_scientifico = 'Haplospiza unicolor' and descrizione is null;
update specie set descrizione = 'The Philippine trogon is a species of bird in the family Trogonidae. It is endemic to the Philippines found on regions of Luzon, Eastern Visayas, and Mindanao. It is the only species of trogon in the country. While not a threatened species, its population is declining due to habitat loss and hunting.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Philippine_trogon' where nome_scientifico = 'Harpactes ardens' and descrizione is null;
update specie set descrizione = 'The scarlet-rumped trogon is a species of bird in the family Trogonidae. It has also been called the red-rumped trogon and Duvaucel''s trogon. It is distinguishable from other trogons by its small size and reddish rump. This species is generally solitary except mating and raising young, which is done in pairs. It is found within certain lowland forests of Indonesia, Malaysia, Myanmar, and Thailand. It is currently considered near threatened by Red List Assessments due to habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet-rumped_trogon' where nome_scientifico = 'Harpactes duvaucelii' and descrizione is null;
update specie set descrizione = 'The red-headed trogon is a species of bird in the family Trogonidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-headed_trogon' where nome_scientifico = 'Harpactes erythrocephalus' and descrizione is null;
update specie set descrizione = 'The Malabar trogon is a species of bird in the trogon family. It is found in the forests of India and Sri Lanka. In India, it is mainly found in the Western Ghats, hill forests of central India and in parts of the Eastern Ghats. They are insectivorous and although not migratory, may move seasonally in response to rain in hill forest regions. Like in other trogons, males and females vary in plumage. The birds utter low, guttural calls that can be heard only at close quarters, and perch still on a branch under the forest canopy, often facing away from the viewer, making them easy to miss despite their colourful plumage.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Malabar_trogon' where nome_scientifico = 'Harpactes fasciatus' and descrizione is null;
update specie set descrizione = 'The red-naped trogon is a species of bird in the family Trogonidae. It is found in Brunei, Indonesia, Malaysia, and Thailand. Its natural habitat is subtropical or tropical moist lowland forests. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-naped_trogon' where nome_scientifico = 'Harpactes kasumba' and descrizione is null;
update specie set descrizione = 'The orange-breasted trogon is a species of bird in the family Trogonidae. It is a colorful, sedentary species that inhabits the lower canopy of the lowlands and forest of southern China, southeast Asia, Borneo, Sumatra and Java.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-breasted_trogon' where nome_scientifico = 'Harpactes oreskios' and descrizione is null;
