update specie set descrizione = 'The heart-spotted woodpecker is a species of bird in the woodpecker family. It has a contrasting black and white plumage, a distinctively stubby body and a large wedge-shaped head making it easy to identify while its frequent calling make it easy to detect as it forage for invertebrates under the bark of the slender outer branches of trees. They move about in pairs or small groups and are often found in mixed-species foraging flocks. They have a wide distribution across Asia with populations in the forests of southwestern and central India which are slightly separated from their ranges in the Himalayas and Southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Heart-spotted_woodpecker' where nome_scientifico = 'Hemicircus canente' and descrizione is null;
update specie set descrizione = 'The grey-and-buff woodpecker is a species of bird in the family Picidae. It is found in Brunei, Indonesia, Malaysia, southern Myanmar, and southern Thailand, but has become regionally extinct in Singapore. Its natural habitats are lowland and montane tropical or subtropical moist broadleaf forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-and-buff_woodpecker' where nome_scientifico = 'Hemicircus concretus' and descrizione is null;
