update specie set descrizione = 'The pheasant-tailed jacana is a jacana in the monotypic genus Hydrophasianus. Like all other jacanas, they have elongated toes and nails that enable them to walk on floating vegetation in shallow lakes, their preferred habitat. They may also swim or wade in water reaching their body while foraging mainly for invertebrate prey. They are found in tropical Asia from Yemen in the west to the Philippines in the east and move seasonally in parts of their range. They are the only jacanas that migrate long distances and have different non-breeding and breeding plumages. The pheasant-tailed jacana forages by swimming or by walking on aquatic vegetation. Females are larger than males and are polyandrous, laying several clutches that are raised by different males in their harem.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pheasant-tailed_jacana' where nome_scientifico = 'Hydrophasianus chirurgus' and descrizione is null;
