update specie set descrizione = 'The yellowish bulbul is a species of songbird in the bulbul family, Pycnonotidae. It is endemic to the Philippines found only on East Visayas, Mindanao and the Sulu Archipelago. The birds of the Sulu archipelago are sometimes considered a separate species called the Sulu bulbul. This species is declining due to habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellowish_bulbul' where nome_scientifico = 'Hypsipetes everetti' and descrizione is null;
update specie set descrizione = 'The square-tailed bulbul is a species of songbird in the bulbul family, Pycnonotidae.
It is found in south-western India and Sri Lanka. Its natural habitat is subtropical or tropical moist montane forests. It was previously classified as a subspecies of the black bulbul.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Square-tailed_bulbul' where nome_scientifico = 'Hypsipetes ganeesa' and descrizione is null;
update specie set descrizione = 'The black bulbul, also known as the Himalayan black bulbul or Asian black bulbul, is a member of the bulbul family of passerine birds. It is found primarily in the Himalayas, its range stretching from Pakistan eastward to Southeast Asia. It is the type species of the genus Hypsipetes, established by Nicholas Aylward Vigors in the early 1830s. There are a number of subspecies, mostly varying in the shade of the body plumage which ranges from grey to black, and some also occur in white-headed morphs, as also suggested by its specific epithet leucocephalus, literally "white head". The legs and bill are always rich orange-red.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_bulbul' where nome_scientifico = 'Hypsipetes leucocephalus' and descrizione is null;
