update specie set descrizione = 'The black-backed oriole is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is endemic to Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-backed_oriole' where nome_scientifico = 'Icterus abeillei' and descrizione is null;
update specie set descrizione = 'The orange oriole is a small bird species with orange feathers native to the Icteridae family in the Yucatán Peninsula. It has a slender body, long wings, and a pointed beak. Its color resembles the fruit orange, and it has black markings on its wings and tail. The orange oriole is known for its song and can be found in forests and gardens. They have a diverse diet that contributes to their color. According to The Cornell Lab of Ornithology Birds of the World, they have suggested that this species might be better named the "Yucatan Oriole" because they are only found in Southeast Mexico. This species is not endangered and least threatened.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange_oriole' where nome_scientifico = 'Icterus auratus' and descrizione is null;
update specie set descrizione = 'The orange-crowned oriole is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Colombia, Panama, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-crowned_oriole' where nome_scientifico = 'Icterus auricapillus' and descrizione is null;
