update specie set descrizione = 'The orange-backed troupial is a species of bird in the family Icteridae. It is found in Guyana, Brazil, Paraguay, and eastern Ecuador, Bolivia, and Peru. It is closely related to the Venezuelan troupial and Campo troupial, and at one time, all three were considered to be the same species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-backed_troupial' where nome_scientifico = 'Icterus croconotus' and descrizione is null;
update specie set descrizione = 'The hooded oriole is a medium-sized New World oriole. The male of this species ranges in color from a bright orange to a paler yellow, with a black back, face, tail and bib, with the wing containing two white bars. The female is more of an olive color with some yellow accents.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hooded_oriole' where nome_scientifico = 'Icterus cucullatus' and descrizione is null;
