update specie set descrizione = 'The white-edged oriole is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Ecuador and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-edged_oriole' where nome_scientifico = 'Icterus graceannae' and descrizione is null;
update specie set descrizione = 'The Altamira oriole is a New World oriole. The bird is widespread in subtropical lowlands of the Mexican Gulf Coast and northern Central America, the Pacific coast and inland. They have since spread to southern Texas, but this was not until 1939.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Altamira_oriole' where nome_scientifico = 'Icterus gularis' and descrizione is null;
update specie set descrizione = 'Il trupiale del Venezuela è un uccello passeriforme della famiglia Icteridae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Icterus_icterus' where nome_scientifico = 'Icterus icterus' and descrizione is null;
update specie set descrizione = 'The campo troupial or campo oriole is a species of bird in the family Icteridae that is found in northeastern Brazil. At one time thought to be conspecific with the Venezuelan troupial and orange-backed troupial, it is now accepted as a separate species. It is a fairly common bird and the International Union for Conservation of Nature has rated it as a "least-concern species".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Campo_troupial' where nome_scientifico = 'Icterus jamacaii' and descrizione is null;
update specie set descrizione = 'The Jamaican oriole is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Jamaica and on the Colombian island of San Andrés.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Jamaican_oriole' where nome_scientifico = 'Icterus leucopteryx' and descrizione is null;
update specie set descrizione = 'The yellow-tailed oriole is a passerine bird in the New World family Icteridae. It breeds from southern Mexico to western Peru and northwestern Venezuela; in Peru it also lives in a river valley corridor.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-tailed_oriole' where nome_scientifico = 'Icterus mesomelas' and descrizione is null;
update specie set descrizione = 'The yellow oriole is a passerine bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Aruba, Bonaire, Brazil, Colombia, Curaçao, French Guiana, Guyana, Suriname, Trinidad, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow_oriole' where nome_scientifico = 'Icterus nigrogularis' and descrizione is null;
update specie set descrizione = 'The spot-breasted oriole is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found from Mexico to Costa Rica. It also has an introduced population in southern Florida.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spot-breasted_oriole' where nome_scientifico = 'Icterus pectoralis' and descrizione is null;
update specie set descrizione = 'The Puerto Rican oriole, or calandria is a species of bird in the family Icteridae, and genus Icterus or New World blackbirds. This species is a part of a subgroup of orioles that includes the North American orchard oriole, Icterus spurius, and the hooded oriole, Icterus cucullatus.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Puerto_Rican_oriole' where nome_scientifico = 'Icterus portoricensis' and descrizione is null;
update specie set descrizione = 'The black-cowled oriole is a species of bird in the family Icteridae. It is common and widespread in the Caribbean lowlands and foothills from southern Mexico to western Panama. It lives primarily in humid or semihumid forest, as well as in clearings, along forest edges, in plantations, in semi-open areas with scattered trees and bushes, and in gardens. The adult male is black, with yellow on the belly, shoulder, rump, wing lining, and crissum. The female''s plumage varies depending on location. In the south of its range, it is similar to that of the male. In the north, its crown and upperparts are olive-yellow, while its face, throat, upper breast, wings, and tail are black.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-cowled_oriole' where nome_scientifico = 'Icterus prosthemelas' and descrizione is null;
update specie set descrizione = 'The streak-backed oriole is a medium-sized species of passerine bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Mexico, in Central America from Guatemala to Costa Rica, and occasionally in the United States.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Streak-backed_oriole' where nome_scientifico = 'Icterus pustulatus' and descrizione is null;
update specie set descrizione = 'The variable oriole is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Argentina, Bolivia, Brazil, Paraguay, and Uruguay and as a vagrant to Chile.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Variable_oriole' where nome_scientifico = 'Icterus pyrrhopterus' and descrizione is null;
update specie set descrizione = 'The orchard oriole is the smallest species of icterid. The subspecies of the Caribbean coast of Mexico, I. s. fuertesi, is sometimes considered a separate species, the ochre oriole or Fuertes''s oriole.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orchard_oriole' where nome_scientifico = 'Icterus spurius' and descrizione is null;
update specie set descrizione = 'The black-vented oriole is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds.. It is found in El Salvador, Guatemala, Honduras, Mexico, and Nicaragua and has reached the United States as a vagrant.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-vented_oriole' where nome_scientifico = 'Icterus wagleri' and descrizione is null;
update specie set descrizione = 'The black eagle is a bird of prey. Like all eagles, it is in the family Accipitridae, and it is the only member of the genus Ictinaetus. It soars over forests in the hilly regions of tropical and subtropical South and Southeast Asia, as well as southeastern China, hunting mammals and birds, particularly at their nests. It is easily identified by its widely splayed and long primary "fingers", the characteristic silhouette, slow flight and yellow ceres and legs that contrast with the dark feathers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_eagle' where nome_scientifico = 'Ictinaetus malaiensis' and descrizione is null;
update specie set descrizione = 'The Mississippi kite is a small bird of prey in the family Accipitridae. Mississippi kites have narrow, pointed wings and are graceful in flight, often appearing to float in the air. It is common to see several circling in the same area.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mississippi_kite' where nome_scientifico = 'Ictinia mississippiensis' and descrizione is null;
update specie set descrizione = 'The plumbeous kite is a bird of prey in the family Accipitridae that is resident in much of northern South America. It is migratory in the northern part of its range which extends north to Mexico. It feeds on insects which it catches either from a perch or while in flight.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plumbeous_kite' where nome_scientifico = 'Ictinia plumbea' and descrizione is null;
update specie set descrizione = 'The booted warbler is a species of passerine bird belonging to the family Acrocephalidae, the reed and tree warblers. This species breeds in Eastern Europe and western Asia, wintering in south Asia. it is a regular vagrant to Western Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Booted_warbler' where nome_scientifico = 'Iduna caligata' and descrizione is null;
update specie set descrizione = 'The African yellow warbler, also known as Natal yellow warbler, dark-capped yellow warbler or yellow flycatcher-warbler, is a species of Acrocephalidae warblers; formerly, these were placed in the paraphyletic "Old World warblers".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_yellow_warbler' where nome_scientifico = 'Iduna natalensis' and descrizione is null;
update specie set descrizione = 'The western olivaceous warbler, also known as the isabelline warbler, is a "warbler", formerly placed in the Old World warblers when these were a paraphyletic wastebin taxon. It is now considered a member of the acrocephaline warblers, Acrocephalidae, in the tree warbler genus Iduna. It was formerly regarded as part of a wider "olivaceous warbler" species, but as a result of modern taxonomic developments, this species is now usually considered distinct from the eastern olivaceous warbler, Iduna pallida.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_olivaceous_warbler' where nome_scientifico = 'Iduna opaca' and descrizione is null;
update specie set descrizione = 'The eastern olivaceous warbler, known simply as the olivaceous warbler when its western relative is referred to as the ''isabelline warbler'', is a small passerine bird with drab plumage tones, that is native to the Old World. For the most part it breeds in southeastern Europe, the Middle East and adjacent western Asia, and winters in the northern Afrotropics.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_olivaceous_warbler' where nome_scientifico = 'Iduna pallida' and descrizione is null;
update specie set descrizione = 'The Mountain yellow warbler is a medium sized bird with a mix of olive and yellow coloration. This bird is native to the eastern Afromontane. It normally feeds on flies but sometimes on remaining crops from harvests. An easy way to recognize this bird is with its whistle-tone vocalizations. The Mountain yellow warbler has a conservation status of Least Concern. This bird is a species of Acrocephalidae warbler; formerly, these were placed in the paraphyletic "Old World warblers".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mountain_yellow_warbler' where nome_scientifico = 'Iduna similis' and descrizione is null;
update specie set descrizione = 'L’ifrita di Kowald è un uccello passeriforme endemico della Nuova Guinea. È l''unica specie del genere Ifrita e della famiglia Ifritidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ifrita_kowaldi' where nome_scientifico = 'Ifrita kowaldi' and descrizione is null;
update specie set descrizione = 'The pin-tailed manakin is a suboscine species of bird within the manakin family, Pipridae. This species is endemic to the Eastern coast of Brazil within the humid Atlantic Forest, and its range extends from the State of Bahia to the State of Rio Grande Do Sul. The pin-tailed manakin is monotypic within the genus Ilicura, and has no known subspecies. It is a relatively small species that has pronounced sexual dimorphism. Male birds of this species have a bright white neck, chest, auriculars, and flanks. They have black and dark-green wings, with a signature pin shape tail that has a small fork near the tip, helping to give it its common name in English. The males are most easily identified by their characteristically vibrant red fore-crown and rump. The females of this species are a muted green, except for their neck and auriculars—which are light grey, and their cream-colored chest. Both male and female birds of this species share a slightly elongated head shape that gives them a distinguished raised forehead. The pin-tailed manakin''s vocalizations are quiet, but resemble a high-pitched "see-see-see" in descending tones.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pin-tailed_manakin' where nome_scientifico = 'Ilicura militaris' and descrizione is null;
update specie set descrizione = 'The scaly-breasted illadopsis is a species of bird in the family Pellorneidae. It is widespread throughout the Congo Basin, with a few isolated pockets in northern Angola, Uganda and South Sudan. Its natural habitat is subtropical or tropical moist lowland forest, specifically in the understory and lower levels.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scaly-breasted_illadopsis' where nome_scientifico = 'Illadopsis albipectus' and descrizione is null;
update specie set descrizione = 'The blackcap illadopsis is a species of bird in the family Pellorneidae. It is native to areas surrounding the Gulf of Guinea. Its natural habitat is subtropical or tropical moist lowland forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blackcap_illadopsis' where nome_scientifico = 'Illadopsis cleaveri' and descrizione is null;
update specie set descrizione = 'The brown illadopsis or brown thrush-babbler, is a species of bird in the family Pellorneidae. The species was first described by John Cassin in 1859. It is widely spread throughout the African tropical rainforest. Its natural habitats are subtropical or tropical dry forests and subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_illadopsis' where nome_scientifico = 'Illadopsis fulvescens' and descrizione is null;
update specie set descrizione = 'The mountain illadopsis is a species of bird in the family Pellorneidae. It is found in the Albertine Rift montane forests, Kenya, northern Malawi and western Tanzania. Its natural habitats are subtropical or tropical dry forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mountain_illadopsis' where nome_scientifico = 'Illadopsis pyrrhoptera' and descrizione is null;
update specie set descrizione = 'The pale-breasted illadopsis is a species of bird in the family Pellorneidae. It is found throughout the African tropical rainforest. The Tanzanian illadopsis was formerly considered a subspecies. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale-breasted_illadopsis' where nome_scientifico = 'Illadopsis rufipennis' and descrizione is null;
update specie set descrizione = 'The buff-bridled Inca finch is a species of bird in the family Thraupidae. It is endemic to Peru where its natural habitats are subtropical or tropical dry forests and subtropical or tropical high-altitude shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buff-bridled_Inca_finch' where nome_scientifico = 'Incaspiza laeta' and descrizione is null;
