update specie set descrizione = 'L''indicatore golanera o indicatore maggiore è un uccello piciforme appartenente alla famiglia Indicatoridae, diffuso nell''Africa subsahariana.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Indicator_indicator' where nome_scientifico = 'Indicator indicator' and descrizione is null;
update specie set descrizione = 'The lesser honeyguide is a species of bird in the family Indicatoridae that is widely distributed across sub-Saharan Africa. Like other honeyguides, it is a brood parasite that lays eggs most commonly in the nests of African barbets, but will also occasionally use the nests of other birds as well, such as starlings and woodpeckers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_honeyguide' where nome_scientifico = 'Indicator minor' and descrizione is null;
update specie set descrizione = 'The scaly-throated honeyguide is a species of bird in the family Indicatoridae. They have a mutualistic relationship with humans in which they attract beekeepers towards bees'' nests and then feeding on the remains, especially larvae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scaly-throated_honeyguide' where nome_scientifico = 'Indicator variegatus' and descrizione is null;
