update specie set descrizione = 'The buff-throated purpletuft is a small Endangered species of bird in the family Tityridae, the tityras, becards, and allies. It is endemic to Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buff-throated_purpletuft' where nome_scientifico = 'Iodopleura pipra' and descrizione is null;
update specie set descrizione = 'The buff-vented bulbul is a species of songbird in the bulbul family, Pycnonotidae.
It is found in south-eastern Myanmar, south-western Thailand, on the Malay Peninsula, Sumatra and nearby islands.
Its natural habitat is subtropical or tropical moist lowland forests.
It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buff-vented_bulbul' where nome_scientifico = 'Iole crypta' and descrizione is null;
update specie set descrizione = 'The  yellow-browed bulbul, or golden-browed bulbul, is a species of songbird in the bulbul family, Pycnonotidae. It is found in the forests of southern India and Sri Lanka. The yellow-browed bulbul is mainly yellow on the underside and olive above with a distinct yellow brow. They are easily located by their loud calls but tend to skulk within foliage below the forest canopy. While its taxonomic classification has changed over time, it is currently the sole species within the monotypic genus Acritillas which is closely related to Hemixos.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-browed_bulbul' where nome_scientifico = 'Iole indica' and descrizione is null;
update specie set descrizione = 'The grey-eyed bulbul is a species of songbird in the bulbul family, Pycnonotidae.
It is found in Southeast Asia in its natural habitat of subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-eyed_bulbul' where nome_scientifico = 'Iole propinqua' and descrizione is null;
update specie set descrizione = 'The olive bulbul is a species of songbird in the bulbul family, Pycnonotidae.
