update specie set descrizione = 'The varied triller like its better-known relative the white-winged triller, is a smaller member of the cuckoo-shrike family, Campephagidae. Varied trillers prefer warm, reasonably moist environments and are found in New Guinea and the Bismarck Archipelago, along much of the tropical and sub-tropical coastal hinterland of eastern Australia, from about the Sydney area to the tip of Cape York Peninsula, in the moister part of the Kimberley, and throughout the Top End.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Varied_triller' where nome_scientifico = 'Lalage leucomela' and descrizione is null;
update specie set descrizione = 'The long-tailed triller is a species of bird in the family Campephagidae. It is found in New Caledonia, Solomon Islands, and Vanuatu. The Norfolk Island subspecies of the long-tailed triller, the Norfolk triller, has become extinct. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-tailed_triller' where nome_scientifico = 'Lalage leucopyga' and descrizione is null;
