update specie set descrizione = 'The black-winged cuckooshrike, also known as lesser grey cuckooshrike or dark grey cuckooshrike, is a species of cuckooshrike found in South to Southeast Asia. Despite the name, they (cuckooshrikes) are unrelated to either shrikes or cuckoos. They have broad based bills with grey upper parts, black wings, white vent, graduated white-tipped tails, black bills and legs. Females are overall lighter in all taxa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-winged_cuckooshrike' where nome_scientifico = 'Lalage melaschistos' and descrizione is null;
