update specie set descrizione = 'The white-winged triller is one of the smaller members of the cuckooshrike family, Campephagidae. It is found throughout mainland Australia and possibly on the islands to the north, including New Guinea and eastern Indonesia. It is resident or nomadic over the warmer part of its range, and a summer breeding migrant to the cooler southern parts of Australia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-winged_triller' where nome_scientifico = 'Lalage tricolor' and descrizione is null;
