update specie set descrizione = 'The green-throated mountaingem or green-throated mountain-gem is a species of hummingbird in tribe Lampornithini of subfamily Trochilinae. It is found in El Salvador, Guatemala, Honduras, and Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-throated_mountaingem' where nome_scientifico = 'Lampornis viridipallens' and descrizione is null;
update specie set descrizione = 'The velvet-fronted grackle is a species of bird in the family Icteridae, monotypic within the genus Lampropsar. It is found in Bolivia, Brazil, Colombia, Ecuador, Guyana, Peru, and Venezuela where its natural habitats are subtropical or tropical swamps and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Velvet-fronted_grackle' where nome_scientifico = 'Lampropsar tanagrinus' and descrizione is null;
update specie set descrizione = 'The red-billed pied tanager is a species of bird in the family Mitrospingidae. It is found in Bolivia, Brazil, French Guiana, Guyana, Peru and Suriname. Placed in family Thraupidae, the "true" tanagers, for over two centuries, the International Ornithological Committee reclassified this species to Mitrospingidae in 2018.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-billed_pied_tanager' where nome_scientifico = 'Lamprospiza melanoleuca' and descrizione is null;
update specie set descrizione = 'The pied starling or African pied starling is a bird endemic to South Africa, Lesotho and Eswatini. It is common in most of its range, but largely absent from the arid northwest and the eastern lowlands of South Africa. It is found in open habitats such as grassland, karoo scrub, thornbush and agricultural land, and often associates with farm animals.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pied_starling' where nome_scientifico = 'Lamprotornis bicolor' and descrizione is null;
update specie set descrizione = 'The long-tailed glossy starling is a member of the starling family of birds. It is a resident breeder in tropical Africa from Senegal east to Sudan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-tailed_glossy_starling' where nome_scientifico = 'Lamprotornis caudatus' and descrizione is null;
update specie set descrizione = 'The greater blue-eared starling or greater blue-eared glossy-starling is a bird that breeds from Senegal east to Ethiopia and south through eastern Africa to northeastern South Africa and Angola. It is a very common species of open woodland bird, and undertakes some seasonal migration.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greater_blue-eared_starling' where nome_scientifico = 'Lamprotornis chalybaeus' and descrizione is null;
update specie set descrizione = 'The lesser blue-eared starling or lesser blue-eared glossy-starling is a species of starling in the family Sturnidae.
It is found in Benin, Burkina Faso, Burundi, Cameroon, the Central African Republic, Chad, the Democratic Republic of the Congo, Eritrea, Ethiopia, Gambia, Ghana, Guinea, Guinea-Bissau, Ivory Coast, Kenya, Liberia, Malawi, Malaysia, Mali, Mozambique, Namibia, Nigeria, Senegal, Sierra Leone, South Sudan, Sudan, Tanzania, Togo, Uganda, Zambia, and Zimbabwe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_blue-eared_starling' where nome_scientifico = 'Lamprotornis chloropterus' and descrizione is null;
update specie set descrizione = 'Lo storno splendente del Capo è un uccello passeriforme della famiglia Sturnidae, diffuso in Africa australe.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lamprotornis_nitens' where nome_scientifico = 'Lamprotornis nitens' and descrizione is null;
update specie set descrizione = 'The splendid starling, also known as the splendid glossy-starling, is a species of starling in the family Sturnidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Splendid_starling' where nome_scientifico = 'Lamprotornis splendidus' and descrizione is null;
update specie set descrizione = 'Lo storno superbo è un uccello della famiglia degli Sturnidi, diffuso in Africa.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lamprotornis_superbus' where nome_scientifico = 'Lamprotornis superbus' and descrizione is null;
update specie set descrizione = 'The ashy starling is a species of starling in the family Sturnidae. It is found in Kenya and Tanzania. It is alternatively placed in the genus Cosmopsarus or Spreo.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ashy_starling' where nome_scientifico = 'Lamprotornis unicolor' and descrizione is null;
update specie set descrizione = 'The Ethiopian boubou is a species of bird in the family Malaconotidae.
It is found in Eritrea, Ethiopia, northwest Somalia, and northern Kenya. Its natural habitat is moist savanna.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ethiopian_boubou' where nome_scientifico = 'Laniarius aethiopicus' and descrizione is null;
update specie set descrizione = 'The crimson-breasted shrike or the crimson-breasted gonolek,, or the crimson-breasted boubou, is a southern African bird. It has black upper parts with a white flash on the wing, and bright scarlet underparts. The International Union for Conservation of Nature has rated it as a "least-concern species".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-breasted_shrike' where nome_scientifico = 'Laniarius atrococcineus' and descrizione is null;
update specie set descrizione = 'The yellow-breasted boubou is a species of bird in the family Malaconotidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-breasted_boubou' where nome_scientifico = 'Laniarius atroflavus' and descrizione is null;
update specie set descrizione = 'The yellow-crowned gonolek, also known as the common gonolek, is a medium-sized passerine bird in the bushshrike family. It is a common resident breeding bird in equatorial Africa from Senegal and Democratic Republic of Congo east to Ethiopia. It is a skulking bird and frequents dense undergrowth in forests and other wooded habitats. The nest is a cup structure in a bush or tree in which two eggs are laid.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-crowned_gonolek' where nome_scientifico = 'Laniarius barbarus' and descrizione is null;
update specie set descrizione = 'The swamp boubou, also known as the Gabon boubou, is a species of bird in the Malaconotidae or bushshrike family. It is native to western and southern Central Africa. In the north of their range, savannah thickets constitute an important part of their habitat, while in the south they are strongly associated with river systems and marshes, for which they are named. The pair bond appears to be maintained by duetting, which in the south is generally synchronous or overlapping. It is most similar to L. major major, with which it perhaps hybridizes, but the underpart plumage is immaculate white, while the female contributes a ratchet-like note to the duet.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Swamp_boubou' where nome_scientifico = 'Laniarius bicolor' and descrizione is null;
update specie set descrizione = 'The black-headed gonolek is a species of bird in the family Malaconotidae. It is found in the African countries of Burundi, Cameroon, Central African Republic, Chad, Democratic Republic of the Congo, Eritrea, Ethiopia, Kenya, Nigeria, Rwanda, South Sudan, Sudan, Tanzania, and Uganda.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_gonolek' where nome_scientifico = 'Laniarius erythrogaster' and descrizione is null;
update specie set descrizione = 'The southern boubou is a species of bushshrike. Though these passerine birds and their relations were once included with true shrikes in the Laniidae, they are not closely related to that family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_boubou' where nome_scientifico = 'Laniarius ferrugineus' and descrizione is null;
update specie set descrizione = 'The slate-colored boubou or slate-coloured boubou is a species of bird in the family Malaconotidae. It is found in Ethiopia, Kenya, Rwanda, Somalia, South Sudan, Tanzania, and Uganda. Its natural habitats are subtropical or tropical dry forests, dry savanna, subtropical or tropical dry shrubland, and subtropical or tropical moist shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slate-colored_boubou' where nome_scientifico = 'Laniarius funebris' and descrizione is null;
update specie set descrizione = 'The tropical boubou or bell shrike is a medium-sized passerine bird of sub-Saharan Africa. This very diverse "species" with its numerous subspecies and morphs has since long posed a taxonomic problem, and recent research suggests it is a cryptic species complex that has now been split into several species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tropical_boubou' where nome_scientifico = 'Laniarius major' and descrizione is null;
update specie set descrizione = 'The papyrus gonolek is a species of bird in the family Malaconotidae. It is found in Burundi, Democratic Republic of the Congo, Kenya, Rwanda, Tanzania, and Uganda.
It has specialised habitat requirements, being restricted to papyrus swamps. Not yet a threatened species, it has become rare due to habitat loss and pollution.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Papyrus_gonolek' where nome_scientifico = 'Laniarius mufumbiri' and descrizione is null;
update specie set descrizione = 'The mountain sooty boubou, western boubou or mountain boubou, is a species of bird in the family Malaconotidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mountain_sooty_boubou' where nome_scientifico = 'Laniarius poensis' and descrizione is null;
update specie set descrizione = 'The East Coast boubou or Zanzibar boubou is a species of bird in the family Malaconotidae.
It is found from southeast Somalia to northeast Tanzania, and Zanzibar island.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/East_Coast_boubou' where nome_scientifico = 'Laniarius sublacteus' and descrizione is null;
update specie set descrizione = 'The Brazilian laniisoma is a species of bird in the family Tityridae, the tityras, becards, and allies. It is endemic to Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brazilian_laniisoma' where nome_scientifico = 'Laniisoma elegans' and descrizione is null;
update specie set descrizione = 'The black-throated shrike-tanager is a species of bird in the family Thraupidae. It is found in Belize, Guatemala, Honduras, and Mexico. Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_shrike-tanager' where nome_scientifico = 'Lanio aurantius' and descrizione is null;
update specie set descrizione = 'The fulvous shrike-tanager is a South American bird in the tanager family Thraupidae.
It is found in Brazil, Colombia, Ecuador, French Guiana, Guyana, Peru, Suriname, and Venezuela.
Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fulvous_shrike-tanager' where nome_scientifico = 'Lanio fulvus' and descrizione is null;
update specie set descrizione = 'The white-throated shrike-tanager is a species of bird in the family Thraupidae. It is found in Costa Rica, Honduras, Nicaragua, and Panama. Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_shrike-tanager' where nome_scientifico = 'Lanio leucothorax' and descrizione is null;
update specie set descrizione = 'The white-winged shrike-tanager is a species of bird in the family Thraupidae. It is found in Bolivia, Brazil, and Peru in subtropical or tropical moist lowland forests. Two subspecies are recognised: L. v. versicolor from eastern Peru, western Brazil, and northern Bolivia, and L. v. parvus from eastern and central Brazil and northeastern Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-winged_shrike-tanager' where nome_scientifico = 'Lanio versicolor' and descrizione is null;
update specie set descrizione = 'The cinereous mourner is a species of bird in the family Tityridae, the tityras, becards, and allies. It is found in every mainland South American country except Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cinereous_mourner' where nome_scientifico = 'Laniocera hypopyrra' and descrizione is null;
update specie set descrizione = 'The speckled mourner is a species of bird in the family Tityridae. It is found in Mexico, in every Central American country except El Salvador, and in Colombia and Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Speckled_mourner' where nome_scientifico = 'Laniocera rufescens' and descrizione is null;
