update specie set descrizione = 'Il Lanius collaris Linnaeus, 1766) è un uccello passeriforme della famiglia Laniidae. Si trova in gran parte dell''Africa sub-sahariana.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_collaris' where nome_scientifico = 'Lanius collaris' and descrizione is null;
update specie set descrizione = 'The red-backed shrike is a carnivorous passerine bird and member of the shrike family, Laniidae. Its breeding range stretches from Western Europe east to central Russia. It is migratory and winters in the eastern areas of tropical Africa and southern Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-backed_shrike' where nome_scientifico = 'Lanius collurio' and descrizione is null;
update specie set descrizione = 'L''averla birmana o averla dorsobruno è un uccello passeriforme della famiglia Laniidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_collurioides' where nome_scientifico = 'Lanius collurioides' and descrizione is null;
update specie set descrizione = 'The yellow-billed shrike is a large passerine bird in the shrike family. It is sometimes known as the long-tailed shrike, but this invites confusion with the long-tailed shrike, Lanius schach, of tropical southern Asia. It is the only species placed in the genus Corvinella. The yellow-billed shrike is a common resident breeding bird in tropical Africa from Senegal eastwards to Uganda and locally in westernmost Kenya. It frequents forest and other habitats with trees.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-billed_shrike' where nome_scientifico = 'Lanius corvinus' and descrizione is null;
update specie set descrizione = 'L''averla bruna è un uccello passeriforme della famiglia Laniidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_cristatus' where nome_scientifico = 'Lanius cristatus' and descrizione is null;
update specie set descrizione = 'L''averla maggiore è un uccello passeriforme della famiglia Laniidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_excubitor' where nome_scientifico = 'Lanius excubitor' and descrizione is null;
update specie set descrizione = 'The northern fiscal is a member of the shrike family found through most of Sub-Saharan Africa. It used to be grouped with the southern fiscal. Together they were called the common fiscal. The fiscal gets its English and Afrikaans common names from its black and white ''suit-and-tie'' appearance reminiscent of the taxman (‘fiscal’).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_fiscal' where nome_scientifico = 'Lanius humeralis' and descrizione is null;
update specie set descrizione = 'The isabelline shrike or Daurian shrike is a member of the shrike family (Laniidae). It was previously considered conspecific with the red-backed shrike and red-tailed shrike. It is found in an extensive area between the Caspian Sea and north and central China southeast to the Qaidam Basin. Overwinters in Africa and Arabia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Isabelline_shrike' where nome_scientifico = 'Lanius isabellinus' and descrizione is null;
update specie set descrizione = 'The loggerhead shrike is a passerine bird in the family Laniidae. It is the only member of the shrike family endemic to North America; the related northern shrike occurs north of its range; however, it is also found in Siberia. It is nicknamed the butcherbird after its carnivorous tendencies, as it consumes prey such as insects, amphibians, lizards, small mammals and small birds, and some prey end up displayed and stored at a site, for example in a tree. Due to its small size and weak talons, this predatory bird relies on impaling its prey upon thorns or barbed wire for facilitated consumption. The numbers of loggerhead shrike have significantly decreased in recent years, especially in Midwestern, New England and Mid-Atlantic areas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Loggerhead_shrike' where nome_scientifico = 'Lanius ludovicianus' and descrizione is null;
update specie set descrizione = 'Il Lanius meridionalis è un uccello passeriforme della famiglia Laniidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_meridionalis' where nome_scientifico = 'Lanius meridionalis' and descrizione is null;
update specie set descrizione = 'L''averla minore o averla cenerina è un uccello passeriforme della famiglia Laniidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_minor' where nome_scientifico = 'Lanius minor' and descrizione is null;
update specie set descrizione = 'L''averla mascherata è un uccello passeriforme della famiglia dell''averla (Laniidae). Nidifica nell''Europa sud-orientale e dell''estremità orientale del Mediterraneo, con un popolazione separata nell''Iraq orientale e nell''Iran occidentale. È un uccello migratore, sverna principalmente nell''Africa nord-orientale. Sebbene sia un migratore a corto raggio, le migrazioni si verificano altrove, compresa l''Europa nord-occidentale. È il membro più piccolo del suo genere, dalla coda lunga e dal becco uncinato. Il maschio ha le parti superiori prevalentemente nere, con il bianco sulla corona, sulla fronte e sul supercilium e grandi macchie bianche sulle spalle e sulle ali. La gola, i lati del collo e le parti inferiori sono bianchi, con fianchi e petto arancioni. La femmina ha una colorazione più opaca del maschio, con parti superiori nere brunastre e un tono grigio o camoscio sulle spalle e sulle parti inferiori. Il "giovane" ha le parti superiori grigio-marroni con una fronte più chiara e barrata dalla testa alla groppa, parti inferiori bianco sporco barrate e ali marroni a parte le macchie primarie bianche. I richiami della specie sono brevi e stridenti, ma il canto ha componenti melodiche simili a quelle dei silvidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_nubicus' where nome_scientifico = 'Lanius nubicus' and descrizione is null;
update specie set descrizione = 'L''averla codirossa o averla del Turkestan è un uccello passeriforme della famiglia dei Laniidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_phoenicuroides' where nome_scientifico = 'Lanius phoenicuroides' and descrizione is null;
update specie set descrizione = 'L''averla dalla coda lunga o averla dorso rossiccio è un uccello appartenente alla famiglia dei Lanidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_schach' where nome_scientifico = 'Lanius schach' and descrizione is null;
update specie set descrizione = 'L''averla capirossa è un uccello della famiglia dei Laniidae, che è possibile osservare in Italia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_senator' where nome_scientifico = 'Lanius senator' and descrizione is null;
update specie set descrizione = 'L''averla maggiore cinese è un uccello passeriforme della famiglia Laniidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lanius_sphenocercus' where nome_scientifico = 'Lanius sphenocercus' and descrizione is null;
