update specie set descrizione = 'Il gabbiano della California è un uccello della famiglia dei Laridi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Larus_californicus' where nome_scientifico = 'Larus californicus' and descrizione is null;
update specie set descrizione = 'The common gull is a gull that breeds in cool temperate regions of the Palearctic from Iceland and Scotland east to Kamchatka in the Russian Far East. Most common gulls migrate further south in winter, reaching the Mediterranean Sea, the southern Caspian Sea, and the seas around China and Japan; northwest European populations are at least partly resident. The closely related short-billed gull was formerly often included in this species, which was then sometimes known collectively as "mew gull".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_gull' where nome_scientifico = 'Larus canus' and descrizione is null;
update specie set descrizione = 'The black-tailed gull is a gull native to shorelines of East Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-tailed_gull' where nome_scientifico = 'Larus crassirostris' and descrizione is null;
update specie set descrizione = 'La gavina americana, gabbiano di Delaware o gabbiano del Delaware è un uccello della famiglia dei Laridi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Larus_delawarensis' where nome_scientifico = 'Larus delawarensis' and descrizione is null;
update specie set descrizione = 'The  kelp gull, also known as the Dominican gull, is a gull that breeds on coasts and islands through much of the Southern Hemisphere. The nominate L. d. dominicanus is the subspecies found around South America, parts of Australia, and New Zealand. L. d. vetula is a subspecies occurring around Southern Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Kelp_gull' where nome_scientifico = 'Larus dominicanus' and descrizione is null;
update specie set descrizione = 'The lesser black-backed gull is a large gull that breeds on the Atlantic and Arctic coasts of Europe. It is migratory, wintering from the British Isles south to West Africa. However, it has increased dramatically in North America, especially along the east coast. Formerly just a winter visitor to North America, it now occurs in large numbers some winters and birds are recorded year-round. However, there is serious concern about decline in many parts of its range. The species is on the UK Amber List because the UK is home to 40 per cent of the European population and more than half of these are found at fewer than ten breeding sites.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_black-backed_gull' where nome_scientifico = 'Larus fuscus' and descrizione is null;
update specie set descrizione = 'The glaucous-winged gull is a large, white-headed gull. The genus name is from Latin Larus which appears to have referred to a gull or other large seabird. The specific glaucescens is Neo-Latin for "glaucous" from the Ancient Greek, glaukos, denoting the grey color of its wings.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Glaucous-winged_gull' where nome_scientifico = 'Larus glaucescens' and descrizione is null;
