update specie set descrizione = 'The Indian blue robin is a small bird found in the Indian subcontinent. Formerly considered a thrush, it is now considered one of the Old World flycatchers in the family Muscicapidae. It was earlier also called the Indian blue chat. It is migratory, breeding in the forests along the Himalayas of Nepal, India, Myanmar and Bangladesh. They winter in the hill forests of the Western Ghats of India and in Sri Lanka.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_blue_robin' where nome_scientifico = 'Larvivora brunnea' and descrizione is null;
