update specie set descrizione = 'The white-fronted manakin is a species of bird in the family Pipridae, the manakins. It is native to French Guiana, Guyana, Suriname and northeastern Brazil where it inhabits subtropical and tropical moist lowland forest. The male is mainly black, with a blue rump, yellow belly patches and a conspicuous patch of white feathers extending forwards from its forehead. The female is gray and black with a pale yellow belly and white eye ring. This is a fairly common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-fronted_manakin' where nome_scientifico = 'Lepidothrix serena' and descrizione is null;
