update specie set descrizione = 'The purple-rumped sunbird is a sunbird endemic to the Indian Subcontinent. Like other sunbirds, they are small in size, feeding mainly on nectar but sometimes take insects, particularly when feeding young. They can hover for short durations but usually perch to lap nectar from flowers. They build a hanging pouch nest made up of cobwebs, lichens and plant material. Males are contrastingly coloured but females are olive above and yellow to buff below. Males are easily distinguished from the purple sunbird by the light coloured underside while females can be told apart from males by their whitish throats.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Purple-rumped_sunbird' where nome_scientifico = 'Leptocoma zeylonica' and descrizione is null;
