update specie set descrizione = 'The buffy hummingbird is a species of bird in the hummingbird family Trochilidae. It is the only species placed in the genus Leucippus. This bird lives in dry forest and scrubland in northern South America where it feeds on insects and the nectar, flesh, and juice of cactus fruits.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buffy_hummingbird' where nome_scientifico = 'Leucippus fallax' and descrizione is null;
update specie set descrizione = 'Il colibrì golabianca è un uccello della famiglia Trochilidae. È l''unica specie nota del genere Leucochloris .', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Leucochloris_albicollis' where nome_scientifico = 'Leucochloris albicollis' and descrizione is null;
update specie set descrizione = 'La gru siberiana è un uccello della famiglia dei Gruidi. Gli adulti si distinguono da tutte le altre gru per il fatto di avere il piumaggio di colore interamente bianco candido, fatta eccezione per le remiganti primarie nere, visibili solamente quando l''uccello è in volo. È presente, con due popolazioni disgiunte, nella tundra artica della Russia occidentale e orientale. La popolazione orientale migra in Cina durante l''inverno, mentre quella occidentale trascorre i mesi invernali in Iran e, in passato, in India e Nepal. Tra le gru, questa specie è quella che migra sulle distanze più lunghe. Il numero di esemplari, in particolare quello degli appartenenti alla popolazione occidentale, è diminuito drasticamente nel corso del XX secolo a causa della caccia lungo le rotte migratorie e del degrado ambientale. Attualmente la popolazione globale viene stimata in 3500-4000 unità, per lo più appartenenti alla popolazione orientale, che sverna per il 95% nel bacino del lago Poyang, in Cina, un habitat che potrebbe aver subito delle alterazioni in seguito alla costruzione della diga delle Tre Gole. Fatta eccezione per gli esemplari reintrodotti, in Siberia occidentale rimangono solamente una decina di esemplari selvatici.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Leucogeranus_leucogeranus' where nome_scientifico = 'Leucogeranus leucogeranus' and descrizione is null;
