update specie set descrizione = 'The grey-eared honeyeater, also known as the dark-brown honeyeater, is a passerine bird of the honeyeater family which is found in Vanuatu and New Caledonia in the south-west Pacific. It is sometimes known as the silver-eared honeyeater, but this name is also used for the silver-eared honeyeater of New Guinea.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-eared_honeyeater' where nome_scientifico = 'Lichmera incana' and descrizione is null;
update specie set descrizione = 'The brown honeyeater is a species of bird in the family Meliphagidae. It belongs to the honeyeaters, a group of birds which have highly developed brush-tipped tongues adapted for nectar feeding. Honeyeaters are found mainly in Australia, New Guinea, and parts of Indonesia, but the brown honeyeater is unique in that it also occurs on the island of Bali, making it the only honeyeater to be found west of the Wallace Line, the biogeographical boundary between the Australian-Papuan and Oriental zoogeographical regions.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_honeyeater' where nome_scientifico = 'Lichmera indistincta' and descrizione is null;
update specie set descrizione = 'The brown honeyeater is a species of bird in the family Meliphagidae. It belongs to the honeyeaters, a group of birds which have highly developed brush-tipped tongues adapted for nectar feeding. Honeyeaters are found mainly in Australia, New Guinea, and parts of Indonesia, but the brown honeyeater is unique in that it also occurs on the island of Bali, making it the only honeyeater to be found west of the Wallace Line, the biogeographical boundary between the Australian-Papuan and Oriental zoogeographical regions.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_honeyeater' where nome_scientifico = 'Lichmera limbata' and descrizione is null;
update specie set descrizione = 'The scaly-breasted honeyeater, also known as the white-tufted honeyeater, is a species of bird in the family Meliphagidae. It is endemic to Indonesia, where it occurs in the southern Moluccas. Its natural habitats are subtropical or tropical dry forests, subtropical or tropical moist lowland forests, and subtropical or tropical mangrove forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scaly-breasted_honeyeater' where nome_scientifico = 'Lichmera squamata' and descrizione is null;
