update specie set descrizione = 'The Hudsonian godwit is a large shorebird in the sandpiper family, Scolopacidae. It is a long distance migratory species that breeds at remote sites in northern Canada and winters in southern South America. The genus name Limosa is from Latin and means "muddy", from limus, "mud". The specific haemastica is from Ancient Greek and means "bloody".The English term "godwit" is believed to imitate the bird''s call.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hudsonian_godwit' where nome_scientifico = 'Limosa haemastica' and descrizione is null;
update specie set descrizione = 'The bar-tailed godwit is a large and strongly migratory wader in the family Scolopacidae, which feeds on bristle-worms and shellfish on coastal mudflats and estuaries. It has distinctive red breeding plumage, long legs, and a long upturned bill. Bar-tailed godwits breed on Arctic coasts and tundra from Scandinavia to Alaska, and overwinter on coasts in temperate and tropical regions of Australia and New Zealand. The migration of the subspecies Limosa lapponica baueri across the Pacific Ocean from Alaska to New Zealand is the longest known non-stop flight of any bird, and also the longest journey without pausing to feed by any animal. The round-trip migration for this subspecies is over 29,000 km (18,020 mi).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bar-tailed_godwit' where nome_scientifico = 'Limosa lapponica' and descrizione is null;
