update specie set descrizione = 'The rufous piha is a species of bird in the family Cotingidae, the cotingas. Its range extends from southern Mexico throughout Central America and the Chocó-Magdalena region.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous_piha' where nome_scientifico = 'Lipaugus unirufus' and descrizione is null;
update specie set descrizione = 'The screaming piha is a species of passerine bird in the lesser-known family Cotingidae, the cotingas. It is found in every mainland South American country except for these four countries: Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Screaming_piha' where nome_scientifico = 'Lipaugus vociferans' and descrizione is null;
update specie set descrizione = 'The chestnut-capped piha is a species of bird in the family Cotingidae. It is endemic to a small portion of Colombia''s central Andes in the department of Antioquia. The chestnut-capped piha resides only in a narrow band of humid premontane cloud forest. It is a dark grey passerine with a notable chestnut crown on the upper nape and pale cinnamon-colored undertail coverts. Adults are small for pihas, measuring about 20 to 25 cm long. Males have modified primary feathers with elongated and stiff barbules that enable them to create a whirring noise with their wings, which the piha likely uses for display purposes. Its call is extremely loud and can be heard over 100 m (330 ft) away. The chestnut-capped piha is mostly frugivorous, although it will eat some invertebrates. Little is known about the species'' breeding ecology, although it is believed to be a lekking species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-capped_piha' where nome_scientifico = 'Lipaugus weberi' and descrizione is null;
update specie set descrizione = 'La rana toro, anche conosciuta come rana bue, è un anfibio anuro della famiglia Ranidae, originario del Nord America.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lithobates_catesbeianus' where nome_scientifico = 'Lithobates catesbeianus' and descrizione is null;
update specie set descrizione = 'Lithobastes clamitans (Latreille, 1801), o Rana clamitans, comunemente nota come rana verde, è una specie di rana originaria del Nord America orientale. Le due sottospecie riconosciute sono la rana bronzea e la rana verde settentrionale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lithobates_clamitans' where nome_scientifico = 'Lithobates clamitans' and descrizione is null;
update specie set descrizione = 'The pickerel frog is a small North American frog, characterized by the appearance of seemingly "hand-drawn" squares on its dorsal surface.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pickerel_frog' where nome_scientifico = 'Lithobates palustris' and descrizione is null;
update specie set descrizione = 'Lithobates sylvaticus, o Rana sylvatica, comunemente nota come rana dei boschi, è una specie di rana ampiamente distribuita in Nord America: il suo areale si estende dalle foreste boreali settentrionali fino agli Appalachi meridionali, con alcune popolazioni isolate di particolare interesse, tra cui quelle delle pianure orientali della Carolina del Nord. La rana dei boschi ha attirato l''attenzione dei biologi per la sua tolleranza al congelamento, per il grado relativamente elevato di terrestrità, insolito per un ranide, per le sue peculiari associazioni ambientali, come torbiere, pozze vernali e ambienti di altopiano, e per la capacità di compiere spostamenti su distanze relativamente lunghe. È l''unica rana nordamericana presente a nord del Circolo polare artico.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lithobates_sylvaticus' where nome_scientifico = 'Lithobates sylvaticus' and descrizione is null;
update specie set descrizione = 'The sharp-tailed streamcreeper is a passerine bird of South America in the Furnariinae subfamily of the ovenbird family Furnariidae. Alternate names include streamside Lochmias, sharp-tailed creeper, and simply streamcreeper. It is found in Panama and every mainland South American country except Chile, French Guiana, and Suriname.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sharp-tailed_streamcreeper' where nome_scientifico = 'Lochmias nematura' and descrizione is null;
update specie set descrizione = 'Locustella alishanensis è una specie di uccelli passeriformi della famiglia delle Locustellidae endemica dei pascoli d''altitudine delle montagne dell''Isola di Taiwan. Durante l''inverno predilige zone con altitudine inferiore rispetto all''areale estivo, che include rilievi fino a 3000 metri d''altezza.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Locustella_alishanensis' where nome_scientifico = 'Locustella alishanensis' and descrizione is null;
update specie set descrizione = 'The long-tailed bush warbler also known as the Long-tailed grasshopper-warbler is a species of grass warbler. It was formerly included in the "Old World warbler" assemblage. It is found only in the Philippines on the islands of Mindanao and Luzon.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-tailed_bush_warbler' where nome_scientifico = 'Locustella caudata' and descrizione is null;
update specie set descrizione = 'The Baikal bush warbler, also known as Baikal grasshopper-warbler or David''s bush warbler, is a migratory species of Old World warbler in the family Locustellidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Baikal_bush_warbler' where nome_scientifico = 'Locustella davidi' and descrizione is null;
update specie set descrizione = 'The river warbler is an Old World warbler in the genus Locustella. It breeds in eastern and central Europe and is migratory, wintering in inland southern Africa, from around the Zambezi River south to the vicinity of Pretoria in South Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/River_warbler' where nome_scientifico = 'Locustella fluviatilis' and descrizione is null;
update specie set descrizione = 'The lanceolated warbler is a species of Old World warbler in the genus Locustella. It breeds from northeast European Russia across the Palearctic to northern Hokkaidō, Japan. It is migratory, wintering in Southeast Asia. The genus name Locustella is from Latin and is a diminutive of locusta, "grasshopper". This refers to the song of the common grasshopper warbler and some others in this genus. The specific  lanceolata is Latin for "spear-shaped" and refers to the streaks on the breast.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lanceolated_warbler' where nome_scientifico = 'Locustella lanceolata' and descrizione is null;
update specie set descrizione = 'The brown bush warbler is a songbird species. Formerly placed in the "Old World warbler" assemblage as Bradypterus luteoventrus, it is now placed in the newly recognized family Locustellidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_bush_warbler' where nome_scientifico = 'Locustella luteoventris' and descrizione is null;
update specie set descrizione = 'The russet bush warbler is a songbird species. Formerly placed in the "Old World warbler" assemblage, it is now placed in the newly recognized family Locustellidae. B. mandelli was until recently considered a subspecies of B. seebohmi, and the name "russet bush warbler" was applied to the entire species complex. After this was split up, Benguet bush warbler was proposed as a new name for B. seebohmi proper. The species is found in southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Russet_bush_warbler' where nome_scientifico = 'Locustella mandelli' and descrizione is null;
update specie set descrizione = 'The Javan bush warbler is a songbird species. Formerly placed in the "Old World warbler" assemblage, it is now placed in the newly recognized family Locustellidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Javan_bush_warbler' where nome_scientifico = 'Locustella montis' and descrizione is null;
update specie set descrizione = 'The common grasshopper warbler or just grasshopper warbler is a species of Old World warbler in the genus Locustella. It breeds across much of temperate Europe and the western Palearctic. It is migratory, wintering across northern tropical Africa just south of the Sahara, and also locally in India.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_grasshopper_warbler' where nome_scientifico = 'Locustella naevia' and descrizione is null;
update specie set descrizione = 'The Chinese bush warbler is an Old World warbler in the family Locustellidae. The species was first described by Robert Swinhoe in 1871. It breeds in the East Palearctic ; it winters to Northeast India, Yunnan and Southeast Asia.
