update specie set descrizione = 'La paradisea superba è un uccello passeriforme della famiglia Paradisaeidae. Un tempo considerata l''unica specie del genere Lophorina Vieillot, 1816. Uno studio del 2018 però suggerisce il riconoscimento come specie della Lophorina niedda, sulla base di differenze nel corteggiamento.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lophorina_superba' where nome_scientifico = 'Lophorina superba' and descrizione is null;
update specie set descrizione = 'Il gufo crestato o gufo dalla lunga cresta è un uccello rapace della famiglia Strigidae, presente nel sud del Messico, in Venezuela, Suriname, Guyana, Colombia, Ecuador, Perù, Brasile e Bolivia. È l''unica specie del genere Lophostrix. È un gufo di medie dimensioni, facilmente riconoscibile per i suoi lunghi ciuffi auricolari biancastri e l''aspetto altrimenti più scuro. Abita le foreste pluviali di pianura e predilige le aree di vecchia crescita in prossimità dell''acqua. Il gufo crestato è una specie strettamente notturna, ma si sa molto poco del suo comportamento.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Lophostrix_cristata' where nome_scientifico = 'Lophostrix cristata' and descrizione is null;
