update specie set descrizione = 'The Malaysian eared nightjar or Malay eared nightjar is a species of nightjar in the family Caprimulgidae. It was formerly placed in the genus Eurostopodus. It is known as Taptibau Kecil in Bahasa melayu or Tukang Tabtibau amongst Malaysian indigenous communities. It is dispersed throughout Southeast Asia, primarily occurring in Malaysia, Sumatra, Borneo, Thailand, Indonesia and Singapore. It is a nocturnal insectivorous bird characterised by cryptic colouration of brown and white patterns, to aid it in camouflaging into its environment. Due to the nocturnal nature and feeding habits, it prefers subtropical, tropical and moist lowland forests, and have been recorded from sea-level to 1065 meters. It is easily distinguished by its ''ear-tufts,'' giving it an "eared" appearance which led to its name.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Malaysian_eared_nightjar' where nome_scientifico = 'Lyncornis temminckii' and descrizione is null;
