update specie set descrizione = 'The cattle tyrant is a species of bird in the tyrant flycatcher family Tyrannidae. In Brazil, it is called suiriri-cavaleiro. It is the only member of the genus Machetornis. The relationships of this species and genus to other genera in the tyrant flycatchers are uncertain. It resembles Tyrannus flycatchers, but this may be the result of convergence.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cattle_tyrant' where nome_scientifico = 'Machetornis rixosa' and descrizione is null;
update specie set descrizione = 'The Indian black-lored tit, Indian tit, or Indian yellow tit is a passerine bird in the tit family Paridae. The yellow-cheeked tit is probably its closest relative, and both may be related to the yellow tit. These three tits almost certainly form a distinct lineage as evidenced by morphology, and mtDNA cytochrome b sequence analysis. The subgenus name Macholophus may apply for them.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_black-lored_tit' where nome_scientifico = 'Machlolophus aplonotus' and descrizione is null;
