update specie set descrizione = 'The Himalayan black-lored tit, also known as simply black-lored tit, is a passerine bird in the tit family Paridae. The yellow-cheeked tit is probably its closest relative, and it may also be related to the yellow tit. These three tits almost certainly form a distinct lineage, as indicated by morphology, and mtDNA cytochrome b sequence analysis.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Himalayan_black-lored_tit' where nome_scientifico = 'Machlolophus xanthogenys' and descrizione is null;
