update specie set descrizione = 'The golden-tufted mountain grackle, also known as the golden-tufted grackle and tepui mountain-grackle, is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Brazil, Guyana, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-tufted_mountain_grackle' where nome_scientifico = 'Macroagelaius imthurni' and descrizione is null;
