update specie set descrizione = 'The Cape longclaw or orange-throated longclaw is a passerine bird in the family Motacillidae, which comprises the longclaws, pipits and wagtails. It occurs in Southern Africa in Zimbabwe and southern and eastern South Africa. This species is found in coastal and mountain grassland, often near water.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cape_longclaw' where nome_scientifico = 'Macronyx capensis' and descrizione is null;
