update specie set descrizione = 'The Amboyna cuckoo-dove is a dove in the genus Macropygia found in the Moluccas and New Guinea. It was one of three new species defined when the slender-billed cuckoo-dove was split up in 2016 and retains the Latin binomial of the former species.[1]', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Amboyna_cuckoo-dove' where nome_scientifico = 'Macropygia amboinensis' and descrizione is null;
update specie set descrizione = 'The brown cuckoo-dove is a dove in the genus Macropygia found in Australia from Weipa and Aurukun in the north to Bega in the south, and most inland at Atherton and Toowoomba. It is sometimes called the "brown pigeon" or "pheasant pigeon", but both terms are best avoided, as they can lead to confusion with the brown doves and the true pheasant pigeon. It was one of three new species defined when the slender-billed cuckoo-dove was split in 2016.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_cuckoo-dove' where nome_scientifico = 'Macropygia phasianella' and descrizione is null;
