update specie set descrizione = 'The grey-headed bushshrike, colloquially known as the ghostbird, is a species of passerine bird in the family Malaconotidae. It is widespread throughout sub-Saharan Africa, although relatively absent in Central Africa and the interior of southern Africa. It is the most widespread species of its genus, which consists of large bushshrikes with massive bills and mournful hooting calls. It occurs sparsely in a range of wooded habitats, though typically in denser vegetation within dry or moist savannah. The monogamous pairs occupy woodland with sufficient cover. They are sedentary, but will undertake limited post-breeding movements.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-headed_bushshrike' where nome_scientifico = 'Malaconotus blanchoti' and descrizione is null;
