update specie set descrizione = 'The semicollared puffbird is a species of near-passerine bird in the family Bucconidae, the puffbirds, nunlets, and nunbirds. It is one of seven species of the genus Malacoptila. It is found in Bolivia, Brazil, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Semicollared_puffbird' where nome_scientifico = 'Malacoptila semicincta' and descrizione is null;
update specie set descrizione = 'The crescent-chested puffbird is a species of near-passerine bird in the family Bucconidae, the puffbirds, nunlets, and nunbirds. It is endemic to Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crescent-chested_puffbird' where nome_scientifico = 'Malacoptila striata' and descrizione is null;
update specie set descrizione = 'L''anatra guancerosa è un uccello della famiglia degli Anatidi originario dell''Australia. È l''unica specie vivente del genere Malacorhynchus Swainson, 1831; un suo parente stretto, di dimensioni leggermente superiori, è l''ormai estinta anatra di Scarlett, diffusa fino a non molti secoli fa in Nuova Zelanda.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Malacorhynchus_membranaceus' where nome_scientifico = 'Malacorhynchus membranaceus' and descrizione is null;
update specie set descrizione = 'The rufous-eared warbler is a species of bird in the family Cisticolidae. It is found in Botswana, Namibia, and South Africa. It is the only species in the genus Malcorus.
Its natural habitats are subtropical or tropical dry shrubland and subtropical or tropical dry lowland grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-eared_warbler' where nome_scientifico = 'Malcorus pectoralis' and descrizione is null;
update specie set descrizione = 'La Malia grata Schlegel, 1881 è una specie di uccello passeriforme della famiglia Locustellidae endemica dell''isola di Sulawesi, in Indonesia. La dieta di questa specie è costituita principalmente da insetti, coleotteri e altri artropodi e si trova in normalmente in coppie o piccoli gruppi composti da un numero variabile di esemplari che puoi variare dai tre ai sette uccelli.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Malia_grata' where nome_scientifico = 'Malia grata' and descrizione is null;
update specie set descrizione = 'The blue-billed malimbe or Gray''s malimbe is a species of bird in the family Ploceidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-billed_malimbe' where nome_scientifico = 'Malimbus nitens' and descrizione is null;
update specie set descrizione = 'The white-shouldered fairywren is a species of bird in the Australasian wren family, Maluridae.
It is found in New Guinea.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-shouldered_fairywren' where nome_scientifico = 'Malurus alboscapulatus' and descrizione is null;
update specie set descrizione = 'The lovely fairywren, or lovely wren, is a species of bird in the Australasian wren family, Maluridae. It is endemic to northeastern Australia. Its natural habitats are subtropical or tropical dry forest and subtropical or tropical moist lowland forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lovely_fairywren' where nome_scientifico = 'Malurus amabilis' and descrizione is null;
update specie set descrizione = 'The purple-backed fairywren is a fairywren that is native to Australia. Described by Alfred John North in 1901, it has four recognised subspecies. In a species that exhibits sexual dimorphism, the brightly coloured breeding male has chestnut shoulders and azure crown and ear coverts, while non-breeding males, females and juveniles have predominantly grey-brown plumage, although females of two subspecies have mainly blue-grey plumage. Distributed over much of the Australian continent, the purple-backed fairywren is found in scrubland with plenty of vegetation providing dense cover.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Purple-backed_fairywren' where nome_scientifico = 'Malurus assimilis' and descrizione is null;
update specie set descrizione = 'The superb fairywren is a passerine bird in the Australasian wren family, Maluridae, and is common and familiar across south-eastern Australia. It is a sedentary and territorial species, also exhibiting a high degree of sexual dimorphism; the male in breeding plumage has a striking bright blue forehead, ear coverts, mantle, and tail, with a black mask and black or dark blue throat. Non-breeding males, females and juveniles are predominantly grey-brown in colour; this gave the early impression that males were polygamous, as all dull-coloured birds were taken for females. Six subspecies groups are recognized: three larger and darker forms from Tasmania, Flinders and King Island respectively, and three smaller and paler forms from mainland Australia and Kangaroo Island.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Superb_fairywren' where nome_scientifico = 'Malurus cyaneus' and descrizione is null;
update specie set descrizione = 'The emperor fairywren is a species of bird in the Australasian wren family, Maluridae. It is found in New Guinea in its natural habitat of subtropical or tropical moist lowland forests. It is the largest species of fairywren. It is highly sexually dimorphic. Males have a blue and black plumage, with the females having blue and black plumage only on their heads, with the rest of the body being coloured a rusty brown and having a black tail tipped with white. There are 3 recognized subspecies of the emperor fairywren, one from north and northwestern New Guinea, one from Biak Island, and one from south New Guinea and the Aru Islands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Emperor_fairywren' where nome_scientifico = 'Malurus cyanocephalus' and descrizione is null;
update specie set descrizione = 'The red-winged fairywren is a species of passerine bird in the Australasian wren family, Maluridae. It is non-migratory and endemic to the southwestern corner of Western Australia. Exhibiting a high degree of sexual dimorphism, the male adopts a brilliantly coloured breeding plumage, with an iridescent silvery-blue crown, ear coverts and upper back, red shoulders, contrasting with a black throat, grey-brown tail and wings and pale underparts. Non-breeding males, females and juveniles have predominantly grey-brown plumage, though males may bear isolated blue and black feathers. No separate subspecies are recognised. Similar in appearance and closely related to the variegated fairywren and the blue-breasted fairywren, it is regarded as a separate species as no intermediate forms have been recorded where their ranges overlap. Though the red-winged fairywren is locally common, there is evidence of a decline in numbers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-winged_fairywren' where nome_scientifico = 'Malurus elegans' and descrizione is null;
update specie set descrizione = 'Il maluro variegato, scricciolo fatato variegato o scricciolo australiano variegato è un uccello passeriforme del genere Malurus, a sua volta appartenente alla famiglia delle Maluridae. È endemico dell''Australia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Malurus_lamberti' where nome_scientifico = 'Malurus lamberti' and descrizione is null;
update specie set descrizione = 'Il Malurus leucopterus è una uccello passeriforme appartenente alla famiglia Maluridae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Malurus_leucopterus' where nome_scientifico = 'Malurus leucopterus' and descrizione is null;
update specie set descrizione = 'The red-backed fairywren is a species of passerine bird in the Australasian wren family, Maluridae. It is endemic to Australia and can be found near rivers and coastal areas along the northern and eastern coastlines from the Kimberley in the northwest to the Hunter Region in New South Wales. The male adopts a striking breeding plumage, with a black head, upperparts and tail, and a brightly coloured red back and brown wings. The female has brownish upperparts and paler underparts. The male in eclipse plumage and the juvenile resemble the female. Some males remain in non-breeding plumage while breeding. Two subspecies are recognised; the nominate M. m. melanocephalus of eastern Australia has a longer tail and orange back, and the short-tailed M. m. cruentatus from northern Australia has a redder back.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-backed_fairywren' where nome_scientifico = 'Malurus melanocephalus' and descrizione is null;
update specie set descrizione = 'Lo scricciolo azzurro splendente è un uccello passeriforme della famiglia Maluridae. È osservabile in gran parte del continente australiano dal Nuovo Galles del Sud alla parte sud-ovest del Queensland, fino alla costa occidentale dell''Australia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Malurus_splendens' where nome_scientifico = 'Malurus splendens' and descrizione is null;
update specie set descrizione = 'The orange-collared manakin is a passerine bird in the manakin family. It is an endemic resident breeder in Costa Rica and western Panama, where it is found in forests, secondary growth and plantations. It is a small, plump bird about 10 centimetres (4 in) long. Males have a black crown, mid back, wings and tail and an olive-green rump. The rest of the head, neck, breast and upper back are orange, and the belly is yellow. Females are olive-green with yellow underparts and resemble female white-collared manakins. At breeding time, males are involved in lekking behaviour on the forest floor. This is a fairly common species with a somewhat restricted range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-collared_manakin' where nome_scientifico = 'Manacus aurantiacus' and descrizione is null;
update specie set descrizione = 'The white-collared manakin is a passerine bird in the manakin family. It is a resident breeder in the tropical New World from southeastern Mexico to Costa Rica and the extreme west of Panama. It typically inhabits thickets at the edges of moist forest, tall secondary growth and old cacao plantations. It is a small, plump bird about 11 centimetres (4.3 in) long. Males have a black crown, mid-back band, wings and tail, an olive-green rump and yellow belly. Females and juveniles are olive-green with yellow bellies and resemble female orange-collared manakins. At breeding time, males are involved in lekking behaviour on the forest floor during which they puff out their neck feathers. This is a fairly common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-collared_manakin' where nome_scientifico = 'Manacus candei' and descrizione is null;
update specie set descrizione = 'The white-bearded manakin is a small passerine bird which breeds in tropical South America. It can be found in Colombia, Venezuela and Trinidad south to Bolivia and northern Argentina. This manakin is found in forests, secondary growth and plantations. It is a small, plump bird about 10.7 centimetres (4.2 in) long. Males have a black crown, upper back, wings and tail and are otherwise white. Females are olive-green and resemble female golden-headed manakins. At breeding time, males are involved in lekking behaviour on the forest floor during which they puff out their neck feathers. This is a fairly common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-bearded_manakin' where nome_scientifico = 'Manacus manacus' and descrizione is null;
update specie set descrizione = 'The golden-collared manakin is a species of bird in the family Pipridae. It is found in Colombia and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-collared_manakin' where nome_scientifico = 'Manacus vitellinus' and descrizione is null;
update specie set descrizione = 'The yellow-throated miner is a species of colonial honeyeater, endemic to Australia. It is also known as the white-rumped miner. The distinctive white rump is easy to observe in the field and distinguishes it from the other miner species. Yellow-throated miners are medium-sized, grey passerines with yellow throat markings, legs, and bare patches around the eye. The common name ''miner'' is an alternative spelling of the word myna, mynah or minah, and is shared with other members of the genus Manorina. Though miners were originally named due to their resemblance to the common myna of South and Southeast Asia that shares similar yellow eye-patch and legs, common mynas are from the starling family and are not closely related to the honeyeater family. Common mynas are an aggressive introduced pest in Australia, which causes some confusion with the native aggressive miners.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_miner' where nome_scientifico = 'Manorina flavigula' and descrizione is null;
update specie set descrizione = 'The noisy miner is a bird in the honeyeater family, Meliphagidae, and is endemic to eastern and southeastern Australia. This miner is a grey bird, with a black head, orange-yellow beak and feet, a distinctive yellow patch behind the eye, and white tips on the tail feathers. The Tasmanian subspecies has a more intense yellow panel in the wing, and a broader white tip to the tail. Males, females and juveniles are similar in appearance, though young birds are a brownish-grey. As the common name suggests, the noisy miner is a vocal species with a large range of songs, calls, scoldings and alarms, and almost constant vocalisations, particularly from young birds. One of four species in the genus Manorina, the noisy miner itself is divided into four subspecies. The separation of the Tasmanian M. m. leachi is of long standing, and the mainland birds were further split in 1999.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Noisy_miner' where nome_scientifico = 'Manorina melanocephala' and descrizione is null;
update specie set descrizione = 'The bell miner or bellbird is a colonial honeyeater, endemic to southeastern Australia. The common name refers to their bell-like call. "Miner" is an old alternative spelling of "myna", and is shared with other members of the genus Manorina. The birds feed almost exclusively on the dome-like coverings, referred to as lerps, of certain psyllid bugs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bell_miner' where nome_scientifico = 'Manorina melanophrys' and descrizione is null;
