update specie set descrizione = 'The black-capped screech owl, or variable screech owl, is a species of owl in the family Strigidae. It is found in Argentina, Brazil, and Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-capped_screech_owl' where nome_scientifico = 'Megascops atricapilla' and descrizione is null;
update specie set descrizione = 'The Chocó screech owl is a species of owl in the family Strigidae. It is found from central Panama to western Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Choc%C3%B3_screech_owl' where nome_scientifico = 'Megascops centralis' and descrizione is null;
update specie set descrizione = 'The tropical screech owl is a small species of owl in the family Strigidae. It is found in Costa Rica, Panama, Trinidad, and every mainland South American country.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tropical_screech_owl' where nome_scientifico = 'Megascops choliba' and descrizione is null;
update specie set descrizione = 'The bare-shanked screech owl is a species of owl in the family Strigidae. It is a large owl that feeds at night in forests and lives in a family size group, even during breeding season. The owl''s range is only in Costa Rica, Panama, and far northwestern Colombia. The owl preys on large insects, shrews, and small rodents.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bare-shanked_screech_owl' where nome_scientifico = 'Megascops clarkii' and descrizione is null;
update specie set descrizione = 'The Pacific screech owl is a species of owl in the family Strigidae. It is found in Costa Rica, El Salvador, Guatemala, Honduras, Mexico, and Nicaragua. The Pacific screech owl has sometimes been treated as a race of western screech owl or eastern screech owl but its vocalizations are distinct from theirs. Two subspecies are recognized, the nominate M. c. cooperi and M. c. lambi. The latter has also sometimes been treated as a separate species. The IUCN has assessed the Pacific screech owl as being of Least Concern. Its population is estimated to exceed 50,000 mature individuals but is believed to be decreasing.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pacific_screech_owl' where nome_scientifico = 'Megascops cooperi' and descrizione is null;
update specie set descrizione = 'The Santa Marta screech owl is a species of owl in the family Strigidae. It is found only in the Sierra Nevada de Santa Marta of Colombia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Santa_Marta_screech_owl' where nome_scientifico = 'Megascops gilesi' and descrizione is null;
