update specie set descrizione = 'L''orchetto marino americano è una grande anatra marina, lunga da 43 a 49 centimetri. Insieme all''orchetto marino, M. nigra, forma il sottogenere Oidemia; le due specie vengono a volte considerate conspecifiche, e in tal caso ci si riferisce all''orchetto nero come a M. nigra americana. Il suo nome francese, usato in alcune parti del suo areale canadese, è macreuse noire.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Melanitta_americana' where nome_scientifico = 'Melanitta americana' and descrizione is null;
update specie set descrizione = 'L''orco marino è una grande anatra marina che nidifica oltre l''estremo nord di Europa e Asia, ad ovest del bacino dello Yenisey. Una piccola popolazione isolata nidifica in Turchia orientale, su di un''isola nel lago di Balık. L''orco marino del Pacifico della Siberia orientale e del Nordamerica viene a volte considerato conspecifico dell''orco marino, e le due sottospecie che costituisce sono conosciute come M. f. stejnegeri e M. f. deglandi. L''orco marino e quello del Pacifico, insieme all''orco marino dagli occhiali, vengono classificati nel sottogenere Melanitta, distinto dal sottogenere Oidemia, gli orchetti marini americani e quelli euroasiatici.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Melanitta_fusca' where nome_scientifico = 'Melanitta fusca' and descrizione is null;
update specie set descrizione = 'L''orchetto marino è una grande anatra marina, lunga 43–54 cm, che nidifica oltre l''estremo nord di Europa e Asia, spingendosi ad est fino al fiume Olenyok. La M. americana americana/est siberiana viene a volte considerata una sottospecie di M. nigra.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Melanitta_nigra' where nome_scientifico = 'Melanitta nigra' and descrizione is null;
update specie set descrizione = 'L''orco marino dagli occhiali è una grande anatra marina che nidifica in Canada e in Alaska. Viene classificato nel sottogenere Melanitta, insieme agli orchi marini e agli orchi marini del Pacifico, distinto dal sottogenere Oidemia, gli orchetti marini americani e agli orchetti marini.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Melanitta_perspicillata' where nome_scientifico = 'Melanitta perspicillata' and descrizione is null;
