update specie set descrizione = 'The calandra lark or European calandra-lark breeds in warm temperate countries around the Mediterranean and eastwards through Turkey into northern Iran and southern Russia. It is replaced further east by its relative, the bimaculated lark.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Calandra_lark' where nome_scientifico = 'Melanocorypha calandra' and descrizione is null;
update specie set descrizione = 'The Tibetan lark is a species of lark in the family Alaudidae found on the Tibetan Plateau from north-western India to central China. Alternate names for this species include the Asiatic lark, long-billed calandra lark and long-billed lark.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tibetan_lark' where nome_scientifico = 'Melanocorypha maxima' and descrizione is null;
update specie set descrizione = 'The white-bridled finch, also known as the canary-winged finch or black-throated finch, is a small passerine bird belonging to the genus Melanodera together with the yellow-bridled finch. Formerly placed in the family Emberizidae, it is now considered a tanager. It is found in grassland in southernmost South America. There are two subspecies: M. m. melanodera in the Falkland Islands and M. m. princetoniana in southern Argentina and Chile.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-bridled_finch' where nome_scientifico = 'Melanodera melanodera' and descrizione is null;
