update specie set descrizione = 'La petroica dal cappuccio è un piccolo uccello della famiglia dei Petroicidi originario dell''Australia. Come molte specie dai colori brillanti della famiglia cui appartiene, presenta un certo dimorfismo sessuale: il maschio, infatti, indossa un variopinto piumaggio bianco e nero, mentre la femmina è di un grigio-marrone scialbo.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Melanodryas_cucullata' where nome_scientifico = 'Melanodryas cucullata' and descrizione is null;
