update specie set descrizione = 'Microcentrum rhombifolium is a species of insect in the family Tettigoniidae. Common names include greater angle-wing katydid, broad-winged katydid, and angular-winged katydid. They live across North America in trees and shrubs. Adults reach 50–65 millimetres (2.0–2.6 in) in length and are rhombus-shaped. Their green coloration mimics leaves. Adults are active in late summer and autumn and have a "ticking" call.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Microcentrum_rhombifolium' where nome_scientifico = 'Microcentrum rhombifolium' and descrizione is null;
