update specie set descrizione = 'The rufous woodpecker is a medium-sized brown woodpecker native to South and Southeast Asia. It is short-billed, foraging in pairs on small insects, particularly ants and termites, in scrub, evergreen, and deciduous forests and is noted for building its nest within the carton nests of arboreal ants in the genus Crematogaster. It was for sometime placed in the otherwise Neotropical genus Celeus but this has been shown to be a case of evolutionary convergence and molecular phylogenetic studies support its placement in the monotypic genus Micropternus.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous_woodpecker' where nome_scientifico = 'Micropternus brachyurus' and descrizione is null;
