update specie set descrizione = 'The yellow-faced myna is a species of starling in the family Sturnidae. It is found in New Guinea and nearby smaller islands, where its natural habitat is subtropical or tropical moist lowland forests. The long-tailed myna was formerly included as a subspecies. One of the largest species of starling, this species attains 23 to 26 cm in length and weighs around 217 g (7.7 oz). They have dark plumage with a metallic lustre and bright orange facial markings and beak. These birds are social and omnivorous. Their diet consists of fruit and insects for which they forage high in the canopy. They are common birds with a wide range, and the International Union for Conservation of Nature has assessed their conservation status as being of "least concern". It was named after Charles Dumont.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-faced_myna' where nome_scientifico = 'Mino dumontii' and descrizione is null;
