update specie set descrizione = 'Il vaccaro testabruna, o mòlotro è un piccolo uccello passeriforme della famiglia Icteridae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Molothrus_ater' where nome_scientifico = 'Molothrus ater' and descrizione is null;
update specie set descrizione = 'Il Vaccaro splendente è un uccello passeriforme del Nuovo Mondo della famiglia degli Itteridi. Si riproduce nella maggior parte del Sud America ad eccezione delle fitte foreste e aree di alta quota come le montagne. Dal 1900 la distribuzione dei Vaccari spendenti si è spostata verso nord, ed è stata registrata nelle isole dei Caraibi e negli Stati Uniti, dove si riproduce nel sud della Florida. È un uccello associato ad habitat aperti, incluse le terre deturpata dall''agricoltura e dalla deforestazione.
Gli adulti sono sessualmente dimorfici. I maschi sono tutti neri con un''iridescenza viola-blu. La femmina è più piccola, con piumaggio bruno opaco che a volte è più chiaro sulle parti inferiori. Le femmine della specie possono essere distinte dalla femmina Vaccaro testa bruna per i loro becchi più lunghi e sottili e le teste più piatte. La dieta del Vaccaro splendente è costituita principalmente da insetti e semi ed è stato registrato il foraggiamento di cereali direttamente dalle mangiatoie dei bovini. Come la maggior parte degli altri Vaccari, è un parassita della covata, che depone le uova nei nidi di molte altre specie di uccelli come il Passero dal collare rossiccio o il Fornaio rossiccio. Diverse specie ospiti mostrano differenti risposte quando i loro nidi vengono parassitati, con comportamenti che vanno dall''accettare e prendersi cura delle uova di Vaccaro, al loro rigetto con espulsione dal nido. Poiché il Vaccaro è un efficace parassita della covata, può essere considerato la controparte sudamericana del Vaccaro testa bruna.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Molothrus_bonariensis' where nome_scientifico = 'Molothrus bonariensis' and descrizione is null;
update specie set descrizione = 'The giant cowbird is a large passerine bird in the New World family Icteridae. It breeds from southern Mexico south to northern Argentina, and on Trinidad and Tobago. It may have relatively recently colonised the latter island. It is a brood parasite and lays its eggs in the nests of other birds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Giant_cowbird' where nome_scientifico = 'Molothrus oryzivorus' and descrizione is null;
update specie set descrizione = 'The screaming cowbird is an obligate brood parasite belonging to the family Icteridae and is found in South America. It is also known commonly as the short billed cowbird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Screaming_cowbird' where nome_scientifico = 'Molothrus rufoaxillaris' and descrizione is null;
