update specie set descrizione = 'The blue-capped motmot or blue-crowned motmot, is a colorful near-passerine bird found in forests and woodlands of eastern Mexico. This species and the Lesson''s Motmot, Whooping Motmot, Trinidad Motmot, Amazonian Motmot, and Andean Motmot were all considered conspecific. The IUCN uses blue-crowned as their identifier for this species; however, it was also the name used for the prior species complex.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-capped_motmot' where nome_scientifico = 'Momotus coeruliceps' and descrizione is null;
