update specie set descrizione = 'The Palani laughingthrush is a species of laughingthrush endemic to the hills of the Western Ghats south of the Palghat Gap in Southern India. Found in the high montane forests, this grey bibbed, rufous bellied bird with a prominent dark eyestripe and broad white brow was grouped along with the grey-breasted subspecies of the black-chinned laughingthrush and known as the grey-breasted laughingthrush. This species is found in the Palni Hills while another closely related form, the Ashambu laughingthrush with a shorter white brow is found in the high hills south of the Achankovil Gap and was treated as a subspecies. The two forms were together formerly treated as the Kerala laughingthrush.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Palani_laughingthrush' where nome_scientifico = 'Montecincla fairbanki' and descrizione is null;
