update specie set descrizione = 'The Cape wagtail, also known as Wells''s wagtail, is a small insectivorous bird which is widespread in southern Africa. It frequents water''s edge, lawns and gardens. It is a mostly resident, territorial species, but has been known to undertake limited altitudinal migration or form flocks outside of the breeding season. Like other wagtails they are passerine birds of the family Motacillidae, which also includes the pipits and longclaws.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cape_wagtail' where nome_scientifico = 'Motacilla capensis' and descrizione is null;
