update specie set descrizione = 'The eastern yellow wagtail is a small passerine in the wagtail family Motacillidae, which also includes the pipits and longclaws. It was formerly usually classified as a subspecies of the western yellow wagtail, but was split from it in 2003 when genetic data showed this classification to be paraphyletic with respect to the citrine wagtail. It breeds in the eastern Palearctic and Alaska and migrates to South Asia and Australia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_yellow_wagtail' where nome_scientifico = 'Motacilla tschutschensis' and descrizione is null;
update specie set descrizione = 'The ashy woodpecker is a species of bird in the woodpecker family Picidae. It is endemic to Sulawesi and surrounding islands in Indonesia. There are two subspecies, the nominate race M. f. fulvus, which is found in northern Sulawesi, the islands of Lembeh and Manterawu, and the archipelagos of Togian and Banggai; and M. f. wallacei, from southern Sulawesi and the islands of Muna and Buton. The second subspecies is named for the collector and scientist Alfred Russel Wallace.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ashy_woodpecker' where nome_scientifico = 'Mulleripicus fulvus' and descrizione is null;
update specie set descrizione = 'The great slaty woodpecker is a species of bird in the family Picidae. It is found across the Indian subcontinent and Southeast Asia. A unique and basically unmistakable bird, it is the largest confirmed living woodpecker species, behind the likely extinct imperial woodpecker and ivory-billed woodpecker.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Great_slaty_woodpecker' where nome_scientifico = 'Mulleripicus pulverulentus' and descrizione is null;
update specie set descrizione = 'The African dusky flycatcher, also known as the dusky-brown flycatcher or dusky alseonax, is a small passerine bird of the Old World flycatcher family, Muscicapidae. It is a resident breeder in elevated areas of Sub-Saharan Africa. It is very common in its woodland habitat, which includes riverine forests, evergreen forest edges and clearings, especially near water bodies such as lakes, dams and streams, and well-wooded suburban gardens.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_dusky_flycatcher' where nome_scientifico = 'Muscicapa adusta' and descrizione is null;
update specie set descrizione = 'The swamp flycatcher or swamp alseonax is a species of bird in the family Muscicapidae.
Its range stretches east across the Sudan (region) and south towards Zambia.
Its natural habitats are subtropical or tropical moist shrubland and swamps.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Swamp_flycatcher' where nome_scientifico = 'Muscicapa aquatica' and descrizione is null;
