update specie set descrizione = 'The grey-streaked flycatcher or grey-spotted flycatcher is a small passerine bird breeding in the eastern Palearctic belonging to the genus Muscicapa in the Old World flycatcher family Muscicapidae. The species was first described by Robert Swinhoe in 1861.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-streaked_flycatcher' where nome_scientifico = 'Muscicapa griseisticta' and descrizione is null;
update specie set descrizione = 'The brown-breasted flycatcher or Layard''s flycatcher is a small passerine bird in the flycatcher family Muscicapidae. The species breeds in north eastern India, central and Southern China and northern Burma and Thailand, and migrates to southern India and Sri Lanka. It forages for insects below the forest canopy, often close to the forest floor.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-breasted_flycatcher' where nome_scientifico = 'Muscicapa muttui' and descrizione is null;
update specie set descrizione = 'The dark-sided flycatcher is a small passerine bird belonging to the genus Muscicapa in the Old World flycatcher family Muscicapidae. It has a wide breeding distribution in the East Palearctic with northern birds migrating south for the winter. It is also known as the Siberian flycatcher or sooty flycatcher, the latter name is also used for the sooty flycatcher of Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dark-sided_flycatcher' where nome_scientifico = 'Muscicapa sibirica' and descrizione is null;
update specie set descrizione = 'Il pigliamosche comune è un piccolo uccello passeriforme della famiglia dei Muscicapidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Muscicapa_striata' where nome_scientifico = 'Muscicapa striata' and descrizione is null;
update specie set descrizione = 'The brown-streaked flycatcher is a species of bird in the family Muscicapidae.
It is found in southern Myanmar, southern Thailand, northern peninsular Malaysia, and northeast Borneo. Some authorities consider it to be a subspecies of the Asian brown flycatcher. In 2020, a vagrant was sighted 300 km (190 mi) south of the Australian town of Broome and its identity was confirmed from DNA analysis of the droppings of the bird. 
The species has a rufescent plumage in the breeding season and then becomes drab.
The species name is after the collector Sir Walter James Franklin Williamson.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-streaked_flycatcher' where nome_scientifico = 'Muscicapa williamsoni' and descrizione is null;
