update specie set descrizione = 'The shear-tailed grey tyrant is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Brazil, and Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Shear-tailed_grey_tyrant' where nome_scientifico = 'Muscipipra vetula' and descrizione is null;
update specie set descrizione = 'The white-browed ground tyrant is a species of bird in the family Tyrannidae, the tyrant flycatchers.
