update specie set descrizione = 'La schiribilla collobianco o schiribilla golacenere, unica specie del genere Mustelirallus Bonaparte, 1856, è un uccello della famiglia dei Rallidi originario delle regioni settentrionali, centro-meridionali e sud-orientali del Sudamerica.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Mustelirallus_albicollis' where nome_scientifico = 'Mustelirallus albicollis' and descrizione is null;
