update specie set descrizione = 'The ʻōmaʻo, also called the Hawaiian thrush, is an endemic species of robin-like bird found only on the island of Hawaii. ʻŌmaʻo are closely related to the other endemic thrushes of the Hawaiian Islands, the kāmaʻo, the olomaʻo, and the puaiohi. ʻŌmaʻo are found primarily in rainforests in the eastern and southeastern regions of the Big Island. Population estimates approximate 170,000 birds, making it the most common of the Hawaiian thrushes. It appears to have a stable population, but because the entire population exists on a small range and is endemic to a single island, it is considered near threatened.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/%CA%BB%C5%8Cma%CA%BBo' where nome_scientifico = 'Myadestes obscurus' and descrizione is null;
update specie set descrizione = 'The brown-backed solitaire is a thrush found in montane pine-oak woodlands from Mexico to Honduras.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-backed_solitaire' where nome_scientifico = 'Myadestes occidentalis' and descrizione is null;
update specie set descrizione = 'The puaiohi or small Kauaʻi thrush is a rare species of songbird in the thrush family, Turdidae, that is endemic to the Hawaiian island of Kauaʻi. It is closely related to the other three endemic Hawaiian thrushes, the kāmaʻo, olomaʻo, and ʻōmaʻo. It was first collected by Henry Palmer in 1891 at Halemanu around the entrance to the Kōkeʻe State Park.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Puaiohi' where nome_scientifico = 'Myadestes palmeri' and descrizione is null;
