update specie set descrizione = 'The shining flycatcher is a species of bird in the family Monarchidae.
It is found in northern Australia, and from the Moluccas to the Bismarck Archipelago.
Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical mangrove forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Shining_flycatcher' where nome_scientifico = 'Myiagra alecto' and descrizione is null;
