update specie set descrizione = 'The satin flycatcher is a species of bird in the family Monarchidae. Males stand out with their blue-black feathers contrasting their white bellies, and the females with their bright orange throats. It breeds mostly in south-eastern Tasmania and Australia. It is declining throughout the eastern seaboard due to predation from the introduced Red Fox and habitat loss. It is a vagrant to New Zealand.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Satin_flycatcher' where nome_scientifico = 'Myiagra cyanoleuca' and descrizione is null;
