update specie set descrizione = 'The restless flycatcher or restless myiagra is a passerine bird in the family Monarchidae; it is also known as the razor grinder or scissors grinder because of its distinctive call. It is a native of eastern and southern Australia. Populations in New Guinea and northern Australia, which were at one time considered to be a subspecies, are now accepted as a separate species, the paperbark flycatcher. It is a small to medium-sized bird and has similar colouring to the willie wagtail.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Restless_flycatcher' where nome_scientifico = 'Myiagra inquieta' and descrizione is null;
update specie set descrizione = 'The paperbark flycatcher, also known as the little restless flycatcher, is a passerine bird in the family Monarchidae. It occurs in tropical woodland and riverine habitats of northern Australia and southern New Guinea. Previously, some authorities lumped the paperbark flycatcher as a distinctive subspecies of the restless flycatcher of southern and eastern Australia, with which it forms a superspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Paperbark_flycatcher' where nome_scientifico = 'Myiagra nana' and descrizione is null;
update specie set descrizione = 'The leaden flycatcher is a species of passerine bird in the family Monarchidae. Around 15 cm (6 in) in length, the male is lustrous azure with white underparts, while the female possesses leaden head, mantle and back and rufous throat and breast. It is found in eastern and northern Australia, Indonesia, and Papua New Guinea. Its natural habitat is subtropical or tropical mangrove forests in the northern parts of its range, in the south and inland it is eucalypt woodland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Leaden_flycatcher' where nome_scientifico = 'Myiagra rubecula' and descrizione is null;
update specie set descrizione = 'The broad-billed flycatcher is a species of bird in the family Monarchidae. It is found in northern Australia, the Lesser Sunda Islands and southern New Guinea. Its natural habitats are subtropical or tropical moist lowland forest, subtropical or tropical mangrove forest, and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Broad-billed_flycatcher' where nome_scientifico = 'Myiagra ruficollis' and descrizione is null;
update specie set descrizione = 'The Vanikoro flycatcher is a species of monarch flycatcher in the family Monarchidae. It has a slightly disjunct distribution, occurring on Vanikoro island and in Fiji.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Vanikoro_flycatcher' where nome_scientifico = 'Myiagra vanikorensis' and descrizione is null;
