update specie set descrizione = 'The great crested flycatcher is a large insect-eating bird of the tyrant flycatcher family. It is the most widespread member of the genus Myiarchus in North America, and is found over most of the eastern and mid-western portions of the continent. It dwells mostly in the treetops and rarely is found on the ground.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Great_crested_flycatcher' where nome_scientifico = 'Myiarchus crinitus' and descrizione is null;
