update specie set descrizione = 'The brown-crested flycatcher is a passerine bird in the tyrant flycatcher family Tyrannidae. It is found from the southwestern United States south through Mexico and Central America to Costa Rica; on Aruba, Bonaire, Curaçao, Trinidad, and Tobago; and in every mainland South American country except Chile and possibly Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-crested_flycatcher' where nome_scientifico = 'Myiarchus tyrannulus' and descrizione is null;
