update specie set descrizione = 'The black-tailed myiobius or black-tailed flycatcher is a species of passerine bird in the family Onychorhynchidae. It was previously placed in family Tyrannidae or Tityridae. Black-tailed flycatchers are found in Brazil, Colombia, Costa Rica, Ecuador, Panama, Peru, and Venezuela. Their natural habitats are subtropical or tropical moist lowland forests and heavily degraded former forest. They are usually found alone or in pairs, but may join flocks of several species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-tailed_myiobius' where nome_scientifico = 'Myiobius atricaudus' and descrizione is null;
update specie set descrizione = 'The whiskered myiobius or bearded flycatcher is a species of bird in the family Onychorhynchidae, having previously been included in Tyrannidae and Tityridae. Some taxonomic authorities continue to place them with the flycatchers or tityras. The whiskered myiobius is found in Brazil, Colombia, Ecuador, French Guiana, Guyana, Peru, Suriname, and Venezuela. Its natural habitats are subtropical or tropical moist lowland forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Whiskered_myiobius' where nome_scientifico = 'Myiobius barbatus' and descrizione is null;
update specie set descrizione = 'The sulphur-rumped myiobius or sulphur-rumped flycatcher is a species of passerine bird in the family Onychorhynchidae. It is found in Belize, Colombia, Costa Rica, Ecuador, Guatemala, Honduras, Mexico, Nicaragua, and Panama. Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sulphur-rumped_myiobius' where nome_scientifico = 'Myiobius sulphureipygius' and descrizione is null;
update specie set descrizione = 'The white-fronted whitestart or white-fronted redstart is a species of bird in the family Parulidae. It is endemic to forest and woodland in the Andes in western Venezuela. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-fronted_whitestart' where nome_scientifico = 'Myioborus albifrons' and descrizione is null;
update specie set descrizione = 'The brown-capped whitestart or brown-capped redstart is a species of bird in the family Parulidae.
It is found in humid Andean forests and woodlands in Bolivia and north-western Argentina. It sometimes includes the tepui whitestart as a subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-capped_whitestart' where nome_scientifico = 'Myioborus brunniceps' and descrizione is null;
update specie set descrizione = 'The tepui whitestart or tepui redstart is a species of bird in the family Parulidae.
It is found in humid highland forest, woodland and scrub in the tepuis in southern Venezuela, western Guyana and northern Brazil. It is sometimes included as a subspecies of the brown-capped whitestart.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tepui_whitestart' where nome_scientifico = 'Myioborus castaneocapilla' and descrizione is null;
update specie set descrizione = 'The yellow-crowned whitestart, Santa Marta whitestart or yellow-crowned redstart, is a species of bird in the family Parulidae. It is endemic to the highland forest and woodland in the Santa Marta Mountains in Colombia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-crowned_whitestart' where nome_scientifico = 'Myioborus flavivertex' and descrizione is null;
update specie set descrizione = 'The spectacled whitestart or spectacled redstart is a species of bird in the family Parulidae. It is found in humid Andean forests, woodland and scrub from southern Colombia to Bolivia', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spectacled_whitestart' where nome_scientifico = 'Myioborus melanocephalus' and descrizione is null;
update specie set descrizione = 'The slate-throated whitestart, also known as the slate-throated redstart, is a small insectivorous bird in the New World warbler family Parulidae that is native to Central and South America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slate-throated_whitestart' where nome_scientifico = 'Myioborus miniatus' and descrizione is null;
update specie set descrizione = 'The golden-fronted whitestart or the golden-fronted redstart, is a species of bird in the family Parulidae. It is found in forest, woodland and scrub in the Andes of Colombia and far western Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-fronted_whitestart' where nome_scientifico = 'Myioborus ornatus' and descrizione is null;
update specie set descrizione = 'The painted redstart or painted whitestart is a species of New World warbler found in mountainous areas across inland Central America. They are among the largest warblers, reaching the length of 6 inches (150 mm), tail included. Adult birds have glossy black plumage, with white strips on the wing and a bright red belly. Female and male birds have similar appearance. Unusually for warblers, females are known to be as proficient at singing as their male counterparts.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Painted_redstart' where nome_scientifico = 'Myioborus pictus' and descrizione is null;
update specie set descrizione = 'The collared whitestart, also known as the collared redstart, is a tropical New World warbler endemic to the mountains of Costa Rica and western-central Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Collared_whitestart' where nome_scientifico = 'Myioborus torquatus' and descrizione is null;
