update specie set descrizione = 'The golden-bellied flycatcher is a passerine bird in the family Tyrannidae, the tyrant flycatchers. It is found in Colombia, Costa Rica, Ecuador, Panama, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-bellied_flycatcher' where nome_scientifico = 'Myiodynastes hemichrysus' and descrizione is null;
update specie set descrizione = 'The sulphur-bellied flycatcher is a large member of the family Tyrannidae, the tyrant flycatchers. It is regularly found from southern Arizona in the United States south to Bolivia and occurs casually or as a vagrant further north, east, and south of its usual range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sulphur-bellied_flycatcher' where nome_scientifico = 'Myiodynastes luteiventris' and descrizione is null;
update specie set descrizione = 'The streaked flycatcher is a passerine bird in the family Tyrannidae, the tyrant flycatchers. It is found in Mexico, in every South American country except El Salvador, in Trinidad and Tobago, in every mainland South American country, and as a vagrant to Bonaire.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Streaked_flycatcher' where nome_scientifico = 'Myiodynastes maculatus' and descrizione is null;
update specie set descrizione = 'The white-tailed robin is an Old World flycatcher in the family Muscicapidae. It ranges across the northern regions of the Indian subcontinent and adjacent areas of Southeast Asia. It is found in Bangladesh, Bhutan, Cambodia, India, Laos, Malaysia, Myanmar, Nepal, Taiwan, Thailand, and Vietnam. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-tailed_robin' where nome_scientifico = 'Myiomela leucura' and descrizione is null;
