update specie set descrizione = 'The white-eared myza or greater Sulawesi honeyeater is a species of bird in the family Meliphagidae, with only its sharp calls revealing its presence. The white-eared myza is approximately 20 cm long.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-eared_myza' where nome_scientifico = 'Myza sarasinorum' and descrizione is null;
update specie set descrizione = 'The cardinal myzomela a species of passerine bird in the honeyeater family Meliphagidae. It is named for the scarlet color of the male. It is permanent resident to the Loyalty Islands of New Caledonia, Temotu and Makira-Ulawa of theSolomon Islands, and the entirety of Vanuatu. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical mangrove forest. It frequents areas with flowers, such as gardens. This is a small, active bird, measuring about 13 cm (5.1 in) from bill to tail. Males are red and black in coloration, females are grayish-olive, sometimes with a red cap or red head. Its long, curved bill is especially adapted for reaching into flowers for nectar. It has sometimes been considered as conspecific with the Samoan myzomela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cardinal_myzomela' where nome_scientifico = 'Myzomela cardinalis' and descrizione is null;
update specie set descrizione = 'The red-headed myzomela or red-headed honeyeater is a passerine bird of the honeyeater family Meliphagidae found in Australia, Indonesia, and Papua New Guinea. It was described by John Gould in 1840. Two subspecies are recognised, with the nominate race M. e. erythrocephala distributed around the tropical coastline of Australia, and M. e. infuscata in New Guinea. Though widely distributed, the species is not abundant within this range. While the IUCN lists the Australian population of M. e. infuscata as being near threatened, as a whole the widespread range means that its conservation is of least concern.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-headed_myzomela' where nome_scientifico = 'Myzomela erythrocephala' and descrizione is null;
update specie set descrizione = 'The dusky myzomela or dusky honeyeater is a small, brown bird that is a common resident of the Aru Islands, southern New Guinea and northern and eastern Australia, where there are two separated populations, one in the Top End, another from Cape York Peninsula along the east coast as far south as the New South Wales border, though the species is rare south of Rockhampton. The Moluccan myzomela, red-tinged myzomela, and Biak myzomela were formerly considered conspecific, but was split as distinct species by the IOC in 2021.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky_myzomela' where nome_scientifico = 'Myzomela obscura' and descrizione is null;
update specie set descrizione = 'The red-collared myzomela is a species of bird in the family Meliphagidae.
It is found in New Guinea. The long-billed myzomela of Goodenough Island was formerly considered conspecific, but was split as a distinct species by the IOC in 2021.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-collared_myzomela' where nome_scientifico = 'Myzomela rosenbergii' and descrizione is null;
update specie set descrizione = 'The Micronesian myzomela, also known as the micronesian honeyeater, is a species of honeyeater.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Micronesian_myzomela' where nome_scientifico = 'Myzomela rubratra' and descrizione is null;
update specie set descrizione = 'The scarlet myzomela or scarlet honeyeater is a small passerine bird of the honeyeater family Meliphagidae native to Australia. It was first described by English ornithologist John Latham in 1801. At 9 to 11 cm long, it is the smallest honeyeater in Australia. It has a short tail and relatively long down-curved bill. It is sexually dimorphic; the male is a striking bright red with black wings, while the female is entirely brown. The species is more vocal than most honeyeaters, and a variety of calls have been recorded, including a bell-like tinkling.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet_myzomela' where nome_scientifico = 'Myzomela sanguinolenta' and descrizione is null;
update specie set descrizione = 'Il pappagallino dei tepui è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Nannopsittaca_panychlora' where nome_scientifico = 'Nannopsittaca panychlora' and descrizione is null;
update specie set descrizione = 'The double-crested cormorant is a member of the cormorant family of water birds. It is found near rivers and lakes and in coastal areas and is widely distributed across North America, from the Aleutian Islands in Alaska down to Florida and Mexico. Measuring 70–90 cm (28–35 in) in length, it is entirely black except for a bare patch of orange-yellow facial skin and some extra plumage that it exhibits in the breeding season when it grows a double crest in which black feathers are mingled with white. Five subspecies are recognized. It mainly eats fish and hunts by swimming and diving. Its feathers, like all cormorants, are not waterproof, and it must dry them out after spending time in the water. Once threatened by the use of DDT, the numbers of this bird have increased markedly in recent years.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Double-crested_cormorant' where nome_scientifico = 'Nannopterum auritum' and descrizione is null;
update specie set descrizione = 'The neotropic cormorant or olivaceous cormorant is a medium-sized cormorant found throughout the American tropics and subtropics, from the middle Rio Grande and the Gulf and Californian coasts of the United States south through Mexico and Central America to southern South America, where it is called by the indigenous name of biguá. It also breeds in the Bahamas, Cuba, and Trinidad. It can be found both on coasts and in inland waters. There are at least two subspecies: N. b. mexicanum from Nicaragua northwards and N. b. brasilianum further south. In Peru, the neotropic cormorant is used by the Uru people for fishing.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Neotropic_cormorant' where nome_scientifico = 'Nannopterum brasilianum' and descrizione is null;
update specie set descrizione = 'The short-tailed scimitar babbler or Indochinese wren-babbler, is a species of bird in the family Pellorneidae.
It is found in Laos and Vietnam.
Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.
It is threatened by habitat loss. The Naung Mung scimitar babbler was formerly considered a distinct species, but is now considered conspecific.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Short-tailed_scimitar_babbler' where nome_scientifico = 'Napothera danjoui' and descrizione is null;
