update specie set descrizione = 'Neoconocephalus robustus, known generally as the robust conehead or crepitating conehead, is a species of conehead in the family Tettigoniidae. It is found in North America.
The song of this insect has an incredible volume of 116 decibels.
The peak frequency of the song is 8 kilohertz and the sound can be heard from 500 meters away, even in a driving car with closed windows. From a distance, the song has a whining quality but at close range, it becomes painful to listen to.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Neoconocephalus_robustus' where nome_scientifico = 'Neoconocephalus robustus' and descrizione is null;
