update specie set descrizione = 'Neonemobius cubensis, the Cuban ground cricket, is a species of ground cricket in the family Gryllidae. It is found in the Caribbean. During its mating process the female will often feed upon the male’s glandular tibial spurs. Males who have mated previously will likely be found with some sort of damage done to their tibial spurs because of their mating process.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Neonemobius_cubensis' where nome_scientifico = 'Neonemobius cubensis' and descrizione is null;
update specie set descrizione = 'The saffron-crested tyrant-manakin, or the saffron-crested neopelma, is a species of bird in the family Pipridae, the manakins. A visually striking bird species, it is endemic to the lowland tropical rainforests of South America, with primary distribution areas in countries such as Brazil, Peru, and Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Saffron-crested_tyrant-manakin' where nome_scientifico = 'Neopelma chrysocephalum' and descrizione is null;
