update specie set descrizione = 'The yellow-throated honeyeater is a species of passerine bird in the honeyeater family Meliphagidae. It is similar in behaviour and appearance to the white-eared honeyeater and is endemic to Australia''s island state of Tasmania. It was formerly considered a pest of orchards.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_honeyeater' where nome_scientifico = 'Nesoptilotis flavicollis' and descrizione is null;
update specie set descrizione = 'The white-eared honeyeater is a medium-sized honeyeater found in Australia. It is a member of the family Meliphagidae which has 190 recognised species with about half of them found in Australia. This makes them members of the most diverse family of birds in Australia. White-eared honeyeaters are easily identifiable by their olive-green body, black head and white ear-patch.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-eared_honeyeater' where nome_scientifico = 'Nesoptilotis leucotis' and descrizione is null;
