update specie set descrizione = 'The large niltava is a species of bird in the Old world flycatcher family Muscicapidae. It is found in Bangladesh, Bhutan, Cambodia, China, India, Indonesia, Laos, Malaysia, Myanmar, Nepal, Thailand and Vietnam. Its natural habitat is subtropical or tropical montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Large_niltava' where nome_scientifico = 'Niltava grandis' and descrizione is null;
update specie set descrizione = 'The small niltava is a species of bird in the family Muscicapidae, native to the Indian subcontinent and Southeast Asia. It is found in Bangladesh, Bhutan, India, Laos, Myanmar, Nepal, Thailand, Tibet and Vietnam. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Small_niltava' where nome_scientifico = 'Niltava macgrigoriae' and descrizione is null;
update specie set descrizione = 'The rufous-bellied niltava is a species of bird in the family Muscicapidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-bellied_niltava' where nome_scientifico = 'Niltava sundara' and descrizione is null;
update specie set descrizione = 'The Taiwan vivid niltava or small vivid niltava is a bird in the family Muscicapidae. The species was first described by Robert Swinhoe in 1864. It is endemic to Taiwan. The Chinese vivid niltava of the Asian mainland, which is larger in size, was formerly considered conspecific. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Taiwan_vivid_niltava' where nome_scientifico = 'Niltava vivida' and descrizione is null;
update specie set descrizione = 'The Australian boobook, is a species of owl native to mainland Australia, southern New Guinea, the island of Timor, and the Sunda Islands. Described by John Latham in 1801, it was generally considered to be the same species as the morepork of New Zealand until 1999. Its name is derived from its two-tone boo-book call. Eight subspecies of the Australian boobook are recognized, with three further subspecies being reclassified as separate species in 2019 due to their distinctive calls and genetics.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Australian_boobook' where nome_scientifico = 'Ninox boobook' and descrizione is null;
update specie set descrizione = 'The barking owl or barking boobook, also known as the winking owl, is a nocturnal bird species native to mainland Australia and parts of New Guinea and the Moluccas. They are medium-sized brown owls and have a characteristic voice with calls ranging from a barking dog noise to an intense human-like howl.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Barking_owl' where nome_scientifico = 'Ninox connivens' and descrizione is null;
update specie set descrizione = 'The cinnabar boobook, also known as the cinnabar hawk-owl, is a hawk-owl endemic to the island of Sulawesi, Indonesia. It was described as a new species to science by American ornithologist Pamela C. Rasmussen in 1999 based on a single specimen collected by Frank Rozendaal from Bogani Nani Wartabone National Park on Minahassa Peninsula, northern Sulawesi, in 1985. Subsequently, it has also been observed in Lore Lindu National Park in central Sulawesi, greatly expanding the known habitat range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cinnabar_boobook' where nome_scientifico = 'Ninox ios' and descrizione is null;
update specie set descrizione = 'The northern boobook belongs to the family Strigidae and is a raptorial owl endemic to eastern and southern countries of Asia. The species was considered, until recently, a conspecific of Ninox scutulata or brown boobook, a species of similar distribution encompassing 11 subspecies. The species currently includes two subspecies, the migrant Ninox japonica japonica and the non-migrant Ninox japonica totogo. Despite being considered as the most common breeding owl in Japan, little research has been conducted on the species and subspecies and the taxonomic classification of N. j. totogo and N. j. japonica has been a subject of debate. There are no indications of significant decline in northern boobook populations and therefore its conservation status has been classified as least concern by the IUCN Red List.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_boobook' where nome_scientifico = 'Ninox japonica' and descrizione is null;
update specie set descrizione = 'Il gufastore della Nuova Zelanda, noto anche come civetta boobook, è un uccello rapace della famiglia Strigidae, endemico della Nuova Zelanda.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ninox_novaeseelandiae' where nome_scientifico = 'Ninox novaeseelandiae' and descrizione is null;
update specie set descrizione = 'The Luzon boobook or Luzon hawk owl, also Philippine hawk owl or Philippine boobook, is a species of owl in the family Strigidae. It is endemic to the Philippines where it lives in forests. It is a brown and white mottled bird and males and females look much alike.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Luzon_boobook' where nome_scientifico = 'Ninox philippensis' and descrizione is null;
update specie set descrizione = 'The brown boobook, also known as the brown hawk-owl, is an owl which is a resident breeder in south Asia from India, Sri Lanka, Bhutan, Bangladesh and Nepal east to western Indonesia and south China.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_boobook' where nome_scientifico = 'Ninox scutulata' and descrizione is null;
update specie set descrizione = 'The powerful owl, a species of owl native to south-eastern and eastern Australia, is the largest owl on the continent. It is found in coastal areas and in the Great Dividing Range, rarely more than 200 km (120 mi) inland. The IUCN Red List of Threatened Species also refers to this species as the powerful boobook.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Powerful_owl' where nome_scientifico = 'Ninox strenua' and descrizione is null;
update specie set descrizione = 'The Papuan boobook, jungle boobook or jungle hawk owl, is a medium-sized, dark-colored owl. It has a dark gray-brown facial disk with lighter colored eyebrows, sooty or chocolate underparts, and mainly dark gray wings.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Papuan_boobook' where nome_scientifico = 'Ninox theomacha' and descrizione is null;
