update specie set descrizione = 'The eastern bluebonnet, also known as the greater bluebonnet, is an Australian parrot, one of two species in the genus Northiella. It was originally included in the genus Psephotus but due to distinctive physical and behavioural differences was reclassified into its own genus in 1994 by ornithologists and taxonomists Christidis and Boles. The bluebonnet is a medium-sized inland parrot commonly found in the interior of southeastern and central-southern Australia. It is adapted to life in semi-arid regions but can also flourish in regions of medium rainfall towards the eastern and southern extremities of its range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_bluebonnet' where nome_scientifico = 'Northiella haematogaster' and descrizione is null;
