update specie set descrizione = 'The Guianan puffbird is a species of bird in the family Bucconidae, the puffbirds, nunlets, and nunbirds. It is found in Brazil, French Guiana, Guyana, Suriname, and Venezuela. It was formerly considered to be conspecific with the white-necked puffbird and the buff-bellied puffbird with the English name "white-necked puffbird".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Guianan_puffbird' where nome_scientifico = 'Notharchus macrorhynchos' and descrizione is null;
