update specie set descrizione = 'The stitchbird or hihi is a honeyeater-like bird endemic to the North Island and adjacent offshore islands of New Zealand. Its evolutionary relationships have long puzzled ornithologists, but it is now classed as the only member of its own family, the Notiomystidae. It is rare, being extirpated everywhere except Little Barrier Island, but has been reintroduced to two other island sanctuaries and four locations on the North Island mainland. Current population estimations for mature individuals in the wild are 2,500–3,400.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Stitchbird' where nome_scientifico = 'Notiomystis cincta' and descrizione is null;
