update specie set descrizione = 'The white-tailed deer, also known commonly as the whitetail and the Virginia deer, is a medium-sized species of deer native to North and South America. It is the most widely distributed mainland ungulate herbivore in the Americas; coupled with its natural predator, the mountain lion, it is one of the most widely distributed terrestrial mammal species in the Americas and the world. Highly adaptable, the various subspecies of white-tailed deer inhabit many different ecosystems, from arid grasslands to the Amazon and Orinoco basins; from the Llanos to the high-elevation terrain of the Andes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-tailed_deer' where nome_scientifico = 'Odocoileus virginianus' and descrizione is null;
