update specie set descrizione = 'The familiar chat is a small passerine bird of the Old World flycatcher family Muscicapidae. It is a common resident breeder in Africa south of the Sahara in rocky and mountainous habitat and around human habitation.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Familiar_chat' where nome_scientifico = 'Oenanthe familiaris' and descrizione is null;
update specie set descrizione = 'The brown rock chat or Indian chat is a bird species of the family Muscicapidae. It is found mainly in northern and central India. It is often found in old buildings and rocky areas. It resembles a female Indian robin but lacks the reddish vent and differs in posture and behaviour apart from being larger. In flight it bears some resemblance to thrushes and redstarts. It feeds on insects, captured mainly on the ground. It was formerly placed as the sole species in the genus Cercomela but is now included with the wheatears in the genus Oenanthe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_rock_chat' where nome_scientifico = 'Oenanthe fusca' and descrizione is null;
update specie set descrizione = 'La monachella è un uccello passeriforme, migratore, della famiglia dei Muscicapidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Oenanthe_hispanica' where nome_scientifico = 'Oenanthe hispanica' and descrizione is null;
update specie set descrizione = 'The isabelline wheatear is a small passerine bird that was formerly classed as a member of the thrush family Turdidae, but is now more generally considered to be an Old World flycatcher in the family Muscicapidae. It is a migratory insectivorous bird. Its habitat is steppe and open countryside and it breeds in southern Russia and Central Asia to northern Pakistan, wintering in Africa and northwestern India. It is a very rare vagrant to western Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Isabelline_wheatear' where nome_scientifico = 'Oenanthe isabellina' and descrizione is null;
update specie set descrizione = 'The white-crowned wheatear, or white-crowned black wheatear is a wheatear, a small passerine bird that was formerly classed as a member of the thrush family Turdidae, but is now more generally considered to be an Old World flycatcher, Muscicapidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-crowned_wheatear' where nome_scientifico = 'Oenanthe leucopyga' and descrizione is null;
update specie set descrizione = 'The black wheatear is a wheatear, a small passerine bird in the Old World flycatcher family Muscicapidae. It is found in the Iberian Peninsula and western North Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_wheatear' where nome_scientifico = 'Oenanthe leucura' and descrizione is null;
