update specie set descrizione = 'The blackstart is a chat found in desert regions in North Africa, the Middle East and the Arabian Peninsula. It is resident throughout its range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blackstart' where nome_scientifico = 'Oenanthe melanura' and descrizione is null;
update specie set descrizione = 'The northern wheatear or wheatear is a small passerine bird in the Old World flycatcher family. It is the most widespread member of the wheatear genus Oenanthe in Europe and North and Central Asia. The northern wheatear is a migratory insectivorous species breeding in open stony country in Europe and east across the Palearctic with footholds in northeastern Canada and Greenland as well as in northwestern Canada and Alaska. It nests in rock crevices and rabbit burrows. All birds spend most of their winter in Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_wheatear' where nome_scientifico = 'Oenanthe oenanthe' and descrizione is null;
update specie set descrizione = 'The capped wheatear is a small insectivorous passerine bird that is widely distributed over southern Africa. It was formerly classed as a member of the thrush family Turdidae, but is now placed in the Old World flycatcher family, Muscicapidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Capped_wheatear' where nome_scientifico = 'Oenanthe pileata' and descrizione is null;
update specie set descrizione = 'The pied wheatear is a wheatear, a small insectivorous passerine bird that was formerly classed as a member of the thrush family Turdidae, but is now more generally considered to be an Old World flycatcher. This migratory central Asiatic wheatear occurs from the extreme southeast of Europe to China, and has been found wintering in India and northeastern Africa. It is a very rare vagrant to western Europe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pied_wheatear' where nome_scientifico = 'Oenanthe pleschanka' and descrizione is null;
