update specie set descrizione = 'The ʻakikiki, also called the Kauaʻi creeper, is a critically endangered Hawaiian honeycreeper endemic to Kauaʻi, Hawaiʻi. It is the only member of the genus Oreomystis. Of the Hawaiian birds known to be extant, it is thought to be the most endangered, with only 454 wild individuals reported as of 2018. A survey report in 2021 estimated the population at 45 with a 5 percent annual decrease, in July 2023 the remaining number of wild birds was estimated to be just 5 individuals.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/%CA%BBAkikiki' where nome_scientifico = 'Oreomystis bairdi' and descrizione is null;
