update specie set descrizione = 'La ciacialaca testagrigia è un uccello galliforme della famiglia dei Cracidi. Nidifica nelle pianure dall''Honduras orientale alla Colombia nordoccidentale fino a 1.100 m di altitudine.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_cinereiceps' where nome_scientifico = 'Ortalis cinereiceps' and descrizione is null;
update specie set descrizione = 'Il ciacialaca colombiano è un uccello galliforme della famiglia dei Cracidi, endemico delle foreste e dei boschi delle valli interandine della Colombia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_columbiana' where nome_scientifico = 'Ortalis columbiana' and descrizione is null;
update specie set descrizione = 'La ciacialaca testarossa è una specie di uccello della famiglia Cracidae. Si trova in Colombia, Ecuador e Perù. I suoi habitat naturali sono le foreste secche di latifoglie tropicali e subtropicali, le foreste pluviali di latifoglie tropicali e subtropicali, la foresta montana umida tropicale e subtropicale, le macchie tropicali e subtropicali e le piantagioni. È minacciato dalla distruzione dell''habitat, che causa una continua diminuzione della popolazione.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_erythroptera' where nome_scientifico = 'Ortalis erythroptera' and descrizione is null;
update specie set descrizione = 'La ciacialaca alicastane è un uccello galliforme della famiglia dei Cracidi. Si trova solo in Colombia e i suoi habitat naturali sono le foreste aride di latifoglie tropicali e subtropicali, le foreste pluviali di latifoglie tropicali e subtropicali e le foreste fortemente degradate, ma può adattarsi facilmente a molti ambienti.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_garrula' where nome_scientifico = 'Ortalis garrula' and descrizione is null;
update specie set descrizione = 'Il ciacialaca marezzato è un uccello galliforme della famiglia dei Cracidi. È diffuso in Bolivia, Brasile, Colombia, Ecuador e Perù.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_guttata' where nome_scientifico = 'Ortalis guttata' and descrizione is null;
update specie set descrizione = 'La ciacialaca ventrebianco è una specie di uccello della famiglia Cracidae. Si trova in Costa Rica, El Salvador, Guatemala, Honduras, Messico e Nicaragua. I suoi habitat naturali sono le foreste secche di latifoglie tropicali e subtropicali, le foreste pluviali di latifoglie tropicali e subtropicali e le foreste fortemente degradate.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_leucogastra' where nome_scientifico = 'Ortalis leucogastra' and descrizione is null;
update specie set descrizione = 'La ciacialaca minore è un uccello galliforme della famiglia dei Cracidi, diffuso nella parte settentrionale del Sud America. Misura circa 38 cm di lunghezza e il suo peso varia tra i 380 e i 620 g. Alcune autorità tassonomiche considerano la specie Ortalis ruficeps come una sottospecie del ciacialaca minore, anche se molti la ritengono una specie a sé stante.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_motmot' where nome_scientifico = 'Ortalis motmot' and descrizione is null;
