update specie set descrizione = 'La ciacialaca codarossa è un uccello galliforme della famiglia dei Cracidi. È conosciuto come "guacharaca" in Venezuela e "cocrico" in Trinidad e Tobago, dove è anche l''uccello nazionale insieme all''ibis scarlatto e sullo stemma del Paese rappresenta l''isola di Tobago.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_ruficauda' where nome_scientifico = 'Ortalis ruficauda' and descrizione is null;
