update specie set descrizione = 'La ciacialaca orientale è un uccello galliforme della famiglia dei Cracidi, diffuso in Texas e Messico.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_vetula' where nome_scientifico = 'Ortalis vetula' and descrizione is null;
update specie set descrizione = 'La ciacialaca di Wagler è un uccello galliforme della famiglia dei Cracidi. Si trova solo in Messico e i suoi habitat naturali sono le foreste secche di latifoglie tropicali e subtropicali e le foreste pluviali di latifoglie tropicali e subtropicali, ma si è adattato a vivere anche in ambienti degradati dall''azione umana. Questi uccelli si nutrono di frutta e vivono fino ad un''altezza di 1300 metri, anche se occasionalmente se ne rinvengono esemplari anche a 2000 metri.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortalis_wagleri' where nome_scientifico = 'Ortalis wagleri' and descrizione is null;
