update specie set descrizione = 'The red-bellied macaw, also known as Guacamaya manilata, is a medium-sized, mostly green parrot, a member of a group of large Neotropical parrots known as macaws. It is the largest of what are commonly called "mini-macaws". The belly has a large maroon patch which gives the species its name.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-bellied_macaw' where nome_scientifico = 'Orthopsittaca manilatus' and descrizione is null;
