update specie set descrizione = 'The green-backed tailorbird, also known as the trilling tailorbird, is a species of bird formerly placed in the "Old World warbler" assemblage, but now placed in the family Cisticolidae. The bird is endemic to the Philippines on the Northern side of the island of Luzon. Its natural habitats are tropical moist lowland forests, tropical mangrove forests and secondary growth.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-backed_tailorbird' where nome_scientifico = 'Orthotomus chloronotus' and descrizione is null;
update specie set descrizione = 'L''uccello sarto di Luzon è un uccello della famiglia Cisticolidae, endemico delle Filippine.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Orthotomus_derbianus' where nome_scientifico = 'Orthotomus derbianus' and descrizione is null;
update specie set descrizione = 'The rufous-fronted tailorbird is a species of bird formerly placed in the Old World warbler assemblage, but now placed in the family Cisticolidae. It is native to the southern and eastern Philippines. Its natural habitats are tropical moist lowland forests and tropical mangrove forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-fronted_tailorbird' where nome_scientifico = 'Orthotomus frontalis' and descrizione is null;
update specie set descrizione = 'The black-headed tailorbird, also known as the white-browed tailorbird, is a species of songbird in the cisticola family, Cisticolidae. First formally described by the Scottish ornithologist Arthur Hay in 1877, it is endemic to the southeastern Philippines, where it is found on the islands of Mindanao, Dinagat, and Siargao. It inhabits dense undergrowth in lowland forests at elevations of up to 1,000 m (3,300 ft).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_tailorbird' where nome_scientifico = 'Orthotomus nigriceps' and descrizione is null;
update specie set descrizione = 'The ashy tailorbird is a species of bird formerly placed in the "Old World warbler" assemblage, it but now placed in the family Cisticolidae.
It is found in Brunei, Indonesia, Malaysia, Myanmar, the Philippines, Singapore, and Thailand, Vietnam.
Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical mangrove forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ashy_tailorbird' where nome_scientifico = 'Orthotomus ruficeps' and descrizione is null;
update specie set descrizione = 'The olive-backed tailorbird is a species of passerine bird formerly placed in the "Old World warbler" assemblage, it but now placed in the family Cisticolidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive-backed_tailorbird' where nome_scientifico = 'Orthotomus sepium' and descrizione is null;
update specie set descrizione = 'The rufous-tailed tailorbird is a species of bird formerly placed in the "Old World warbler" assemblage, it but now placed in the family Cisticolidae.
It is found in Brunei, Indonesia, Malaysia, Myanmar, the Philippines, Singapore, and Thailand.
Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical mangrove forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-tailed_tailorbird' where nome_scientifico = 'Orthotomus sericeus' and descrizione is null;
update specie set descrizione = 'The common tailorbird is a songbird found across tropical Asia. Popular for its nest made of leaves "sewn" together and immortalized by Rudyard Kipling as Darzee in his Jungle Book, it is a common resident in urban gardens. Although shy birds that are usually hidden within vegetation, their loud calls are familiar and give away their presence. They are distinctive in having a long upright tail, greenish upper body plumage and rust coloured forehead and crown. This passerine bird is typically found in open farmland, scrub, forest edges and gardens. Tailorbirds get their name from the way their nest is constructed. The edges of a large leaf are pierced and sewn together with plant fibre or spider silk to make a cradle in which the actual nest is built. Punjab tailor birds produce shiny red eggs, but became extinct around 1975 due to laying their eggs in fields used to grow fodder crops.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_tailorbird' where nome_scientifico = 'Orthotomus sutorius' and descrizione is null;
update specie set descrizione = 'The grey francolin is a species of francolin found in the plains and drier parts of the Indian subcontinent and Iran. This species was formerly also called the grey partridge, not to be confused with the European grey partridge. They are mainly ground-living birds and are found in open cultivated lands as well as scrub forest and their local name of teetar is based on their calls, a loud and repeated Ka-tee-tar...tee-tar, which is produced by one or more birds. The term teetar can also refer to other partridges and quails. During the breeding season, calling males attract challengers, and decoys were used to trap these birds especially for fighting.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey_francolin' where nome_scientifico = 'Ortygornis pondicerianus' and descrizione is null;
update specie set descrizione = 'Il francolino crestato (Ortygornis sephaena è un uccello galliforme della famiglia dei Fasianidi, diffuso nell''Africa subsahariana.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ortygornis_sephaena' where nome_scientifico = 'Ortygornis sephaena' and descrizione is null;
