update specie set descrizione = 'The collared scops owl is an owl which is a resident breeder in south Asia from northern Pakistan, northern India, Nepal, Bangladesh, the Himalayas east to southern China, and Taiwan. It is partially migratory, with some birds wintering in India, Sri Lanka and Malaysia. This species was formerly considered to be included within what is now separated as the Indian scops owl.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Collared_scops_owl' where nome_scientifico = 'Otus lettia' and descrizione is null;
