update specie set descrizione = 'Il tordo acquaiolo settentrionale è uno dei rappresentanti più grandi della famiglia dei Parulidi. Nidifica nella parte settentrionale del Nordamerica in Canada e negli Stati Uniti settentrionali, Alaska compresa. È un uccello migratore, che sverna in America centrale, nelle Indie Occidentali e in Florida, nonché in Venezuela, Colombia ed Ecuador. Come visitatore occasionale molto raro, compare talvolta in altri Paesi sudamericani e nell''Europa occidentale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Parkesia_noveboracensis' where nome_scientifico = 'Parkesia noveboracensis' and descrizione is null;
