update specie set descrizione = 'The cinereous tit or Asian tit is a species of bird in the tit family Paridae. This species is made up of several populations that were earlier treated as subspecies of the great tit. These birds are grey backed with white undersides. The great tit in the new sense is distinguishable by the greenish-back and yellowish underside. The distribution of this species extends from parts of West Asia across South Asia and into Southeast Asia. The Japanese tit was formerly treated as a separate species but is now grouped together with the cinereous tit.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cinereous_tit' where nome_scientifico = 'Parus cinereus' and descrizione is null;
