update specie set descrizione = 'Il passero mattugio o passera mattugia è un uccello dell''ordine dei Passeriformes e della famiglia dei Ploceidi, molto comune nei paesi europei.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Passer_montanus' where nome_scientifico = 'Passer montanus' and descrizione is null;
update specie set descrizione = 'Il passero del Sind è una specie di uccello passeriforme della famiglia dei Passeridae. È una specie autoctona del nord ovest del subcontinente indiano, trovandosi oggigiorno principalmente diffuso nell''estremo sudest dell''Iran, in Pakistan e nel nordovest dell''India, vivendo unicamente nelle zone boscose di questi paesi, specialmente nelle zone in presenza di fonti d''acqua dolce e di alti prati. Per il suo aspetto, può essere facilmente confuso con il passero comune diffuso in india grazie alla sottospecie Passer domesticus indicus, anche se è leggermente più piccolo e dai colori più brillanti.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Passer_pyrrhonotus' where nome_scientifico = 'Passer pyrrhonotus' and descrizione is null;
