update specie set descrizione = 'The pale-vented pigeon is a large pigeon found in the tropical Americas. Formerly often placed in Columba, it actually belongs to a clade of the older New World genus Patagioenas. With its relatives it represents an evolutionary radiation extending through most of the warm-temperate to tropical Americas. Grey-hued birds, even their males generally lack iridescent display plumage, although the present species has some coppery gloss on the nape.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale-vented_pigeon' where nome_scientifico = 'Patagioenas cayennensis' and descrizione is null;
update specie set descrizione = 'The bare-eyed pigeon is a species of bird in the family Columbidae. It is found in Colombia, Venezuela, and the Netherlands Antilles.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bare-eyed_pigeon' where nome_scientifico = 'Patagioenas corensis' and descrizione is null;
update specie set descrizione = 'La colomba fasciata è un columbide priginario delle Americhe, nonché il rappresentante più grande della famiglia per quanto riguarda il Nord America. Il suo areale si estende dagli Stati Uniti sud-occidentali e dal Messico fino al Perù.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Patagioenas_fasciata' where nome_scientifico = 'Patagioenas fasciata' and descrizione is null;
update specie set descrizione = 'The red-billed pigeon is a relatively large, robust species of pigeon. Its breeding range extends from southern Texas, United States, to Costa Rica. It is primarily found throughout coastal and lowland areas of Mexico and Central America. It belongs to a clade of Patagioenas which generally lack iridescent display plumage, except some vestiges in the pale-vented pigeon.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-billed_pigeon' where nome_scientifico = 'Patagioenas flavirostris' and descrizione is null;
update specie set descrizione = 'The dusky pigeon is a species of bird in the family Columbidae. It is found in Colombia and Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky_pigeon' where nome_scientifico = 'Patagioenas goodsoni' and descrizione is null;
update specie set descrizione = 'Il piccione capobianco o colomba corona bianca è un uccello della famiglia dei Columbidi originario di un’area che comprende la Florida meridionale, i Caraibi e il Centroamerica orientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Patagioenas_leucocephala' where nome_scientifico = 'Patagioenas leucocephala' and descrizione is null;
update specie set descrizione = 'The spot-winged pigeon is a species of bird in the family Columbidae. It is found in Argentina, Bolivia, Brazil, Chile, Paraguay, Peru, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spot-winged_pigeon' where nome_scientifico = 'Patagioenas maculosa' and descrizione is null;
update specie set descrizione = 'The short-billed pigeon is a largish pigeon which breeds from southern Mexico south to northwestern Colombia. It is a member of a clade of Patagioenas that contains the smaller and rather plain species with characteristic calls that constitute the subgenus Oenoenas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Short-billed_pigeon' where nome_scientifico = 'Patagioenas nigrirostris' and descrizione is null;
