update specie set descrizione = 'The plumbeous pigeon is a species of bird in the family Columbidae. It is found in Bolivia, Brazil, Colombia, Ecuador, French Guiana, Guyana, Panama, Paraguay, Peru, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plumbeous_pigeon' where nome_scientifico = 'Patagioenas plumbea' and descrizione is null;
update specie set descrizione = 'La colomba squamata o piccione squamato è un uccello columbiforme della famiglia Columbidae, diffuso in America del Sud.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Patagioenas_speciosa' where nome_scientifico = 'Patagioenas speciosa' and descrizione is null;
update specie set descrizione = 'The scaly-naped pigeon, also known as the red-necked pigeon, is a bird belonging to the family Columbidae. The species occurs throughout the Caribbean.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scaly-naped_pigeon' where nome_scientifico = 'Patagioenas squamosa' and descrizione is null;
update specie set descrizione = 'The ruddy pigeon is a largish pigeon which breeds from Costa Rica south to western Ecuador, Bolivia, and central Brazil. It belongs to a clade of small and rather plain species of Patagioenas with characteristic calls that constitute the subgenus Oenoenas. Like the other New World pigeons, it was formerly united with their Old World relatives in Columba, but today the New World genus Patagioenas is recognized as distinct again.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ruddy_pigeon' where nome_scientifico = 'Patagioenas subvinacea' and descrizione is null;
