update specie set descrizione = 'Il martin pescatore dal becco di cicogna è un uccello della famiglia Alcedinidae, largamente, ma discontinuamente, diffuso nell''Asia meridionale tropicale, dall''India e dallo Sri Lanka fino all''Indonesia. Questo martin pescatore è pressoché stanziale in tutto il suo areale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pelargopsis_capensis' where nome_scientifico = 'Pelargopsis capensis' and descrizione is null;
