update specie set descrizione = 'The mourning babbler, previously the short-tailed babbler, is a species of bird in the ground babbler family Pellorneidae. It is found in the Malay Peninsula, Anambas Islands, Sumatra, Banyak Islands, Batu Islands, Riau Islands, Lingga Islands and the Natuna Islands. It was formerly considered to be conspecific with the glissando babbler and the leaflitter babbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mourning_babbler' where nome_scientifico = 'Pellorneum malaccense' and descrizione is null;
update specie set descrizione = 'The marsh babbler is a member of the family Pellorneidae. The marsh babbler is endemic to the Brahmaputra floodplain, its associated tributaries and adjacent hill ranges in Assam, Arunachal Pradesh and Meghalaya in India and eastern Bangladesh.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Marsh_babbler' where nome_scientifico = 'Pellorneum palustre' and descrizione is null;
update specie set descrizione = 'The Malayan swamp babbler, previously named the white-chested babbler, is a species of bird in the ground babbler family, Pellorneidae, that is found in the Malay Peninsula, Sumatra, the Riau Islands, the Lingga Islands and the island of Belitung. It was formerly considered to be conspecific with the Bornean swamp babbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Malayan_swamp_babbler' where nome_scientifico = 'Pellorneum rostratum' and descrizione is null;
update specie set descrizione = 'The puff-throated babbler or spotted babbler is a species of passerine bird found in Asia. They are found in scrub and moist forest mainly in hilly regions. They forage in small groups on the forest floor, turning around leaf litter to find their prey and usually staying low in the undergrowth where they can be hard to spot. However, they have loud and distinct calls, including a morning song, contact and alarm calls. It is the type species of the genus Pellorneum which may, however, currently include multiple lineages.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Puff-throated_babbler' where nome_scientifico = 'Pellorneum ruficeps' and descrizione is null;
update specie set descrizione = 'The buff-breasted babbler is a species of bird in the family Pellorneidae. It is found in Bangladesh, Cambodia, China, India, Laos, Malaysia, Myanmar, Thailand, and Vietnam. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buff-breasted_babbler' where nome_scientifico = 'Pellorneum tickelli' and descrizione is null;
