update specie set descrizione = 'The band-tailed guan is a species of bird in the family Cracidae, the chachalacas, guans, and curassows. It is found in Colombia and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Band-tailed_guan' where nome_scientifico = 'Penelope argyrotis' and descrizione is null;
