update specie set descrizione = 'The marail guan or Cayenne guan is a species of bird in the family Cracidae, the chachalacas, guans, and curassows. It is found in Brazil, French Guiana, Guyana, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Marail_guan' where nome_scientifico = 'Penelope marail' and descrizione is null;
update specie set descrizione = 'The Andean guan is a gamefowl species of the family Cracidae, in which it belongs to the guan subfamily Penelopinae. This bird occurs in the highlands of the Andes, from Venezuela and Colombia through Ecuador and Peru south to Bolivia and perhaps northwesternmost Argentina.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Andean_guan' where nome_scientifico = 'Penelope montagnii' and descrizione is null;
update specie set descrizione = 'The dusky-legged guan is a species of bird in the family Cracidae, the chachalacas, guans, and curassows. It is found in Uruguay, northeastern Argentina and southernmost areas of Paraguay and Brazil. In early 2021, the former subspecies P. o. bridgesi, found in southwestern Bolivia and northwestern Argentina, was elevated to species rank as Yungas guan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky-legged_guan' where nome_scientifico = 'Penelope obscura' and descrizione is null;
update specie set descrizione = 'The Cauca guan is a bird in the chachalaca, guan and curassow family, Cracidae. It is a large guan, and like most guans leads a mostly arboreal life in humid forests, where it forages for fruit and leaves. The Cauca guan is endemic to Colombia''s Cauca River valley.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cauca_guan' where nome_scientifico = 'Penelope perspicax' and descrizione is null;
update specie set descrizione = 'The crested guan is a Near Threatened species in an ancient group of birds of the family Cracidae, which are related to the Australasian megapodes or mound builders (Megapodiidae). It is found from central Mexico through Central America and in Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crested_guan' where nome_scientifico = 'Penelope purpurascens' and descrizione is null;
