update specie set descrizione = 'La penelopina nera, guan dalle alture, penelope sopracciliare, o sciacupenba, unica specie del genere Penelopina Reichenbach, 1861, è un uccello galliforme della famiglia dei Cracidi diffuso dal Messico meridionale al Nicaragua.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Penelopina_nigra' where nome_scientifico = 'Penelopina nigra' and descrizione is null;
