update specie set descrizione = 'The Allpahuayo antbird is a Vulnerable species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is endemic to northeastern Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Allpahuayo_antbird' where nome_scientifico = 'Percnostola arenarum' and descrizione is null;
update specie set descrizione = 'The black-headed antbird is a species of passerine bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Brazil, Colombia, French Guiana, Guyana, Peru, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_antbird' where nome_scientifico = 'Percnostola rufifrons' and descrizione is null;
update specie set descrizione = 'The rock bush quail is a species of quail found in parts of peninsular India. It is a common species with a wide range and the IUCN has rated it as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rock_bush_quail' where nome_scientifico = 'Perdicula argoondah' and descrizione is null;
update specie set descrizione = 'The jungle bush quail is a species of quail in the family Phasianidae. It is native to the Indian subcontinent, where it is found in peninsular India and Sri Lanka. It has also been reported from Nepal but has not been seen there since the 19th century, and an introduced population exists on the island of Réunion. A small species of quail 15–18 cm (5.9–7.1 in) long and weighing 57–82 g (2.0–2.9 oz), it shows significant sexual dimorphism. Males have brown upperparts with blackish and buff marking and whitish underparts with black barring. The face is mainly dark reddish-brown, with brown ear-coverts, a buffy-white moustachial stripe, and the supercilium turning whitish towards the back of the neck. Females have a similar pattern, but with pinkish-brown underparts, more uniform wings, and duller moustachial stripes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Jungle_bush_quail' where nome_scientifico = 'Perdicula asiatica' and descrizione is null;
update specie set descrizione = 'The painted bush quail is a species of quail found in the hill forests of India. They move in small coveys on hillsides and are distinguished by their red bills and legs. They have a liquid alarm call and small groups will run in single file along paths before taking flight when flushed.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Painted_bush_quail' where nome_scientifico = 'Perdicula erythrorhyncha' and descrizione is null;
update specie set descrizione = 'La  starna  (Perdix perdix, è un uccello galliforme appartenente alla famiglia dei Fasianidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Perdix_perdix' where nome_scientifico = 'Perdix perdix' and descrizione is null;
update specie set descrizione = 'Swinhoe''s minivet or the brown-rumped minivet is a bird in the cuckooshrike family, Campephagidae. The species was first described by Robert Swinhoe in 1861.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Swinhoe''s_minivet' where nome_scientifico = 'Pericrocotus cantonensis' and descrizione is null;
update specie set descrizione = 'The small minivet is a small passerine bird. This minivet is found in tropical southern Asia from the Indian subcontinent east to Indonesia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Small_minivet' where nome_scientifico = 'Pericrocotus cinnamomeus' and descrizione is null;
update specie set descrizione = 'The ashy minivet is a passerine bird of eastern Asia belonging to the minivet genus Pericrocotus in the cuckooshrike family Campephagidae. While most of the minivets have shades of yellow, orange and red in their plumage, this species has only greys, whites and blacks. The male is distinctive with a white face and black nape although females can be confused with the female of the brown-rumped minivet. They forage in the canopy, often along with other minivets and join mixed-species foraging flocks.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ashy_minivet' where nome_scientifico = 'Pericrocotus divaricatus' and descrizione is null;
update specie set descrizione = 'The white-bellied minivet is a species of minivet found in India, mostly in dry deciduous forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-bellied_minivet' where nome_scientifico = 'Pericrocotus erythropygius' and descrizione is null;
update specie set descrizione = 'The long-tailed minivet is a species of bird in the family Campephagidae. It is found in southern and south-eastern Asia where it occurs in Afghanistan, Bangladesh, Bhutan, China, India, Laos, Myanmar, Nepal, Pakistan, Thailand, and Vietnam. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-tailed_minivet' where nome_scientifico = 'Pericrocotus ethologus' and descrizione is null;
update specie set descrizione = 'The orange minivet is a brightly colored bird in the cuckooshrike family, Campephagidae.
It is found all along the Western Ghats and west coast of India and Sri Lanka.
It was formerly considered a subspecies of the scarlet minivet which is considered to have a wider distribution in eastern and northern India and South-east Asia. Its natural habitats are temperate forests, subtropical or tropical moist lowland forest, and subtropical or tropical moist montane forest. The orange minivet is a species resident in southern India and Sri Lanka, that feeds primarily on insects while foraging in mixed-species bird flocks or in small single-species groups.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange_minivet' where nome_scientifico = 'Pericrocotus flammeus' and descrizione is null;
update specie set descrizione = 'The grey-chinned minivet is a species of bird in the family Campephagidae. It is found from the Himalayas to China, Taiwan and Southeast Asia. Its natural habitat is forests about 1,000–2,000 m (3,300–6,600 ft) in elevation. The International Union for Conservation of Nature (IUCN) has assessed it as a least-concern species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-chinned_minivet' where nome_scientifico = 'Pericrocotus solaris' and descrizione is null;
update specie set descrizione = 'The scarlet minivet is a small passerine bird in the cuckooshrike family Campephagidae. This minivet is found in tropical southern Asia from Northeast India to southern China, Indonesia, and the Philippines. They are common resident breeding birds in forests and other well-wooded habitats including gardens, especially in hilly country. While the male of most subspecies are scarlet to orange with black upper parts, the females are usually yellow with greyish olive upper parts. Several former subspecies have been elevated to a species status in recent works. These include the orange minivet. All subspecies have the same habits of gleaning for insects and are often seen in mixed-species foraging flocks, usually foraging in small groups, high up in the forest canopy.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet_minivet' where nome_scientifico = 'Pericrocotus speciosus' and descrizione is null;
update specie set descrizione = 'The Ryukyu minivet is a species of bird in the family Campephagidae.
It is endemic to Japan. The species was previously thought to be a subspecies of the ashy minivet. Its specific name is named for the Japanese naturalist Seiichi Tegima.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ryukyu_minivet' where nome_scientifico = 'Pericrocotus tegimae' and descrizione is null;
update specie set descrizione = 'La Cincia mora è un uccello della famiglia delle cince (Paridae).', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Periparus_ater' where nome_scientifico = 'Periparus ater' and descrizione is null;
update specie set descrizione = 'The elegant tit is a species of bird in the tit family Paridae endemic to the Philippines. Its natural habitat is tropical moist lowland forests and tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Elegant_tit' where nome_scientifico = 'Periparus elegans' and descrizione is null;
update specie set descrizione = 'The rufous-vented tit is an Asian songbird species in the tit and chickadee family (Paridae). Some of its subspecies were formerly assigned to its western relative the rufous-naped tit, or these two were considered entirely conspecific.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-vented_tit' where nome_scientifico = 'Periparus rubidiventris' and descrizione is null;
update specie set descrizione = 'The rufous-naped tit, also known as the black-breasted tit or dark-grey tit, is an Asian songbird species in the tit and chickadee family (Paridae). It was sometimes considered conspecific with the rufous-vented tit, and was formerly placed in the genus Parus.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-naped_tit' where nome_scientifico = 'Periparus rufonuchalis' and descrizione is null;
update specie set descrizione = 'The yellow-bellied tit is a bird in the family Paridae. The species was first described by Robert Swinhoe in 1870.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-bellied_tit' where nome_scientifico = 'Periparus venustulus' and descrizione is null;
