update specie set descrizione = 'La ghiandaia siberiana è un uccello passeriforme della famiglia dei corvidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Perisoreus_infaustus' where nome_scientifico = 'Perisoreus infaustus' and descrizione is null;
update specie set descrizione = 'L''uccello cappuccino è un uccello passeriforme della famiglia Cotingidae, unica specie ascritta al genere Perissocephalus Oberholser, 1899.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Perissocephalus_tricolor' where nome_scientifico = 'Perissocephalus tricolor' and descrizione is null;
update specie set descrizione = 'Il pecchiaiolo occidentale è una specie di rapace diurno appartenente alla famiglia degli Accipitridi. Specie protetta, insettivora e migratrice, è presente in Europa solamente in estate.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pernis_apivorus' where nome_scientifico = 'Pernis apivorus' and descrizione is null;
update specie set descrizione = 'Il pecchiaiolo orientale è un uccello della famiglia degli Accipitridi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pernis_ptilorhynchus' where nome_scientifico = 'Pernis ptilorhynchus' and descrizione is null;
update specie set descrizione = 'The fairy martin is a member of the swallow family of passerine birds which breeds in Australia. It is migratory wintering through most of Australia, with some birds reaching New Guinea and Indonesia. It is increasingly a wanderer to New Zealand, where it may have bred. This species is frequently placed in the genus Hirundo as Hirundo ariel.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fairy_martin' where nome_scientifico = 'Petrochelidon ariel' and descrizione is null;
update specie set descrizione = 'The streak-throated swallow or the Indian cliff swallow is a passerine bird, which includes a large number of other species including many swallows. It is native of South Asia where it is a breeder, year-round resident or winter visitor in the countries of Afghanistan, India, Nepal and Pakistan. It occurs as a vagrant in the Maldives, Sri Lanka, and the Middle East.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Streak-throated_swallow' where nome_scientifico = 'Petrochelidon fluvicola' and descrizione is null;
update specie set descrizione = 'The cave swallow is a medium-sized, squarish-tailed swallow belonging to the same genus as the more familiar and widespread cliff swallow of North America. The cave swallow, also native to the Americas, nests and roosts primarily in caves and sinkholes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cave_swallow' where nome_scientifico = 'Petrochelidon fulva' and descrizione is null;
update specie set descrizione = 'The tree martin is a member of the swallow family of passerine birds. It breeds in Australia, mostly south of latitude 20°S, and on Timor island. It is migratory, wintering through most of Australia, New Guinea, Indonesia east of the Wallace Line, and the Solomon Islands. It is a vagrant to New Zealand, where it has bred, and New Caledonia. This species is frequently placed in the genus Hirundo as Hirundo nigricans.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tree_martin' where nome_scientifico = 'Petrochelidon nigricans' and descrizione is null;
update specie set descrizione = 'The cliff swallow or  American cliff swallow is a member of the passerine bird family Hirundinidae, the swallows and martins. The generic name Petrochelidon is derived from the Ancient Greek petros meaning "stone" and khelidon (χελιδών) "swallow", and the specific name pyrrhonota comes from purrhos meaning "flame-coloured" and -notos "-backed".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cliff_swallow' where nome_scientifico = 'Petrochelidon pyrrhonota' and descrizione is null;
update specie set descrizione = 'The South African cliff swallow, also known as the South African swallow, is a species of bird in the family Hirundinidae native southern Africa. It winters to the lower Congo Basin.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/South_African_cliff_swallow' where nome_scientifico = 'Petrochelidon spilodera' and descrizione is null;
update specie set descrizione = 'La petroica bruna dell''Isola del Sud è un uccello della famiglia dei Petroicidi originario della Nuova Zelanda, dove gode dello status di specie endemica protetta. È diffusa nell''Isola del Sud e nell''isola Stewart/Rakiura, sebbene la sua distribuzione non sia continua. La specie è strettamente imparentata con la petroica bruna dell''Isola del Nord e con la rarissima petroica delle Chatham dell''arcipelago omonimo.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Petroica_australis' where nome_scientifico = 'Petroica australis' and descrizione is null;
update specie set descrizione = 'La petroica scarlatta è un uccello della famiglia dei Petroicidi originario dell''Australia meridionale e orientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Petroica_boodang' where nome_scientifico = 'Petroica boodang' and descrizione is null;
update specie set descrizione = 'La petroica fronterossa è un uccello della famiglia dei Petroicidi originario dell''Australia centrale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Petroica_goodenovii' where nome_scientifico = 'Petroica goodenovii' and descrizione is null;
update specie set descrizione = 'La petroica bruna dell''Isola del Nord è un uccello della famiglia dei Petroicidi endemico dell''Isola del Nord della Nuova Zelanda. In passato era classificata in un''unica specie assieme alla petroica bruna dell''Isola del Sud dell''Isola del Sud e dell''isola Stewart, ma il sequenziamento del DNA mitocondriale ha mostrato che le due linee evolutive si separarono prima del Pleistocene, supportando perciò la classificazione in due specie distinte.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Petroica_longipes' where nome_scientifico = 'Petroica longipes' and descrizione is null;
update specie set descrizione = 'La petroica della Nuova Zelanda è un uccello della famiglia dei Petroicidi originario, come indica il nome, della Nuova Zelanda. Oltre che sulle due isole principali, questa specie, nota nei luoghi d''origine come Tomtit, si incontra anche su vari arcipelaghi vicini. Gli studiosi ne riconoscono alcune sottospecie, che variano considerevolmente nel piumaggio e nelle dimensioni. La specie non è minacciata e si è adattata bene ai cambiamenti apportati dall''uomo alla biodiversità della Nuova Zelanda.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Petroica_macrocephala' where nome_scientifico = 'Petroica macrocephala' and descrizione is null;
update specie set descrizione = 'La petroica di fiamma è un uccello della famiglia dei Petroicidi originario dell''Australia sud-orientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Petroica_phoenicea' where nome_scientifico = 'Petroica phoenicea' and descrizione is null;
update specie set descrizione = 'La petroica del Pacifico è un uccello della famiglia dei Petroicidi diffuso in Melanesia e Polinesia. È simile nell''aspetto alla petroica scarlatta dell''Australia e fino ad epoca recente le due venivano considerate conspecifiche, prima di essere suddivise in specie distinte da Schodde e Mason nel 1999. Attualmente ne vengono riconosciute nove sottospecie, che differiscono notevolmente tra loro per colorazione del piumaggio, preferenze alimentari e habitat. Anche la petroica di Norfolk e la petroica delle Salomone, con le sue quattro sottospecie, erano considerate varietà della petroica del Pacifico, ma vengono oggi considerate specie a sé.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Petroica_pusilla' where nome_scientifico = 'Petroica pusilla' and descrizione is null;
