update specie set descrizione = 'The common poorwill is a nocturnal bird of the family Caprimulgidae, the nightjars. It is found from British Columbia and southeastern Alberta, through the western United States to northern Mexico. The bird''s habitat is dry, open areas with grasses or shrubs, and even stony desert slopes with very little vegetation.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_poorwill' where nome_scientifico = 'Phalaenoptilus nuttallii' and descrizione is null;
update specie set descrizione = 'The red phalarope or grey phalarope is a small wader. This phalarope breeds in the Arctic regions of North America and Eurasia. It is migratory, and, unusually for a wader, migrates mainly on oceanic routes, wintering at sea on tropical oceans.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red_phalarope' where nome_scientifico = 'Phalaropus fulicarius' and descrizione is null;
