update specie set descrizione = 'The common bronzewing is a species of medium-sized, heavily built pigeon. Native to Australia and one of the country''s most common pigeons, the common bronzewing is able to live in almost any habitat, with the possible exception of very barren areas and dense rainforests. Its advertising call is an extraordinary mournful whooo repeated at metronomic intervals.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_bronzewing' where nome_scientifico = 'Phaps chalcoptera' and descrizione is null;
update specie set descrizione = 'Il piccione alibronzate elegante, alibronzo di macchia o tortora elegante è un uccello appartenente alla famiglia Columbidae endemico dell''Australia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Phaps_elegans' where nome_scientifico = 'Phaps elegans' and descrizione is null;
update specie set descrizione = 'The crested quetzal is a species of bird in the family Trogonidae native to South America, where it is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crested_quetzal' where nome_scientifico = 'Pharomachrus antisianus' and descrizione is null;
update specie set descrizione = 'The golden-headed quetzal or corequenque is a strikingly coloured bird in the genus Pharomachrus. It is found in moist mid-elevation forests from eastern Panama to northern Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-headed_quetzal' where nome_scientifico = 'Pharomachrus auriceps' and descrizione is null;
update specie set descrizione = 'The white-tipped quetzal is a species of bird in the family Trogonidae found in Venezuela, Colombia, and Guyana. Two subspecies have been described. Pharomachrus fulgidus fulgidus is found in the mountains of northern Venezuela and Pharomachrus fulgidus festatus ranges through the Santa Marta mountains of northeast Colombia. Quetzals are iridescent and colourful birds found in forests, woodlands and humid highlands. The white-tipped quetzal has been a limited subject of research. Pharomachrus nests have been studied to analyse the effects of rainfall on breeding, however conclusions are based on single observations. On the IUCN Red list of threatened species, the white-tipped quetzal is listed as a species of least concern.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-tipped_quetzal' where nome_scientifico = 'Pharomachrus fulgidus' and descrizione is null;
update specie set descrizione = 'Il quetzal splendente o trogone splendido è un uccello appartenente alla famiglia Trogonidae, diffuso in America centrale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pharomachrus_mocinno' where nome_scientifico = 'Pharomachrus mocinno' and descrizione is null;
update specie set descrizione = 'The pavonine quetzal is a species of bird in the family Trogonidae, the trogons. It is also known at the peacock trogon, red-billed train bearer, or viuda pico rojo in Spanish. The pavonine quetzal lives in the Neotropics, more specifically in the northern region of the Amazon basin, spreading from Colombia to Bolivia. The most notable characteristics helpful in identifying this bird are its plumage, red beak, and its distribution - it is the only quetzal occupying the lowland rainforest east of the Andes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pavonine_quetzal' where nome_scientifico = 'Pharomachrus pavoninus' and descrizione is null;
