update specie set descrizione = 'The black-backed grosbeak is a bird in the family Cardinalidae, the cardinals or cardinal grosbeaks. It is found in Argentina, Brazil, Bolivia, Colombia, Ecuador, Paraguay, Peru, and Venezuela. They are often kept as cagebirds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-backed_grosbeak' where nome_scientifico = 'Pheucticus aureoventris' and descrizione is null;
update specie set descrizione = 'The golden grosbeak, also known as golden-bellied grosbeak or southern yellow grosbeak, is a species of grosbeak in the family Cardinalidae. It is similar to, and has sometimes been considered conspecific with, the yellow grosbeak.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden_grosbeak' where nome_scientifico = 'Pheucticus chrysogaster' and descrizione is null;
update specie set descrizione = 'The yellow grosbeak, also known as the Mexican yellow grosbeak, is a medium-sized seed-eating bird in the same family as the northern cardinal, "tropical" or "New World" buntings, and "cardinal-grosbeaks" or New World grosbeaks.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow_grosbeak' where nome_scientifico = 'Pheucticus chrysopeplus' and descrizione is null;
update specie set descrizione = 'The rose-breasted grosbeak, colloquially called "cut-throat" due to its coloration, is a large, seed-eating grosbeak in the cardinal family (Cardinalidae). It is primarily a foliage gleaner. Males have black heads, wings, backs, and tails, and a bright rose colored patch on their white breast. Males and females exhibit marked sexual dimorphism.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rose-breasted_grosbeak' where nome_scientifico = 'Pheucticus ludovicianus' and descrizione is null;
update specie set descrizione = 'The black-headed grosbeak is a medium-sized, seed-eating bird in the family Cardinalidae. It is sometimes considered conspecific with the rose-breasted grosbeak with which it hybridizes on the American Great Plains.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_grosbeak' where nome_scientifico = 'Pheucticus melanocephalus' and descrizione is null;
