update specie set descrizione = 'The black-throated wren is a species of bird in the family Troglodytidae. It is found in Costa Rica, Nicaragua, and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_wren' where nome_scientifico = 'Pheugopedius atrogularis' and descrizione is null;
update specie set descrizione = 'The coraya wren is a species of bird in the family Troglodytidae, the wrens.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Coraya_wren' where nome_scientifico = 'Pheugopedius coraya' and descrizione is null;
update specie set descrizione = 'The Inca wren is a species of bird in the family Troglodytidae. It is endemic to Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Inca_wren' where nome_scientifico = 'Pheugopedius eisenmanni' and descrizione is null;
update specie set descrizione = 'The plain-tailed wren is a species of songbird in the family Troglodytidae. It has a mostly rufous body with a gray, black, and white striped head. It is found in the Andes of southern Colombia, Ecuador, and northern Peru. Its natural habitat is subtropical or tropical moist montane forests. Plain-tailed wrens are so-called bamboo specialists and live almost exclusively in chusquea bamboo thickets. Like other wrens, its diet consists mainly of insects with some seeds and berries.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plain-tailed_wren' where nome_scientifico = 'Pheugopedius euophrys' and descrizione is null;
update specie set descrizione = 'The black-bellied wren is a species of bird in the family Troglodytidae. It is found in Colombia, Costa Rica, and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-bellied_wren' where nome_scientifico = 'Pheugopedius fasciatoventris' and descrizione is null;
update specie set descrizione = 'The happy wren is a species of bird in the family Troglodytidae. It is endemic to the Pacific slope of western Mexico, from the state of Sonora to the state of Oaxaca, and also on islands west of the Mexican coast. As with other species of Pheugopedius, older sources classify it within genus Thryothorus. Some authorities have treated it as a subspecies of P. rutilus or P. sclateri. There is significant geographical variation, and six subspecies are recognized: P. f. sonorae is found in southern Sonora and northern Sinaloa; P. f. pallidus is found in central Sinaloa, western Durango and southwards to Jalisco and Michoacán; P. f. lawrencii and P. f. magdalenae are found on different islands of the Islas Marías; P. f. grandis is found in the Balsas River basin, and the nominate subspecies, P. f. felix in southwestern Mexico from Jalisco to Oaxaca.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Happy_wren' where nome_scientifico = 'Pheugopedius felix' and descrizione is null;
update specie set descrizione = 'The moustached wren is a species of bird in the family Troglodytidae. It is found in Bolivia, Brazil, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Moustached_wren' where nome_scientifico = 'Pheugopedius genibarbis' and descrizione is null;
update specie set descrizione = 'The spot-breasted wren is a species of bird in the family Troglodytidae. It is found in Belize, Costa Rica, El Salvador, Guatemala, Honduras, Mexico, and Nicaragua.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spot-breasted_wren' where nome_scientifico = 'Pheugopedius maculipectus' and descrizione is null;
