update specie set descrizione = 'The helmeted friarbird is part of the Meliphagidae family. The helmeted friarbird, along with all their subspecies, is commonly referred to as "leatherhead" by the birding community.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Helmeted_friarbird' where nome_scientifico = 'Philemon buceroides' and descrizione is null;
update specie set descrizione = 'The little friarbird, also known as the little leatherhead or yellow-throated friarbird, is the smallest of the friarbirds within the Philemon genus. It is found throughout northern and eastern Australia as well as southern Papua New Guinea. It lives a very prominent life, whereby it can easily be seen chasing other honeyeaters, and also it is very vocal. However, the little friarbird is usually spotted high up in trees, rarely being seen on the ground.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Little_friarbird' where nome_scientifico = 'Philemon citreogularis' and descrizione is null;
update specie set descrizione = 'The noisy friarbird is a passerine bird of the honeyeater family Meliphagidae native to southern New Guinea and eastern Australia. It is one of several species known as friarbirds whose heads are bare of feathers. It is brown-grey in colour, with a prominent knob on its bare black-skinned head. It feeds on insects and nectar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Noisy_friarbird' where nome_scientifico = 'Philemon corniculatus' and descrizione is null;
