update specie set descrizione = 'Il calleide caruncolato dell''Isola del Nord o sellarossa dell''Isola del Nord è un uccello passeriforme della famiglia dei Calleidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Philesturnus_rufusater' where nome_scientifico = 'Philesturnus rufusater' and descrizione is null;
update specie set descrizione = 'The sociable weaver is a species of bird in the weaver family, endemic to Southern Africa. It is the only species in its genus Philetairus. It is found in South Africa, Namibia, and Botswana, but its range is centered within the Northern Cape Province of South Africa. The species builds large, compound, community nests, a rarity among birds. These nests are perhaps the most spectacular structure built by any bird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sociable_weaver' where nome_scientifico = 'Philetairus socius' and descrizione is null;
