update specie set descrizione = 'The Ecuadorian piedtail is a species of hummingbird in the "coquettes", tribe Lesbiini of subfamily Lesbiinae. It is found in Colombia, Ecuador, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ecuadorian_piedtail' where nome_scientifico = 'Phlogophilus hemileucurus' and descrizione is null;
update specie set descrizione = 'The Sri Lanka bay owl is a species of bay owl in the family Tytonidae. It is endemic to the island of Sri Lanka and the Western Ghats in Kerala, South Western India. It was considered a subspecies of the Oriental bay owl but is now treated as a full species due to its distinctive call, plumage and disjunct distribution.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sri_Lanka_bay_owl' where nome_scientifico = 'Phodilus assimilis' and descrizione is null;
update specie set descrizione = 'The Oriental bay owl is a species of bay owl. It is completely nocturnal, and can be found throughout Southeast Asia and parts of India. It has several subspecies. It has a heart-shaped face with earlike extensions. The Congo bay owl was formerly classified as a subspecies of Oriental bay owl due to insufficient knowledge, but it has turned out that it might not even belong to the same genus. The Sri Lanka bay owl was also considered a subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Oriental_bay_owl' where nome_scientifico = 'Phodilus badius' and descrizione is null;
update specie set descrizione = 'L''albatro di Laysan è un grosso uccello marino diffuso in tutto il Pacifico settentrionale. Questo volatile, di dimensioni piuttosto piccole rispetto agli altri membri della famiglia dei Diomedeidi, è la seconda specie di uccello marino più comune delle Isole Hawaii, dove si stima ne vivano 2,5 milioni di esemplari; inoltre, sta colonizzando altre isole. Prende il nome da Laysan, una delle Isole Hawaii Nord-occidentali; su quest''isola, infatti, è presente la colonia più numerosa di questi uccelli.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Phoebastria_immutabilis' where nome_scientifico = 'Phoebastria immutabilis' and descrizione is null;
