update specie set descrizione = 'The Guianan red cotinga is a species of bird in the family Cotingidae, the cotingas. It is found in Brazil, French Guiana, Guyana, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Guianan_red_cotinga' where nome_scientifico = 'Phoenicircus carnifex' and descrizione is null;
