update specie set descrizione = 'Il fenicottero minore è un uccello appartenente alla famiglia Phoenicopteridae. È la specie di fenicottero più piccola e più diffusa numericamente in assoluto.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Phoeniconaias_minor' where nome_scientifico = 'Phoeniconaias minor' and descrizione is null;
