update specie set descrizione = 'The green wood hoopoe is a large, up to 44 cm (17 in) long tropical bird native to Africa. It is a member of the family Phoeniculidae, the wood hoopoes, and was formerly known as the red-billed wood hoopoe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green_wood_hoopoe' where nome_scientifico = 'Phoeniculus purpureus' and descrizione is null;
update specie set descrizione = 'The Daurian redstart is a small passerine bird from temperate Asia. The species was first described by Peter Simon Pallas in 1776.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Daurian_redstart' where nome_scientifico = 'Phoenicurus auroreus' and descrizione is null;
update specie set descrizione = 'The blue-fronted redstart is a species of bird in the family Muscicapidae, the Old World flycatchers. It breeds in central China and the Himalayas (where it winters in the southern foothills, as well as in southern Yunnan, the Patkai and northern Indochina. Its natural habitat is temperate forests. The female is brownish-grey, with paler underparts.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-fronted_redstart' where nome_scientifico = 'Phoenicurus frontalis' and descrizione is null;
update specie set descrizione = 'The plumbeous water redstart is a passerine bird in the Old World flycatcher family Muscicapidae. It is found in South Asia, Southeast Asia and China. Males are slate blue in colour, while females are grey. The bird''s common name refers to its colour which resembles lead. They tend to live near fast-moving streams and rivers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plumbeous_water_redstart' where nome_scientifico = 'Phoenicurus fuliginosus' and descrizione is null;
update specie set descrizione = 'The white-capped redstart or white-capped water redstart is a passerine bird of the Old World flycatcher family Muscicapidae native to the Indian subcontinent, Southeast Asia, much of China, and to certain regions of Central Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-capped_redstart' where nome_scientifico = 'Phoenicurus leucocephalus' and descrizione is null;
