update specie set descrizione = 'The Iberian chiffchaff is a species of passerine belonging to the family Phylloscopidae, the leaf warblers. This species is found as a breeding bird in southwestern Europe and northwestern Africa. It winters in western Africa south of the Sahara Desert.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Iberian_chiffchaff' where nome_scientifico = 'Phylloscopus ibericus' and descrizione is null;
update specie set descrizione = 'The yellow-browed warbler is a leaf warbler which breeds in the east Palearctic. This warbler is strongly migratory and winters mainly in tropical South Asia and South-east Asia, but also in small numbers in western Europe. Like the rest of Phylloscopidae, it was formerly included in the Old World warbler assemblage.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-browed_warbler' where nome_scientifico = 'Phylloscopus inornatus' and descrizione is null;
update specie set descrizione = 'The white-spectacled warbler is a species of leaf warbler in the family Phylloscopidae. It is found in Asia from the eastern Himalayas to south-eastern China and southern Vietnam. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests. It was formerly included in the Old World warbler family, Sylviidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-spectacled_warbler' where nome_scientifico = 'Phylloscopus intermedius' and descrizione is null;
update specie set descrizione = 'The Gansu leaf warbler is a small passerine bird known only from China. It belongs to the leaf warbler genus Phylloscopus within the family Phylloscopidae. It was formerly treated as a subspecies of Pallas''s warbler but is now regarded as a separate species based on differences in voice and cytochrome-b gene sequences.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gansu_leaf_warbler' where nome_scientifico = 'Phylloscopus kansuensis' and descrizione is null;
