update specie set descrizione = 'The large-billed leaf warbler is a species of migratory leaf warbler found in Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Large-billed_leaf_warbler' where nome_scientifico = 'Phylloscopus magnirostris' and descrizione is null;
update specie set descrizione = 'The yellow-breasted warbler is a species of Old World warbler in the family Phylloscopidae. It is found in Indonesia, Malaysia, and Palawan Island in the Philippines. The species is most common on the islands of Sumatra and Borneo in Indonesia. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-breasted_warbler' where nome_scientifico = 'Phylloscopus montis' and descrizione is null;
