update specie set descrizione = 'The yellow-throated woodland warbler is a species of Old World warbler in the family Phylloscopidae. It is endemic to the Afromontane, from Kenya to South Africa. Its natural habitats are subtropical or tropical dry forest and subtropical or tropical moist lowland forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_woodland_warbler' where nome_scientifico = 'Phylloscopus ruficapilla' and descrizione is null;
update specie set descrizione = 'The Lompobattang leaf warbler is a species of Old World warbler in the family Phylloscopidae.
It is found only in Sulawesi Island, Indonesia. The Sulawesi leaf warbler was formerly considered conspecific with the Lompobattang leaf warbler and both were grouped under the name P. sarasinorum, but more recent analyses indicate that it is a distinct species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lompobattang_leaf_warbler' where nome_scientifico = 'Phylloscopus sarasinorum' and descrizione is null;
