update specie set descrizione = 'The Japanese leaf warbler is a leaf warbler. The species was first described by Robert Swinhoe in 1863. It was formerly included in the "Old World warbler" assemblage. It is closely related to the Arctic warbler and the Kamchatka leaf warbler, to which it was formerly considered conspecific.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Japanese_leaf_warbler' where nome_scientifico = 'Phylloscopus xanthodryas' and descrizione is null;
