update specie set descrizione = 'The black-rumped magpie is a species of magpie native to west-central China and Bhutan, and possibly also irregularly in Sikkim in India, and in eastern Nepal. It is similar to other magpies in the genus Pica, with pied plumage with bluish-green iridescent wings and tail, but differs from the other species in the genus except for Asir magpie in having no white on the rump. It was described as a species in 1840, but had long been treated as a subspecies of Eurasian magpie, before being restored to species rank in 2018. In breeding behaviour it is largely similar to other Pica magpies, laying a single brood from April to June.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-rumped_magpie' where nome_scientifico = 'Pica bottanensis' and descrizione is null;
