update specie set descrizione = 'Il picchio cenerino, detto anche picchio bigio, è un uccello facente parte della famiglia dei Picchi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Picus_canus' where nome_scientifico = 'Picus canus' and descrizione is null;
update specie set descrizione = 'The lesser yellownape is a type of woodpecker which is a widespread and often common breeder in tropical and sub-tropical Asia, primarily the Indian subcontinent and Southeast Asia. It ranges from India, Bhutan, Nepal, Bangladesh and Sri Lanka eastwards to Thailand, Burma, Cambodia, Laos, Indonesia, Malaysia and Vietnam. Much of the scientific knowledge gathered about this species is sourced from formal studies in various parts of India.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_yellownape' where nome_scientifico = 'Picus chlorolophus' and descrizione is null;
update specie set descrizione = 'The black-headed woodpecker is a species of bird in the family Picidae. It typically inhabits deciduous and coniferous forests and is found in Cambodia, Laos, Myanmar, Thailand, and Vietnam.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_woodpecker' where nome_scientifico = 'Picus erythropygius' and descrizione is null;
update specie set descrizione = 'The crimson-winged woodpecker is a species of bird in the woodpecker family. It is found in Brunei, Indonesia, Malaysia, Myanmar, Singapore, and Thailand. Its natural habitat is subtropical or tropical moist lowland forests. It can grow up to 25 cm long. Its diet is mainly insects and larvae. It is a bright and colourful bird that is hard to misidentify.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-winged_woodpecker' where nome_scientifico = 'Picus puniceus' and descrizione is null;
update specie set descrizione = 'The Iberian green woodpecker is a medium-sized woodpecker endemic to the Iberian peninsula. It was formerly considered as a subspecies of the European green woodpecker but differs in having little black on the head and a dusky rather than a black ring around each eye. Its sound has been described as sibilant, or hiss-like.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Iberian_green_woodpecker' where nome_scientifico = 'Picus sharpei' and descrizione is null;
update specie set descrizione = 'The scaly-bellied woodpecker is a species of bird in the family Picidae. It is found in the Indian subcontinent and adjoining regions, ranging across Afghanistan, Iran, India, Nepal, Pakistan, and Turkmenistan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scaly-bellied_woodpecker' where nome_scientifico = 'Picus squamatus' and descrizione is null;
update specie set descrizione = 'Il picchio verde è un uccello della famiglia dei Picidae, diffuso in Eurasia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Picus_viridis' where nome_scientifico = 'Picus viridis' and descrizione is null;
update specie set descrizione = 'The laced woodpecker is a species of bird in the family Picidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Laced_woodpecker' where nome_scientifico = 'Picus vittatus' and descrizione is null;
update specie set descrizione = 'The streak-throated woodpecker is a species of woodpecker found in the Indian subcontinent. It occurs in drier woodland, from lowland to the foothills of mountains.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Streak-throated_woodpecker' where nome_scientifico = 'Picus xanthopygaeus' and descrizione is null;
update specie set descrizione = 'The pine grosbeak is a large member of the true finch family, Fringillidae. It is the only species in the genus Pinicola. It is found in coniferous woods across Alaska, the western mountains of the United States, Canada, and in subarctic Fennoscandia and across the Palearctic to Siberia. The species is a frugivore, especially in winter, favoring small fruits, such as rowans. With fruit-crop abundance varying from year to year, pine grosbeak is one of many subarctic-resident bird species that exhibit irruptive behavior. In irruption years, individuals can move long distances in search of suitable food supplies, bringing them farther south and/or downslope than is typical of years with large fruit crops.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pine_grosbeak' where nome_scientifico = 'Pinicola enucleator' and descrizione is null;
update specie set descrizione = 'The white-bellied parrot, or white-bellied caique in aviculture, is a species of bird in the subfamily Arinae of the family Psittacidae, the African and New World parrots. It is found in Bolivia, Brazil, Colombia, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-bellied_parrot' where nome_scientifico = 'Pionites leucogaster' and descrizione is null;
update specie set descrizione = 'The black-headed parrot is a species of bird in subfamily Arinae of the family Psittacidae, the African and New World parrots. Other colloquial names are black-crowned parrot, black-capped parrot, black-headed caique, and for subspecies P. m. pallidus, pallid caique. It is found in Brazil, Colombia, Ecuador, French Guiana, Guyana, Peru, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_parrot' where nome_scientifico = 'Pionites melanocephalus' and descrizione is null;
update specie set descrizione = 'Il pappagallo pileato è un uccello della famiglia degli Psittacidi. È l''unica specie del genere Pionopsitta Bonaparte, 1854.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pionopsitta_pileata' where nome_scientifico = 'Pionopsitta pileata' and descrizione is null;
update specie set descrizione = 'Il pappagallo alibronzate è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pionus_chalcopterus' where nome_scientifico = 'Pionus chalcopterus' and descrizione is null;
update specie set descrizione = 'Il pappagallo fosco è un uccello della famiglia degli Psittacidi. È sicuramente il Pionus più difficile da trovare in cattività, nonostante sia ben diffuso nel suo areale che si estende dalla Guyana al Venezuela alla Colombia al nord del Brasile. Si presenta con colore base marroncino violaceo, testa sfumata in azzurro, petto e parti ventrali in rosa. Remiganti e timoniere sono blu, sottocoda rosso, sottoala viola, groppone nero. Ha un evidente anello perioftalmico bianco, iride bruna, becco nerastro segnato di giallo alla base, zampe grigie. Ha taglia attorno ai 26 cm. Abita ambienti diversi, dalle foreste primarie fino ai 1800 metri di quota, alle foreste a galleria, a quelle costiere e alle savane. Nidifica in alberi alti e secchi, a partire da aprile, abbastanza in alto e le nidiate sono normalmente di 2-4 piccoli.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pionus_fuscus' where nome_scientifico = 'Pionus fuscus' and descrizione is null;
update specie set descrizione = 'Il pappagallo testasquamata è un uccello della famiglia degli Psittacidi. Classificato in quattro sottospecie piuttosto simili tra loro, questo pappagallo ha taglia attorno ai 29 cm, colorazione generale verde intenso, ampio collare tra gola e petto di un blu cupo, sottocoda rosso, anello perioftalmico chiaro, iride bruna, becco e zampe grigio-neri. Vive nel nord dell''Argentina e nel Brasile centro-orientale, dove abita prevalentemente le foreste umide subtropicali temperate di pianura, le boscaglie aperte e le foreste a galleria e quelle ricche di araucaria, delle cui noci è ghiotto. È stato avvistato fino ad altezze attorno ai 2000 metri. Comune nel suo areale è anche piuttosto noto in cattività, dove si riproduce con regolarità.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pionus_maximiliani' where nome_scientifico = 'Pionus maximiliani' and descrizione is null;
update specie set descrizione = 'Il pappagallo testablu è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pionus_menstruus' where nome_scientifico = 'Pionus menstruus' and descrizione is null;
