update specie set descrizione = 'The green-tailed towhee is a species of bird in the family Passerellidae, the New World sparrows. It is found in the western United States and much of Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-tailed_towhee' where nome_scientifico = 'Pipilo chlorurus' and descrizione is null;
update specie set descrizione = 'The eastern towhee, also known as chewink, joree, or joree bird, is a large New World sparrow. The taxonomy of the towhees has been under debate in recent decades, and formerly this bird and the spotted towhee were considered a single species, the rufous-sided towhee.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_towhee' where nome_scientifico = 'Pipilo erythrophthalmus' and descrizione is null;
update specie set descrizione = 'The spotted towhee is a large New World sparrow. The taxonomy of the towhees has been debated in recent decades, and until 1995 this bird and the eastern towhee were considered a single species, then named rufous-sided towhee. Another outdated name for the spotted towhee is the Oregon towhee. The call may be harsher and more varied than for the eastern towhee.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spotted_towhee' where nome_scientifico = 'Pipilo maculatus' and descrizione is null;
update specie set descrizione = 'The collared towhee is a species of bird in the family Passerellidae, the New World sparrows. It is endemic to Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Collared_towhee' where nome_scientifico = 'Pipilo ocai' and descrizione is null;
update specie set descrizione = 'The crimson-hooded manakin, also known as orange-headed manakin, is a species of passerine bird in the family Pipridae. It is found in Brazil, French Guiana, Guyana, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-hooded_manakin' where nome_scientifico = 'Pipra aureola' and descrizione is null;
update specie set descrizione = 'The band-tailed manakin is a species of bird in the family Pipridae. It is a small, frugivorous passerine found in humid montane and lowland tropical forests throughout Argentina, Bolivia, Brazil, Paraguay, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Band-tailed_manakin' where nome_scientifico = 'Pipra fasciicauda' and descrizione is null;
update specie set descrizione = 'The wire-tailed manakin is a species of bird in the family Pipridae. It is found Brazil, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Wire-tailed_manakin' where nome_scientifico = 'Pipra filicauda' and descrizione is null;
update specie set descrizione = 'The fawn-breasted tanager is a species of tanager with a blue head and yellow breast. It occurs in the Andes of northwestern Argentina, Bolivia, Colombia, Ecuador, Peru, and Venezuela, as well as in the highlands of northeastern Argentina, south Brazil, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fawn-breasted_tanager' where nome_scientifico = 'Pipraeidea melanonota' and descrizione is null;
update specie set descrizione = 'The barred fruiteater is a species of bird in the family Cotingidae, the cotingas. It is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Barred_fruiteater' where nome_scientifico = 'Pipreola arcuata' and descrizione is null;
update specie set descrizione = 'The golden-breasted fruiteater is a species of bird in the family Cotingidae, the cotingas. It is found in Colombia and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-breasted_fruiteater' where nome_scientifico = 'Pipreola aureopectus' and descrizione is null;
update specie set descrizione = 'The handsome fruiteater is a species of bird in the family Cotingidae, the cotingas. It is endemic to Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Handsome_fruiteater' where nome_scientifico = 'Pipreola formosa' and descrizione is null;
update specie set descrizione = 'The scarlet-breasted fruiteater is a species of bird in the family Cotingidae.
It is found in Bolivia, Ecuador, and Peru where its natural habitat is subtropical and tropical moist montane forests. Two subspecies are recognised though some researchers consider these should be regarded as distinct species. It is a plump green bird with a black head, the males having red throats and the females yellow. It is a relatively common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet-breasted_fruiteater' where nome_scientifico = 'Pipreola frontalis' and descrizione is null;
update specie set descrizione = 'The band-tailed fruiteater is a species of bird in the family Cotingidae, the cotingas. It is found in Bolivia and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Band-tailed_fruiteater' where nome_scientifico = 'Pipreola intermedia' and descrizione is null;
update specie set descrizione = 'The orange-breasted fruiteater is a species of bird in the family Cotingidae native to Colombia and Ecuador. Its natural habitat is subtropical or tropical moist montane forests. It is a plump green bird about 18 centimetres (7 in) long. Males have a glossy black head and bib, an orange throat and yellow belly. Females lack the dark head and have green upper parts and green and yellow streaked underparts. Both sexes have orange beaks and greyish-green legs. This is a relatively common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-breasted_fruiteater' where nome_scientifico = 'Pipreola jucunda' and descrizione is null;
update specie set descrizione = 'The black-chested fruiteater is a species of bird in the family Cotingidae found in Colombia, Ecuador, and Peru, mostly on the eastern side of the Andes. Its natural habitat is subtropical and tropical moist montane forests and the IUCN lists its status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-chested_fruiteater' where nome_scientifico = 'Pipreola lubomirskii' and descrizione is null;
update specie set descrizione = 'The green-and-black fruiteater is a species of bird in the family Cotingidae, the cotingas. It is found in Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-and-black_fruiteater' where nome_scientifico = 'Pipreola riefferii' and descrizione is null;
update specie set descrizione = 'The red-banded fruiteater is a species of bird in the family Cotingidae, the cotingas. It is found in Brazil, Guyana, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-banded_fruiteater' where nome_scientifico = 'Pipreola whitelyi' and descrizione is null;
update specie set descrizione = 'The wing-barred piprites is a species of bird in subfamily Pipritinae of family Tyrannidae, the tyrant flycatchers. It is found in every mainland South American country except Chile and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Wing-barred_piprites' where nome_scientifico = 'Piprites chloris' and descrizione is null;
update specie set descrizione = 'Il manachino testagrigia è un uccello passeriforme della famiglia Tyrannidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Piprites_griseiceps' where nome_scientifico = 'Piprites griseiceps' and descrizione is null;
update specie set descrizione = 'The black-capped piprites, also known as the black-capped manakin, bailarín castaño, or piprites capirotado, is a species of suboscine passerine. It has been placed in the genus Piprites, part of the Tyrannidae family. Previously, the species was included in the family Pipridae, but was reclassified following genetic studies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-capped_piprites' where nome_scientifico = 'Piprites pileata' and descrizione is null;
update specie set descrizione = 'The flame-colored tanager, formerly known as the stripe-backed tanager, is a medium-sized American songbird in the family Cardinalidae, the cardinals or cardinal grosbeaks. It is found from Mexico throughout Central America to northern Panama and occasionally in the United States; four subspecies are recognized. The flame-colored tanager is 18 to 19 cm long, the male having predominantly red-orange while the female is more yellowish orange.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Flame-colored_tanager' where nome_scientifico = 'Piranga bidentata' and descrizione is null;
update specie set descrizione = 'The red-headed tanager is a medium-sized American songbird in the family Cardinalidae, the cardinals or cardinal grosbeaks, endemic to Mexico. Comprising two subspecies, it is around 15 cm (5.9 in) long. Males have predominantly yellow-olive plumage with a red head and throat and females have yellow forecrowns.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-headed_tanager' where nome_scientifico = 'Piranga erythrocephala' and descrizione is null;
update specie set descrizione = 'Piranga flava è un uccello canoro di media taglia appartenente alla famiglia Cardinalidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Piranga_flava' where nome_scientifico = 'Piranga flava' and descrizione is null;
update specie set descrizione = 'The white-winged tanager is a medium-sized American songbird in the family Cardinalidae, the cardinals or cardinal grosbeaks. It is found from Mexico, through Central America, across northern South America and as far south as Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-winged_tanager' where nome_scientifico = 'Piranga leucoptera' and descrizione is null;
update specie set descrizione = 'The western tanager is a medium-sized American songbird. Formerly placed in the tanager family (Thraupidae), it and other members of its genus are classified in the cardinal family (Cardinalidae). The species'' plumage and vocalizations are similar to other members of the cardinal family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_tanager' where nome_scientifico = 'Piranga ludoviciana' and descrizione is null;
update specie set descrizione = 'The scarlet tanager is a medium-sized American songbird. Until recently, it was placed in the tanager family (Thraupidae), but it and other members of its genus are now classified as belonging to the cardinal family (Cardinalidae). The species'' plumage and vocalizations are similar to other members of the cardinal family, although the Piranga species lacks the thick conical bill that many cardinals possess. The species resides in thick deciduous woodlands and suburbs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet_tanager' where nome_scientifico = 'Piranga olivacea' and descrizione is null;
update specie set descrizione = 'The rose-throated tanager is a medium-sized songbird in the family Cardinalidae, the cardinals or cardinal grosbeaks. Endemic to the Yucatán Peninsula in Central America, it is found in Belize, Guatemala, and Mexico. The male has greyish plumage with a deep rose throat and crown, while the female is similar but for a yellow crown and throat.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rose-throated_tanager' where nome_scientifico = 'Piranga roseogularis' and descrizione is null;
update specie set descrizione = 'The summer tanager is a medium-sized American songbird. Formerly placed in the tanager family (Thraupidae), it and other members of its genus are now classified in the cardinal family (Cardinalidae). The species''s plumage and vocalizations are similar to other members of the cardinal family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Summer_tanager' where nome_scientifico = 'Piranga rubra' and descrizione is null;
update specie set descrizione = 'The red-hooded tanager, is a medium-sized American songbird in the family Cardinalidae, the cardinals or cardinal grosbeaks. It is found in Colombia, Ecuador, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-hooded_tanager' where nome_scientifico = 'Piranga rubriceps' and descrizione is null;
update specie set descrizione = 'The lesser kiskadee is a species of passerine bird in the family Tyrannidae, the tyrant flycatchers. It is found in Panama and every mainland South American country except Chile, Paraguay, and Uruguay, though only as a vagrant in Argentina.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_kiskadee' where nome_scientifico = 'Pitangus lictor' and descrizione is null;
update specie set descrizione = 'The great kiskadee is a passerine bird in the tyrant flycatcher family Tyrannidae. It is the only member of the genus Pitangus. It breeds in open woodland with some tall trees, including cultivation and around human habitation. It is found from the extreme southern United States south to Argentina. It was introduced to Bermuda in 1957, and to Tobago in about 1970.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Great_kiskadee' where nome_scientifico = 'Pitangus sulphuratus' and descrizione is null;
update specie set descrizione = 'L’aquila delle Filippine, è un uccello rapace della famiglia degli Accipitridi, endemico delle foreste delle Filippine. Presenta un piumaggio di colore marrone e bianco, e una cresta ispida, e misura generalmente 86–102 cm di lunghezza e pesa 4,7-8,0 kg.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pithecophaga_jefferyi' where nome_scientifico = 'Pithecophaga jefferyi' and descrizione is null;
update specie set descrizione = 'Il pigliaformiche facciabianca è un uccello passeriforme della famiglia Thamnophilidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pithys_albifrons' where nome_scientifico = 'Pithys albifrons' and descrizione is null;
update specie set descrizione = 'The northern variable pitohui is a species of pitohui in the family Oriolidae. It is found on New Guinea and a number of neighbouring islands. Its natural habitat is subtropical or tropical moist lowland forests. It is also one of the few known poisonous birds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_variable_pitohui' where nome_scientifico = 'Pitohui kirhocephalus' and descrizione is null;
