update specie set descrizione = 'The stub-tailed spadebill is a passerine bird in the Tyrannidae family. It is commonly found in tropical dry rainforests or tropical moist lowlands throughout Central America. First scientifically described in 1860, it was originally thought to be the same as Platyrinchus mystaceus but was later reclassified as a sympatric species. The stub-tailed spadebill may grow up to 9.5 cm (3.74 in) long and may weigh up to 12 g (0.42 oz). It has a white throat, yellow breast, and brown mantle and wings. The stub-tailed spadebill is most easily recognizable due to its stubby tail, broad bill, and its distinctive bird song. Some morphological differences like its greatly reduced crown differentiate it from other related species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Stub-tailed_spadebill' where nome_scientifico = 'Platyrinchus cancrominus' and descrizione is null;
update specie set descrizione = 'The golden-crowned spadebill is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found Central America from Honduras to Panama and in every mainland South American country except Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-crowned_spadebill' where nome_scientifico = 'Platyrinchus coronatus' and descrizione is null;
update specie set descrizione = 'The yellow-throated spadebill is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_spadebill' where nome_scientifico = 'Platyrinchus flavigularis' and descrizione is null;
update specie set descrizione = 'The russet-winged spadebill is a Vulnerable species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Brazil, and Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Russet-winged_spadebill' where nome_scientifico = 'Platyrinchus leucoryphus' and descrizione is null;
update specie set descrizione = 'The white-throated spadebill is a tiny passerine bird in the family Tyrannidae, the tyrant flycatchers. It is found in Costa Rica, Panama, on Trinidad and Tobago, and in every mainland South American country except Chile, French Guiana, Uruguay, and Suriname.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_spadebill' where nome_scientifico = 'Platyrinchus mystaceus' and descrizione is null;
