update specie set descrizione = 'The chestnut wattle-eye is a species of bird in the family Platysteiridae. It is widespread across Central Africa. Its natural habitats are subtropical or tropical moist lowland forest, subtropical or tropical swamps, and moist savanna. It is often found on cocoa farms.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut_wattle-eye' where nome_scientifico = 'Platysteira castanea' and descrizione is null;
