update specie set descrizione = 'The brown-throated wattle-eye, also known as the common wattle-eye or scarlet-spectacled wattle-eye, is a small, insectivorous passerine bird. The wattle-eyes were previously classed as a subfamily of the Old World flycatcher family Muscicapidae, but are now usually separated from that group.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-throated_wattle-eye' where nome_scientifico = 'Platysteira cyanea' and descrizione is null;
