update specie set descrizione = 'The striped honeyeater is a passerine bird of the honeyeater family, Meliphagidae, found in Australia. It is a medium-sized honeyeater, about 23 cm (9.1 in) in length. Both sexes are a light greyish brown with dark brown centres to the feathers, which give the appearance of stripes. The stripes are particularly distinct on the head and back of the neck. While it is found mainly in inland eastern Australia where it inhabits the drier open forest, it is also found in coastal swamp forest from southeast Queensland to the central coast of New South Wales.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Striped_honeyeater' where nome_scientifico = 'Plectorhyncha lanceolata' and descrizione is null;
