update specie set descrizione = 'The white-browed sparrow-weaver is a predominantly brown, sparrow-sized bird found throughout central and north-central southern Africa. It is found in groups of two to eleven individuals consisting of one breeding pair and other non-reproductive individuals.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-browed_sparrow-weaver' where nome_scientifico = 'Plocepasser mahali' and descrizione is null;
update specie set descrizione = 'Il tessitore passerino capocastano è un uccello della famiglia dei Ploceidi originario della fascia di territorio che va da Senegal e Gambia fino all''Eritrea, all''Etiopia e alle regioni occidentali del Kenya.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Plocepasser_superciliosus' where nome_scientifico = 'Plocepasser superciliosus' and descrizione is null;
