update specie set descrizione = 'Il tessitore gendarme, noto anche come tessitore testanera dei villaggi, è un uccello della famiglia Ploceidae, diffuso nell''Africa subsahariana.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ploceus_cucullatus' where nome_scientifico = 'Ploceus cucullatus' and descrizione is null;
update specie set descrizione = 'The Asian golden weaver is a species of bird in the family Ploceidae.
It is found in Cambodia, Indonesia, Laos, Myanmar, Thailand, and Vietnam.
Its natural habitats are subtropical or tropical seasonally wet or flooded lowland grassland, swamps, and arable land.
It is threatened by habitat loss and capture, notably for the merit release trade.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Asian_golden_weaver' where nome_scientifico = 'Ploceus hypoxanthus' and descrizione is null;
update specie set descrizione = 'The lesser masked weaver is a species of bird in the family Ploceidae. It builds its nests in large colonies, often alongside the village weaver and sometimes the red-billed buffalo weaver. This species is commonly parasitised by the Diederik cuckoo. It is found in eastern, south-eastern and southern Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Lesser_masked_weaver' where nome_scientifico = 'Ploceus intermedius' and descrizione is null;
update specie set descrizione = 'The Golden-Backed Weaver, also known as Jackson''s weaver, is a species of bird in the family Ploceidae. This family of birds are called weavers, because they commonly weave their nests from grasses, stems, and other plant materials. Their nests are hung off of trees, or other tall places. More specifically, the Golden-backed Weavers nests are woven to look like tear-drops. These birds have bright coloring, but are often confused with other birds, and are found in various parts of Africa and Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-backed_weaver' where nome_scientifico = 'Ploceus jacksoni' and descrizione is null;
update specie set descrizione = 'The little weaver is a species of bird in the family Ploceidae.
It is found in western, central and eastern Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Little_weaver' where nome_scientifico = 'Ploceus luteolus' and descrizione is null;
update specie set descrizione = 'The streaked weaver is a species of weaver bird found in South Asia and South-east Asia in the countries of Bangladesh, Bhutan, Cambodia, China, Egypt, India, Indonesia, Myanmar, Nepal, Pakistan, Singapore, Sri Lanka, Thailand, Vietnam and also introduced in Qatar and United Arab Emirates (UAE). These are not as common as the baya weaver but are similar looking but have streaked underparts.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Streaked_weaver' where nome_scientifico = 'Ploceus manyar' and descrizione is null;
update specie set descrizione = 'The black-headed weaver, also known as yellow-backed weaver, is a species of bird in the family Ploceidae. It is a resident breeder in damp areas in tropical Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_weaver' where nome_scientifico = 'Ploceus melanocephalus' and descrizione is null;
update specie set descrizione = 'The nelicourvi weaver is a species of bird in the family Ploceidae. It is endemic to Madagascar. Together with its closest relative, the sakalava weaver, it is sometimes placed in a separate genus Nelicurvius. A slender, sparrow-like bird, it is 15 cm (5.9 in) long and weighing 20–28 g (0.71–0.99 oz). Breeding males have a black bill and head, brown eyes, yellow collar, grey belly, chestnut-brown lower tail coverts, olive back, and blackish flight feathers edged greenish. Non-breeding males have mottled grey and green heads. In the breeding female the front of the head is yellow and the back olive green, with a broad yellow eyebrow. It builds solitary, roofed, retort-shaped nests, hanging by a rope from a branch, vine or bamboo stem, in an open space. It primarily feeds on insects, looking on its own or in very small groups, often together with long-billed bernieria. Its natural habitat is subtropical or tropical moist lowland and mountain forests. The conservation status of Nelicourvi weaver is least concern according to the IUCN Red List.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Nelicourvi_weaver' where nome_scientifico = 'Ploceus nelicourvi' and descrizione is null;
update specie set descrizione = 'The black-necked weaver is a resident breeding bird species in much of central Africa from Cameroon in the west to Kenya and southern Somalia in the east.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-necked_weaver' where nome_scientifico = 'Ploceus nigricollis' and descrizione is null;
update specie set descrizione = 'The spectacled weaver is a species of bird in the family Ploceidae. It is found widely in woodland, forest edge and gardens of central, eastern and south-eastern Africa, but is absent from the most arid regions and dense, primary rainforest. This common species breeds in solitary pairs, and both sexes are bright yellow, have an olive-yellow back, black "spectacles" and pale eyes. The male has a black throat.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spectacled_weaver' where nome_scientifico = 'Ploceus ocularis' and descrizione is null;
update specie set descrizione = 'The baya weaver is a weaverbird found across the Indian subcontinent and Southeast Asia. Flocks are found in grasslands, cultivated areas, scrub and secondary growth. They are known for their hanging retort shaped nests woven from leaves, usually found on thorny trees or palm fronds, near or hanging over water where predators cannot easily reach. They are widespread and common within their range and are prone to local, seasonal movements in response to rain and food availability.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Baya_weaver' where nome_scientifico = 'Ploceus philippinus' and descrizione is null;
update specie set descrizione = 'Il tessitore di Sakalava è un uccello della famiglia Ploceidae, endemico del Madagascar.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ploceus_sakalava' where nome_scientifico = 'Ploceus sakalava' and descrizione is null;
update specie set descrizione = 'The eastern golden weaver is a species of bird in the family Ploceidae.
It is found in eastern and south-eastern Africa. Alternative names used for the eastern golden weaver include yellow weaver, olive-headed golden weaver, and African golden weaver.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_golden_weaver' where nome_scientifico = 'Ploceus subaureus' and descrizione is null;
update specie set descrizione = 'The southern masked weaver, or African masked weaver, is a resident breeding bird species common throughout southern Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_masked_weaver' where nome_scientifico = 'Ploceus velatus' and descrizione is null;
