update specie set descrizione = 'The black-capped chickadee is a small, nonmigratory, North American passerine bird that lives in deciduous and mixed forests. It is a member of the Paridae family, also known as tits. It has a distinct black cap on its head, a black bib underneath, and white cheeks. It has a white belly, buff sides, and grey wings, back, and tail. The bird is well known for its vocalizations, including its fee-bee song and its chick-a-dee-dee-dee call, from which it derives its name.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-capped_chickadee' where nome_scientifico = 'Poecile atricapillus' and descrizione is null;
