update specie set descrizione = 'The red-rumped tinkerbird is a small bird species in the Lybiidae family. It is widely distributed across the tropical rainforests of mid-western Africa. This species is monotypic, with no recognized subspecies. Measuring approximately 12–13 cm in length and weighing 14–21.5 g, the Red-rumped Tinkerbird is noted for its distinct coloration—a yellow chest, black head and back, and red lower back or rump that gives the species its name. The wings are black with yellow-tipped feathers, and younger birds tend to display duller plumage with a yellowish bill.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-rumped_tinkerbird' where nome_scientifico = 'Pogoniulus atroflavus' and descrizione is null;
update specie set descrizione = 'The yellow-rumped tinkerbird is a bird species in the family Lybiidae, which is native to the moist tropical and subtropical regions of sub-Saharan Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-rumped_tinkerbird' where nome_scientifico = 'Pogoniulus bilineatus' and descrizione is null;
update specie set descrizione = 'The yellow-fronted tinkerbird is a small bird in the family Lybiidae formerly known as yellow-fronted tinker barbet. It is sometimes considered conspecific with its southern counterpart, the red-fronted tinkerbird, Pogoniulus pusillus. Barbets are near passerine birds with bristles around the base of the bill and a world-wide tropical distribution.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-fronted_tinkerbird' where nome_scientifico = 'Pogoniulus chrysoconus' and descrizione is null;
update specie set descrizione = 'The moustached tinkerbird is a species of bird in the large Piciformes order in the Lybiidae family. It occurs in high-altitude forests in central Africa. It is greenish with little sexual dimorphism. The tinkerbird eats berries and insects.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Moustached_tinkerbird' where nome_scientifico = 'Pogoniulus leucomystax' and descrizione is null;
update specie set descrizione = 'The southern red-fronted tinkerbird, is a small bird in the African barbet family Lybiidae. It is found in southern Mozambique and eastern South Africa. This species was formerly regarded as conspecific with the northern red-fronted tinkerbird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_red-fronted_tinkerbird' where nome_scientifico = 'Pogoniulus pusillus' and descrizione is null;
update specie set descrizione = 'The speckled tinkerbird is a species of bird in the Lybiidae family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Speckled_tinkerbird' where nome_scientifico = 'Pogoniulus scolopaceus' and descrizione is null;
