update specie set descrizione = 'The yellow-throated tinkerbird is a species of bird in the Lybiidae family. They are small and sedentary, and typically forage in the higher canopy of primary or established secondary forest. Yellow-throated tinkerbirds located closer to the coast, as well as those in louder environments, have been found to make higher-pitched vocalizations.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_tinkerbird' where nome_scientifico = 'Pogoniulus subsulphureus' and descrizione is null;
update specie set descrizione = 'The white-starred robin is a species of bird in the Old World flycatcher and chat family Muscicapidae. It is also sometimes more simply called the starred robin. It is monotypic within the genus Pogonocichla. There are around twelve subspecies. The species is found in East and southern Africa. It occurs in forested areas in the Afromontane of sub-Saharan Africa. It is a brightly coloured robin with a bright yellow breast and belly, a slate coloured head with spots on the eyes and throat and blueish wings.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-starred_robin' where nome_scientifico = 'Pogonocichla stellata' and descrizione is null;
