update specie set descrizione = 'The black-crowned scimitar babbler is a species of bird in the family Timaliidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-crowned_scimitar_babbler' where nome_scientifico = 'Pomatorhinus ferruginosus' and descrizione is null;
update specie set descrizione = 'The Indian scimitar babbler is an Old World babbler. It is found in peninsular India in a range of forest habitats. They are most often detected by their distinctive calls, which include an antiphonal duet by a pair of birds. They are often hard to see as they forage through dense vegetation. The long, curved yellow, scimitar-shaped bills give them their name. It has been treated in the past as a subspecies of the white-browed scimitar babbler which is found along the Himalayas but now separated into two species, the peninsular Indian species and the Sri Lanka scimitar babbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_scimitar_babbler' where nome_scientifico = 'Pomatorhinus horsfieldii' and descrizione is null;
update specie set descrizione = 'The Sri Lanka scimitar babbler or Ceylon scimitar babbler is an Old World babbler. It is endemic to the island of Sri Lanka and was formerly treated as a subspecies of Indian scimitar babbler. The nominate form is found in the western part of wet hill regions of Sri Lanka, while race holdsworthi is found in the dry lowlands and eastern hills.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sri_Lanka_scimitar_babbler' where nome_scientifico = 'Pomatorhinus melanurus' and descrizione is null;
update specie set descrizione = 'The Javan scimitar babbler is a species of bird in the family Timaliidae. It is endemic to Java, Indonesia. The Sunda scimitar babbler, which is found in Sumatra, Borneo, and Malaysia, was formerly considered conspecific, with both species being grouped as the chestnut-backed scimitar babbler. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Javan_scimitar_babbler' where nome_scientifico = 'Pomatorhinus montanus' and descrizione is null;
update specie set descrizione = 'The Taiwan scimitar babbler is a bird in the family Timaliidae, the Old World babblers. It is endemic to Taiwan. The species was first described by Robert Swinhoe in 1859. It was formerly treated as a subspecies of the streak-breasted scimitar babbler. Its population is declining, but not rapidly enough for it to be considered vulnerable.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Taiwan_scimitar_babbler' where nome_scientifico = 'Pomatorhinus musicus' and descrizione is null;
