update specie set descrizione = 'The white-browed babbler is a small, gregarious species of bird in the family Pomatostomidae. They are endemic to the open woodlands and shrubby areas of central and southern Australia. The Latin name superciliosus refers to the supercilium, or ''eyebrow'', which is a feature synonymous with the pomatostomine babblers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-browed_babbler' where nome_scientifico = 'Pomatostomus superciliosus' and descrizione is null;
