update specie set descrizione = 'A power tool is a tool that is actuated by an additional power source and mechanism other than the solely manual labor used with hand tools. The most common types of power tools use electric motors. Internal combustion engines and compressed air are also commonly used. Tools directly driven by animal power are not generally considered power tools. Power tools can produce large amounts of particulates, including ultrafine particles. Airborne particulate matter is a Group 1 carcinogen.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Power_tool' where nome_scientifico = 'Power tools' and descrizione is null;
update specie set descrizione = 'The spotted barbtail is a species of bird in the family Furnariidae. Its natural habitat is subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spotted_barbtail' where nome_scientifico = 'Premnoplex brunnescens' and descrizione is null;
