update specie set descrizione = 'The golden-collared macaw or yellow-collared macaw is a small, mostly green Central South American parrot, a member of a large group of Neotropical parrots known as macaws. It has a bright yellow patch on the back of its neck/upper shoulders that gives the species its name. In aviculture, it is one of a number of smaller macaws often called "mini-macaws".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-collared_macaw' where nome_scientifico = 'Primolius auricollis' and descrizione is null;
update specie set descrizione = 'L''ara testablu è un uccello della famiglia degli Psittacidi originario del Perù orientale, della Bolivia nord-occidentale e dell''estremità occidentale del Brasile. La sua lunghezza totale di circa 41 cm ne fa una delle specie di piccole are riunite nel gruppo delle cosiddette «mini-are», che comprende tutte le specie di ara lunghe meno di 50 cm. Come tutte le are, presenta una coda lunga e appuntita e un becco grosso e robusto.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Primolius_couloni' where nome_scientifico = 'Primolius couloni' and descrizione is null;
update specie set descrizione = 'L''ara aliblu è un uccello della famiglia degli Psittacidi diffuso nel Sudamerica centrale e orientale. In passato è stata classificata sia nel genere Ara che in Propyrrhura. Può vivere fino a 50–60 anni.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Primolius_maracana' where nome_scientifico = 'Primolius maracana' and descrizione is null;
update specie set descrizione = 'The black-throated prinia is a species of bird in the family Cisticolidae. It is found in the eastern Himalayas from eastern Nepal through northern India, Bhutan and southwestern China. The species was considered to be the same species as the hill prinia, a widespread species in Southeast Asia, and the rufous-crowned prinia of eastern India and Myanmar, but is now treated as a separate species on the basis of morphology, song and genetic studies. The rufuos-crowned prinia is considered its closest relative based on mitochondrial DNA sequence data, and they are thought to have diverged from each other 3.4 million years ago.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_prinia' where nome_scientifico = 'Prinia atrogularis' and descrizione is null;
update specie set descrizione = 'The banded prinia is a species of bird in the family Cisticolidae. It is native to central Africa. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Banded_prinia' where nome_scientifico = 'Prinia bairdii' and descrizione is null;
update specie set descrizione = 'The rufous-fronted prinia is a species of bird in the family Cisticolidae.
It is found in India and Pakistan.
Its natural habitat is subtropical or tropical dry forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-fronted_prinia' where nome_scientifico = 'Prinia buchanani' and descrizione is null;
update specie set descrizione = 'The Himalayan prinia is a species of bird in the family Cisticolidae. It was formerly lumped in with the striped prinia as the striated prinia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Himalayan_prinia' where nome_scientifico = 'Prinia crinigera' and descrizione is null;
update specie set descrizione = 'The red-winged prinia or the red-winged warbler is a bird species in the family Cisticolidae. It formerly belonged in the monotypic genus Heliolais. It is found in Benin, Burkina Faso, Cameroon, Central African Republic, Chad, Democratic Republic of the Congo, Ivory Coast, Ethiopia, Gambia, Ghana, Guinea, Guinea-Bissau, Kenya, Liberia, Malawi, Mali, Mozambique, Niger, Nigeria, Senegal, Sierra Leone, Sudan, Tanzania, Togo, Uganda, Zambia, and Zimbabwe, where its natural habitat is dry savanna.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-winged_prinia' where nome_scientifico = 'Prinia erythroptera' and descrizione is null;
update specie set descrizione = 'The bar-winged prinia is a species of bird in the cisticola family Cisticolidae. The species is sometimes known as the bar-winged wren-warbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bar-winged_prinia' where nome_scientifico = 'Prinia familiaris' and descrizione is null;
update specie set descrizione = 'The black-chested prinia is a species of bird in the family Cisticolidae.
