update specie set descrizione = 'The graceful prinia is a small warbler. This prinia is a resident breeder in northeastern Africa and southern Asia, from Egypt and Somalia east to Saudi Arabia, where it is sometimes called streaked wren-warbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Graceful_prinia' where nome_scientifico = 'Prinia gracilis' and descrizione is null;
update specie set descrizione = 'The grey-breasted prinia or Franklin''s prinia is a wren-warbler belonging to the family of small passerine birds found mainly in warmer southern regions of the Old World. This prinia is a resident breeder in the Indian subcontinent, Sri Lanka and southeast Asia. Like other prinias, it often holds the tail upright but it is easily told by a smoky grey band across the breast which contrasts with a white throat. The beak is all black while the legs are pink. The tail is graduated as in other prinias and the grey feathers are tipped in white. In the breeding plumage the upperparts are grey while non-breeding birds are pale above with rufous wings and a weak supercilium. It is found in scrub, forest clearings and other open but well vegetated habitats. It can be confused with the rufescent prinia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-breasted_prinia' where nome_scientifico = 'Prinia hodgsonii' and descrizione is null;
update specie set descrizione = 'The Drakensberg prinia or saffron-breasted prinia is a small passerine bird. It lives in eastern South Africa and Eswatini.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Drakensberg_prinia' where nome_scientifico = 'Prinia hypoxantha' and descrizione is null;
update specie set descrizione = 'The plain prinia, also known as the plain wren-warbler or white-browed wren-warbler, is a small cisticolid warbler found in southeast Asia. It is a resident breeder from Pakistan and India to south China and southeast Asia. It was formerly included in the tawny-flanked prinia, resident in Africa south of the Sahara. The two are now usually considered to be separate species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plain_prinia' where nome_scientifico = 'Prinia inornata' and descrizione is null;
update specie set descrizione = 'The delicate prinia is a small warbler. This prinia is a resident breeder in southern Asia, from Turkey to North India.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Delicate_prinia' where nome_scientifico = 'Prinia lepida' and descrizione is null;
update specie set descrizione = 'The Karoo prinia or spotted prinia is a small passerine bird. It is a resident breeder in South Africa, Lesotho and far southern Namibia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Karoo_prinia' where nome_scientifico = 'Prinia maculosa' and descrizione is null;
update specie set descrizione = 'The brown prinia is a species of bird in the family Cisticolidae. The Burmese prinia and the Annam prinia were formerly lumped with this species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_prinia' where nome_scientifico = 'Prinia polychroa' and descrizione is null;
update specie set descrizione = 'The rufescent prinia is a species of bird in the family Cisticolidae.
It is found in Southeast Asia, the Indian subcontinent and southern Yunnan.
Its natural habitat is subtropical or tropical dry forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufescent_prinia' where nome_scientifico = 'Prinia rufescens' and descrizione is null;
update specie set descrizione = 'The red-fronted prinia, also known as the red-fronted warbler and the red-faced apalis, is a species of bird in the family Cisticolidae.
It is found in Chad, Djibouti, Eritrea, Ethiopia, Kenya, Somalia, Sudan, Tanzania, and Uganda.
Its natural habitat is dry savanna.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-fronted_prinia' where nome_scientifico = 'Prinia rufifrons' and descrizione is null;
update specie set descrizione = 'The ashy prinia or ashy wren-warbler is a small warbler in the family Cisticolidae. This prinia is a resident breeder in the Indian subcontinent, ranging across most of India, Nepal, Bangladesh, eastern Pakistan, Bhutan, Sri Lanka and western Myanmar. It is a common bird in urban gardens and farmlands in many parts of India and its small size, distinctive colours and upright tail make it easy to identify. The northern populations have a rufous rump and back and have a distinct breeding and non-breeding plumage while other populations lack such variation.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ashy_prinia' where nome_scientifico = 'Prinia socialis' and descrizione is null;
update specie set descrizione = 'The striped prinia or Swinhoe''s prinia is a species of bird in the family Cisticolidae. It was formerly lumped with the Himalayan prinia as the striated prinia, but was split from it following a study published in 2019.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Striped_prinia' where nome_scientifico = 'Prinia striata' and descrizione is null;
update specie set descrizione = 'The tawny-flanked prinia is a small passerine bird belonging to the genus Prinia in the family Cisticolidae, a family of Old World warblers. It is widespread and common in most parts of Africa south of the Sahara. The plain prinia of southern Asia was formerly included in this species but is now usually considered to be a separate species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tawny-flanked_prinia' where nome_scientifico = 'Prinia subflava' and descrizione is null;
update specie set descrizione = 'The hill prinia is a species of passerine bird in the family Cisticolidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hill_prinia' where nome_scientifico = 'Prinia superciliaris' and descrizione is null;
update specie set descrizione = 'The jungle prinia is a small passerine bird, a warbler in the family Cisticolidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Jungle_prinia' where nome_scientifico = 'Prinia sylvatica' and descrizione is null;
update specie set descrizione = 'The yellow-breasted flowerpecker is a species of bird in the family Dicaeidae. It is found in Brunei, Indonesia, Malaysia, Myanmar, Singapore, and Thailand. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-breasted_flowerpecker' where nome_scientifico = 'Prionochilus maculatus' and descrizione is null;
update specie set descrizione = 'The scarlet-breasted flowerpecker is a species of bird in the family Dicaeidae. It is found in Brunei, Indonesia, Malaysia, and Thailand. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical swamps. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet-breasted_flowerpecker' where nome_scientifico = 'Prionochilus thoracicus' and descrizione is null;
update specie set descrizione = 'The yellow-rumped flowerpecker is a species of bird in the family Dicaeidae. It is found in Brunei, Indonesia, and Malaysia on the island of Borneo, to which it is endemic. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-rumped_flowerpecker' where nome_scientifico = 'Prionochilus xanthopygius' and descrizione is null;
update specie set descrizione = 'L''averla dall''elmo crestalunga è un uccello passeriforme della famiglia Vangidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Prionops_plumatus' where nome_scientifico = 'Prionops plumatus' and descrizione is null;
update specie set descrizione = 'The Hispaniolan trogon is a species of bird in the family Trogonidae. It
is endemic to Hispaniola in the Caribbean. It is one of the only two trogon species found in the Caribbean.
It is the national bird of Haiti.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hispaniolan_trogon' where nome_scientifico = 'Priotelus roseigaster' and descrizione is null;
update specie set descrizione = 'Il tocororo o trogone cubano è un uccello della famiglia dei Trogonidae, endemico dell''isola di Cuba, dove, a causa del suo piumaggio bianco, rosso e blu, è stato scelto come simbolo nazionale ed è rappresentato su monete e banconote.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Priotelus_temnurus' where nome_scientifico = 'Priotelus temnurus' and descrizione is null;
update specie set descrizione = 'Il cacatua delle palme è un uccello della famiglia dei Cacatuidae (Psittaciformes). È l''unica specie del genere Probosciger.
È il più grande Cacatuidae esistente al mondo e possiede il becco più grande dell''ordine dei pappagalli. Il suo areale è esteso ad Australia e Nuova Guinea. Si tratta di uccelli tipici delle foreste. Diversamente dalla maggior parte dei cacatua, questo uccello tende a riunirsi in gruppi poco numerosi, composti da non più di otto esemplari.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Probosciger_aterrimus' where nome_scientifico = 'Probosciger aterrimus' and descrizione is null;
update specie set descrizione = 'The dark-breasted rosefinch is a species of true finch in the monotypic genus Procarduelis. It is found in Bhutan, China, India, Laos, Myanmar, Nepal, Pakistan, Thailand, and Vietnam. Its natural habitats are boreal forests and subtropical or tropical high-altitude shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dark-breasted_rosefinch' where nome_scientifico = 'Procarduelis nipalensis' and descrizione is null;
update specie set descrizione = 'The white bellbird is a species of bird in the family Cotingidae, the cotingas. It is found in Brazil, French Guiana, Guyana, Suriname, Venezuela, and as a vagrant to Trinidad.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White_bellbird' where nome_scientifico = 'Procnias albus' and descrizione is null;
update specie set descrizione = 'The bearded bellbird, also known as the campanero or anvil-bird, is a passerine bird which occurs in northern South America. The male is about 28 cm (11 in) long with white plumage apart from a brown head and black wings. At his throat hang several black, unfeathered wattles. The female is a little smaller with olive-green head and upper parts, yellow underparts streaked with green and a yellow vent area. The male has a loud, repeated metallic hammering call, as well as various other vocalisations.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bearded_bellbird' where nome_scientifico = 'Procnias averano' and descrizione is null;
update specie set descrizione = 'The bare-throated bellbird is a species of bird in the family Cotingidae. It is found in moist subtropical and tropical forests in Argentina, Brazil, and Paraguay. The male has white plumage and bristly bluish-black bare skin around its eye, beak and throat. The female is more drab, being olive-brown above with streaked yellow underparts. The male has one of the loudest known bird calls, producing a metallic sound similar to a hammer striking an anvil. This bird feeds strictly on fruit and plays a part in dispersing the seeds of forest trees. It is considered Near Threatened because of loss of its forest habitat and collection for the pet bird trade.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bare-throated_bellbird' where nome_scientifico = 'Procnias nudicollis' and descrizione is null;
update specie set descrizione = 'Il campanaro dalle tre caruncole è un uccello passeriforme migratore appartenente alla famiglia Cotingidae, endemico dell''America centrale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Procnias_tricarunculatus' where nome_scientifico = 'Procnias tricarunculatus' and descrizione is null;
update specie set descrizione = 'The grey-breasted martin is a large swallow from Central and South America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-breasted_martin' where nome_scientifico = 'Progne chalybea' and descrizione is null;
update specie set descrizione = 'The southern martin is a species of bird in the family Hirundinidae, the swallows and martins. One source states that it is known in every mainland South American country except Colombia, Guyana, and Venezuela, and there are undocumented sight records in those three countries. It has occurred as a vagrant in the Malvinas/Falkland Islands and the U.S. state of Florida', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_martin' where nome_scientifico = 'Progne elegans' and descrizione is null;
