update specie set descrizione = 'The brown accentor is a species of bird in the family Prunellidae. It is found in Afghanistan, China, India, Kazakhstan, Mongolia, Nepal, Pakistan, Russia, Tajikistan, Turkmenistan, and Uzbekistan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_accentor' where nome_scientifico = 'Prunella fulvescens' and descrizione is null;
update specie set descrizione = 'La passera scopaiola è un uccello della famiglia Prunellidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Prunella_modularis' where nome_scientifico = 'Prunella modularis' and descrizione is null;
update specie set descrizione = 'The Siberian accentor is a small passerine bird that breeds in northern Russia from the Ural Mountains eastwards across Siberia. It is migratory, wintering in Korea and eastern China, with rare occurrences in western Europe and northwestern North America. Its typical breeding habitat is subarctic deciduous forests and open coniferous woodland, often close to water, although it also occurs in mountains and spruce taiga. It inhabits bushes and shrubs in winter, frequently near streams, but may also be found in dry grassland and woods.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Siberian_accentor' where nome_scientifico = 'Prunella montanella' and descrizione is null;
update specie set descrizione = 'The robin accentor is a species of bird in the family Prunellidae. It is found in the mountainous regions of Afghanistan, Pakistan, India, Nepal, Bhutan and China, at altitudes between about 3,000 and 5,500 m. It is a brown bird with a grey head and an orange-red breast. It is common in parts of its range and its conservation status has been assessed by the International Union for Conservation of Nature as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Robin_accentor' where nome_scientifico = 'Prunella rubeculoides' and descrizione is null;
update specie set descrizione = 'The rufous-breasted accentor is passerine bird in the family Prunellidae, endemic to the Himalayas, descending in the winter to lower-to-middle altitudes. It is found in Afghanistan, Bhutan, Tibet, China, India, Myanmar, Nepal, and Pakistan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-breasted_accentor' where nome_scientifico = 'Prunella strophiata' and descrizione is null;
update specie set descrizione = 'The black saw-wing, also known as the blue saw-wing or black rough-winged swallow, is a small passerine bird in the swallow family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_saw-wing' where nome_scientifico = 'Psalidoprocne pristoptera' and descrizione is null;
update specie set descrizione = 'Il codibugnolo americano è un uccello passeriforme della famiglia Aegithalidae, fra i quali rappresenta l''unica specie ascritta al genere Psaltriparus Bonaparte, 1850.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psaltriparus_minimus' where nome_scientifico = 'Psaltriparus minimus' and descrizione is null;
update specie set descrizione = 'Il beccolargo codalunga, conosciuto anche come beccolargo pappagallo o eurilaimo psittacino è un uccello passeriforme della famiglia degli Eurilaimidi. Si tratta dell''unica specie ascritta al genere Psarisomus Swainson, 1837.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psarisomus_dalhousiae' where nome_scientifico = 'Psarisomus dalhousiae' and descrizione is null;
update specie set descrizione = 'The russet-backed oropendola is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Bolivia, Brazil, Colombia, Ecuador, Peru, and Venezuela. It is a "noisy and social bird that forages, nests, and roosts in groups".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Russet-backed_oropendola' where nome_scientifico = 'Psarocolius angustifrons' and descrizione is null;
update specie set descrizione = 'The dusky-green oropendola is a species of bird in the family Icteridae. It is found on the eastern slope of the Andes in Bolivia and Peru. Its natural habitats are subtropical or tropical moist montane forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky-green_oropendola' where nome_scientifico = 'Psarocolius atrovirens' and descrizione is null;
update specie set descrizione = 'The olive oropendola is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Brazil, Bolivia, Colombia, Ecuador, Peru, and Venezuela. It is a "spectacularly large oropendola".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive_oropendola' where nome_scientifico = 'Psarocolius bifasciatus' and descrizione is null;
update specie set descrizione = 'The crested oropendola, also known as the cornbird, is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Costa Rica, Panama, Trinidad and Tobago, and every mainland South American country except Chile and Uruguay. It is "[u]ndoubtedly overall the commonest and most widespread oropendola".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crested_oropendola' where nome_scientifico = 'Psarocolius decumanus' and descrizione is null;
update specie set descrizione = 'The Montezuma oropendola is a New World tropical icterid bird. It is a resident breeder in the Caribbean coastal lowlands from southeastern Mexico to central Panama, but is absent from El Salvador and southern Guatemala. It also occurs on the Pacific slope of Nicaragua and Honduras and northwestern and southwestern Costa Rica. It is among the oropendola species sometimes separated in the genus Gymnostinops. The English and scientific names of this species commemorate the Aztec emperor Moctezuma II.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Montezuma_oropendola' where nome_scientifico = 'Psarocolius montezuma' and descrizione is null;
update specie set descrizione = 'The green oropendola is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Bolivia, Brazil, Colombia, Ecuador, French Guiana, Guyana, Peru, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green_oropendola' where nome_scientifico = 'Psarocolius viridis' and descrizione is null;
update specie set descrizione = 'The chestnut-headed oropendola is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is found in Mexico, in every Central American country except El Salvador, and in Colombia and Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-headed_oropendola' where nome_scientifico = 'Psarocolius wagleri' and descrizione is null;
update specie set descrizione = 'Il parrocchetto dal groppone rosso è un uccello appartenente alla famiglia degli Psittaculidi, endemico dell''Australia. È l''unica specie del genere Psephotus.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psephotus_haematonotus' where nome_scientifico = 'Psephotus haematonotus' and descrizione is null;
update specie set descrizione = 'Il pappagallo della mulga è un uccello della famiglia degli Psittaculidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psephotellus_varius' where nome_scientifico = 'Psephotus varius' and descrizione is null;
update specie set descrizione = 'The spotted chorus frog or Clark''s tree frog is a small, nocturnal chorus frog native to the grasslands and prairies of the central United States and Tamaulipas, Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spotted_chorus_frog' where nome_scientifico = 'Pseudacris clarkii' and descrizione is null;
update specie set descrizione = 'Pseudacris crucifer Wied-Neuwied, 1838 è un anfibio appartenente alla famiglia Hylidae, diffuso in Nordamerica, nota anche con il nome di raganella primaverile.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pseudacris_crucifer' where nome_scientifico = 'Pseudacris crucifer' and descrizione is null;
update specie set descrizione = 'The upland chorus frog is a species of chorus frog found in the United States. It was recently separated from the Western chorus frog, being identified as an individual species rather than a subspecies. They are a rarely seen species, but their calls are frequently heard soon after rains in the spring time.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Upland_chorus_frog' where nome_scientifico = 'Pseudacris feriarum' and descrizione is null;
update specie set descrizione = 'The southern chorus frog is a species of frog in the family Hylidae, endemic to the southeastern United States. Its natural habitats are temperate forests, temperate grassland, shrub-dominated wetlands, swamps, freshwater marshes, intermittent freshwater marshes, ponds, open excavations, seasonally flooded agricultural land, and canals and ditches.
It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_chorus_frog' where nome_scientifico = 'Pseudacris nigrita' and descrizione is null;
update specie set descrizione = 'The little grass frog is a species of chorus frog endemic to the Southeastern United States. It is currently the smallest North American anuran and occurs in a wide variety of ephemeral and semi-permanent wetlands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Little_grass_frog' where nome_scientifico = 'Pseudacris ocularis' and descrizione is null;
update specie set descrizione = 'The ornate chorus frog is a species of chorus frog endemic to the Southeastern United States. Their distribution ranges from North Carolina, east to the very eastern part of Louisiana, and south to northern parts of Florida.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ornate_chorus_frog' where nome_scientifico = 'Pseudacris ornata' and descrizione is null;
update specie set descrizione = 'The western chorus frog, also known as striped chorus frog, or midland chorus frog is a species of frog found in Canada and the United States.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_chorus_frog' where nome_scientifico = 'Pseudacris triseriata' and descrizione is null;
update specie set descrizione = 'The dusky-tailed canastero is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is endemic to Chile.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky-tailed_canastero' where nome_scientifico = 'Pseudasthenes humicola' and descrizione is null;
update specie set descrizione = 'La poiana bianca è un uccello rapace della famiglia degli Accipitridi, diffuso in America centrale e Sud America.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pseudastur_albicollis' where nome_scientifico = 'Pseudastur albicollis' and descrizione is null;
