update specie set descrizione = 'The grey-and-white tyrannulet is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Ecuador and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-and-white_tyrannulet' where nome_scientifico = 'Pseudelaenia leucospodia' and descrizione is null;
update specie set descrizione = 'The cardinal lory is a species of parrot in the family Psittaculidae. The cardinal lory lives mainly in the mangrove and the lowland forests of the Solomon Islands, Bougainville Island and easternmost islands of the Bismarck Archipelago. It was previously placed in the genus Pseudeos.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cardinal_lory' where nome_scientifico = 'Pseudeos cardinalis' and descrizione is null;
update specie set descrizione = 'The red-naped ibis, also known as the Indian black ibis or black ibis, is a species of ibis found in the plains, agriculture fields and cities of the Indian subcontinent. Unlike other ibises in the region it is not found very often in waterbodies and is often found in dry fields, but are attracted more to areas that have more wetlands. It is usually seen in pairs or loose groups and can be identified by the nearly all dark body with a white patch on the shoulder and a bare dark head with a patch of crimson red warty skin on the crown and nape. It has a loud call and is noisy when breeding. It builds its nest most often on the top of a large tree or palm, and an increasing number of pairs are building on cell phone towers and electricity pillion towers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-naped_ibis' where nome_scientifico = 'Pseudibis papillosa' and descrizione is null;
update specie set descrizione = 'The streaked tuftedcheek is a passerine bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Streaked_tuftedcheek' where nome_scientifico = 'Pseudocolaptes boissonneautii' and descrizione is null;
update specie set descrizione = 'The buffy tuftedcheek or Lawrence''s tuftedcheek, is a passerine bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Costa Rica and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buffy_tuftedcheek' where nome_scientifico = 'Pseudocolaptes lawrencii' and descrizione is null;
update specie set descrizione = 'The ticking doradito is a species of bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Bolivia, Chile, and possibly Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ticking_doradito' where nome_scientifico = 'Pseudocolopteryx citreola' and descrizione is null;
update specie set descrizione = 'The warbling doradito is a species of bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Paraguay, Uruguay and Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Warbling_doradito' where nome_scientifico = 'Pseudocolopteryx flaviventris' and descrizione is null;
update specie set descrizione = 'The crested doradito is a species of bird in subfamily Elaeniinae of family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Bolivia, Brazil, Guyana, Paraguay, Uruguay, and Venezuela, possibly in French Guiana, and as a vagrant to Trinidad.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crested_doradito' where nome_scientifico = 'Pseudocolopteryx sclateri' and descrizione is null;
update specie set descrizione = 'The yellow-rumped marshbird is a species of bird in the family Icteridae. It is a medium-sized bird found in Argentina, Brazil, Paraguay, and Uruguay, where its natural habitats are dry savanna, swamps, and pastureland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-rumped_marshbird' where nome_scientifico = 'Pseudoleistes guirahuro' and descrizione is null;
