update specie set descrizione = 'Lo psittorinco di Maui o kiwikiu è un uccello passeriforme della famiglia Fringillidae, unica specie ascritta al genere Psittirostra Rothschild, 1893.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pseudonestor_xanthophrys' where nome_scientifico = 'Pseudonestor xanthophrys' and descrizione is null;
update specie set descrizione = 'The grey-capped social weaver is a sparrow-like liver-colored bird, with a pale grey crown, a dark grey bill, a whitish eye-ring, horn-colored legs, with some black in the wing and a light terminal band in the tail, that builds roofed nests made of straws, breeds in colonies in thorny Acacia trees, and feeds in groups gathering grass seeds and insects. Male and female have near identical plumage. DNA-analysis confirms it is part of the weaver family. It is found in Ethiopia, Kenya, Somalia, South Sudan, Sudan, Tanzania, and Uganda.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-capped_social_weaver' where nome_scientifico = 'Pseudonigrita arnaudi' and descrizione is null;
update specie set descrizione = 'The white-crowned manakin is a small passerine bird in the manakin family Pipridae. This common and extremely widespread manakin is one of the most easily identified, even in female plumage. It is a resident breeder in the tropical New World from Costa Rica to northeastern Peru and eastern Brazil. It was traditionally placed in the genus Pipra, but is now placed in its own monotypic genus Pseudopipra. It is a small, compact bird about 10 cm (3.9 in) long. Males have black plumage with a white crown which can be erected as a crest, the only member of the Pipridae to possess both an all-black body and a gleaming white crown. Females and juveniles are olive-green, with a grey head and throat, and greyish-green or olive underparts. At breeding time, males are involved in a lekking behaviour. This is a fairly common species with a wide range, and the International Union for Conservation of Nature has rated its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-crowned_manakin' where nome_scientifico = 'Pseudopipra pipra' and descrizione is null;
update specie set descrizione = 'The ground tit, Tibetan ground tit, or Hume''s ground tit is a bird of the Tibetan plateau north of the Himalayas. The peculiar appearance confused ornithologists who in the past variously called it Hume''s groundpecker, Hume''s ground jay or Tibetan ground jay on the assumption it belonged to the family Corvidae that includes the crows and jays. Although morphologically confusing, the species has since been identified using molecular sequence comparisons as being a member of the tit family (Paridae), and is now treated as the only species in the genus Pseudopodoces. It is found in the Tibetan Plateau of China, India, Nepal & Bhutan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ground_tit' where nome_scientifico = 'Pseudopodoces humilis' and descrizione is null;
update specie set descrizione = 'The rusty pitohui is a species of bird in the family Pachycephalidae. It is found throughout the lowlands of the Aru Islands and New Guinea.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rusty_pitohui' where nome_scientifico = 'Pseudorectes ferrugineus' and descrizione is null;
update specie set descrizione = 'The Caatinga cacholote is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is endemic to Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Caatinga_cacholote' where nome_scientifico = 'Pseudoseisura cristata' and descrizione is null;
update specie set descrizione = 'The white-throated cacholote is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is endemic to Argentina.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_cacholote' where nome_scientifico = 'Pseudoseisura gutturalis' and descrizione is null;
update specie set descrizione = 'The brown cacholote is a medium-sized bird of the ovenbird family Furnariidae. It was described by Ludwig Reichenbach in 1853, with its subspecies, argentina, described in 1960 by Kenneth Carroll Parkes. It is nonmigratory, and is found in the forests and parks of Argentina, Bolivia, Brazil, Paraguay, and Uruguay. Unlike many other birds, the brown cacholote builds large, pitcher-like nests year-round, each weighing many times more than the bird itself. Breeding begins in mid-November, with both parents sharing the responsibility for taking care of the nest equally. Incubation takes 17–20 days, and nestlings fledge at 19 days. They are omnivorous, primarily eating various arthropods, along with the eggs of other birds, fruits, and grain. The causes of death in adults is not well researched; however, nestlings are subject to parasitism from various insects. Egg success rate is 59%. They are a least-concern species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_cacholote' where nome_scientifico = 'Pseudoseisura lophotes' and descrizione is null;
update specie set descrizione = 'The grey-crested cacholote is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Bolivia, Brazil, and Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-crested_cacholote' where nome_scientifico = 'Pseudoseisura unirufa' and descrizione is null;
