update specie set descrizione = 'The Indochinese barbet, also called Annam barbet, is a bird belonging to the family Megalaimidae. It inhabits tropical and subtropical forests. It is found in Laos, Vietnam and Cambodia. It used to be considered a subspecies of the black-browed barbet.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indochinese_barbet' where nome_scientifico = 'Psilopogon annamensis' and descrizione is null;
