update specie set descrizione = 'The blue-throated barbet is a green Asian barbet native to the foothills of the Himalayas and Southeast Asia. It inhabits lowland and montane forests at elevations of 200–2,000 m (660–6,560 ft), frequenting fruiting trees. Due to its green colour, it is difficult to spot but is easily located by its continual loud calls. Sexes are similar in most respects and share domestic duties.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-throated_barbet' where nome_scientifico = 'Psilopogon asiaticus' and descrizione is null;
