update specie set descrizione = 'The coppersmith barbet, also called crimson-breasted barbet and coppersmith, is an Asian barbet with crimson forehead and throat, known for its metronomic call that sounds similar to a coppersmith striking metal with a hammer. It is a resident bird in the Indian subcontinent and parts of Southeast Asia. It carves out holes inside a tree to build its nest. It is predominantly frugivorous, but has been observed eating insects, especially winged termites.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Coppersmith_barbet' where nome_scientifico = 'Psilopogon haemacephalus' and descrizione is null;
