update specie set descrizione = 'The red-crowned barbet is part of one of the two subfamilies of Megalaimidae birds. it is in the order of woodpeckers (Piciformes) and their relatives. It is distributed in Myanmar, Thailand, Malaysia, Singapore, Indonesia and Brunei. Its natural habitats are subtropical or tropical moist lowland forests and plantations with a distribution area of 3,180,000 km2 (1,230,000 sq mi).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-crowned_barbet' where nome_scientifico = 'Psilopogon rafflesii' and descrizione is null;
