update specie set descrizione = 'Il parrocchetto testaprugna è un uccello della famiglia degli Psittaculidi. È endemico del subcontinente indiano e una volta si pensava fosse conspecifico con il parrocchetto facciarosa, ma in seguito fu elevato al rango di specie. I parrocchetti testaprugna si trovano in branchi, i maschi hanno una testa porpora rosata e le femmine una testa grigia. Volano rapidamente effettuando rapidi cambi di direzione accompagnati dai loro richiami distintivi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psittacula_cyanocephala' where nome_scientifico = 'Psittacula cyanocephala' and descrizione is null;
