update specie set descrizione = 'Il parrocchetto testagrigia (Psittacula finschii è un uccello della famiglia degli Psittaculidi. Per alcuni autori è una sottospecie dello P. himalayana; quasi identico a questo, con la testa color ardesia, è diffuso in un areale che va dall''est dell''Himalaya all''Indocina. L''habitat di questo pappagallo è costituito da foreste tra i 650 e i 3800 metri di quota. Ha taglia attorno ai 40 cm.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psittacula_finschii' where nome_scientifico = 'Psittacula finschii' and descrizione is null;
update specie set descrizione = 'Il parrocchetto testardesia (Psittacula himalayana è un uccello della famiglia degli Psittaculidi. Del tutto simile al parrocchetto testaprugna, dal quale differisce sostanzialmente per la colorazione del capo tendente al grigio violaceo e per la taglia attorno ai 40 cm, vive nella zona dell''Himalaya, tra i 1350 e i 2500 metri.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psittacula_himalayana' where nome_scientifico = 'Psittacula himalayana' and descrizione is null;
