update specie set descrizione = 'Il pappagallo cenerino, noto anche come pappagallo cenerino del Congo o pappagallo cenerino maggiore, è un pappagallo di medie dimensioni della famiglia Psittacidae, nativo dell''Africa centrale. Insieme al pappagallo di Timneh, un tempo identificato come una sottospecie del pappagallo cenerino ma oggi riconosciuto come una specie a sé stante, fa parte del genere Psittacus.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psittacus_erithacus' where nome_scientifico = 'Psittacus erithacus' and descrizione is null;
