update specie set descrizione = 'Il trombettiere aligrigie è un uccello della famiglia degli Psofiidi originario delle regioni settentrionali dell''Amazzonia, e nello Scudo della Guiana, nel Sud America tropicale. A differenza di tutti gli altri trombettieri (Psophia), il dorso e le ali di questa specie hanno una livrea grigio-argentata.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Psophia_crepitans' where nome_scientifico = 'Psophia crepitans' and descrizione is null;
