update specie set descrizione = 'The groundscraper thrush is a passerine bird of southern and eastern Africa belonging to the thrush family, Turdidae. It was previously considered the only member of the genus Psophocichla, but phylogenetic analysis supports it belonging in the genus Turdus, where it forms a sister group to the remaining Turdus species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Groundscraper_thrush' where nome_scientifico = 'Psophocichla litsitsirupa' and descrizione is null;
update specie set descrizione = 'The chirruping wedgebill is a medium-sized member of the genus Psophodes, which consists or four to five songbirds endemic to Australia. Commonly found in low shrublands in south-eastern inland Australia, the species is distinguished by its distinctive, chirruping call. The chirruping wedgebill and chiming wedgebill were considered to be a single species until as late as 1973, when they were separated due to marked differences in their calls.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chirruping_wedgebill' where nome_scientifico = 'Psophodes cristatus' and descrizione is null;
update specie set descrizione = 'The western whipbird is a passerine bird found in several scattered populations in Southwest Australia. It is predominantly olive green in colour. The western whipbird has sometimes been split into two species: the black-throated whipbird and the white-bellied whipbird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_whipbird' where nome_scientifico = 'Psophodes nigrogularis' and descrizione is null;
