update specie set descrizione = 'The white-necked petrel, also known as the white-naped petrel, is a species of seabird in the family Procellariidae. During the non-breeding season it occurs throughout a large part of the Pacific, but it is only known to breed on Macauley Island in New Zealand''s Kermadec Islands and the Australian territory of Norfolk Island and Phillip Island. It formerly bred on Raoul Island, but has now been extirpated from this locality due to predation by rats and cats. Reports of breeding on Merelava, Vanuatu, are more likely to be the very similar Vanuatu petrel, P. occulta, which some consider to be a subspecies of the white-necked petrel. The IUCN rating as vulnerable is for the "combined" species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-necked_petrel' where nome_scientifico = 'Pterodroma cervicalis' and descrizione is null;
update specie set descrizione = 'Il petrello di Juan Fernández è un uccello marino della famiglia dei Procellariidi originario del Pacifico orientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pterodroma_externa' where nome_scientifico = 'Pterodroma externa' and descrizione is null;
update specie set descrizione = 'The Bonin petrel or nunulu is a seabird in the family Procellariidae. It is a small gadfly petrel that is found in the northwest Pacific Ocean. Its secretive habits, remote breeding colonies and limited range have resulted in few studies and many aspects of the species'' biology are poorly known.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bonin_petrel' where nome_scientifico = 'Pterodroma hypoleuca' and descrizione is null;
update specie set descrizione = 'The mottled petrel or kōrure is a species of seabird and a member of the gadfly petrels. It usually attains 33 to 35 cm (13–14 in) in length with a 74 to 82 cm (29–32 in) wingspan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mottled_petrel' where nome_scientifico = 'Pterodroma inexpectata' and descrizione is null;
update specie set descrizione = 'The Kermadec petrel is a species of gadfly petrel in the family Procellariidae. It is 38 cm long with a wingspan of 100 cm. It is polymorphic, with light, dark and intermediate morphs known. It eats squid, fish and other marine creatures.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Kermadec_petrel' where nome_scientifico = 'Pterodroma neglecta' and descrizione is null;
update specie set descrizione = 'The black-winged petrel is a species of seabird in the family Procellariidae. It breeds on a number of oceanic islands in the tropical and subtropical East Pacific Ocean and spends the rest of the year at sea.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-winged_petrel' where nome_scientifico = 'Pterodroma nigripennis' and descrizione is null;
update specie set descrizione = 'The Galápagos petrel is one of the six endemic seabirds of the Galápagos. Its scientific name derives from Ancient Greek: Pterodroma originates from pteron and dromos, meaning "wing" and "runner", and phaeopygia comes from phaios and pugios, meaning "dusky" and "rump". Members of Pterodroma genus are also called the gadfly petrels because their erratic twisting and turning in flight resemble that of gadflies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gal%C3%A1pagos_petrel' where nome_scientifico = 'Pterodroma phaeopygia' and descrizione is null;
update specie set descrizione = 'The Hawaiian petrel or ʻuaʻu is a large, dark grey-brown and white petrel that is endemic to Hawaiʻi.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Hawaiian_petrel' where nome_scientifico = 'Pterodroma sandwichensis' and descrizione is null;
update specie set descrizione = 'The black-necked aracari or black-necked araçari is a near-passerine bird in the toucan family Ramphastidae. It is found in Brazil, French Guiana, Guyana, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-necked_aracari' where nome_scientifico = 'Pteroglossus aracari' and descrizione is null;
