update specie set descrizione = 'The saffron toucanet is a species of bird in the family Ramphastidae found in the Atlantic Forest in far north-eastern Argentina, south-eastern Brazil, and eastern Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Saffron_toucanet' where nome_scientifico = 'Pteroglossus bailloni' and descrizione is null;
update specie set descrizione = 'The curl-crested aracari or curl-crested araçari is a near-passerine bird in the toucan family Ramphastidae. It is found in Bolivia, Brazil, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Curl-crested_aracari' where nome_scientifico = 'Pteroglossus beauharnaisii' and descrizione is null;
