update specie set descrizione = 'The fiery-billed aracari or fiery-billed araçari is a near-passerine bird in the toucan family Ramphastidae. It is found in Costa Rica and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fiery-billed_aracari' where nome_scientifico = 'Pteroglossus frantzii' and descrizione is null;
