update specie set descrizione = 'The collared aracari or collared araçari is a near-passerine bird in the toucan family Ramphastidae. It is found from Mexico to Colombia and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Collared_aracari' where nome_scientifico = 'Pteroglossus torquatus' and descrizione is null;
update specie set descrizione = 'Pterophylla camellifolia, the common true katydid, is a common North American insect. It can be found in southeastern Canada, through the eastern United States from Maine to Florida. P. camellifolia belongs to the family Tettigoniidae (katydids). Within the Tettigoniidae, it belongs to the subfamily Pseudophyllinae. Other common names include northern true katydid and rough-winged katydid.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pterophylla_camellifolia' where nome_scientifico = 'Pterophylla camellifolia' and descrizione is null;
update specie set descrizione = 'The chestnut-throated huet-huet is a large passerine bird of the family Rhinocryptidae. At an average mass of 165 grams (5.8 oz), it is, with the related black-throated huet-huet, the largest rhinocryptid and the third-heaviest tracheophone suboscine behind the giant and great antpittas. It is a stockily-built bird, averaging 23 centimetres (9.1 in) in length with a predominantly dark brown plumage except for a dark red throat and a pale buff bar on its wind – lacking in the black-throated species. For many decades intense debate existed as to whether these two were one species or two, but molecular studies in the 1990s demonstrated that the two species had been separated since before the Patagonian Ice Sheet first formed in southern Chile.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-throated_huet-huet' where nome_scientifico = 'Pteroptochos castaneus' and descrizione is null;
update specie set descrizione = 'The moustached turca is a passerine bird which is endemic to Chile and belongs to the tapaculo family Rhinocryptidae. Common names of this species include "Turco" or "Turca". It is a terrestrial bird that burrows its nest on steep hillsides and uses flight for short distances. It is not threatened, yet it is unfortunately an understudied species of bird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Moustached_turca' where nome_scientifico = 'Pteroptochos megapodius' and descrizione is null;
update specie set descrizione = 'The black-throated huet-huet Spanish pronunciation: [wet wet] is a species of bird in the family Rhinocryptidae. It is found in southern/central Chile and adjacent western Argentina. Its natural habitat is temperate forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_huet-huet' where nome_scientifico = 'Pteroptochos tarnii' and descrizione is null;
update specie set descrizione = 'The white-throated laughingthrush is a species of passerine bird in the family Leiothrichidae. It is found mainly in the northern regions of the Indian subcontinent, primarily the Himalayas, and some adjoining and disjunct areas. It ranges across Afghanistan, Bhutan, India, Myanmar, Nepal, Tibet and Vietnam. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_laughingthrush' where nome_scientifico = 'Pterorhinus albogularis' and descrizione is null;
update specie set descrizione = 'The buffy laughingthrush, also known as the chestnut-winged laughingthrush is a species of bird in the family Leiothrichidae. It was formerly considered a subspecies of the rusty laughingthrush, P. poecilorhynchus; a species restricted to Taiwan following the split. Compared to the rusty laughingthrush, the buffy laughingthrush has paler grey underparts, more contrasting rufous wings, broader white tips to the tail, and distinct black lores.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buffy_laughingthrush' where nome_scientifico = 'Pterorhinus berthemyi' and descrizione is null;
update specie set descrizione = 'The black-throated laughingthrush is a species of bird in the family Leiothrichidae. It is found in Cambodia, China, Laos, Myanmar, Thailand, and Vietnam. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest, mostly at submontane to montane elevations.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_laughingthrush' where nome_scientifico = 'Pterorhinus chinensis' and descrizione is null;
update specie set descrizione = 'The Wayanad laughingthrush is a species of laughingthrush in the family Leiothrichidae. It is endemic to the Western Ghats south of Goa in India. These laughingthrushes move in groups in dense forests, producing loud calls but tend to be hard to spot in the undergrowth. They have brown upperparts, a white throat, a broad black mask through the eye and a heavy bill with pale yellow on the lower mandible. Despite the name, derived from the Wayanad region, this species has a wider range than the four other south Indian species of laughingthrush that are restricted to the higher elevation hills.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Wayanad_laughingthrush' where nome_scientifico = 'Pterorhinus delesserti' and descrizione is null;
update specie set descrizione = 'The chestnut-capped laughingthrush, also known as the spectacled laughingthrush, is a species of bird in the family Leiothrichidae.
It is found in Sumatra (Indonesia) and the Thai-Malay Peninsula.
Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests. The chestnut-hooded laughingthrush was previously considered a subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-capped_laughingthrush' where nome_scientifico = 'Pterorhinus mitratus' and descrizione is null;
update specie set descrizione = 'The greater necklaced laughingthrush is a species of passerine bird in the family Leiothrichidae. It is found in Bangladesh, Bhutan, China, India, Laos, Myanmar, Nepal, Thailand and Vietnam. It is introduced to Hawaii. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greater_necklaced_laughingthrush' where nome_scientifico = 'Pterorhinus pectoralis' and descrizione is null;
update specie set descrizione = 'The masked laughingthrush is a species of laughingthrush found in China, Vietnam, Hong Kong and Macau. It is often seen in small noisy flocks of seven. Its Chinese name qī zǐ-mèi means ''seven brothers and sisters''.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Masked_laughingthrush' where nome_scientifico = 'Pterorhinus perspicillatus' and descrizione is null;
update specie set descrizione = 'The rusty laughingthrush is a species of bird in the family Leiothrichidae. It is endemic to Taiwan. It formerly included the buffy laughingthrush of mainland China as a subspecies. Compared to the rusty laughingthrush, the buffy laughingthrush has paler grey underparts, more contrasting rufous wings, broader white tips to the tail, and distinct black lores.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rusty_laughingthrush' where nome_scientifico = 'Pterorhinus poecilorhynchus' and descrizione is null;
update specie set descrizione = 'The rufous-necked laughingthrush is a bird species in the laughingthrush family, Leiothrichidae. It is found in Bangladesh, Bhutan, China, India, Myanmar and Nepal, where its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical moist montane forest. Little study was done on this species due to its abundance and lack of interest in its conservation.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-necked_laughingthrush' where nome_scientifico = 'Pterorhinus ruficollis' and descrizione is null;
update specie set descrizione = 'The white-browed laughingthrush is a bird in the family Leiothrichidae. The species was first described by Robert Swinhoe in 1867. It is found in China, Hong Kong, India, Laos, Myanmar, Thailand, and Vietnam.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-browed_laughingthrush' where nome_scientifico = 'Pterorhinus sannio' and descrizione is null;
update specie set descrizione = 'The chestnut-hooded laughingthrush is a species of bird in the laughingthrush family Leiothrichidae endemic to Borneo. Described by the British ornithologist Richard Bowdler Sharpe as a distinct species in 1879, it was subsequently considered a subspecies of the chestnut-capped laughingthrush until 2007, when it was again raised to species status by the ornithologists Nigel Collar and Craig Robson. It is 22–24 cm (8.7–9.4 in) long, with a chestnut brown head and chin, with grey feathering on the top of the head. The upperparts and the side of the neck are slaty-grey, with a long white wing patch. The throat, breast, and upper belly are dull yellowish-brown, with purer grey flanks and a reddish-brown vent, lower belly, and thighs. It has a yellow half eye-ring behind and below the eye, while the tail has a blackish tip. Both sexes look similar, while juveniles are duller than adults.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-hooded_laughingthrush' where nome_scientifico = 'Pterorhinus treacheri' and descrizione is null;
update specie set descrizione = 'The clicking shrike-babbler is a species of bird in the family Vireonidae. It is found from Assam, India, eastern Myanmar to southern China, and southern Vietnam. Its natural habitats are subtropical or tropical moist lowland forests and subtropical or tropical moist montane forests. It used to be considered a subspecies of the chestnut-fronted shrike-babbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Clicking_shrike-babbler' where nome_scientifico = 'Pteruthius intermedius' and descrizione is null;
update specie set descrizione = 'The black-eared shrike-babbler is a bird species in the vireo family, Vireonidae. It was traditionally considered as an aberrant Old World babbler and formerly placed in the family Timaliidae. It was long noted that their habits resembled those of vireos, but this was previously ascribed to the result of convergent evolution. It is found in Southeast Asia from the Himalayas to western Malaysia. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-eared_shrike-babbler' where nome_scientifico = 'Pteruthius melanotis' and descrizione is null;
update specie set descrizione = 'The Himalayan shrike-babbler is a bird subspecies found in the western Himalayas that belongs to the shrike-babbler group. The genus was once considered to be an aberrant Old World babbler and placed in the family Timaliidae until molecular phylogenetic studies showed them to be closely related to the vireos of the New World, leading to their addition in the family Vireonidae. Males and females have distinctive plumages, with the males being all black about with a cinnamon-rufous tertial patch and a distinctive white stripe running from behind the eye. The underside is whitish with some pinkish buff on the flanks. Females have a greyish head, lack the white stripe and have the upperparts and wings with greens, yellow and chestnut. The subspecies is part of a cryptic species complex that was earlier considered as one species, white-browed shrike-babbler with several subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Himalayan_shrike-babbler' where nome_scientifico = 'Pteruthius ripleyi' and descrizione is null;
update specie set descrizione = 'The black-headed shrike-babbler is a bird species traditionally placed with the Old World babblers in the family Timaliidae. However, it might be one of the few Eurasian vireos (Vireonidae).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_shrike-babbler' where nome_scientifico = 'Pteruthius rufiventer' and descrizione is null;
update specie set descrizione = 'The green shrike-babbler is a bird species that was earlier placed in the family Timaliidae. The species is now considered to be an Asian offshoot of the American vireos and belongs in the family Vireonidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green_shrike-babbler' where nome_scientifico = 'Pteruthius xanthochlorus' and descrizione is null;
update specie set descrizione = 'La tortora beccafrutta panciarancio o colomba frugivora ventrearancione è un uccello della famiglia dei columbidi, diffuso in Indonesia, in Papua Nuova Guinea e in Australia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ptilinopus_iozonus' where nome_scientifico = 'Ptilinopus iozonus' and descrizione is null;
