update specie set descrizione = 'The black-naped fruit dove, also known as the black-headed fruit dove, is a medium-sized, up to 24 cm (9.4 in) long, green fruit dove with yellowish bill and iris. The male has a pale grey head with a black nape, yellow throat, and golden yellow and pink undertail coverts. The plumage of the female and the young is entirely green.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-naped_fruit_dove' where nome_scientifico = 'Ptilinopus melanospilus' and descrizione is null;
update specie set descrizione = 'The yellow-breasted fruit dove, known locally as balorinay, is a species of bird in the family Columbidae. It is endemic to the Philippines. Its natural habitat is tropical moist lowland forest. While it is listed as least concern in IUCN, it is declining due to habitat loss, hunting, and trapping for the illegal wildlife trade. This species was formerly placed in the genus Ptilinopus.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-breasted_fruit_dove' where nome_scientifico = 'Ptilinopus occipitalis' and descrizione is null;
