update specie set descrizione = 'The crimson-crowned fruit dove, also the Tongan fruit dove or purple-capped fruit dove, is a species of bird in the family Columbidae. It is found in American Samoa, Fiji, the Marshall Islands, Niue, Samoa, Tonga, and Wallis and Futuna. Its natural habitats are subtropical or tropical moist lowland forest and subtropical or tropical mangrove forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-crowned_fruit_dove' where nome_scientifico = 'Ptilinopus porphyraceus' and descrizione is null;
