update specie set descrizione = 'The yellow-plumed honeyeater is a species of bird in the family Meliphagidae. It is endemic to Australia, where it inhabits temperate forests and Mediterranean-type shrubby vegetation.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-plumed_honeyeater' where nome_scientifico = 'Ptilotula ornata' and descrizione is null;
update specie set descrizione = 'The white-plumed honeyeater is a medium sized passerine of the family Meliphagidae (honeyeaters) endemic to mainland Australia. Its key identifying characteristics are a primarily olive-grey body and yellow face, a slightly down-curved bill and its white distal neck-plumes from which it takes its name. White-Plumed Honeyeaters exhibit a preference for woodlands and riparian areas and have a very strong association with River Red Gums. They exhibit a small seasonal migration from ranges to lower areas in winter. Today the species is most commonly seen through Victoria, South Australia and New South Wales, but is also found in regions of Western Australia and the Northern Territory. They are often seen in gardens and backyards with vegetation cover.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-plumed_honeyeater' where nome_scientifico = 'Ptilotula penicillata' and descrizione is null;
update specie set descrizione = 'The Cuban blackbird is a species of bird in the family Icteridae, the oropendolas, New World orioles, and New World blackbirds. It is endemic to Cuba', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cuban_blackbird' where nome_scientifico = 'Ptiloxena atroviolacea' and descrizione is null;
update specie set descrizione = 'The dusky crag martin is a small passerine bird in the swallow family. It is about 13 cm (5 in) long with a broad body and wings, and a short square tail that has small white patches near the tips of most of its feathers. This martin has sooty-brown upperparts and slightly paler underparts. The two subspecies are resident breeding birds in South Asia from the Indian subcontinent to southwestern China and the northern parts of Thailand, Vietnam and Laos.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky_crag_martin' where nome_scientifico = 'Ptyonoprogne concolor' and descrizione is null;
update specie set descrizione = 'The large rock martin, also known as the southern crag-martin, is a small passerine bird in the swallow family that is resident in southern Africa. It was formerly considered to be conspecific with the red-throated rock martin. It breeds mainly in the mountains, but also at lower altitudes, especially in rocky areas and around towns, and, unlike most swallows, it is often found far from water. It is 12–15 cm (4.7–5.9 in) long, with mainly brown plumage, paler-toned on the upper breast and underwing coverts, and with white "windows" on the spread tail in flight. The sexes are similar in appearance, but juveniles have pale fringes to the upperparts and flight feathers. The former northern subspecies are smaller, paler, and whiter-throated than southern African forms, and are now usually split as a separate species, the pale crag martin. The large rock martin hunts along cliff faces for flying insects using a slow flight with much gliding. Its call is a soft twitter.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Large_rock_martin' where nome_scientifico = 'Ptyonoprogne fuligula' and descrizione is null;
