update specie set descrizione = 'Il gufo ventrefasciato, gufo dalla coda a fasce o gufo panciabarrata è un uccello rapace della famiglia Strigidae, presente in Bolivia, Colombia, Ecuador e Perù.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pulsatrix_melanota' where nome_scientifico = 'Pulsatrix melanota' and descrizione is null;
update specie set descrizione = 'Il gufo dagli occhiali è un grande rapace tropicale appartenente alla famiglia degli Strigidi. È il più grande rappresentante dei gufi nell''ecozona neotropicale ed è chiamato così perché il disegno facciale di colore bianco assomiglia ad un paio di occhiali.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pulsatrix_perspicillata' where nome_scientifico = 'Pulsatrix perspicillata' and descrizione is null;
update specie set descrizione = 'The white-fronted honeyeater is a medium-sized bird species endemic to Australia. Mainly distributed throughout arid and semi-arid landscapes. The white-fronted honeyeater has distinct colourings with a white face, black or brown upper chest with white speckles and yellow panels on their brown wings.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-fronted_honeyeater' where nome_scientifico = 'Purnella albifrons' and descrizione is null;
