update specie set descrizione = 'The sooty-headed bulbul is a species of songbird in the Bulbul family, Pycnonotidae.
It is found in south-eastern Asia.
Its natural habitat is subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sooty-headed_bulbul' where nome_scientifico = 'Pycnonotus aurigaster' and descrizione is null;
update specie set descrizione = 'The common bulbul is a member of the bulbul family of passerine birds. It is widespread throughout most of Africa except for the very arid areas, and has recently begun breeding in southernmost Spain. Ten subspecies are recognised based on the geographical variation in plumage. Some of these were formerly considered as separate species: Dodson''s bulbul, the Somali bulbul and the dark-capped bulbul.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_bulbul' where nome_scientifico = 'Pycnonotus barbatus' and descrizione is null;
