update specie set descrizione = 'The fire-eyed diucon is a passerine bird of South America belonging to the tyrant flycatcher family Tyrannidae. It is found in Argentina and Chile and as a vagrant to the Falkland Islands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fire-eyed_diucon' where nome_scientifico = 'Pyrope pyrope' and descrizione is null;
