update specie set descrizione = 'The redthroat is a small, mostly ground-dwelling species of bird in the family Acanthizidae. It is endemic to Australia, occurring mostly in arid and semi-arid areas containing acacia and chenopod shrublands. The species has a distinctive red throat patch and is able to mimic the calls of numerous other bird species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Redthroat' where nome_scientifico = 'Pyrrholaemus brunneus' and descrizione is null;
update specie set descrizione = 'The speckled warbler is a species of bird in the family Acanthizidae. It is endemic to eastern Australia. Its natural habitat is temperate forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Speckled_warbler' where nome_scientifico = 'Pyrrholaemus sagittatus' and descrizione is null;
update specie set descrizione = 'The cinnamon flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Bolivia, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cinnamon_flycatcher' where nome_scientifico = 'Pyrrhomyias cinnamomeus' and descrizione is null;
update specie set descrizione = 'The Grey-headed bullfinch, Gray-headed bullfinch, or Beavan''s Bullfinch is a species of finch in the family Fringillidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-headed_bullfinch' where nome_scientifico = 'Pyrrhula erythaca' and descrizione is null;
update specie set descrizione = 'The brown bullfinch is a species of bird in the true finch family, Fringillidae. It is found in Bhutan, China, India, Malaysia, Myanmar, Nepal, Pakistan, Taiwan, and Vietnam. Its natural habitats are temperate forests and subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_bullfinch' where nome_scientifico = 'Pyrrhula nipalensis' and descrizione is null;
update specie set descrizione = 'The Eurasian bullfinch or common bullfinch is a small passerine bird in the finch family, Fringillidae. In Anglophone Europe it is known simply as the bullfinch, as it is the original bird to bear the name bullfinch.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eurasian_bullfinch' where nome_scientifico = 'Pyrrhula pyrrhula' and descrizione is null;
update specie set descrizione = 'Il parrocchetto collobianco è un uccello della famiglia degli Psittacidi. Questa specie, di taglia attorno ai 24 cm, è affine al P. melanura; da quest''ultimo si differenzia per il petto bianco privo di scagliature e per la zona periauricolare color arancio. Vive nelle foreste primarie del sud-est dell''Ecuador, a un''altitudine tra i 1400 e i 1800 metri di quota.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_albipectus' where nome_scientifico = 'Pyrrhura albipectus' and descrizione is null;
update specie set descrizione = 'Il parrocchetto di Hellmayr è un uccello della famiglia Psittacidae, endemico del Brasile.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_amazonum' where nome_scientifico = 'Pyrrhura amazonum' and descrizione is null;
update specie set descrizione = 'Il parrocchetto pettobruno è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_calliptera' where nome_scientifico = 'Pyrrhura calliptera' and descrizione is null;
update specie set descrizione = 'Il parrocchetto golablu, noto anche come conuro golablu, è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_cruentata' where nome_scientifico = 'Pyrrhura cruentata' and descrizione is null;
update specie set descrizione = 'Il parrocchetto panciamarrone è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_frontalis' where nome_scientifico = 'Pyrrhura frontalis' and descrizione is null;
update specie set descrizione = 'Il parrocchetto guancerosse è un uccello della famiglia degli Psittacidi. Questa specie è affine al P. melanura, da cui si diversifica per la colorazione rossa della zona periauricolare, per una ridotta estensione della scagliatura e per le remiganti blu. Ha taglia attorno ai 25 cm ed è censita in 2 sottospecie: P. h. hoematotis e P. h. immarginata. Vive sui monti a nord del Venezuela, tra i 1000 e i 2000 metri.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_hoematotis' where nome_scientifico = 'Pyrrhura hoematotis' and descrizione is null;
update specie set descrizione = 'Il parrocchetto alizolfo è un uccello della famiglia degli Psittacidi. Affine al P. melanura, con taglia attorno ai 24 cm e classificato in due sottospecie, P. h. hoffmanni e P. h. gaudens, vive nel sud della Costa Rica e nella zona ovest di Panama, tra i 1000 e i 2400 metri. Si diversifica per una scagliatura giallo-verde che copre testa, collo, petto e parte del ventre e per la totale assenza di scudo sul basso petto e sul ventre; ha un segno rosso dietro l''occhio e remiganti bluastre.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_hoffmanni' where nome_scientifico = 'Pyrrhura hoffmanni' and descrizione is null;
update specie set descrizione = 'Il parrocchetto guancebianche è un uccello della famiglia degli Psittacidi. Affine e simile al P. picta, questa specie si differenzia per la zona periauricolare bianca e per una maggiore diffusione dell''azzurro, colore presente anche sulla scagliatura tipica. Vive nel Brasile orientale, dal Bahia meridionale verso sud fino all''Espírito Santo e al Minas Gerais orientale; in passato viveva anche nel San Paolo. È stato introdotto senza successo nel Giardino Botanico di Rio de Janeiro.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_leucotis' where nome_scientifico = 'Pyrrhura leucotis' and descrizione is null;
update specie set descrizione = 'Il parrocchetto codamarrone è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_melanura' where nome_scientifico = 'Pyrrhura melanura' and descrizione is null;
update specie set descrizione = 'Il parrocchetto guanceverdi è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_molinae' where nome_scientifico = 'Pyrrhura molinae' and descrizione is null;
update specie set descrizione = 'Il parrocchetto di El Oro è un uccello della famiglia degli Psittacidi. Endemico dell''Ecuador, è una specie relativamente nuova alla scienza, essendo stato scoperto solamente nel 1980, e non sappiamo molto della sua biologia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_orcesi' where nome_scientifico = 'Pyrrhura orcesi' and descrizione is null;
