update specie set descrizione = 'Il parrocchetto testarosa è un uccello della famiglia degli Psittacidi. Specie affine al P. melanura, con taglia attorno ai 24 cm, si diversifica per fronte e corona rosse, assenza di scagliatura, bordo alare bianco e remiganti blu. Vive nel nord-ovest del Venezuela a quote tra i 1500 e i 2000 metri.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_rhodocephala' where nome_scientifico = 'Pyrrhura rhodocephala' and descrizione is null;
update specie set descrizione = 'Il parrocchetto capirosso (Pyrrhura roseifrons è un uccello della famiglia Psittacidae, diffuso in Amazzonia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_roseifrons' where nome_scientifico = 'Pyrrhura roseifrons' and descrizione is null;
update specie set descrizione = 'Il parrocchetto capinero è un uccello della famiglia degli Psittacidi. Questa specie, affine e molto simile al P. melanura, è classificata in due sottospecie: P. r. rupicola e P. r. sandiae, con taglia attorno ai 25 cm. Vive nel bacino del Rio delle Amazzoni.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_rupicola' where nome_scientifico = 'Pyrrhura rupicola' and descrizione is null;
update specie set descrizione = 'Il parrocchetto di Santa Marta è un uccello della famiglia degli Psittacidi. Questa specie, affine al parrocchetto panciacremisi ma diversa nella colorazione, si presenta completamente verde, con una banda rossa sul petto e lo scudo ventrale ridotto; con taglia attorno ai 25 cm; ha sfumature rosse anche sulla spalla, sul sottocoda, sotto l''ala, insieme a un po'' di giallo, e nella zona periauricolare. Ha un areale ridottissimo, nella Sierra Nevada di Santa Marta in Colombia, dove abita la foresta primaria tra i 1800 e i 2800 metri. Le coltivazioni di marijuana e di cocaina prima, i diserbanti per distruggere la droga poi, hanno ridotto il suo habitat a circa il 15% di quello che era pochi anni fa portando la specie sull''orlo dell''estinzione: in natura ne esistono non più di 200 esemplari.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Pyrrhura_viridicata' where nome_scientifico = 'Pyrrhura viridicata' and descrizione is null;
