update specie set descrizione = 'Il corvo beccafrutta golaviola è un uccello passeriforme della famiglia Cotingidae, unica specie ascritta al genere Querula Vieillot, 1816.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Querula_purpurata' where nome_scientifico = 'Querula purpurata' and descrizione is null;
update specie set descrizione = 'The Carib grackle is a New World tropical blackbird, a resident breeder in the Lesser Antilles and northern South America east of the Andes, from Colombia east to Venezuela and northeastern Brazil. There are eight subspecies, of which the most widespread is the nominate subspecies of Trinidad and the South American mainland. This subspecies was introduced to Tobago in 1905 and is now common there.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Carib_grackle' where nome_scientifico = 'Quiscalus lugubris' and descrizione is null;
