update specie set descrizione = 'The Nicaraguan grackle is a species of passerine bird belonging to the genus Quiscalus, a genus of grackles in the New World blackbird family, Icteridae. It is found only in Nicaragua and northernmost Costa Rica.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Nicaraguan_grackle' where nome_scientifico = 'Quiscalus nicaraguensis' and descrizione is null;
update specie set descrizione = 'The Greater Antillean grackle is a grackle found throughout the Greater Antilles, as well as smaller nearby islands. Like all Quiscalus grackles, it is a rather large, gregarious bird. It lives largely in heavily settled areas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greater_Antillean_grackle' where nome_scientifico = 'Quiscalus niger' and descrizione is null;
update specie set descrizione = 'The common grackle is an icterid bird found in large numbers through much of North America. It was first described in 1758 by Carl Linnaeus and has three officially recognized subspecies. Adult common grackles have a long and dark bill, pale yellow eyes, and a long tail. Adults often have a bluish iridescent appearance on their head, this feature being more pronounced on males. Common grackles can be found widely across North America east of the Rocky Mountains and are highly adaptable to their environment.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_grackle' where nome_scientifico = 'Quiscalus quiscula' and descrizione is null;
update specie set descrizione = 'The radjah shelduck is a species of shelduck found mostly in New Guinea and Australia, and also on some of the Moluccas. It is known alternatively as the raja shelduck, black-backed shelduck, or in Australia as the Burdekin duck.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Radjah_shelduck' where nome_scientifico = 'Radjah radjah' and descrizione is null;
