update specie set descrizione = 'The white-throated toucan is a near-passerine bird in the family Ramphastidae found in South America throughout the Amazon Basin including the adjacent Tocantins and Araguaia River drainage. It prefers tropical humid forest, but also occurs in woodland and locally in riverine forest within cerrado.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_toucan' where nome_scientifico = 'Ramphastos tucanus' and descrizione is null;
