update specie set descrizione = 'Lo zanzariere beccolungo è un uccello passeriforme della famiglia Polioptilidae. È l''unica specie del genere Ramphocaenus.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ramphocaenus_melanurus' where nome_scientifico = 'Ramphocaenus melanurus' and descrizione is null;
