update specie set descrizione = 'The Brazilian tanager is a species of bird in the family Thraupidae.
It is endemic to eastern Brazil and far northeastern Argentina, occurring in the coastal region from Paraíba and southwards to Santa Catarina and Misiones.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brazilian_tanager' where nome_scientifico = 'Ramphocelus bresilius' and descrizione is null;
update specie set descrizione = 'The silver-beaked tanager is a medium-sized passerine bird. This tanager is a resident breeder in South America from eastern Colombia and Venezuela south to Paraguay and central Brazil, Peru and on Trinidad. It is common and conspicuous.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Silver-beaked_tanager' where nome_scientifico = 'Ramphocelus carbo' and descrizione is null;
update specie set descrizione = 'The crimson-backed tanager is a species of bird in the family Thraupidae. It is found in Colombia, Panama, and Venezuela, and introduced to French Polynesia. Its natural habitats are subtropical or tropical moist lowland forests and heavily degraded former forest. A nickname in Panama is sangre de toro.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-backed_tanager' where nome_scientifico = 'Ramphocelus dimidiatus' and descrizione is null;
update specie set descrizione = 'The flame-rumped tanager is a passerine bird in the tanager family Thraupidae. It is found from Panama to western Ecuador in semi-open forest and woodland. The subspecies with a yellow rump from the Cauca Valley in Colombia, the lemon-rumped tanager, has sometimes been considered as a separate species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Flame-rumped_tanager' where nome_scientifico = 'Ramphocelus flammigerus' and descrizione is null;
update specie set descrizione = 'The Huallaga tanager or black-bellied tanager, is a species of bird in the family Thraupidae.
It is endemic to Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Huallaga_tanager' where nome_scientifico = 'Ramphocelus melanogaster' and descrizione is null;
update specie set descrizione = 'The masked crimson tanager is a species of bird in the family Thraupidae.
It is found in Bolivia, Brazil, Colombia, Ecuador, Peru, and Venezuela.
Its natural habitats are subtropical or tropical swamps and subtropical or tropical moist shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Masked_crimson_tanager' where nome_scientifico = 'Ramphocelus nigrogularis' and descrizione is null;
update specie set descrizione = 'The scarlet-rumped tanager is a medium-sized passerine bird. This tanager is a resident breeder in the Caribbean lowlands from southern Mexico to western Panama. This species was formerly known as the scarlet-rumped tanager, but was renamed to Passerini''s Tanager after Carlo Passerini, a professor at the Museum of Zoology of the University of Florence, when the distinctive form found on the Pacific coast of Costa Rica and Panama was reclassified as a separate species, the Cherrie''s tanager, Ramphocelus costaricensis. While most authorities had accepted this split, there were notable exceptions. It was renamed back to the scarlet-rumped tanager in 2018 when Cherrie''s Tanager was lumped back into the species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scarlet-rumped_tanager' where nome_scientifico = 'Ramphocelus passerinii' and descrizione is null;
update specie set descrizione = 'The crimson-collared tanager is a rather small Middle American songbird. It was first described by the French naturalist René-Primevère Lesson in 1831, its specific epithet from the Latin adjective sanguinolentus, "bloodied", referring to its red plumage.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-collared_tanager' where nome_scientifico = 'Ramphocelus sanguinolentus' and descrizione is null;
update specie set descrizione = 'L''eremita becco a sega è un uccello appartenente alla famiglia Trochilidae, endemico del Brasile. È l''unica specie del genere Ramphodon Lesson, 1830.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Ramphodon_naevius' where nome_scientifico = 'Ramphodon naevius' and descrizione is null;
update specie set descrizione = 'The purple-backed thornbill is a species of hummingbird in the "coquettes", tribe Lesbiini of subfamily Lesbiinae. It is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Purple-backed_thornbill' where nome_scientifico = 'Ramphomicron microrhynchum' and descrizione is null;
update specie set descrizione = 'The flammulated flycatcher is a species of bird in the family Tyrannidae. It was formerly placed in the monotypic genus Deltarhynchus but was moved to the genus Ramphotrigon based on genetic analysis. It is endemic to the dry deciduous forest, arid thorn forest, and scrubby woodland of Mexico’s Pacific coast. The flycatcher is an olive to gray-brown bird with a streaked, pale gray chest, white throat, black bill, dark gray feet, and dark brown wings. It is a skulking bird that typically remains hidden in the underbrush. It feeds by gleaning insects off of leaves and twigs that it spots from an exposed perch. The female lays approximately three eggs in a nest made in a shallow tree cavity.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Flammulated_flycatcher' where nome_scientifico = 'Ramphotrigon flammulatum' and descrizione is null;
update specie set descrizione = 'The dusky-tailed flatbill is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Bolivia, Brazil, Colombia, Ecuador, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky-tailed_flatbill' where nome_scientifico = 'Ramphotrigon fuscicauda' and descrizione is null;
update specie set descrizione = 'The large-headed flatbill, also known as the bamboo flatbill, is a species of bird in the family Tyrannidae, the tyrant flycatchers.
It is found in Argentina, Bolivia, Brazil, Colombia, Ecuador, Guyana, Paraguay, Peru, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Large-headed_flatbill' where nome_scientifico = 'Ramphotrigon megacephalum' and descrizione is null;
update specie set descrizione = 'The rufous-tailed flatbill is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in every mainland South American country except Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-tailed_flatbill' where nome_scientifico = 'Ramphotrigon ruficauda' and descrizione is null;
