update specie set descrizione = 'The Chinese penduline tit is a species of bird in the family Remizidae. The species was first described by Robert Swinhoe in 1870. It is native to Manchuria. There are 10 species in the family Remizidae. They are similar to true tits, but make characteristic penduline nests. They inhabit open fields and wetlands. They have sharp bill tips and the sexes look alike.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chinese_penduline_tit' where nome_scientifico = 'Remiz consobrinus' and descrizione is null;
