update specie set descrizione = 'Il pendolino europeo è un uccello della famiglia Remizidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Remiz_pendulinus' where nome_scientifico = 'Remiz pendulinus' and descrizione is null;
update specie set descrizione = 'Il bucero corrugato è un rappresentante di medie dimensioni della famiglia dei Bucerotidi diffuso in Malaysia e Indonesia. Come tutti i buceri, nidifica nelle cavità degli alberi. La femmina trascorre i tre mesi della stagione riproduttiva murata all''interno della cavità del nido, collegata all''aperto solo attraverso una stretta fessura. Durante questo periodo, lei e in seguito i nidiacei che escono dalle uova vengono nutriti dal maschio.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Rhabdotorrhinus_corrugatus' where nome_scientifico = 'Rhabdotorrhinus corrugatus' and descrizione is null;
update specie set descrizione = 'Il bucero di Sulawesi è un uccello della famiglia dei Bucerotidi presente, con le sue due sottospecie, nel Sud-est asiatico.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Rhabdotorrhinus_exarhatus' where nome_scientifico = 'Rhabdotorrhinus exarhatus' and descrizione is null;
update specie set descrizione = 'The silver-rumped spinetail or silver-rumped needletail is a species of swift in the family Apodidae.
It is found in Brunei, Indonesia, Malaysia, Myanmar, Singapore, and Thailand.
Its natural habitat is subtropical or tropical moist lowland forests.
Research on the silver- Rumped spine tail has utilized facultative heterothermy, or even torpor, as a physiological mechanism to reduce its metabolic rate and conserve energy in its tropical environment.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Silver-rumped_spinetail' where nome_scientifico = 'Rhaphidura leucopygialis' and descrizione is null;
update specie set descrizione = 'Il nandù comune è un uccello incapace di volare originario del Sud America orientale. Conosciuto anche come nandù grigio, maggiore o americano; ñandú ; o ema, è una delle due specie del genere Rhea, facente parte della famiglia Rheidae. Il nandù comune è originario dell''Argentina, della Bolivia, del Brasile, Paraguay e Uruguay. Abita in una gran varietà di habitat aperti, come praterie, savane o zone umide erbose. Con un peso di 20–27 chilogrammi (44–60 lb), il nandù comune è l''uccello più grande del Sud America. In natura, il nandù comune ha un''aspettativa di vita di 10,5 anni. È anche notevole per le sue abitudini riproduttive e per il fatto che una popolazione rinselvatichita si è stabilita nella Germania settentrionale negli ultimi anni. La specie è elencata come prossima alla minaccia dalla IUCN.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Rhea_americana' where nome_scientifico = 'Rhea americana' and descrizione is null;
