update specie set descrizione = 'The blue-headed fantail is a fantail endemic to the northern Philippines where it is found on the islands of Luzon and Catanduanes. Until recently, it was considered conspecific with the Tablas fantail and Visayan fantail.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-headed_fantail' where nome_scientifico = 'Rhipidura cyaniceps' and descrizione is null;
update specie set descrizione = 'The Arafura fantail, sometimes known as the wood fantail, inhabits the Lesser Sunda Islands, the northern coast of Australia from the Kimberley to the western side of the Cape York Peninsula, including subcoastally in the Top End of the Northern Territory, and southern New Guinea. It is similar to the rufous fantail, from which it has been split taxonomically but, apart from minor overlap in the eastern Moluccas, their geographic ranges are discrete. It is generally duller than the rufous fantail with the rufous colouration more restricted.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Arafura_fantail' where nome_scientifico = 'Rhipidura dryas' and descrizione is null;
