update specie set descrizione = 'The Sunda pied fantail, also known as the Malaysian pied fantail, is a species of bird in the fantail family. It is locally referred to as murai gila, literally "crazy thrush" in the Malay language. It was previously considered conspecific with the Philippine pied fantail.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sunda_pied_fantail' where nome_scientifico = 'Rhipidura javanica' and descrizione is null;
update specie set descrizione = 'Il coda a ventaglio ballerina è un uccello passeriforme originario di Australia, Nuova Guinea, isole Salomone, arcipelago di Bismarck e Indonesia orientale. È una specie comune e familiare in gran parte del suo areale, essendo presente nella maggior parte degli ambienti, a eccezione delle foreste troppo fitte. Lungo 19-21,5 cm, il coda a ventaglio ballerina presenta una colorazione contrastante, con regioni superiori quasi interamente nere e regioni inferiori bianche; maschi e femmine hanno piumaggio simile.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Rhipidura_leucophrys' where nome_scientifico = 'Rhipidura leucophrys' and descrizione is null;
