update specie set descrizione = 'The crimson-breasted finch, is a species of small finch-like bird native to woodland and scrub of western Ecuador and adjacent north-western Peru. It is the only member of the genus Rhodospingus. It has traditionally been placed in the family Emberizidae, but molecular phylogenetic studies have shown that it belongs to the tanager family Thraupidae. It is strongly sexually dichromatic, with males being blackish above and rich orange-red below and on the crown, while females are overall dull greyish-buff.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson-breasted_finch' where nome_scientifico = 'Rhodospingus cruentus' and descrizione is null;
