update specie set descrizione = 'The Beijing babbler, also known as the white-browed Chinese warbler, Chinese hill warbler, or Chinese bush-dweller, is a species of bird in the genus Rhopophilus. It is now thought to be a close relative of the parrotbills and is placed in the family Paradoxornithidae; previously, it was placed in the families Cisticolidae, Timaliidae or Sylviidae. It is found in northern China and North Korea, and formerly occurred in South Korea. The species was first described by Robert Swinhoe in 1868.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Beijing_babbler' where nome_scientifico = 'Rhopophilus pekinensis' and descrizione is null;
