update specie set descrizione = 'Il bucero caruncolato è un uccello della famiglia dei Bucerotidi diffuso solamente su alcune isole indonesiane. Come tutti i buceri, nidifica nelle cavità degli alberi: la femmina, segregata all''interno del nido, mura l''ingresso della camera di cova ad eccezione di una stretta fessura, e trascorre un periodo di tre mesi in compagnia dei nidiacei, durante il quale lei e i piccoli vengono nutriti dal maschio.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Rhyticeros_cassidix' where nome_scientifico = 'Rhyticeros cassidix' and descrizione is null;
update specie set descrizione = 'Il bucero ondulato è un uccello della famiglia dei Bucerotidi originario del Sud-est asiatico. Come tutti i buceri, nidifica nelle cavità degli alberi. La femmina trascorre i tre mesi della stagione riproduttiva murata all''interno della cavità del nido, collegata all''aperto solo attraverso una stretta fessura. Durante questo periodo, lei e in seguito i nidiacei che escono dalle uova vengono nutriti dal maschio.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Rhyticeros_undulatus' where nome_scientifico = 'Rhyticeros undulatus' and descrizione is null;
