update specie set descrizione = 'Il gabbiano tridattilo è un uccello che appartiene alla famiglia dei Laridae. Ha abitudini tipicamente pelagiche, vivendo per la stragrande maggioranza della sua vita in mare aperto, ed è caratterizzato da una tecnica di volo molto agile che gli consente di compiere movimenti accuratamente controllati e di spostarsi anche in condizioni di vento forte. Il perfetto controllo dell''atterraggio gli consente di posarsi sulle sporgenze delle falesie dove costruisce il nido, formando delle colonie di grandi dimensioni.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Rissa_tridactyla' where nome_scientifico = 'Rissa tridactyla' and descrizione is null;
