update specie set descrizione = 'The spectacled bulbul, also known as the lesser brown bulbul, is a member of the bulbul family of passerine birds. It is found on the Malay Peninsula, Sumatra, and Borneo. The spectacled bulbul was originally described in the genus Ixos.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spectacled_bulbul' where nome_scientifico = 'Rubigula erythropthalmos' and descrizione is null;
