update specie set descrizione = 'The flame-throated bulbul is a member of the bulbul family of passerine birds and the state bird of Goa. It is found only in the forests of the Western Ghats in southern India. Formerly included as a subspecies of Pycnonotus flaviventris, it has since been elevated to the status of a full species. They are olive-backed with yellow undersides, a triangular orange-red throat and a white iris that stands out against the contrasting black head. They are usually seen foraging in groups in the forest canopy for berries and small insects. They have a call often with two or three tinkling notes that can sound similar to those produced by the red-whiskered bulbul. The species has been referred to in the past by names such as ruby-throated bulbul and black-headed bulbul, but these are ambiguous and could apply to other species such as Rubigula flaviventris and R. dispar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Flame-throated_bulbul' where nome_scientifico = 'Rubigula gularis' and descrizione is null;
update specie set descrizione = 'Il galletto di roccia andino è un uccello passeriforme della famiglia Cotingidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Rupicola_peruvianus' where nome_scientifico = 'Rupicola peruvianus' and descrizione is null;
update specie set descrizione = 'The Guianan cock-of-the-rock is a species of cotinga, a passerine bird from South America. It is about 30 cm (12 in) in length and weighs about 200 to 220 g. It is found in tropical rainforests, near its preferred habitat of rocky outcrops. The female''s plumage is brownish/dark smokey grey in colour, and generally less noticeable than the males because of their nesting work in rocky areas. The male''s feathers are a bright orange. Both have a heavy body, broad-based bill and wear a remarkable half-moon crest on the head. It is one of two species of the genus Rupicola, the other being the Andean cock-of-the-rock. The Guianan cock-of-the-rock lives across the forested region of northeastern South America. Its diet consists mostly of fruit, but they sometimes feast on small snakes and lizards.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Guianan_cock-of-the-rock' where nome_scientifico = 'Rupicola rupicola' and descrizione is null;
