update specie set descrizione = 'The slate-coloured grosbeak is a species of grosbeak in the family Thraupidae. Most of its range is the Amazon in South America, but it is also found in forests of the Chocó in Ecuador and Colombia, and southern Central America from Panama to Honduras.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slate-coloured_grosbeak' where nome_scientifico = 'Saltator grossus' and descrizione is null;
update specie set descrizione = 'The thick-billed saltator is a species of saltator in the family Thraupidae. It is found in highland Atlantic Forest in southeastern Brazil, far northeastern Argentina, and perhaps far eastern Paraguay. Unlike most other saltators, it is sexually dichromatic: Females resemble a green-winged saltator, but with a thicker bill, greener face and buff throat. The male thick-billed saltator is unique with its long white eyebrow, grey back, and black and orange beak.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Thick-billed_saltator' where nome_scientifico = 'Saltator maxillosus' and descrizione is null;
