update specie set descrizione = 'The black-cowled saltator is a seed-eating passerine bird in the tanager family Thraupidae. It is found in the southern border region of Ecuador and the northern border region of Peru. Its natural habitats are subtropical or tropical dry forests and subtropical or tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-cowled_saltator' where nome_scientifico = 'Saltator nigriceps' and descrizione is null;
update specie set descrizione = 'The olive-grey saltator, also known as the Caribbean grey saltator, is a quiet, grey-colored passerine bird in the tanager family Thraupidae, native to Colombia, Venezuela, the Guianas, far northern Brazil, and Trinidad. It was formerly considered conspecific with the greyish saltator, but was split as a distinct species by the IOC in 2021. The olive-grey saltator includes the subspecies brewsteri and plumbeus.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive-grey_saltator' where nome_scientifico = 'Saltator olivascens' and descrizione is null;
update specie set descrizione = 'The Orinoco saltator or Orinocan saltator is a species of saltator in the family Thraupidae.
It is found in Venezuela in areas west, north, and upon the Orinoco River region and to the Caribbean coast; also border regions in adjacent northeast Colombia. It can also be found on the eastern shore of Lake Maracaibo.
Its natural habitats are subtropical or tropical dry forests, subtropical or tropical moist lowland forests, and subtropical or tropical dry shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orinoco_saltator' where nome_scientifico = 'Saltator orenocensis' and descrizione is null;
