update specie set descrizione = 'The Siberian stonechat or Asian stonechat is a recently validated species of the Old World flycatcher family (Muscicapidae). Like the other thrush-like flycatchers, it was often placed in the Turdidae in the past. It breeds in the East Palearctic including in easternmost Europe and winters in the Old World tropics.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Siberian_stonechat' where nome_scientifico = 'Saxicola maurus' and descrizione is null;
