update specie set descrizione = 'The European stonechat is a small passerine bird that was formerly classed as a subspecies of the common stonechat. Long considered a member of the thrush family, Turdidae, genetic evidence has placed it and its relatives in the Old World flycatcher family, Muscicapidae. It is found across Europe, as far east as Ukraine and the South Caucasus, and in parts of North Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/European_stonechat' where nome_scientifico = 'Saxicola rubicola' and descrizione is null;
