update specie set descrizione = 'The black phoebe is a passerine bird in the tyrant-flycatcher family. It breeds from southwest Oregon and California south through Central and South America. It occurs year-round throughout most of its range and migrates less than the other birds in its genus though its northern populations are partially migratory. Six subspecies are commonly recognized although two are occasionally combined as a separate species, the white-winged phoebe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_phoebe' where nome_scientifico = 'Sayornis nigricans' and descrizione is null;
update specie set descrizione = 'The eastern phoebe is a small passerine bird. The genus name Sayornis is constructed from the specific part of Charles Lucien Bonaparte''s name for Say''s phoebe, Muscicapa saya, and Ancient Greek ornis, "bird". Phoebe is an alternative name for the Roman moon-goddess Diana, but it may also have been chosen to imitate the bird''s call.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_phoebe' where nome_scientifico = 'Sayornis phoebe' and descrizione is null;
