update specie set descrizione = 'The broad-tailed grassbird is a species of Old World warbler in the family Locustellidae. It is endemic to the Western Ghats of India with a possibility of occurrence in Sri Lanka. A small, mostly brown bird, it has a broad rounded and graduated tail. It is found only on the higher altitude grassy hills where it usually skulks, except during the breeding season when males fly up into the air to sing in their display. The species is believed to be a resident although it is possible that they make local movements.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Broad-tailed_grassbird' where nome_scientifico = 'Schoenicola platyurus' and descrizione is null;
update specie set descrizione = 'The bristled grassbird is a small passerine bird in the genus Schoenicola. Also known as the bristled grass warbler, this species is endemic to the Indian subcontinent, where it is patchily distributed in Bangladesh, India, Nepal and Pakistan. These insectivorous birds skulk in dense and tall grasslands, often in marshy areas, habitats that are threatened by human activities. Formerly considered to be sedentary, the species may be migratory, moving south and east in the Indian peninsula during winter and returning to their breeding grounds in the northern plains south of the Himalayas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bristled_grassbird' where nome_scientifico = 'Schoenicola striatus' and descrizione is null;
