update specie set descrizione = 'The Perijá tapaculo is a species of passerine bird in the family Rhinocryptidae (tapaculos). Endemic to the Serranía del Perijá mountain range on the Colombia–Venezuela border, the Perijá tapaculo is found at altitudes of 1,600–3,225 metres. Its body is 10 to 12 centimetres long and its tail is about 4 cm (1.6 in) long. Specimens have long been stored in museums, but the species was described only in 2015 based on sixteen specimens found between July 2008 and February 2009. It is considered vulnerable to extinction.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Perij%C3%A1_tapaculo' where nome_scientifico = 'Scytalopus perijanus' and descrizione is null;
update specie set descrizione = 'The rock tapaculo or Espinhaço tapaculo is a species of bird in the family Rhinocryptidae. It is endemic to altitudes of 900–2,100 metres (3,000–6,900 ft) in the central and southern Espinhaço Mountains, and the Mantiqueira Mountains in Minas Gerais, Brazil, though it may also occur in adjacent parts of Rio de Janeiro and São Paulo. It is found in shrubby and grassy habitats in rocky regions, and in elfin and cloud forest. It closely resembles the Diamantina tapaculo and Planalto tapaculo in appearance and voice.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rock_tapaculo' where nome_scientifico = 'Scytalopus petrophilus' and descrizione is null;
update specie set descrizione = 'The Ecuadorian tapaculo or El Oro tapaculo is a small passerine bird belonging to the genus Scytalopus, a genus of tapaculos. It is restricted to a small area in south-western Ecuador and was not described until 1997.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/El_Oro_tapaculo' where nome_scientifico = 'Scytalopus robbinsi' and descrizione is null;
