update specie set descrizione = 'The mouse-coloured tapaculo or Serra do Mar tapaculo is a species of bird in the family Rhinocryptidae. It is endemic to humid highland forests in southeastern Brazil, where it ranges from southwestern Espírito Santo to northeastern Rio Grande do Sul. Most of its range is in the Serra do Mar, but it also occurs further inland in Paraná and Santa Catarina. Until 2005, the Planalto tapaculo was included in the mouse-coloured tapaculo.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mouse-coloured_tapaculo' where nome_scientifico = 'Scytalopus speluncae' and descrizione is null;
