update specie set descrizione = 'The yellow-throated scrubwren is a passerine in the family Acanthizidae that is found in parts of eastern coastal Australia. It was formerly placed in the genus Sericornis, but is now the only species in the genus Neosericornis.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_scrubwren' where nome_scientifico = 'Sericornis citreogularis' and descrizione is null;
