update specie set descrizione = 'The Tasmanian scrubwren or brown scrubwren is a bird species endemic to the temperate forests of Tasmania and nearby King Island. It lives in the understory of rainforest, woodland, dry forest, swamps and coastal scrublands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tasmanian_scrubwren' where nome_scientifico = 'Sericornis humilis' and descrizione is null;
