update specie set descrizione = 'The white-capped tanager is a South American bird in the tanager family Thraupidae. It is the only member of the genus Sericossypha. It lives in humid Andean forest in groups of up to 20 individuals. Flocks of these tanagers stay in tight formation, often foraging from tree to tree together. They may eat fruits, seeds, hymenoptera, and coleoptera.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-capped_tanager' where nome_scientifico = 'Sericossypha albocristata' and descrizione is null;
