update specie set descrizione = 'The sooty tyrannulet is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is small, usually weighing 9 grams with a length of 12 centimeters, and has gray or brownish-grey feathers with black tail feathers.
It is found in Argentina, Brazil, and Uruguay; also southern Paraguay. A small extension of its range is in southeastern Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sooty_tyrannulet' where nome_scientifico = 'Serpophaga nigricans' and descrizione is null;
