update specie set descrizione = 'The northern parula is a small New World warbler. It is migratory and breeds in eastern North America from southern Canada to Florida.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_parula' where nome_scientifico = 'Setophaga americana' and descrizione is null;
update specie set descrizione = 'The black-throated blue warbler is a small passerine bird of the New World warbler family. Its breeding ranges are located in the interior of deciduous and mixed coniferous forests in eastern North America. Over the cooler months, it migrates to islands in the Caribbean and Central America. It is very rarely found in western Europe, where it is considered to be a non-indigenous species. The black-throated blue warbler is sexually dimorphic; the adult male has a black face and cheeks, deep blue upperparts and white underparts, while the adult female is olive-brown above and light yellow below.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_blue_warbler' where nome_scientifico = 'Setophaga caerulescens' and descrizione is null;
update specie set descrizione = 'The bay-breasted warbler is a small species of songbird in the New World warbler family, Parulidae. It is one of 35 species in the diverse genus Setophaga. Like all songbirds, or passerines, the species is classified in the order Passeriformes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bay-breasted_warbler' where nome_scientifico = 'Setophaga castanea' and descrizione is null;
update specie set descrizione = 'La dendroica cerulea è un piccolo uccello canoro della famiglia dei siluri del Nuovo Mondo. I maschi adulti hanno parti superiori blu e bianche e cerulee chiare con una collana nera sul petto e strisce nere sul retro e sui fianchi. Le femmine e gli uccelli immaturi hanno parti superiori più grigie o verdastre, una striscia chiara sopra l''occhio e nessuna striscia sulla schiena e nessun collo. Tutti questi uccelli hanno barre alari e un becco sottile e appuntito. Si trovano nelle foreste decidue del Nord America orientale durante la stagione riproduttiva e poi migrano verso le aree boschive montuose del Sud America. La specie è considerata minacciata da uno stato IUCN quasi minacciato, indicando che non deve affrontare alcuna minaccia imminente di estinzione in natura.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Setophaga_cerulea' where nome_scientifico = 'Setophaga cerulea' and descrizione is null;
update specie set descrizione = 'La parula guancedorate è un uccello passeriforme appartenente alla famiglia dei Parulidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Setophaga_chrysoparia' where nome_scientifico = 'Setophaga chrysoparia' and descrizione is null;
