update specie set descrizione = 'La parula di Blackburn è un uccello passeriforme appartenente alla famiglia dei Parulidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Setophaga_fusca' where nome_scientifico = 'Setophaga fusca' and descrizione is null;
