update specie set descrizione = 'The black-throated gray warbler or black-throated grey warbler is a passerine bird of the New World warbler family Parulidae. It is 13 cm (5.1 in) long and has gray and white plumage with black markings. The male has the bold black throat of its name, and black stripes on its head, as well as black streaks on its flanks; the female is a paler version of the male, with a white throat and less distinct black markings on the flanks and wings. It breeds in western North America from British Columbia to New Mexico, and winters in Mexico and the southwestern United States. The habitats it prefers are coniferous and mixed forests and scrubland, especially those with pinyon pines, junipers, sagebrush, and oaks. Its nest is an open cup of plant fibers lined with feathers, built a few metres from the ground in the branches of a tree or shrub. Three to five eggs are laid, and young are fed by both parents. Common in its breeding range, it does not seem to be seriously threatened by human activities, unlike many migratory warblers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_gray_warbler' where nome_scientifico = 'Setophaga nigrescens' and descrizione is null;
update specie set descrizione = 'La Setophaga occidentalis, nota col nome comune di Parula eremita, è un uccello appartenente alla famiglia dei parulidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Setophaga_occidentalis' where nome_scientifico = 'Setophaga occidentalis' and descrizione is null;
update specie set descrizione = 'The palm warbler is a small songbird in the New World warbler family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Palm_warbler' where nome_scientifico = 'Setophaga palmarum' and descrizione is null;
update specie set descrizione = 'The chestnut-sided warbler is a New World warbler. They breed in eastern North America and in southern Canada westwards to the Canadian Prairies. They also breed in the Great Lakes region and in the eastern United States.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-sided_warbler' where nome_scientifico = 'Setophaga pensylvanica' and descrizione is null;
update specie set descrizione = 'The mangrove warbler, also known as the mangrove yellow warbler, is a New World warbler species. It a small bright yellow bird that is found in mangroves on the Atlantic and Pacific coasts of the tropical Americas. It is also present in the Caribbean and on the Galápagos Islands. It was formerly considered to be conspecific with the migratory American yellow warbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mangrove_warbler' where nome_scientifico = 'Setophaga petechia' and descrizione is null;
update specie set descrizione = 'The pine warbler is a small songbird of the New World warbler family Parulidae. It is a permanent resident in the southeastern United States and also breeds in southeastern Canada and the northeastern United States, where it is migratory. Unlike other wood-warblers, in addition to insects the pine warbler also sometimes consumes seeds.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pine_warbler' where nome_scientifico = 'Setophaga pinus' and descrizione is null;
update specie set descrizione = 'The tropical parula is a small New World warbler. It breeds from southernmost Texas and northwest Mexico (Sonora) south through Central America to northern Argentina, including Trinidad and Tobago. This widespread and common species is not considered threatened by the IUCN.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tropical_parula' where nome_scientifico = 'Setophaga pitiayumi' and descrizione is null;
update specie set descrizione = 'The olive-capped warbler is a species of New World warbler that is native to the western and eastern ends of Cuba as well as Grand Bahama and the Abaco Islands in the Bahamas. Its natural habitat is pine forests and occasionally adjacent mixed forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive-capped_warbler' where nome_scientifico = 'Setophaga pityophila' and descrizione is null;
update specie set descrizione = 'Il codirosso americano è un uccello passeriforme della famiglia Parulidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Setophaga_ruticilla' where nome_scientifico = 'Setophaga ruticilla' and descrizione is null;
update specie set descrizione = 'La parula di Blackpoll, conosciuta anche come dendroica striata o parula capinera, è un uccello passeriforme appartenente alla famiglia dei Parulidae e originario dell''America del Nord. Nell''aprile 2015, la rivista scientifica Biology Letters ha svelato le straordinarie capacità migratorie di questo piccolo uccello: infatti esso è capace di migrare dal Canada fino ai Caraibi, sorvolando l''oceano per oltre 2800 chilometri. Lo studioso Ryan Norris dell''Università di Guelph in Ontario ha espresso il suo convincimento dicendo che si tratta di uno delle più straordinarie prodezze migratorie mai studiate.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Setophaga_striata' where nome_scientifico = 'Setophaga striata' and descrizione is null;
update specie set descrizione = 'La parula di Cape May è un uccello passeriforme della famiglia Parulidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Setophaga_tigrina' where nome_scientifico = 'Setophaga tigrina' and descrizione is null;
update specie set descrizione = 'The black-throated green warbler is a small songbird of the New World warbler family.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_green_warbler' where nome_scientifico = 'Setophaga virens' and descrizione is null;
update specie set descrizione = 'The east coast akalat or Gunning''s robin is a small passerine bird which can be found in the east of Africa from Kenya to Mozambique, and is named after J. W. B. Gunning.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/East_coast_akalat' where nome_scientifico = 'Sheppardia gunningi' and descrizione is null;
update specie set descrizione = 'The white-bellied blue robin or white-bellied sholakili, is a bird of the family Muscicapidae. It is endemic to the Shola forests of the higher hills of southern India. The Nilgiri blue robin and this species were once considered separate species, later lumped as sub-species of a single species (major) and elevated again to full species in 2005 by Pamela C. Rasmussen. The species was earlier thought to be related to the shortwings and placed in the genus Brachypteryx and later moved to Myiomela since species in the genus Brachypteryx show marked sexual dimorphism. In 2017, a study found that this is a sister group of the flycatchers in the genera Niltava, Cyornis and Eumyias among others. It was then placed in newly erected genus Sholicola. This small bird is found on the forest floor and undergrowth of dense forest patches sheltered in the valleys of montane grassland, a restricted and threatened habitat.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-bellied_blue_robin' where nome_scientifico = 'Sholicola albiventris' and descrizione is null;
update specie set descrizione = 'The Nilgiri blue robin, also known as Nilgiri shortwing, white-bellied shortwing, Nilgiri sholakili or rufous-bellied shortwing is a species of passerine bird in the family Muscicapidae endemic to the Shola forests of the higher hills of southern India, mainly north of the Palghat Gap. This small bird is found on the forest floor and undergrowth of dense forest patches sheltered in the valleys of montane grassland, a restricted and threatened habitat.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Nilgiri_blue_robin' where nome_scientifico = 'Sholicola major' and descrizione is null;
update specie set descrizione = 'L''azzurro di montagna è un uccello della famiglia dei Turdidae, diffuso in Canada, negli Stati Uniti e in Messico.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sialia_currucoides' where nome_scientifico = 'Sialia currucoides' and descrizione is null;
update specie set descrizione = 'Sialia mexicana Swainson, 1832 è un uccello della famiglia Turdidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sialia_mexicana' where nome_scientifico = 'Sialia mexicana' and descrizione is null;
update specie set descrizione = 'L''azzurrino orientale è un uccello della famiglia Turdidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sialia_sialis' where nome_scientifico = 'Sialia sialis' and descrizione is null;
update specie set descrizione = 'The greater yellow finch is a species of bird in the family Thraupidae.
It is found in Argentina and Chile.
Its natural habitats are subtropical or tropical high-altitude shrubland, temperate grassland, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greater_yellow_finch' where nome_scientifico = 'Sicalis auriventris' and descrizione is null;
update specie set descrizione = 'The stripe-tailed yellow finch is a species of bird in the family Thraupidae.
It is found in Argentina, Bolivia, Brazil, Colombia, Guyana, Paraguay, Peru, Suriname, and Venezuela.
Its natural habitats are dry savanna and pastureland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Stripe-tailed_yellow_finch' where nome_scientifico = 'Sicalis citrina' and descrizione is null;
update specie set descrizione = 'Il fringuello zafferano o botton d''oro è un fringuello del Sud America, molto comune nelle aree aperte e semiaperte delle pianure al di fuori del bacino dell''Amazzonia. Questo piccolo uccello ha un''ampia distribuzione che comprende la Colombia, il Venezuela settentrionale, l''Ecuador occidentale, il Perù occidentale, il Brasile orientale e meridionale, Bolivia, Paraguay, Uruguay, Argentina settentrionale e Trinidad e Tobago. È stato anche introdotto alle Hawaii, a Porto Rico e altrove. Sebbene comunemente considerato un canarino, non è correlato al canarino atlantico. In precedenza, è stato collocato negli Emberizidae ma è più vicino ai "mangia semi".', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sicalis_flaveola' where nome_scientifico = 'Sicalis flaveola' and descrizione is null;
update specie set descrizione = 'The Patagonian yellow finch is a species of bird in the family Thraupidae.
It is found in Patagonia and Tierra del Fuego in southern Argentina and Chile.
Its natural habitats are subtropical or tropical dry shrubland and temperate grassland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Patagonian_yellow_finch' where nome_scientifico = 'Sicalis lebruni' and descrizione is null;
update specie set descrizione = 'The citron-headed yellow finch is a species of bird in the family Thraupidae. It is found in the Andes of Bolivia and far northern Argentina. Its natural habitat is subtropical or tropical high-altitude shrubland.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Citron-headed_yellow_finch' where nome_scientifico = 'Sicalis luteocephala' and descrizione is null;
update specie set descrizione = 'The grassland yellow finch is a small passerine bird. Despite its name, it is not a finch, but is a seedeater. These were formerly united with the buntings and American sparrows in the Emberizidae, but are now known to be tanagers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grassland_yellow_finch' where nome_scientifico = 'Sicalis luteola' and descrizione is null;
update specie set descrizione = 'The greenish yellow finch is a species of bird in the family Thraupidae.
It is found in the central Andes of Argentina, Bolivia, Chile and Peru.
Its natural habitats are subtropical or tropical high-altitude shrubland and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Greenish_yellow_finch' where nome_scientifico = 'Sicalis olivascens' and descrizione is null;
update specie set descrizione = 'The bright-rumped yellow finch is a species of bird in the family Thraupidae. It is found in the Puna grassland: Peru, Bolivia and northern Chile and Argentina. Its natural habitats are subtropical or tropical high-altitude grassland and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bright-rumped_yellow_finch' where nome_scientifico = 'Sicalis uropygialis' and descrizione is null;
update specie set descrizione = 'Il panuro di Webb è un uccello della famiglia dei Silvidi, in passato classificato come facente parte della famiglia dei Timalidi, oppure sempre tra i Silvidi, ma nel genere Paradoxornis. Dal 2023 il genere ha cambiato nome da Sinosuthora in Suthora.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Suthora_webbiana' where nome_scientifico = 'Sinosuthora webbiana' and descrizione is null;
update specie set descrizione = 'The least poorwill or least pauraque is a species of nightjar in the family Caprimulgidae, and the only confirmed extant species of its genus. It is endemic to the island of Hispaniola, which is shared by the Dominican Republic and Haiti.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Least_poorwill' where nome_scientifico = 'Siphonorhis brewsteri' and descrizione is null;
update specie set descrizione = 'The stub-tailed antbird is a species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Colombia and Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Stub-tailed_antbird' where nome_scientifico = 'Sipia berlepschi' and descrizione is null;
update specie set descrizione = 'The dull-mantled antbird is a perching bird species in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Colombia, Costa Rica, and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dull-mantled_antbird' where nome_scientifico = 'Sipia laemosticta' and descrizione is null;
update specie set descrizione = 'The Esmeraldas antbird is a species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Colombia and Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Esmeraldas_antbird' where nome_scientifico = 'Sipia nigricauda' and descrizione is null;
update specie set descrizione = 'The Magdalena antbird is a Near Threatened species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in Colombia and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Magdalena_antbird' where nome_scientifico = 'Sipia palliata' and descrizione is null;
update specie set descrizione = 'The white-rumped sirystes, is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Bolivia, Brazil, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-rumped_sirystes' where nome_scientifico = 'Sirystes albocinereus' and descrizione is null;
update specie set descrizione = 'The Choco sirystes, formerly known as the western sirystes, is a species of passerine bird in the tyrant flycatcher family Tyrannidae. It is found Colombia, Ecuador, and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Choco_sirystes' where nome_scientifico = 'Sirystes albogriseus' and descrizione is null;
update specie set descrizione = 'The sibilant sirystes is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Bolivia, Brazil, and Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sibilant_sirystes' where nome_scientifico = 'Sirystes sibilator' and descrizione is null;
update specie set descrizione = 'The red-breasted nuthatch is a small songbird. The adult has blue-grey upperparts with cinnamon underparts, a white throat and face with a black stripe through the eyes, a straight grey bill and a black crown. Its call, which has been likened to a tin trumpet, is high-pitched and nasal. It breeds in coniferous forests across Canada, Alaska and the northeastern and western United States. Though often a permanent resident, it regularly irrupts further south if its food supply fails. There are records of vagrants occurring as far south as the Gulf Coast and northern Mexico. It forages on the trunks and large branches of trees, often descending head first, sometimes catching insects in flight. It eats mainly insects and seeds, especially from conifers. It excavates its nest in dead wood, often close to the ground, smearing the entrance with pitch.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-breasted_nuthatch' where nome_scientifico = 'Sitta canadensis' and descrizione is null;
update specie set descrizione = 'Il picchio muratore pettobianco è un uccello appartenente alla famiglia Sittidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sitta_carolinensis' where nome_scientifico = 'Sitta carolinensis' and descrizione is null;
update specie set descrizione = 'The chestnut-bellied nuthatch is a species of bird belonging to the family Sittidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-bellied_nuthatch' where nome_scientifico = 'Sitta cinnamoventris' and descrizione is null;
update specie set descrizione = 'Il picchio muratore è un uccello passeriforme della famiglia Sittidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sitta_europaea' where nome_scientifico = 'Sitta europaea' and descrizione is null;
update specie set descrizione = 'The velvet-fronted nuthatch is a small passerine bird in the nuthatch family Sittidae found in southern Asia, from Nepal, India, Sri Lanka ‍and Bangladesh east to southwestern China and Indonesia. Like other nuthatches, it feeds on insects in the bark of trees, foraging on the trunks and branches and their strongly clawed toes allow them to climb down tree trunks or move on the undersides of horizontal branches. They are found in forests with good tree cover and are often found along with other species in mixed-species foraging flocks. Adult males can be told apart by the black stripe that runs behind and above the eyes. They have a rapid chipping call note. They breed in tree cavities and holes, often created by woodpeckers or barbets.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Velvet-fronted_nuthatch' where nome_scientifico = 'Sitta frontalis' and descrizione is null;
update specie set descrizione = 'The white-tailed nuthatch is a species of bird in the family Sittidae. It ranges across the northern and northeastern parts of the Indian subcontinent, existing mainly in the low-to-middle Himalayas, as well as associated mountain ranges. It is found in Bhutan, India, Laos, Myanmar, Nepal, Tibet and Thailand.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-tailed_nuthatch' where nome_scientifico = 'Sitta himalayensis' and descrizione is null;
update specie set descrizione = 'The giant nuthatch is a species of bird in the family Sittidae. It is the longest of the nuthatches, measuring 19.5 cm (7.7 in) in length. Its upperparts are bluish grey, with the front being light grey, contrasting with the darker rest of the back. The bird has two very thick black eyebrow lines and light grey underparts, with whitish cheeks and throat, and a belly more or less washed with buff and cinnamon. For a nuthatch, it has a long beak and tail. The female can be distinguished from the male by its duller eye features and its upperparts having less contrast between the crown, nape, and lower back. The calls are powerful and made up of repetitions of simple patterns. The species gleans its food from the trunks and branches of trees, especially pines, and feeds on insects and berries. It nests around March, in the hole of a tree and without masking the entrance, and the nest has about three young.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Giant_nuthatch' where nome_scientifico = 'Sitta magna' and descrizione is null;
update specie set descrizione = 'The chestnut-vented nuthatch is a species of bird in the nuthatch family Sittidae. It is a medium-sized nuthatch, measuring 12.5–14 cm (4.9–5.5 in) in length. The upperparts are a solid grey-blue, with a markedly black loral stripe. The underparts are uniform grey to buff from the throat to belly, with brick red on the flanks. The undertail is white with a rufous border. The chestnut-vented nuthatch utters different kinds of calls, which can sometimes sound like a wren alarm, and its song is a monotonous, stereotypical crackle, typically chichichichi. Its ecology is poorly known, but it probably feeds on small arthropods and seeds, and the breeding season begins between March and May. The nest is typically located in a hole in the trunk of a tree, and the clutch has two to five eggs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-vented_nuthatch' where nome_scientifico = 'Sitta nagaensis' and descrizione is null;
update specie set descrizione = 'Il picchio muratore di roccia è un uccello passeriforme della famiglia dei Sittidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sitta_neumayer' where nome_scientifico = 'Sitta neumayer' and descrizione is null;
update specie set descrizione = 'The brown-headed nuthatch is a small songbird endemic to pine forests throughout the Southeastern United States. Genetic analyses indicated low differentiation between northern and southern populations in Florida, but the study also found lower genetic diversity among south Florida populations that may be a result of the increased habitat fragmentation that was documented. The Bahama nuthatch was formerly considered a subspecies (S. p. insularis), but has since been reclassified as its own separate species. Two recent studies assessing vocalizations in Bahama and continental nuthatch populations found important differences. One of the studies also demonstrated that continental and Bahama populations did not respond aggressively to calls of the other population. This type of call-response study is often used to help define cryptic species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-headed_nuthatch' where nome_scientifico = 'Sitta pusilla' and descrizione is null;
update specie set descrizione = 'The pygmy nuthatch is a tiny songbird, native to western North America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pygmy_nuthatch' where nome_scientifico = 'Sitta pygmaea' and descrizione is null;
update specie set descrizione = 'The eastern rock nuthatch is a species of bird in the nuthatch family Sittidae. It is found in southwest and central Asia, from eastern Turkey east through Armenia, Georgia, Azerbaijan, Iraq, Iran, Kazakhstan, Tajikistan, and Turkmenistan, and Afghanistan, to northwestern Pakistan. Some authors have used the name Persian nuthatch for the species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_rock_nuthatch' where nome_scientifico = 'Sitta tephronota' and descrizione is null;
update specie set descrizione = 'The Chinese nuthatch or snowy-browed nuthatch is a species of bird in the family Sittidae. It is a small nuthatch, measuring 11.5 cm (4.5 in) in length. The upperparts are blue-grey and the underparts from a dull buff-greyish to a cinnamon-orange; the cheeks are white. There is a marked sexual dimorphism: the adult male is distinguished by its very black crown, while that of the female is the same blue-grey as the back, or at most dark grey when the plumage is worn. In both sexes, a dark grey eyestripe extends in front of and behind the eye, topped by a clear white supercilium separating it from the crown. The song is variable, and composed of repetitions of small invariant whistles. The species feeds mainly on insects in summer and completes its diet with seeds and fruits. The nest is generally placed in the hole of a conifer. The pairs raises one brood per year, with five or six chicks.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chinese_nuthatch' where nome_scientifico = 'Sitta villosa' and descrizione is null;
update specie set descrizione = 'The Corsican nuthatch is a species of bird in the nuthatch family Sittidae. It is a relatively small nuthatch, measuring about 12 cm (4.7 in) in overall length. The upperparts are bluish-grey, the underparts greyish-white. The male is distinguished from the female by its entirely black crown. The species is sedentary, territorial and not very shy. It often feeds high in Corsican pines, consuming mainly pine seeds, but also catching some flying insects. The breeding season takes place between April and May; the nest is placed in the trunk of an old pine, and the clutch has five to six eggs. The young fledge 22 to 24 days after hatching.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Corsican_nuthatch' where nome_scientifico = 'Sitta whiteheadi' and descrizione is null;
update specie set descrizione = 'The Yunnan nuthatch is a bird species in the nuthatch family Sittidae. It was first described by William Robert Ogilvie-Grant in 1900 based on a male holotype. It is a small nuthatch, measuring 12 centimetres (4.7 in) in length on average and weighs between 7.5 and 13 grams. The grey-blue upperparts contrast with the light, smooth, buffy lowerparts. It has a fine white eyebrow above a black eyestripe, which is distinct when the plumage is fresh, and exhibits a small degree of sexual dimorphism. A noisy bird, it produces simple, nasal sounds, sometimes in repetitive series.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yunnan_nuthatch' where nome_scientifico = 'Sitta yunnanensis' and descrizione is null;
update specie set descrizione = 'The olivaceous woodcreeper is a passerine bird in subfamily Dendrocolaptinae of the ovenbird family Furnariidae. It is found from central Mexico south through every Central American country, on the island of Tobago, and in every mainland South American country except Chile, French Guiana, and Suriname.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olivaceous_woodcreeper' where nome_scientifico = 'Sittasomus griseicapillus' and descrizione is null;
update specie set descrizione = 'The chestnut-bellied tit is a small passerine bird in the tit family Paridae that is endemic to Taiwan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-bellied_tit' where nome_scientifico = 'Sittiparus castaneoventris' and descrizione is null;
update specie set descrizione = 'The varied tit is a perching bird from the tit family, Paridae. It occurs in the eastern Palearctic in Japan, Korea, and locally in northeastern China and extreme southeastern Russia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Varied_tit' where nome_scientifico = 'Sittiparus varius' and descrizione is null;
update specie set descrizione = 'The weebill is a species of bird in the family Acanthizidae. It is an insectivorous passerine that is found throughout mainland Australia. At 8 to 9 cm long, it is Australia''s smallest bird. It was originally described by John Gould in 1838, and four subspecies are recognised. The weebill''s plumage is nondescript, with olive-grey upperparts and paler, more yellowish underparts. It grades from more brownish plumage in the southern regions of Australia to more yellow in tropical areas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Weebill' where nome_scientifico = 'Smicrornis brevirostris' and descrizione is null;
