update specie set descrizione = 'The plains spadefoot toad is a species of American spadefoot toad which ranges from southwestern Canada, throughout the Great Plains of the western United States, and into northern Mexico. Like other species of spadefoot toads, they get their name from a spade-like projection on their hind legs which allows them to dig into sandy soils. Their name, in part, comes from their keratinized metatarsals, which are wide instead of "sickle shaped". The species name translates as buzzing leaf shaped. This refers to the species'' distinguishing features; its buzzing mating call, and its leaf-shaped digging metatarsals. It was first described by Cope in 1863.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plains_spadefoot_toad' where nome_scientifico = 'Spea bombifrons' and descrizione is null;
update specie set descrizione = 'The rufous-throated wren-babbler is a species of bird in the family Timaliidae. It is found in Bhutan, India, and Nepal.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-throated_wren-babbler' where nome_scientifico = 'Spelaeornis caudatus' and descrizione is null;
update specie set descrizione = 'The Chin Hills wren-babbler is a bird species in the family Timaliidae. It was until recently considered a subspecies of the long-tailed wren-babbler; the IUCN for example started recognizing it as distinct species in 2008.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chin_Hills_wren-babbler' where nome_scientifico = 'Spelaeornis oatesi' and descrizione is null;
update specie set descrizione = 'The bar-winged wren-babbler is a species of bird in the family Timaliidae. It is found in Bhutan, China, India, and Myanmar. Its natural habitat is subtropical or tropical moist montane forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bar-winged_wren-babbler' where nome_scientifico = 'Spelaeornis troglodytoides' and descrizione is null;
update specie set descrizione = 'The bronze mannikin or bronze munia is a small passerine bird of the Afrotropics. This very social estrildid finch is an uncommon to locally abundant bird in much of Africa south of the Sahara Desert, where it is resident, nomadic or irruptive in mesic savanna or forest margin habitats. It has an estimated global extent of occurrence of 23,600,000 km2 (9,100,000 sq mi). It is the smallest and most widespread of four munia species on the African mainland, the other being black-and-white, red-backed and magpie mannikin. It co-occurs with the Madagascar mannikin on the Comoro Islands, and was introduced to Puerto Rico. Especially in the West Africa, it is considered a pest in grain and rice fields. It is locally trapped for the pet bird trade.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bronze_mannikin' where nome_scientifico = 'Spermestes cucullata' and descrizione is null;
update specie set descrizione = 'Il becco azzurro occidentale è un uccello passeriforme appartenente alla famiglia Estrildidae, diffuso in Africa.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Spermophaga_haematina' where nome_scientifico = 'Spermophaga haematina' and descrizione is null;
update specie set descrizione = 'The Australasian figbird, also known as the green figbird, is a conspicuous, medium-sized passerine bird native to a wide range of wooded habitats in northern and eastern Australia, southern New Guinea, and the Kai Islands. It is common in large parts of its range, and occurs in numerous protected areas. Consequently, it is rated as least concern by BirdLife International and the IUCN.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Australasian_figbird' where nome_scientifico = 'Sphecotheres vieilloti' and descrizione is null;
update specie set descrizione = 'Il pinguino africano, noto anche come pinguino del Capo o pinguino sudafricano, è una specie di pinguino appartenente al genere Spheniscus, originaria delle coste dell''Africa meridionale. Come tutti i pinguini esistenti, è incapace di volare, presenta un corpo aerodinamico ed ali irrigidite e appiattite, trasformate in pagaie adatte alla vita in ambiente marino. Gli adulti pesano in media tra 2,2 e 3,5 kg e possono raggiungere un''altezza di 60-70 cm. Questa specie è caratterizzata da distintive chiazze di pelle rosa sopra gli occhi e da una "maschera" nera che ricopre quasi tutto il volto. La parte superiore del corpo è nera e nettamente delineata dalla parte inferiore bianca, che presenta macchie e una banda nera sul petto. Le ghiandole rosa sopra gli occhi aiutano questi uccelli nella termoregolazione: per far fronte alle variazioni di temperatura, il sangue viene inviato alle ghiandole, dove si raffredda grazie al contatto con l''aria.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Spheniscus_demersus' where nome_scientifico = 'Spheniscus demersus' and descrizione is null;
update specie set descrizione = 'Lo Spheniscus magellanicus, o Pinguino di Magellano, classificato da J.R. Forster nel 1781 sullo stretto di Magellano venne da questi definito anche con il nome di Aptenodytes magellanicus.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Spheniscus_magellanicus' where nome_scientifico = 'Spheniscus magellanicus' and descrizione is null;
update specie set descrizione = 'L''erbarolo del Capo è un uccello passeriforme della famiglia Macrosphenidae, diffuso nell''Africa australe. È l''unica specie nota del genere Sphenoeacus.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sphenoeacus_afer' where nome_scientifico = 'Sphenoeacus afer' and descrizione is null;
update specie set descrizione = 'The oleaginous hemispingus is a species of bird in the family Thraupidae. It is found in Colombia, Ecuador, Peru, and Venezuela. It inhabits wet montane rainforests at elevations of 1,400–2,700 m (4,600–8,900 ft). It is 14 cm (5.5 in) long and weighs 14–20 g (0.5–0.7 oz) on average. It has dull yellow underparts and olive-green upperparts. It is classified as being of least concern by the IUCN.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Oleaginous_hemispingus' where nome_scientifico = 'Sphenopsis frontalis' and descrizione is null;
