update specie set descrizione = 'L''aquila dal ciuffo bianca e nera è un uccello rapace della famiglia degli Accipitridi originario di una vasta fascia del continente americano che dal Messico meridionale giunge fino all''Argentina nord-orientale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Spizaetus_melanoleucus' where nome_scientifico = 'Spizaetus melanoleucus' and descrizione is null;
update specie set descrizione = 'The ornate hawk-eagle is a bird of prey from the tropical Americas. Formerly, some authorities referred to this species as the crested hawk-eagle, a name that may cause some confusion as it is more commonly used for an Asian eagle species. Like all eagles, it is in the family Accipitridae. This species has a feathered tarsus that marks it as a member of the Aquilinae or booted eagle subfamily. This species is notable for the vivid colors and bold markings of adults, which differ considerably from the far more whitish plumage of the juvenile bird. The ornate hawk-eagle ranges from central Mexico south through much of Central America and in a somewhat spotty but broad overall range into South America, including in the west apart from the Andes and broadly on the Atlantic side especially Brazil down to as far as Southeast Brazil and northern Argentina. This species is found largely in primary forests with tall trees, although can be found in many forest types.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ornate_hawk-eagle' where nome_scientifico = 'Spizaetus ornatus' and descrizione is null;
update specie set descrizione = 'The black hawk-eagle, also known as the tyrant hawk-eagle, is a species of eagle found from central Mexico through Central America into the south of Brazil to Colombia, eastern Peru, and as far as northern Argentina. There are two known subspecies, S.t. tyrannus, which is found in Southeastern Brazil and Northeastern Argentina, and the slightly smaller S. t. serus, which can be found elsewhere throughout the species'' range. Its preferred habitats include humid and moist forests close to rivers, and several types of woodland. It is uncommon to fairly common throughout most of its range. Its closest relative is the ornate hawk-eagle, which is similar in size, appearance and behavior but lives at lower elevations.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_hawk-eagle' where nome_scientifico = 'Spizaetus tyrannus' and descrizione is null;
update specie set descrizione = 'The black-chinned sparrow is a small bird in the genus Spizella, in the New World sparrow family Passerellidae. It is found in the southwestern United States and throughout much of Mexico north of the Isthmus of Tehuantepec; most populations in the US migrate south after breeding while those in Mexico are resident. It is a slim, long-tailed bird, primarily gray with a reddish-brown back streaked with black, brown wings and tail, a pink beak, and brownish legs and feet. In the breeding season, the male shows black on his throat, chin, and the front of his face. Females, youngsters and nonbreeding males show little or no black in these areas. An unobtrusive bird, it spends much of its time foraging slowly along the ground, either alone or in small groups, sometimes mixing with other Spizella species. It is an omnivore, feeding primarily on seeds during the winter and insects during the summer. It builds a cup-shaped nest of grasses, rootlets, or plant fibers, into which the female lays 2–5 pale blue eggs. The female does most or all of the egg incubation, but both parents feed the hatched nestlings.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-chinned_sparrow' where nome_scientifico = 'Spizella atrogularis' and descrizione is null;
update specie set descrizione = 'The clay-colored sparrow or clay-coloured sparrow is a small New World sparrow of North America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Clay-colored_sparrow' where nome_scientifico = 'Spizella pallida' and descrizione is null;
update specie set descrizione = 'Il passero cinguettante è una specie di uccello appartenente alla famiglia dei Passerellidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Spizella_passerina' where nome_scientifico = 'Spizella passerina' and descrizione is null;
update specie set descrizione = 'The field sparrow is a small New World sparrow in the family Passerellidae. It is about 140 mm (6 in) long and weighs about 12.5 g (0.4 oz). The head is grey with a rust-coloured crown, white eye-ring and pink bill. The upper parts are brown streaked with black and buff, the breast is buff, the belly is white and the tail is forked. There are two different colour morphs, one being greyer and the other more rufous.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Field_sparrow' where nome_scientifico = 'Spizella pusilla' and descrizione is null;
update specie set descrizione = 'The American tree sparrow, also known as the winter sparrow, is a medium-sized New World sparrow. It breeds in Alaska and Northern Canada and winters in Southern Canada and the Contiguous United States. It is the only member of the genus Spizelloides.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/American_tree_sparrow' where nome_scientifico = 'Spizelloides arborea' and descrizione is null;
