update specie set descrizione = 'The collared finchbill is a species of songbird in the bulbul family, Pycnonotidae. It is found in China, Taiwan, Japan and Vietnam.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Collared_finchbill' where nome_scientifico = 'Spizixos semitorques' and descrizione is null;
update specie set descrizione = 'The white-cheeked starling or grey starling is a passerine bird of the starling family. It is native to eastern Asia where it is a common and well-known bird in much of its range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-cheeked_starling' where nome_scientifico = 'Spodiopsar cineraceus' and descrizione is null;
