update specie set descrizione = 'The variable seedeater is a passerine bird which breeds from southern Mexico through Central America to the Chocó of northwestern South America. The taxonomy is confusing, and it was formerly considered a subspecies of Sporophila americana. Even within the variable seedeater as presently defined, there are great variations in plumage.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Variable_seedeater' where nome_scientifico = 'Sporophila corvina' and descrizione is null;
