update specie set descrizione = 'The thick-billed seed finch is a species of bird in the family Thraupidae, but was until recently placed in Emberizidae. It is found widely in shrubby and grassy areas from southern Mexico, through Central America, to the Chocó in Colombia and Ecuador. It is replaced by the closely related chestnut-bellied seed finch in South America east of the Andes, as well as the valleys of Cauca and Magdalena in Colombia. The two have often been considered conspecific as the lesser seed-finch.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Thick-billed_seed_finch' where nome_scientifico = 'Sporophila funerea' and descrizione is null;
update specie set descrizione = 'The rufous-rumped seedeater, also known as the grey-and-chestnut seedeater, is a species of bird in the family Thraupidae. It breeds in southern Paraguay, Argentina, and Uruguay. It migrates northward to Bolivia, the Pantanal and central Brazil. Its natural habitats are dry savanna, subtropical or tropical seasonally wet or flooded lowland grassland, and pastureland. It is threatened by habitat loss.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-rumped_seedeater' where nome_scientifico = 'Sporophila hypochroma' and descrizione is null;
