update specie set descrizione = 'L''aquila coronata, conosciuta anche come aquila coronata africana, è un grande uccello rapace originario dell''Africa sub-sahariana; in Sudafrica il suo areale è limitato alle zone a est. Il suo habitat è costituito principalmente da boscaglie e foreste. L''aquila coronata è l''unico membro esistente del genere Stephanoaetus. Una seconda specie, l''aquila coronata malgascia si estinse a seguito dell''arrivo di coloni umani in Madagascar.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Stephanoaetus_coronatus' where nome_scientifico = 'Stephanoaetus coronatus' and descrizione is null;
