update specie set descrizione = 'The brown skua, also known as the Antarctic skua, Subantarctic skua, southern great skua, southern skua, or hākoakoa (Māori), is a large seabird that breeds in the subantarctic and Antarctic zones and moves farther north when not breeding. Its taxonomy is highly complex and a matter of dispute, with some splitting it into two or three species: Falkland skua, Tristan skua, and subantarctic skua. To further confuse, it hybridizes with both the south polar and Chilean skuas, and the entire group has been considered to be a subspecies of the great skua, a species otherwise restricted to the Northern Hemisphere.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_skua' where nome_scientifico = 'Stercorarius antarcticus' and descrizione is null;
