update specie set descrizione = 'The burnished-buff tanager, also known as the rufous-crowned tanager, is a common South American species of bird in the family Thraupidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Burnished-buff_tanager' where nome_scientifico = 'Stilpnia cayana' and descrizione is null;
update specie set descrizione = 'The blue-necked tanager is a species of bird in the family Thraupidae. It is found in South America from Colombia to Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-necked_tanager' where nome_scientifico = 'Stilpnia cyanicollis' and descrizione is null;
update specie set descrizione = 'The black-headed tanager is a species of bird in the family Thraupidae.
It is found in the Andes of northeastern Colombia and the Venezuelan Coastal Range.
Its natural habitats are subtropical or tropical moist montane forests, subtropical or tropical high-altitude shrubland, and heavily degraded former forest. The black-hooded tanager was formerly considered to be conspecific with this species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-headed_tanager' where nome_scientifico = 'Stilpnia cyanoptera' and descrizione is null;
update specie set descrizione = 'The black-capped tanager is one of the many species of Neotropical bird in the family Thraupidae. It lives in the mountains of Ecuador, Colombia, and Venezuela year-round. This bird can often be found in open landscapes, alone or in pairs, hiding under branches of trees and bushes. Its natural habitats are subtropical or tropical moist montane forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-capped_tanager' where nome_scientifico = 'Stilpnia heinei' and descrizione is null;
update specie set descrizione = 'The golden-hooded tanager is a medium-sized passerine bird. This tanager is a resident breeder from southern Mexico south to western Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-hooded_tanager' where nome_scientifico = 'Stilpnia larvata' and descrizione is null;
update specie set descrizione = 'The masked tanager is a species of bird in the family Thraupidae. It is found in Bolivia, Brazil, Colombia, Ecuador, Guyana, Peru, and Venezuela. Its natural habitats are subtropical or tropical moist lowland forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Masked_tanager' where nome_scientifico = 'Stilpnia nigrocincta' and descrizione is null;
update specie set descrizione = 'The black-backed tanager is a bird species in the Thraupidae family. It is endemic to the forests and shrubs of south-eastern Brazil. When first described, it was mistakenly believed that it originates from Peru, leading to the misleading scientific name peruviana. It is closely related to the chestnut-backed tanager, and the two have sometimes been considered conspecific.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-backed_tanager' where nome_scientifico = 'Stilpnia peruviana' and descrizione is null;
update specie set descrizione = 'The chestnut-backed tanager is a species of bird in the family Thraupidae. It is found in southern Brazil, north-eastern Argentina, eastern Paraguay, and Uruguay in mature forests up to 1000m elevation. It is closely related to the rarer black-backed tanager, which have identical plumage except for the males'' mantle. Females of the two species are virtually indistinguishable by plumage. This bird is characterized by its blue-green breast and chestnut back. It was previously considered a color morph of the black-backed tanager ; however, Stilpnia is not known to be polymorphic, and the two species have different habitat preferences and breeding range. The tanager is reported as fairly common in part of its range and unlikely to face any particular threats; as a result, the IUCN has listed it as being of Least Concern.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-backed_tanager' where nome_scientifico = 'Stilpnia preciosa' and descrizione is null;
update specie set descrizione = 'The scrub tanager is a species of bird in the family Thraupidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scrub_tanager' where nome_scientifico = 'Stilpnia vitriolina' and descrizione is null;
update specie set descrizione = 'The orange-breasted forest robin is a species of bird mainly found throughout the African tropical rainforest. It has a total length of around 12 cm, has dark upperparts, and a throat and chest that, depending on the subspecies, is yellow-orange or deep orange.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-breasted_forest_robin' where nome_scientifico = 'Stiphrornis erythrothorax' and descrizione is null;
update specie set descrizione = 'The southern emu-wren is a species of bird in the Australasian wren family, Maluridae. It is endemic to Australia. Its natural habitats are temperate forests, and Mediterranean-type shrubby vegetation, and swamplands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_emu-wren' where nome_scientifico = 'Stipiturus malachurus' and descrizione is null;
