update specie set descrizione = 'Il currawong nero, noto anche come currawong cenerino, currawong della Tasmania o ghiandaia nera, è un uccello passeriforme della famiglia Artamidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strepera_fuliginosa' where nome_scientifico = 'Strepera fuliginosa' and descrizione is null;
update specie set descrizione = 'Il currawong bianconero o currawong pezzato è un uccello passeriforme della famiglia Artamidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strepera_graculina' where nome_scientifico = 'Strepera graculina' and descrizione is null;
update specie set descrizione = 'Il currawong grigio è un uccello passeriforme della famiglia Artamidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strepera_versicolor' where nome_scientifico = 'Strepera versicolor' and descrizione is null;
update specie set descrizione = 'The ring-necked dove, also known as the Cape turtle dove, half-collared dove, or the Cape Lager is a widespread and often abundant dove species in East and southern Africa. It is a mostly sedentary bird, found in a variety of open habitats. Within range, its penetrating and rhythmic, three-syllabled crooning is a familiar sound at any time of the year. Its name is derived from the semi-collar of black feathers on the lower nape, a feature shared with a number of Streptopelia species. Like all doves, they depend on surface water. They congregate in large flocks at waterholes in dry regions to drink and bathe.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ring-necked_dove' where nome_scientifico = 'Streptopelia capicola' and descrizione is null;
update specie set descrizione = 'The spotted dove or eastern spotted dove is a small and somewhat long-tailed pigeon that is a common resident breeding bird across its native range on the Indian subcontinent and in East and Southeast Asia. The species has been introduced to many parts of the world and feral populations have become established.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spotted_dove' where nome_scientifico = 'Streptopelia chinensis' and descrizione is null;
update specie set descrizione = 'La tortora dal collare orientale è un uccello della famiglia Columbidae originario dell''Asia che, nel XX secolo, ha avuto una forte espansione in Europa.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Streptopelia_decaocto' where nome_scientifico = 'Streptopelia decaocto' and descrizione is null;
update specie set descrizione = 'The mourning collared dove or African mourning dove is a dove which is a widespread resident breeding bird in Africa south of the Sahara. Despite its name, it is not closely related to the North American mourning dove. This species is common or abundant near water. They often mingle peacefully with other doves.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mourning_collared_dove' where nome_scientifico = 'Streptopelia decipiens' and descrizione is null;
update specie set descrizione = 'The dusky turtle dove or pink-breasted turtle dove is a species of bird in the family Columbidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky_turtle_dove' where nome_scientifico = 'Streptopelia lugens' and descrizione is null;
update specie set descrizione = 'The Oriental turtle dove or rufous turtle dove is a member of the bird family Columbidae. The species has a wide native distribution range from Central Asia east across Asia to Japan. The populations show variations in the patterning of plumage and have been designated into at least six named subspecies. Populations in the higher latitudes tend to migrate south in winter, while those closer to the tropics are sedentary. Vagrants have been recorded in North America. The species is predominantly granivorous and forages on the ground.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Oriental_turtle_dove' where nome_scientifico = 'Streptopelia orientalis' and descrizione is null;
update specie set descrizione = 'La tortora dal collare africana è un uccello della famiglia dei Columbidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Streptopelia_roseogrisea' where nome_scientifico = 'Streptopelia roseogrisea' and descrizione is null;
update specie set descrizione = 'The red-eyed dove is a dove that is widespread and common in Sub-Saharan Africa. It has been listed as Least Concern on the IUCN Red List since 2004.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-eyed_dove' where nome_scientifico = 'Streptopelia semitorquata' and descrizione is null;
update specie set descrizione = 'La tortora delle palme o tortora senegalese è un uccello appartenente alla famiglia Columbidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Spilopelia_senegalensis' where nome_scientifico = 'Streptopelia senegalensis' and descrizione is null;
update specie set descrizione = 'The red collared dove, also known as the red turtle dove, is a small pigeon which is a resident breeding bird in the tropics of Asia. The male has a blue-grey head and a red-brown body. The female is much plainer, with pale brown plumage similar to that of the larger Eurasian collared dove.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red_collared_dove' where nome_scientifico = 'Streptopelia tranquebarica' and descrizione is null;
update specie set descrizione = 'La tortora selvatica è un uccello che fa parte della famiglia dei Columbidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Streptopelia_turtur' where nome_scientifico = 'Streptopelia turtur' and descrizione is null;
update specie set descrizione = 'The vinaceous dove is a bird species in the pigeon family Columbidae that widely resident across northern Sub-Saharan Africa.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Vinaceous_dove' where nome_scientifico = 'Streptopelia vinacea' and descrizione is null;
update specie set descrizione = 'The biscutate swift is a species of bird in subfamily Cypseloidinae of the swift family Apodidae. It is found in Argentina, Bolivia, Brazil, and possibly Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Biscutate_swift' where nome_scientifico = 'Streptoprocne biscutata' and descrizione is null;
update specie set descrizione = 'The chestnut-collared swift is a species of bird in subfamily Cypseloidinae of the swift family Apodidae. It is found from Mexico and Trinidad south to Peru and Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-collared_swift' where nome_scientifico = 'Streptoprocne rutila' and descrizione is null;
update specie set descrizione = 'The white-collared swift is a species of bird in the subfamily Cypseloidinae of the swift family Apodidae. It is found in Mexico, Central America, the Greater and Lesser Antilles, Trinidad, and every mainland South American country.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-collared_swift' where nome_scientifico = 'Streptoprocne zonaris' and descrizione is null;
update specie set descrizione = 'L''allocco comune è un uccello rapace della famiglia degli Strigidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strix_aluco' where nome_scientifico = 'Strix aluco' and descrizione is null;
update specie set descrizione = 'The Chaco owl is an owl found in Argentina, Bolivia, and Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chaco_owl' where nome_scientifico = 'Strix chacoensis' and descrizione is null;
update specie set descrizione = 'The fulvous owl, or Guatemala barred owl, is a resident of the cloud forests of Central America. A medium-sized true owl, it has a round head, lacking ear tufts. Its typical coloration is warm dark brown or reddish brown on the back and lighter brown on the front with darker barring. Adults weigh approximately 600 grams (21 oz), with females being heavier. Its distribution is limited to highland regions of Guatemala, Honduras, and El Salvador. It inhabits elevations from 1,200 to 3,100 meters, and is fairly common within its range. Its behavior is poorly known, as are its population size and distribution. It is classified as a species of least concern by the International Union for Conservation of Nature, although it is considered endangered in Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fulvous_owl' where nome_scientifico = 'Strix fulvescens' and descrizione is null;
update specie set descrizione = 'The desert owl or desert tawny owl, formerly known as Hume''s owl, is a species of owl. It is closely related to the more widespread tawny owl and to the range-restricted Omani owl.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Desert_owl' where nome_scientifico = 'Strix hadorami' and descrizione is null;
update specie set descrizione = 'The rusty-barred owl is a medium-sized "typical owl" in subfamily Striginae. It is found in Argentina, Brazil, and Paraguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rusty-barred_owl' where nome_scientifico = 'Strix hylophila' and descrizione is null;
update specie set descrizione = 'L''allocco bruno malese è un uccello rapace tropicale appartenente alla famiglia Strigidae.
È diffuso nel sud-est asiatico, dove si nasconde nelle fitte foreste sempreverdi equatoriali ed umide.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strix_leptogrammica' where nome_scientifico = 'Strix leptogrammica' and descrizione is null;
update specie set descrizione = 'L''allocco di Lapponia o gufo della Lapponia è un grande uccello rapace notturno appartenente alla famiglia Strigidae, distribuito in tutta l''emisfero nord, nelle foreste di conifere che precedono la tundra.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strix_nebulosa' where nome_scientifico = 'Strix nebulosa' and descrizione is null;
update specie set descrizione = 'The Himalayan owl or Himalayan wood owl is a medium-sized owl native to the forests and mountain ranges of the Himalayas, Taiwan and Korea. Although populations are declining, this owl is not considered endangered and is currently listed as a species of Least Concern on the IUCN Red List due to its large range and slow decline. The Himalayan owl is nocturnal and is rarely seen in most areas of its range. Few studies have been done on its lifestyle and current population trends.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Himalayan_owl' where nome_scientifico = 'Strix nivicolum' and descrizione is null;
update specie set descrizione = 'L''allocco macchiato o allocco maculato americano è un rapace notturno della famiglia degli Strigidi originario del Nordamerica.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strix_occidentalis' where nome_scientifico = 'Strix occidentalis' and descrizione is null;
update specie set descrizione = 'The mottled wood owl is a species of large owl found in India and Nepal. They are found in gardens and thin deciduous forests adjacent to dry thorn forests or farmland. They are easily detected by their distinctive tremulous, eerie calls at dawn and dusk. The characteristic call is a duet of the male and female, while other notes include a low hoot and a screech. Their large size, lack of "ear" tufts and the concentric barring on the face make them easy to identify.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mottled_wood_owl' where nome_scientifico = 'Strix ocellata' and descrizione is null;
update specie set descrizione = 'L''allocco zamperosse è un rapace notturno della famiglia degli Strigidi, originario dell''America del Sud.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strix_rufipes' where nome_scientifico = 'Strix rufipes' and descrizione is null;
update specie set descrizione = 'The spotted wood owl is an owl of the earless owl genus, Strix. Its range is disjunct; it occurs in many regions surrounding Borneo, but not on that island itself.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spotted_wood_owl' where nome_scientifico = 'Strix seloputo' and descrizione is null;
update specie set descrizione = 'L''allocco degli Urali è un grande gufo notturno appartenente al genere Strix della famiglia Strigidae, da cui deriva anche il nome della famiglia secondo la tassonomia linneana. Il suo nome comune e scientifico si riferiscono agli Urali in Russia, dove fu raccolto l''esemplare tipo. Tuttavia, ha un''ampia distribuzione che si estende ad ovest fino alla Scandinavia, alle regioni montuose dell''Europa orientale e, sporadicamente, all''Europa centrale, quindi attraverso il Paleartico in tutta la Russia fino a Sachalin e il Giappone.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strix_uralensis' where nome_scientifico = 'Strix uralensis' and descrizione is null;
update specie set descrizione = 'L''allocco barrato è un uccello rapace notturno appartenente alla famiglia degli Strigidae. È originario dell''America settentrionale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Strix_varia' where nome_scientifico = 'Strix varia' and descrizione is null;
update specie set descrizione = 'The African wood owl or Woodford''s owl, is a typical owl from the genus Strix in the family Strigidae and is arguably the most common forest owl in Africa. It inhabits wooded areas and possesses a distinctive call. During the day it roosts singly or in pairs in dense cover, high in trees, whilst at night it forages for food.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_wood_owl' where nome_scientifico = 'Strix woodfordii' and descrizione is null;
update specie set descrizione = 'L''uccello apostolo è un uccello passeriforme della famiglia dei Corcoracidae, unica specie ascritta al genere Struthidea Gould, 1837.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Struthidea_cinerea' where nome_scientifico = 'Struthidea cinerea' and descrizione is null;
update specie set descrizione = 'The eastern meadowlark is a medium-sized icterid bird, very similar in appearance to its sister species, the western meadowlark. It occurs from eastern North America to northern South America, where it is also most widespread in the east. The Chihuahuan meadowlark was formerly considered to be conspecific with the eastern meadowlark.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_meadowlark' where nome_scientifico = 'Sturnella magna' and descrizione is null;
update specie set descrizione = 'The western meadowlark is a medium-sized icterid bird, about 20 cm (7.9 in) in length. It is found across western and central North America and is a partial migrant, breeding in western Canada and western United States west of the Great Lakes, and in northern Mexico. In the northern half of the breeding range, the birds migrate south for the winter, while further south they are resident all year. The winter range also extends south and southeast of the breeding range, as far as central Mexico, and east to western Florida. The western meadowlark nests on the ground in open grasslands and shrublands. It feeds on bugs and seeds. The western meadowlark has distinctive calls described as watery or flute-like, which distinguish it from the closely related eastern meadowlark. The western meadowlark is the state bird of six states; in Kansas, Montana, Nebraska, North Dakota, Oregon, and Wyoming.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_meadowlark' where nome_scientifico = 'Sturnella neglecta' and descrizione is null;
update specie set descrizione = 'The Malabar starling is a species of starling found in southwestern India. It was previously considered a subspecies of the chestnut-tailed starling.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Malabar_starling' where nome_scientifico = 'Sturnia blythii' and descrizione is null;
update specie set descrizione = 'Lo storno codacastana è un uccello appartenente all''ordine dei passeriformi, della famiglia degli storni.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sturnia_malabarica' where nome_scientifico = 'Sturnia malabarica' and descrizione is null;
update specie set descrizione = 'Lo storno bramino è un uccello passeriforme appartenente alla famiglia degli Sturnidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Sturnia_pagodarum' where nome_scientifico = 'Sturnia pagodarum' and descrizione is null;
update specie set descrizione = 'The white-shouldered starling is a species of bird in the starling family Sturnidae. It breeds in southern China and northern Vietnam; it winters in Southeast Asia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-shouldered_starling' where nome_scientifico = 'Sturnia sinensis' and descrizione is null;
