update specie set descrizione = 'The northern scrub flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Aruba, Bonaire, Colombia, Costa Rica, Curaçao, French Guiana, Guyana, Panama, Suriname, Trinidad, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_scrub_flycatcher' where nome_scientifico = 'Sublegatus arenarum' and descrizione is null;
update specie set descrizione = 'The southern scrub flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Argentina, Bolivia, Brazil, Paraguay, Peru, and Uruguay. Other sources also place it in Guyana, Suriname, as a non-breeding visitor to Colombia, and as a vagrant in Ecuador.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Southern_scrub_flycatcher' where nome_scientifico = 'Sublegatus modestus' and descrizione is null;
update specie set descrizione = 'The Amazonian scrub flycatcher or Todd''s scrub flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in every mainland South American country except Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Amazonian_scrub_flycatcher' where nome_scientifico = 'Sublegatus obscurior' and descrizione is null;
update specie set descrizione = 'The black honeyeater is a species of bird in the honeyeater family Meliphagidae and the sole species in the genus Sugomel. The black honeyeater exhibits sexual dimorphism, with the male being black and white while the female is a speckled grey-brown; immature birds look like the female. The species is endemic to Australia, and ranges widely across the arid areas of the continent, through open woodland and shrubland, particularly in areas where the emu bush and related species occur.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_honeyeater' where nome_scientifico = 'Sugomel nigrum' and descrizione is null;
