update specie set descrizione = 'The brown booby is a large seabird in the booby and gannet family Sulidae, of which it is one of the most common and widespread species. It has a pantropical range, which overlaps with that of other booby species. The gregarious brown booby commutes and forages at low height over inshore waters. Flocks plunge-dive to take small fish, especially when these are driven near the surface by their predators. They nest only on the ground, and roost on solid objects rather than the water surface.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_booby' where nome_scientifico = 'Sula leucogaster' and descrizione is null;
