update specie set descrizione = 'The northern hawk-owl or northern hawk owl, is a medium-sized true owl of the northern latitudes. It is non-migratory and usually stays within its breeding range, though it sometimes irrupts southward. It is one of the few owls that is not strictly nocturnal nor crepuscular, often being active during the day. This is the only living species in the genus Surnia of the family Strigidae, the "typical" owls. The species is sometimes called simply the hawk owl; however, many species of owls in the genus Ninox are also called "hawk owls".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Northern_hawk-owl' where nome_scientifico = 'Surnia ulula' and descrizione is null;
