update specie set descrizione = 'The king quail, also known as the Asian blue quail, blue-breasted quail, Chinese painted quail, button quail, or Chung-Chi, is a very small, diminutive galliform of the tribe Coturnicini in the subfamily Phasianinae. They are the smallest member in this subfamily and the family Phasianidae, as well as being the smallest and lightest member of the order Galliformes. It is quite common in aviculture worldwide, where it is sometimes referred to as the "button quail", although it is not closely related to the family of birds called buttonquails. Its voice is a piping whistle, ti-yu or ti-ti-yu. It also gives sharp cheeps or a tir-tir-tir sound when flushed.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/King_quail' where nome_scientifico = 'Synoicus chinensis' and descrizione is null;
