update specie set descrizione = 'L''airone fischiatore (Syrigma sibilatrix è un uccello della famiglia degli Ardeidi, diffuso in Sud America. È l''unica specie nota del genere Syrigma .', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Syrigma_sibilatrix' where nome_scientifico = 'Syrigma sibilatrix' and descrizione is null;
update specie set descrizione = 'The band-winged nightjar or greater band-winged nightjar is a species of nightjar in the family Caprimulgidae. It is the only species now placed in the genus Systellura. It is widespread in South America, where it is found in the Andes, Venezuelan Coastal Range, Santa Marta Mountains, Tepuis, most of Chile, Argentina, Paraguay, Uruguay, and eastern Brazil. It occurs in a wide range of habitats, from the edge of humid montane forests to shrubby semi-deserts and urban rooftops.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Band-winged_nightjar' where nome_scientifico = 'Systellura longirostris' and descrizione is null;
update specie set descrizione = 'La malcoa sirkir o cuculo di Sirkeer, è un uccello della famiglia dei Cuculidae e unico rappresentante del genere Taccocua.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Taccocua_leschenaultii' where nome_scientifico = 'Taccocua leschenaultii' and descrizione is null;
update specie set descrizione = 'The Antillean palm swift is a species of bird in subfamily Apodinae of the swift family Apodidae. It is found on the Caribbean islands of Cuba, Jamaica, and Hispaniola.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Antillean_palm_swift' where nome_scientifico = 'Tachornis phoenicobia' and descrizione is null;
update specie set descrizione = 'The fork-tailed palm swift or Neotropical palm swift is a species of bird in subfamily Apodinae of the swift family Apodidae. It is found across most of northern South America and on Trinidad and Tobago.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fork-tailed_palm_swift' where nome_scientifico = 'Tachornis squamata' and descrizione is null;
