update specie set descrizione = 'The white-winged swallow is a resident breeding swallow in tropical South America found in Brazil, Colombia, Venezuela, Trinidad, and Argentina. It is not found west of the Andes. This swallow is largely non-migratory.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-winged_swallow' where nome_scientifico = 'Tachycineta albiventer' and descrizione is null;
update specie set descrizione = 'La rondine arboricola bicolore (Tachycineta bicolor è un uccello della famiglia Hirundinidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tachycineta_bicolor' where nome_scientifico = 'Tachycineta bicolor' and descrizione is null;
update specie set descrizione = 'The golden swallow is a swallow endemic to the Caribbean island of Hispaniola and was once native to Jamaica, but is now extirpated there. It is restricted to isolated montane forests that primarily consist of the Hispaniolan pine. This species is considered to be a vulnerable species by the International Union for Conservation of Nature (IUCN). The exact cause of its extirpation from Jamaica is unknown, but likely factors include predation by introduced mammals and habitat loss, although the habitat loss theory is not supported by much evidence. The last sighting of the nominate subspecies was in Hardwar Gap, with three birds being seen on 8 June 1989.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden_swallow' where nome_scientifico = 'Tachycineta euchrysea' and descrizione is null;
update specie set descrizione = 'The Chilean swallow is a species of bird in the family Hirundinidae. It breeds in Chile and Patagonia, migrating north as far as Bolivia, Paraguay, and Rio Grande do Sul.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chilean_swallow' where nome_scientifico = 'Tachycineta leucopyga' and descrizione is null;
update specie set descrizione = 'The white-rumped swallow is a species of bird in the family Hirundinidae. First described and given its binomial name by French ornithologist Louis Pierre Vieillot in 1817, it was for many years considered a subspecies of the Chilean swallow. The species is monotypic with no known population variations. It has a white supraloral streak, or streak above its lores, which can be used to differentiate it from the Chilean swallow. The lores, ear coverts, tail, and wings are black, with white tips on the inner secondaries, tertials, and greater coverts of the wings. The rest of the upperparts are a glossy blue. Its underparts and underwing-coverts are white, in addition to the rump, as the name suggests. The sexes are similar, and the juvenile is duller and browner with a dusky breast.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-rumped_swallow' where nome_scientifico = 'Tachycineta leucorrhoa' and descrizione is null;
update specie set descrizione = 'The violet-green swallow is a small North American passerine bird in the swallow family. These aerial insectivores are distributed along the west coast from Alaska to Mexico, extending as far east as Montana and Texas. With an appearance very similar to the tree swallow, these individuals can be identified by the white rump side-patches that appear to separate their green back and purple tail. Violet-green swallows are secondary cavity nesters, found in a number of habitats including deciduous and coniferous forest. In addition to nesting in tree holes within these habitats, they are also widely observed nesting in the cracks of large cliffs.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Violet-green_swallow' where nome_scientifico = 'Tachycineta thalassina' and descrizione is null;
update specie set descrizione = 'L’anatra vaporiera volatrice è un uccello della famiglia Anatidae, diffuso in Cile e Argentina.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tachyeres_patachonicus' where nome_scientifico = 'Tachyeres patachonicus' and descrizione is null;
