update specie set descrizione = 'La casarca del paradiso è una grossa casarca endemica della Nuova Zelanda. I Maori la chiamano Putangitangi, ma più di frequente la indicano come «anatra del Paradiso»; costituisce un''ambita preda per i cacciatori. Sia il maschio che la femmina hanno un piumaggio molto variopinto, ma il primo ha la testa nera e il corpo barrato dello stesso colore, mentre la femmina ha la testa bianca e il corpo castano.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tadorna_variegata' where nome_scientifico = 'Tadorna variegata' and descrizione is null;
update specie set descrizione = 'The collared owlet, also known as the collared pygmy owl, is a species of owl in the family Strigidae. Its natural habitat is submontane and montane forests with open spaces and is distributed throughout oriental Asia. It is the smallest owl in Asia, at 15 cm (5.9 in) and 60 g (2.1 oz).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Collared_owlet' where nome_scientifico = 'Taenioptynx brodiei' and descrizione is null;
