update specie set descrizione = 'Lo scoiattolo rosso nordamericano è una specie di scoiattolo arboricolo del genere Tamiasciurus originaria del Nordamerica.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tamiasciurus_hudsonicus' where nome_scientifico = 'Tamiasciurus hudsonicus' and descrizione is null;
update specie set descrizione = 'The golden tanager is a species of bird in the family Thraupidae. It is widespread and often common in highland forests of the Andes and Venezuelan Coastal Range in north-western South America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden_tanager' where nome_scientifico = 'Tangara arthus' and descrizione is null;
update specie set descrizione = 'The paradise tanager is a brilliantly multicolored, medium-sized songbird whose length varies between 13.5 and 15 cm. It has a light green head, sky blue underparts and black upper body plumage.The vivid colours of the paradise tanager have been linked to underlying achromatic feather layers that enhance the brilliance of structural colours. Depending on subspecies, the behind is yellow and red or all red. The beak is black and the legs are grey. It is native to the Amazon rainforest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Paradise_tanager' where nome_scientifico = 'Tangara chilensis' and descrizione is null;
update specie set descrizione = 'The red-necked tanager is a species of bird in the family Thraupidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-necked_tanager' where nome_scientifico = 'Tangara cyanocephala' and descrizione is null;
update specie set descrizione = 'The gilt-edged tanager is a species of bird in the family Thraupidae. It is endemic to Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gilt-edged_tanager' where nome_scientifico = 'Tangara cyanoventris' and descrizione is null;
update specie set descrizione = 'The brassy-breasted tanager is a species of bird in the family Thraupidae. It is endemic to Brazil. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brassy-breasted_tanager' where nome_scientifico = 'Tangara desmaresti' and descrizione is null;
update specie set descrizione = 'The spangle-cheeked tanager is a medium-sized passerine bird. This tanager is an endemic resident breeder in the highlands of Costa Rica and western Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spangle-cheeked_tanager' where nome_scientifico = 'Tangara dowii' and descrizione is null;
update specie set descrizione = 'The emerald tanager is a species of bird in the tanager family Thraupidae. It is found in Colombia, Costa Rica, Ecuador, and Panama. Described by the English ornithologists PL Sclater and Osbert Salvin in 1869, it is a medium-sized species that has a length of 10.6–13 cm (4.2–5.1 in) and a mass of 18–20.5 g (0.63–0.72 oz). It can be identified by its bright green plumage, with black streaking on the back and wings, and a black auricular patch and beak. It also has yellow on the crown and rump. The species shows slight sexual dimorphism, with the females being duller and having yellow-green in place of yellow on the head.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Emerald_tanager' where nome_scientifico = 'Tangara florida' and descrizione is null;
update specie set descrizione = 'The bay-headed tanager is a medium-sized passerine bird. This tanager is a resident breeder in Costa Rica, Panama, South America south to Ecuador, Bolivia, and north-western Brazil, and on Trinidad.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bay-headed_tanager' where nome_scientifico = 'Tangara gyrola' and descrizione is null;
update specie set descrizione = 'The silver-throated tanager is a species of passerine bird in the tanager family Thraupidae. It is found in Costa Rica, Panama, Colombia, Ecuador, and northeastern Peru. It inhabits mossy forests, montane forests, tropical lowland evergreen forests and forest edges, along with tall secondary forests and disturbed habitat with remnant trees and forest. It is 13 centimetres (5.1 in) long and weighs 22 grams (0.78 oz) on average, and shows slight sexual dimorphism, with duller female plumage. Adult males are mainly bright yellow, with a silvery-white throat bordered above with a black stripe on the cheeks, black streaking on the back, and green edges to the wings and tail. Juveniles are duller and greener.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Silver-throated_tanager' where nome_scientifico = 'Tangara icterocephala' and descrizione is null;
update specie set descrizione = 'The plain-colored tanager is a species of bird in the family Thraupidae. It is found in Colombia, Costa Rica, and Panama. Its natural habitats are subtropical or tropical moist lowland forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Plain-colored_tanager' where nome_scientifico = 'Tangara inornata' and descrizione is null;
update specie set descrizione = 'The metallic-green tanager is a species of bird in the family Thraupidae. It is found in Colombia, Ecuador, and Peru. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Metallic-green_tanager' where nome_scientifico = 'Tangara labradorides' and descrizione is null;
update specie set descrizione = 'The rufous-winged tanager is a species of bird in the family Thraupidae. It is found in Colombia, Costa Rica, Ecuador, Honduras, Nicaragua, and Panama. Its natural habitats are subtropical or tropical moist lowland forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-winged_tanager' where nome_scientifico = 'Tangara lavinia' and descrizione is null;
update specie set descrizione = 'The turquoise tanager is a medium-sized passerine bird in the tanager family Thraupidae. It is a resident bird from Trinidad, much of Brazil, Colombia, and Venezuela, and south to Bolivia. Despite its scientific name, it is not found in Mexico. It is restricted to areas with humid forest, with its primary distribution being the Amazon. It was formerly treated as being conspecific with the white-bellied tanager which is found in the Atlantic Forest of eastern Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Turquoise_tanager' where nome_scientifico = 'Tangara mexicana' and descrizione is null;
update specie set descrizione = 'The beryl-spangled tanager is a small songbird of the northern Andes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Beryl-spangled_tanager' where nome_scientifico = 'Tangara nigroviridis' and descrizione is null;
update specie set descrizione = 'The flame-faced tanager is a species of bird in the tanager family Thraupidae. It is endemic to South America and is found in the eastern Andes of Colombia, Ecuador, Peru and Venezuela. Its natural habitat is subtropical or tropical moist montane forests. It is a distinctive-looking species with black and opalescent green upperparts, opalescent green and buff underparts, and a deep red and yellow face. The subspecies lunigera lacks the deep red on the face, which is replaced with orangish-red.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Flame-faced_tanager' where nome_scientifico = 'Tangara parzudakii' and descrizione is null;
update specie set descrizione = 'The green-and-gold tanager is a species of bird in the family Thraupidae, the tanagers. It is one of 27 species in the genus Tangara.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-and-gold_tanager' where nome_scientifico = 'Tangara schrankii' and descrizione is null;
update specie set descrizione = 'La tangara testaverde è un uccello appartenente alla famiglia Thraupidae diffuso in America meridionale.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tangara_seledon' where nome_scientifico = 'Tangara seledon' and descrizione is null;
update specie set descrizione = 'The blue-and-black tanager is a species of bird in the tanager family Thraupidae. It is found in the Andes of Bolivia, Colombia, Ecuador, Peru and Venezuela, where it inhabits montane evergreen forest, dwarf forest, and secondary forest at elevations of 1,500–3,500 m (4,900–11,500 ft). It inhabits the highest altitude of any Tangara species, and is the only species from the genus that is found near the tree line. Adults are 13 cm (5.1 in) long and weigh 18 g (0.63 oz) on average, and are mostly blue with black masks, wings, and tails. The species shows slight sexual dimorphism, with females being slightly duller than males.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-and-black_tanager' where nome_scientifico = 'Tangara vassorii' and descrizione is null;
update specie set descrizione = 'The opal-rumped tanager is a species of bird in the family Thraupidae. It is found in the Amazon and Atlantic Forest of South America. The population of the Atlantic Forest has a far paler chest than the other populations, and has often been considered a separate species as the silvery-breasted tanager. Today most authorities treat it as a subspecies of the opal-rumped tanager.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Opal-rumped_tanager' where nome_scientifico = 'Tangara velia' and descrizione is null;
update specie set descrizione = 'The saffron-crowned tanager is a species of bird in the family Thraupidae. Found in the northern Andes of Bolivia, Colombia, Ecuador, Peru, and Venezuela, it inhabits cloud forest, forest edges, and secondary forest, preferring areas with mossy trees. It is an average-sized species of tanager with a blue-green body and yellow head with a black forecrown, lores, orbital area, and chin.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Saffron-crowned_tanager' where nome_scientifico = 'Tangara xanthocephala' and descrizione is null;
update specie set descrizione = 'Il pappagallo groppazzurra è un uccello della famiglia Psittaculidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tanygnathus_sumatranus' where nome_scientifico = 'Tanygnathus sumatranus' and descrizione is null;
update specie set descrizione = 'The common paradise kingfisher, also known as the Galatea paradise kingfisher and the racquet-tailed kingfisher, is a species of bird in the family Alcedinidae. It is found in subtropical or tropical moist lowland forests of the Maluku Islands and New Guinea. Like all paradise kingfishers, it has a red bill and colourful plumage. The species is common and the IUCN has assessed its conservation status as being of "least concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Common_paradise_kingfisher' where nome_scientifico = 'Tanysiptera galatea' and descrizione is null;
update specie set descrizione = 'The buff-breasted paradise kingfisher is a bird in the tree kingfisher subfamily, Halcyoninae. It is native to Australia and New Guinea. It migrates in November from New Guinea to its breeding grounds in the rainforest of North Queensland, Australia. Like all paradise kingfishers, this bird has colourful plumage with a red bill, buff breast and distinctive long tail streamers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Buff-breasted_paradise_kingfisher' where nome_scientifico = 'Tanysiptera sylvia' and descrizione is null;
