update specie set descrizione = 'The great antshrike is a passerine bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is found in southern Mexico, in every Central American country except El Salvador, on Trinidad, and in every mainland South American country except Chile, though only as a vagrant in Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Great_antshrike' where nome_scientifico = 'Taraba major' and descrizione is null;
update specie set descrizione = 'The Chaco earthcreeper is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Argentina, Bolivia, and Paraguay, and as a vagrant in Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chaco_earthcreeper' where nome_scientifico = 'Tarphonomus certhioides' and descrizione is null;
update specie set descrizione = 'The Bolivian earthcreeper is a species of bird in the Furnariinae subfamily of the ovenbird family Furnariidae. It is found in Argentina and Bolivia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bolivian_earthcreeper' where nome_scientifico = 'Tarphonomus harterti' and descrizione is null;
update specie set descrizione = 'The golden bush robin or golden bush-robin was first discovered in 1845 by Brian Houghton Hodgson, a British naturalist.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden_bush_robin' where nome_scientifico = 'Tarsiger chrysaeus' and descrizione is null;
update specie set descrizione = 'The red-flanked bluetail, also known as the orange-flanked bush-robin, is a small passerine bird in the Old World flycatcher family. It breeds in mixed coniferous forests in northern Asia, parts of central Asia, and northeastern Europe. It is migratory, wintering mainly in southeast Asia, in the Indian subcontinent, the Himalayas, Taiwan, and northern Indochina.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-flanked_bluetail' where nome_scientifico = 'Tarsiger cyanurus' and descrizione is null;
update specie set descrizione = 'The white-browed bush robin is a species of passerine bird in the Old World flycatcher family Muscicapidae that is found from the Himalayas to south-central China and north Vietnam. Its natural habitat is Rhododendron and conifer forests. The Taiwan bush robin was formerly regarded as a subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-browed_bush_robin' where nome_scientifico = 'Tarsiger indicus' and descrizione is null;
update specie set descrizione = 'The collared bush-robin or Johnstone''s robin is a species of bird in the family Muscicapidae. It is endemic to Taiwan, living in montane and subalpine forests. The International Union for Conservation of Nature (IUCN) has assessed it as a least-concern species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Collared_bush_robin' where nome_scientifico = 'Tarsiger johnstoniae' and descrizione is null;
update specie set descrizione = 'The Himalayan bluetail, also called the Himalayan red-flanked bush-robin or orange-flanked bush-robin, is a small passerine bird that was formerly classed as a member of the thrush family Turdidae, but is now more generally considered to be an Old World flycatcher of Muscicapidae. While currently under review, this taxon is not current recognized as a species by BirdLife international.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Himalayan_bluetail' where nome_scientifico = 'Tarsiger rufilatus' and descrizione is null;
