update specie set descrizione = 'The black-crowned tchagra is a bushshrike. This family of passerine birds is closely related to the true shrikes in the family Laniidae, and was once included in that group.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-crowned_tchagra' where nome_scientifico = 'Tchagra senegalus' and descrizione is null;
