update specie set descrizione = 'Bocage''s bushshrike, also known as the grey-green bushshrike, is a species of bird in the family Malaconotidae. It is scatteredly present throughout central Africa. Its natural habitats are subtropical or tropical dry forest and subtropical or tropical moist lowland forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bocage''s_bushshrike' where nome_scientifico = 'Telophorus bocagei' and descrizione is null;
update specie set descrizione = 'The black-fronted bushshrike is a passerine bird of the bushshrike family, Malaconotidae. It inhabits forests mainly in East Africa. It forms a superspecies with the many-colored bushshrike and the two are sometimes considered to be a single species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-fronted_bushshrike' where nome_scientifico = 'Telophorus nigrifrons' and descrizione is null;
update specie set descrizione = 'The olive bushshrike is a species of bird in the family Malaconotidae.
It is found in Malawi, Mozambique, South Africa, Eswatini, and Zimbabwe.
Its natural habitats are subtropical or tropical dry forest, subtropical or tropical moist lowland forest, subtropical or tropical moist montane forest, and subtropical or tropical dry shrubland. It forages for insects in the forest canopy.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Olive_bushshrike' where nome_scientifico = 'Telophorus olivaceus' and descrizione is null;
update specie set descrizione = 'The orange-breasted bushshrike or sulphur-breasted bushshrike is a species of bird in the family Malaconotidae. Another bird, Braun''s bushshrike, is also sometimes called the orange-breasted bushshrike.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-breasted_bushshrike' where nome_scientifico = 'Telophorus sulfureopectus' and descrizione is null;
update specie set descrizione = 'The gorgeous bushshrike is a species of bird in the family Malaconotidae. It is also known as the four-coloured bushshrike. Some use the name gorgeous bushshrike for the subspecies Telophorus viridis viridis only.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gorgeous_bushshrike' where nome_scientifico = 'Telophorus viridis' and descrizione is null;
update specie set descrizione = 'The bokmakierie is a bushshrike. This family of passerine birds is closely related to the true shrikes in the family Laniidae, and was once included in that group. This species is endemic to southern Africa, mainly in South Africa and Namibia, with an isolated population in the mountains of eastern Zimbabwe and western Mozambique.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bokmakierie' where nome_scientifico = 'Telophorus zeylonus' and descrizione is null;
