update specie set descrizione = 'The ruddy-tailed flycatcher is a small passerine bird in the family Onychorhynchidae. It was previously place in family Tityridae. Its range extends from southeast Mexico south to the Amazon rainforest. It is the only member of the genus Terenotriccus, but some authorities place it in genus Myiobius. However, it differs in voice, behaviour, and structure from members of that group.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ruddy-tailed_flycatcher' where nome_scientifico = 'Terenotriccus erythrurus' and descrizione is null;
