update specie set descrizione = 'The orange-bellied antwren or Sick''s antwren, is a Critically Endangered species of bird in subfamily Thamnophilinae of family Thamnophilidae, the "typical antbirds". It is endemic to Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-bellied_antwren' where nome_scientifico = 'Terenura sicki' and descrizione is null;
