update specie set descrizione = 'The black paradise flycatcher, also known as the Japanese paradise flycatcher, is a medium-sized passerine bird native to southeastern Asia. It is a glossy black, chestnut and white bird, slightly smaller than either the Amur paradise flycatcher or Blyth''s paradise flycatcher, but similar in appearance. Males have exceptionally long tails. Females are generally duller in appearance and have shorter tails.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_paradise_flycatcher' where nome_scientifico = 'Terpsiphone atrocaudata' and descrizione is null;
