update specie set descrizione = 'The rufous paradise flycatcher is a species of bird in the family Monarchidae native to Indonesia and the Philippines.
Its natural habitat is tropical moist lowland forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous_paradise_flycatcher' where nome_scientifico = 'Terpsiphone cinnamomea' and descrizione is null;
update specie set descrizione = 'The Amur paradise flycatcher is a bird species in the family Monarchidae.
It is native to China and Primorsky Krai in the Russian Far East. It is a winter migrant to Southeast Asia. Until 2015, it was considered as a subspecies of the Asian paradise flycatcher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Amur_paradise_flycatcher' where nome_scientifico = 'Terpsiphone incei' and descrizione is null;
update specie set descrizione = 'Il pigliamosche del Paradiso del Madagascar è un uccello della famiglia Monarchidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Terpsiphone_mutata' where nome_scientifico = 'Terpsiphone mutata' and descrizione is null;
update specie set descrizione = 'The Indian paradise flycatcher is a medium-sized passerine bird in the monarch flycatcher family, Monarchidae. As the global population is considered stable, it has been listed as Least Concern on the IUCN Red List since 2004. It is native to the Indian subcontinent, with resident and breeding populations in most of Bangladesh, India and Sri Lanka, as well as parts of Afghanistan, Bhutan, China, Myanmar, Nepal, Pakistan, Tajikistan and Turkmenistan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_paradise_flycatcher' where nome_scientifico = 'Terpsiphone paradisi' and descrizione is null;
update specie set descrizione = 'The red-bellied paradise flycatcher, also known as the black-headed paradise flycatcher, is a medium-sized passerine bird of the family of monarch flycatchers. It is native to intra-tropical forests of Africa. The male bird is about 17 cm (7 in) long and has a black head, a mainly chestnut body, and a tail with streamers nearly twice as long as the body. The colouring is somewhat variable across the bird''s range. Both females and juveniles lack the tail streamers and are a duller brown colour. It is closely related to the African paradise flycatcher, and the two can hybridise.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Red-bellied_paradise_flycatcher' where nome_scientifico = 'Terpsiphone rufiventer' and descrizione is null;
update specie set descrizione = 'The African paradise flycatcher is a medium-sized passerine bird. The two central tail feathers of the male are extended into streamers that commonly are more than twice as long as the body. The female tail feathers are of moderate length and without streamers. The upper parts of the male body, wings, and tail are boldly coloured in chestnut or rusty shades, but the underparts and the head are variably grey to blue-gray, with the head of the mature male being darker, commonly glossy black with greenish highlights. The beak and other bare areas, including a wattle ring round the eye, match the colour of the surrounding feathers. The female coloration is similar, though not so showy and glossy and with the head paler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_paradise_flycatcher' where nome_scientifico = 'Terpsiphone viridis' and descrizione is null;
update specie set descrizione = 'Il tanagra rondine è un uccello della famiglia Thraupidae, diffuso in America meridionale. È l''unica specie appartenente al genere Tersina.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tersina_viridis' where nome_scientifico = 'Tersina viridis' and descrizione is null;
