update specie set descrizione = 'Il tetraogallo del Tibet, anche tetraogallo tibetano è un uccello galliforme della famiglia dei Fasianidi. È diffuso nelle regioni di alta quota dell''Himalaya occidentale e dell''altopiano del Tibet, dove il suo areale si sovrappone in parte a quello del più grande tetraogallo dell''Himalaya. È caratterizzato da una testa di colore grigiastro, da una macchia bianca a forma di mezzaluna dietro l''occhio e dalla regione inferiore bianca striata di nero. In volo appare ben evidente il bianco del margine posteriore delle remiganti secondarie.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tetraogallus_tibetanus' where nome_scientifico = 'Tetraogallus tibetanus' and descrizione is null;
