update specie set descrizione = 'La gallina prataiola è un grosso uccello della famiglia delle otarde, unico membro del genere Tetrax. Nidifica in Europa meridionale e centrale ed in Asia occidentale e centrale. Gli uccelli che vivono in Europa meridionale sono soprattutto stanziali, ma le altre popolazioni migrano più a sud in inverno.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tetrax_tetrax' where nome_scientifico = 'Tetrax tetrax' and descrizione is null;
