update specie set descrizione = 'The rufous-chested tanager is a species of bird in the family Thraupidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-chested_tanager' where nome_scientifico = 'Thlypopsis ornata' and descrizione is null;
update specie set descrizione = 'The chestnut-headed tanager is a species of bird in the tanager family Thraupidae. It is found in the Atlantic Forest of southeast Brazil, eastern Paraguay, and far northeastern Argentina. It was formerly the only member of the genus Pyrrhocoma but is now placed in Thlypopsis.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-headed_tanager' where nome_scientifico = 'Thlypopsis pyrrhocoma' and descrizione is null;
update specie set descrizione = 'The orange-headed tanager is a species of bird in the family Thraupidae. Native to South America, it is found in Argentina, Bolivia, Brazil, Colombia, Ecuador, Paraguay, Peru, and Venezuela, where it inhabits successional vegetation, cerrado, riparian forest, shrub, brush, and open woodland. Males of the species have sandy-gray upperparts, cinnamon to buff underparts, white on the center of the lower breast, belly, and tail, and rufous-orange and yellow heads. Females are similar but duller.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Orange-headed_tanager' where nome_scientifico = 'Thlypopsis sordida' and descrizione is null;
update specie set descrizione = 'The superciliaried hemispingus is a species of bird in the family Thraupidae. It is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela. Its natural habitats are subtropical or tropical moist montane forests and degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Superciliaried_hemispingus' where nome_scientifico = 'Thlypopsis superciliaris' and descrizione is null;
update specie set descrizione = 'The yellow-winged tanager is a neotropical member of the tanager family. It is of average size for a tanager, about 18-centimetre (7.1 in) long. It is distinguished by the yellow patches on its dusky green wings, marking an otherwise dark bluish and gray body. It has a pale lavender tone on its throat and breast. The juvenile lacks this color, but has an olive-green head and upper back.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-winged_tanager' where nome_scientifico = 'Thraupis abbas' and descrizione is null;
update specie set descrizione = 'The azure-shouldered tanager is a species of bird in the tanager family, Thraupidae. Described by the French zoologist Louis Pierre Vieillot in 1817, it is only found in the Atlantic Forest of southeastern Brazil, from southeastern Bahia, eastern Minas Gerais, and Espírito Santo south to northern Rio Grande do Sul. It inhabits humid montane forests, open woodlands, secondary growth, and forest edges and can be found at elevations of up to 1,600 m (5,200 ft), but usually stays below 1,200 m (3,900 ft).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Azure-shouldered_tanager' where nome_scientifico = 'Thraupis cyanoptera' and descrizione is null;
update specie set descrizione = 'The blue-gray tanager is a medium-sized South American songbird of the tanager family, Thraupidae. Its range is from Mexico south to northeast Bolivia and northern Brazil, all of the Amazon Basin, except the very south. It has been introduced to Lima (Peru) and Florida. On Trinidad and Tobago, this bird is called blue jean.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-gray_tanager' where nome_scientifico = 'Thraupis episcopus' and descrizione is null;
update specie set descrizione = 'The golden-chevroned tanager is a species of bird in the family Thraupidae.
It is endemic to Brazil.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Golden-chevroned_tanager' where nome_scientifico = 'Thraupis ornata' and descrizione is null;
update specie set descrizione = 'The palm tanager is a medium-sized passerine bird. This tanager is a resident breeder from Nicaragua south to Bolivia, Paraguay, and southern Brazil. It also breeds on Trinidad and, since 1962, on Tobago. In Trinidad and Tobago, it is known by colloquial names such as the "palmiste," on American Spanish countries, Brazil Pipira-verde, and the "green jean" in American English.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Palm_tanager' where nome_scientifico = 'Thraupis palmarum' and descrizione is null;
update specie set descrizione = 'The sayaca tanager is a species of bird in the family Thraupidae, the tanagers. It is a common resident in northeastern, central, and southeastern Brazil, and Bolivia, Paraguay, Uruguay, and northeastern Argentina. A few are recorded from far southeastern Peru, but its status there is unclear, in part due to the potential of confusion with the very similar juveniles of the blue-grey tanager.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sayaca_tanager' where nome_scientifico = 'Thraupis sayaca' and descrizione is null;
