update specie set descrizione = 'The Antioquia wren is a passerine from the wren family (Troglodytidae). It was discovered in March 2010 in the vicinity of the Cauca River in Antioquia, Colombia and described as a new species by Lara et al (2012). The epithet commemorates the late Marco Antonio Serna Díaz (1936–1991), a Colombian naturalist from San Vicente Ferrer, Antioquia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Antioquia_wren' where nome_scientifico = 'Thryophilus sernai' and descrizione is null;
update specie set descrizione = 'The Sinaloa wren is a species of bird in the family Troglodytidae. It is endemic to Mexico, with almost annual sightings in the United States, in Arizona.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sinaloa_wren' where nome_scientifico = 'Thryophilus sinaloa' and descrizione is null;
update specie set descrizione = 'The Carolina wren is a species of wren common in the eastern United States, the extreme south of Ontario, Canada, the northeast and southeast of Mexico, and into northern Central America. Severe winters restrict the northern limits of their range, while favorable weather conditions lead to a northward extension of their breeding range. Their preferred habitat is in dense cover in forest, farm edges, and suburban areas. This wren is the state bird of South Carolina.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Carolina_wren' where nome_scientifico = 'Thryothorus ludovicianus' and descrizione is null;
update specie set descrizione = 'The yellow-faced grassquit is a passerine bird in the tanager family Thraupidae and is the only member of the genus Tiaris. It is native to Central America, South America, and the Caribbean.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-faced_grassquit' where nome_scientifico = 'Tiaris olivaceus' and descrizione is null;
