update specie set descrizione = 'The black-tailed tityra is a medium-sized passerine bird of tropical South America. The tityras have been placed in the cotinga or the tyrant flycatcher families by various authors. But the weight of evidence strongly suggest they and their closest relatives are better separated as Tityridae; the AOU for example advocates this separation.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-tailed_tityra' where nome_scientifico = 'Tityra cayana' and descrizione is null;
