update specie set descrizione = 'The Pacific kingfisher is a medium-sized kingfisher belonging to the subfamily Halcyoninae, the tree kingfishers. It has a wide range throughout the South Pacific islands, including American Samoa, Fiji, Tonga, the Solomon Islands and Vanuatu. It was previously considered a subspecies of the collared kingfisher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pacific_kingfisher' where nome_scientifico = 'Todiramphus sacer' and descrizione is null;
update specie set descrizione = 'Il martin pescatore sacro è un uccello della famiglia Alcedinidae che vive tra le mangrovie, nelle foreste e nelle vallate fluviali di Australia, Figi, Indonesia, Nuova Caledonia, Nuova Zelanda, Isola di Norfolk, Papua Nuova Guinea, Isole Salomone e Isole di Wallis e Futuna.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Todiramphus_sanctus' where nome_scientifico = 'Todiramphus sanctus' and descrizione is null;
update specie set descrizione = 'The Torresian kingfisher is a species of bird in the family Alcedinidae. It is found in southern New Guinea and in Australia. Its natural habitats are subtropical or tropical moist lowland forests, mangroves, and plantations. It was formerly considered a subspecies of the collared kingfisher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Torresian_kingfisher' where nome_scientifico = 'Todiramphus sordidus' and descrizione is null;
update specie set descrizione = 'The Melanesian kingfisher is a species of bird in the family Alcedinidae. It is endemic to the Bismarck Archipelago and the northwest and central Solomon Islands. Its natural habitats are subtropical or tropical moist lowland forests and plantations. It was formerly considered a subspecies of the collared kingfisher.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Melanesian_kingfisher' where nome_scientifico = 'Todiramphus tristrami' and descrizione is null;
update specie set descrizione = 'The rufous-lored kingfisher, also known as Winchell''s kingfisher, is a species of bird in the kingfisher family Alcedinidae. It is endemic to the Philippines, its natural habitat consists of tropical moist lowland forests. It is threatened by deforestation, and the International Union for Conservation of Nature (IUCN) has assessed it as a vulnerable species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-lored_kingfisher' where nome_scientifico = 'Todiramphus winchelli' and descrizione is null;
