update specie set descrizione = 'The narrow-billed tody is a species of bird in the family Todidae. It is one of two Todus species endemic to Hispaniola, a Caribbean island shared by the Dominican Republic and Haiti.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Narrow-billed_tody' where nome_scientifico = 'Todus angustirostris' and descrizione is null;
update specie set descrizione = 'The Puerto Rican tody, locally known in Spanish as San Pedrito, is a bird endemic to the main island of Puerto Rico. In 2022, the tody was approved as the official national bird of Puerto Rico by the legislative assembly. However, the proposal did not advance, largely due to the scientific name of the bird which erroneously identifies it as a native of Mexico. In 2023, the assembly approved a petition to the International Commission on Zoological Nomenclature (ICZN) seeking the renaming of the tody as Todus borinquensis.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Puerto_Rican_tody' where nome_scientifico = 'Todus mexicanus' and descrizione is null;
update specie set descrizione = 'The Cuban tody is a bird species in the family Todidae that is restricted to Cuba and the adjacent islands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cuban_tody' where nome_scientifico = 'Todus multicolor' and descrizione is null;
update specie set descrizione = 'The broad-billed tody is a species of bird in the family Todidae, and one of two Todus species found on Hispaniola, along with the narrow-billed tody. They are small insectivorous birds, characterized by their bright green feathers, pink flanks and red throats.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Broad-billed_tody' where nome_scientifico = 'Todus subulatus' and descrizione is null;
