update specie set descrizione = 'The yellow-margined flatbill or Zimmer''s flatbill is a species of bird in the tyrant flycatcher family Tyrannidae. It is found in every mainland South American country except Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-margined_flatbill' where nome_scientifico = 'Tolmomyias assimilis' and descrizione is null;
update specie set descrizione = 'The ochre-lored flatbill or yellow-breasted flycatcher, is a passerine bird in the family Tyrannidae, the tyrant flycatchers. It is found in Bolivia, Brazil, Colombia, French Guiana, Guyana, Panama, Suriname, Trinidad and Tobago, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ochre-lored_flatbill' where nome_scientifico = 'Tolmomyias flaviventris' and descrizione is null;
update specie set descrizione = 'The grey-crowned flatbill or grey-crowned flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in every mainland South American country except Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-crowned_flatbill' where nome_scientifico = 'Tolmomyias poliocephalus' and descrizione is null;
update specie set descrizione = 'The yellow-olive flatbill or yellow-olive flycatcher is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Mexico, in every Central American country, on Trinidad, and in every mainland South American country except Chile.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-olive_flatbill' where nome_scientifico = 'Tolmomyias sulphurescens' and descrizione is null;
