update specie set descrizione = 'The crimson topaz is a species of hummingbird in the family Trochilidae. It is found in Brazil, French Guiana, Guyana, Suriname, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crimson_topaz' where nome_scientifico = 'Topaza pella' and descrizione is null;
update specie set descrizione = 'The fiery topaz is a species of hummingbird in the family Trochilidae. It has brilliant iridescent plumage and resides in northern South America, where it consumes nectar and insects.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fiery_topaz' where nome_scientifico = 'Topaza pyra' and descrizione is null;
update specie set descrizione = 'Il passero di Zapata, unica specie del genere Torreornis Barbour e J. L. Peters, 1927, è un uccello della famiglia dei Passerellidi originario di Cuba.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Torreornis_inexpectata' where nome_scientifico = 'Torreornis inexpectata' and descrizione is null;
update specie set descrizione = 'Il pappagallino codalilla è un uccello della famiglia degli Psittacidi. Il nome comune è indicatore di come si presenti la specie: taglia attorno ai 14 cm, cappuccio giallo-verde, petto grigio-azzurro, parti ventrali verde chiaro, dorso verde scuro sfumato in violaceo variegato di nero, ali viola-brune con banda gialla, coda viola rosata con parte terminale nera. Non c''è dimorfismo sessuale. Vive nelle foreste decidue e umide, fino ai 1700 metri di quota in Guyana, Venezuela e sull''isola di Trinidad.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Touit_batavicus' where nome_scientifico = 'Touit batavicus' and descrizione is null;
update specie set descrizione = 'Il pappagallino fronteblu è un uccello della famiglia degli Psittacidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Touit_dilectissimus' where nome_scientifico = 'Touit dilectissimus' and descrizione is null;
update specie set descrizione = 'Il pappagallino spallescarlatte è un uccello della famiglia degli Psittacidi. Caratterizzato dalle spalle rosse, con una zona rossa molto diffusa nella parte inferiore dell''ala nel maschio e verde con poco rosso nella femmina, ha piumaggio base verde, più pallido nelle parti ventrali, taglia attorno ai 16 cm, una seconda banda sulla spalla di colore blu e la parte inferiore della coda rossa nel maschio. La testa mostra una corona nero-blu appena accennata, guance azzurre e fronte e lati della testa bruni; tutte colorazioni che mancano nei soggetti immaturi, essendo tutta la zona verde. È distribuito in Colombia, Venezuela, Guyana, Ecuador e Bolivia, dove abita le foreste fino ai 1200 metri di quota.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Touit_huetii' where nome_scientifico = 'Touit huetii' and descrizione is null;
update specie set descrizione = 'Il pappagallino dorsobruno è un uccello della famiglia degli Psittacidi. Presenta taglia attorno ai 15 cm, nessun dimorfismo sessuale, colorazione generale verde con dorso e ali screziate di bruno ed evidenti segni neri su spalle e bordo ala. Le timoniere laterali sono rosse e una macchia brunastra compare nella zona periauricolare. Vive nel sud-est del Brasile, dove abita le foreste umide tra i 500 e i 1000 metri di quota e si sottopone a locali migrazioni stagionali che, occasionalmente, lo portano anche fino ai 1400 metri di altitudine.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Touit_melanonotus' where nome_scientifico = 'Touit melanonotus' and descrizione is null;
update specie set descrizione = 'Il pappagallino groppazaffiro è un uccello della famiglia degli Psittacidi. La specie presenta piumaggio generale verde intenso e taglia attorno ai 17 cm. Sono censite due sottospecie del tutto simili: T. p. purpuratus e T. p. viridiceps. Presenta fronte, corona, nuca e auchenio verde-bruni, ali verdi con copritrici brune e bordo blu, groppone blu zaffiro, coda verde con banda rossastra ai lati. Il maschio si differenzia dalla femmina per la colorazione blu più estesa sul groppone e per quella bruna più scura. Vive in Colombia, Ecuador, Perù, Brasile, Venezuela e Guyana, dove sceglie foreste fitte fino ai 1200 metri di quota.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Touit_purpuratus' where nome_scientifico = 'Touit purpuratus' and descrizione is null;
update specie set descrizione = 'Il pappagallino alimacchiate è un uccello della famiglia degli Psittacidi. Specie dalla colorazione generale verde con ali brune, picchiettate di macchie bianche nel maschio e scagliate di verde nella femmina. Ha taglia attorno ai 17 cm e vive in Colombia e Perù nelle foreste umide subtropicali, nelle savane e nelle foreste secondarie a quote che vanno dai 500 ai 2300 metri, anche se il grosso della popolazione vive tra i 1000 e i 1700 metri.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Touit_stictopterus' where nome_scientifico = 'Touit stictopterus' and descrizione is null;
update specie set descrizione = 'Il pappagallino codadorata è un uccello della famiglia degli Psittacidi. Quasi identico al pappagallino dorsobruno, ma privo del bruno dorsale e con le timoniere laterali giallo ocra; ha taglia attorno ai 16 cm ed è censito in due sottospecie: T. s. surdus, diffuso nel sud-est del Brasile; T. s. ruficauda, diffuso nel Brasile orientale. Migratore, preferisce le foreste di pianura, mai oltre gli 800 metri.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Touit_surdus' where nome_scientifico = 'Touit surdus' and descrizione is null;
update specie set descrizione = 'Il beccolungo panciagialla è un uccello passeriforme della famiglia Melanocharitidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Toxorhamphus_novaeguineae' where nome_scientifico = 'Toxorhamphus novaeguineae' and descrizione is null;
update specie set descrizione = 'The gray thrasher is a medium-sized passerine bird belonging to the family Mimidae. It is endemic to the Baja California peninsula of Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gray_thrasher' where nome_scientifico = 'Toxostoma cinereum' and descrizione is null;
update specie set descrizione = 'The crissal thrasher is a large thrasher found in the Southwestern United States to central Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Crissal_thrasher' where nome_scientifico = 'Toxostoma crissale' and descrizione is null;
update specie set descrizione = 'The curve-billed thrasher is a medium-sized mimid native to most of Mexico and to the deserts of southwestern United States. It is a non-migratory species, and throughout most of its range it is the most common desert thrasher. Several subspecies have been classified since 1827, though there is no consensus on the number. Allopatric speciation is believed to have played a major role in the variations of the curve-billed. It is grey-brown overall with a slightly curved bill, and is similar in appearance to the related Bendire''s thrasher. It generally resides in desert regions of the United States and Mexico, but can inhabit areas predominately populated by humans.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Curve-billed_thrasher' where nome_scientifico = 'Toxostoma curvirostre' and descrizione is null;
update specie set descrizione = 'The long-billed thrasher is a medium-sized resident songbird of South Texas and eastern Mexico. It bears a strong resemblance to its close relative the brown thrasher in appearance, calls, and various other behaviors; however, the two species do not overlap in range except in the winter when the brown thrasher will temporarily reside in the northern range of the long-billed.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-billed_thrasher' where nome_scientifico = 'Toxostoma longirostre' and descrizione is null;
update specie set descrizione = 'The ocellated thrasher is a species of bird in the family Mimidae. It is endemic to Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ocellated_thrasher' where nome_scientifico = 'Toxostoma ocellatum' and descrizione is null;
update specie set descrizione = 'The California thrasher is a large member of family Mimidae found primarily in chaparral habitat in California in the United States and Baja California in Mexico. It is the only species of the genus Toxostoma throughout most of its range.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/California_thrasher' where nome_scientifico = 'Toxostoma redivivum' and descrizione is null;
update specie set descrizione = 'The brown thrasher, sometimes erroneously called the brown thrush or fox-coloured thrush, is a bird in the family Mimidae, which also includes the New World catbirds and mockingbirds. The brown thrasher is abundant throughout the eastern and central United States and southern and central Canada, and it is the only thrasher to live primarily east of the Rockies and central Texas. It is the state bird of Georgia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_thrasher' where nome_scientifico = 'Toxostoma rufum' and descrizione is null;
