update specie set descrizione = 'The black-goggled tanager is a species of bird in the family Thraupidae, part of the genus Trichothraupis. It is found at low levels in forest and woodland in a large part of eastern and southern Brazil, eastern Paraguay, and far north-eastern Argentina, with a disjunct population along the East Andean slope in Peru, Bolivia, and far north-western Argentina. While generally common and widespread, and consequently considered to be of least concern by BirdLife International and IUCN, the population associated with the Andes is relatively local and uncommon.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-goggled_tanager' where nome_scientifico = 'Trichothraupis melanops' and descrizione is null;
