update specie set descrizione = 'Il piro-piro culbianco è un uccello della famiglia degli Scolopacidae dell''ordine dei Charadriiformes. È lungo circa 23 cm., con becco breve, con sovraccoda bianco candido e penne ascellari bruno cupe, striate di bianco. Tutte le rachidi delle remiganti sono scure, con timoniere bianche nella metà basale, con 3-4 fasce trasversali nere. il piumaggio presenta variazioni primaverili, con macchiettature biancastre dorsali.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tringa_ochropus' where nome_scientifico = 'Tringa ochropus' and descrizione is null;
