update specie set descrizione = 'Lo scricciolo delle case è un uccello canoro della famiglia Troglodytidae. Lo si trova dal Canada sino all''estremo Sud America, ed è il più comune scricciolo nelle aree suburbane del Nuovo Mondo.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Troglodytes_aedon' where nome_scientifico = 'Troglodytes aedon' and descrizione is null;
update specie set descrizione = 'The winter wren is a very small North American bird and a member of the mainly New World wren family Troglodytidae. The species was formerly often lumped together with Eurasian wren of Eurasia and Pacific wren of western North America under the merged name of northern wren, until they were split in 2010.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Winter_wren' where nome_scientifico = 'Troglodytes hiemalis' and descrizione is null;
update specie set descrizione = 'The ochraceous wren is a small songbird of the wren family. It is a resident breeding species in Costa Rica, Panama, and Colombia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ochraceous_wren' where nome_scientifico = 'Troglodytes ochraceus' and descrizione is null;
update specie set descrizione = 'The Pacific wren is a very small North American bird and a member of the mainly New World wren family Troglodytidae. The species was formerly lumped together with either the winter wren of eastern North America alone, or also with the Eurasian wren of Eurasia, then under the merged name of northern wren with the scientific name T. troglodytes having priority.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pacific_wren' where nome_scientifico = 'Troglodytes pacificus' and descrizione is null;
