update specie set descrizione = 'Lo scricciolo comune, detto anche reattino, è un uccello passeriforme della famiglia Troglodytidae, comune in Nord America, Europa, Nordafrica e Asia.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Troglodytes_troglodytes' where nome_scientifico = 'Troglodytes troglodytes' and descrizione is null;
update specie set descrizione = 'The gartered violaceous trogon, also known as the northern violaceous trogon, is a bird in the family Trogonidae, the quetzals and trogons. It is found in Mexico, all of Central America, and Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gartered_trogon' where nome_scientifico = 'Trogon caligatus' and descrizione is null;
update specie set descrizione = 'The white-tailed trogon is a species of bird in the trogon family. It is found in tropical humid forests of the Chocó, ranging from Panama, through western Colombia, to western Ecuador. It was formerly considered a subspecies of T. viridis, which is widespread in South America east of the Andes, but under the English name white-tailed trogon.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-tailed_trogon' where nome_scientifico = 'Trogon chionurus' and descrizione is null;
update specie set descrizione = 'The citreoline trogon is a species of bird in the family Trogonidae. It is endemic to western Mexico, with an estimated distribution size of 539,000 km2 Due to this very large range, the IUCN consider it a species of Least Concern and that the current population trend is stable. T. citreolus has also been studied as an Ecosystem engineer.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Citreoline_trogon' where nome_scientifico = 'Trogon citreolus' and descrizione is null;
