update specie set descrizione = 'The Ecuadorian trogon is a species of bird in the family Trogonidae, the quetzals and trogons. It is found in Ecuador and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ecuadorian_trogon' where nome_scientifico = 'Trogon mesurus' and descrizione is null;
update specie set descrizione = 'The mountain trogon, also known as the Mexican trogon, is a species of bird in the family Trogonidae. First described by William Swainson in 1827, it is resident in Guatemala, Honduras, and Mexico and has occurred in El Salvador as a vagrant. Like all trogons, the mountain trogon is sexually dimorphic. The male is metallic green on the crown, nape, upperparts and chest, the latter separated from its bright red belly and vent by a narrow band of white. The female is warm brown on the head, upperparts and chest, separated from its paler brown lower chest and red belly and vent by a narrow white band.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Mountain_trogon' where nome_scientifico = 'Trogon mexicanus' and descrizione is null;
update specie set descrizione = 'The masked trogon is a species of bird in the family Trogonidae. It is fairly common in humid highland forests in South America, mainly the Andes and tepuis, and is resident in Bolivia, Brazil, Colombia, Ecuador, Guyana, Peru and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Masked_trogon' where nome_scientifico = 'Trogon personatus' and descrizione is null;
update specie set descrizione = 'The Amazonian trogon, is a species of bird in the family Trogonidae, the trogons and quetzals. It is found in Bolivia, Brazil, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Amazonian_trogon' where nome_scientifico = 'Trogon ramonianus' and descrizione is null;
update specie set descrizione = 'The Amazonian black-throated trogon is a bird in the family Trogonidae, the trogons and quetzals. Although it has also been called "yellow-bellied trogon" it is not the only trogon with a yellow belly. It is found in every mainland South American country except Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Amazonian_black-throated_trogon' where nome_scientifico = 'Trogon rufus' and descrizione is null;
update specie set descrizione = 'The Surucua trogon is a species of bird in the family Trogonidae, the quetzals and trogons. It is found in Argentina, Brazil, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Surucua_trogon' where nome_scientifico = 'Trogon surrucura' and descrizione is null;
update specie set descrizione = 'The Guianan trogon, is a species of bird in the trogon and quetzal family Trogonidae. It is found in Brazil, French Guiana, Guyana, Suriname, Trinidad, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Guianan_trogon' where nome_scientifico = 'Trogon violaceus' and descrizione is null;
update specie set descrizione = 'The green-backed trogon, also known as the Amazonian white-tailed trogon, is a bird in the trogon family Trogonidae. It is widely distributed across the Amazon rainforest with a disjunct population on the southeast coast of Brazil. As with all trogons, this species is sexually dimorphic. The male has a yellow belly without a white breastband, a blue head with a pale-blue orbital eye-ring, a blue bill, a green back and a green tail that is mostly white below. The female is duller with a dark grey head, a dark grey back and some black barring beneath the tail.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-backed_trogon' where nome_scientifico = 'Trogon viridis' and descrizione is null;
update specie set descrizione = 'The green-legged partridge, also known as the scaly-breasted partridge or green-legged hill-partridge, is a bird species in the family Phasianidae. It is found in forest in Indochina, ranging slightly into southernmost China (Yunnan). The Vietnam partridge is now usually considered a subspecies.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Green-legged_partridge' where nome_scientifico = 'Tropicoperdix chloropus' and descrizione is null;
