update specie set descrizione = 'The ochre-crowned greenlet is a species of bird in the family Vireonidae, the vireos, greenlets, and shrike-babblers. It is found in Mexico, every Central American country except El Salvador, and western Colombia. This species was formerly known as the tawny-crowned greenlet and was considered to be conspecific with the Para greenlet, Guianan greenlet and rufous-fronted greenlet.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Ochre-crowned_greenlet' where nome_scientifico = 'Tunchiornis ochraceiceps' and descrizione is null;
