update specie set descrizione = 'The brown babbler is a species of bird in the family Leiothrichidae. It is predominantly found in West Africa, but ranging from the Gambia to Kenya. The species is common across its range. The species is also known as the Sudan babbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown_babbler' where nome_scientifico = 'Turdoides plebejus' and descrizione is null;
