update specie set descrizione = 'The black-lored babbler or Sharpe''s pied-babbler is a species of bird in the family Leiothrichidae. It is found in southwestern Kenya, Tanzania, Uganda, Burundi, Rwanda, and the part of the Democratic Republic of the Congo immediately adjacent to the three last-named countries. This bird was formerly considered the same species as Turdoides melanops of southern Africa, now known as the black-faced babbler.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-lored_babbler' where nome_scientifico = 'Turdoides sharpei' and descrizione is null;
update specie set descrizione = 'The Abyssinian thrush is a passerine bird in the family Turdidae. It is also known as the African mountain thrush, or northern olive thrush The species was formerly treated as conspecific with the olive thrush but the species were split based on the genetic differences. The ranges do not overlap. The Abyssinian thrush is native to the eastern Afromontane.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Abyssinian_thrush' where nome_scientifico = 'Turdus abyssinicus' and descrizione is null;
update specie set descrizione = 'The white-necked thrush is a species of bird in the family Turdidae. It is found on Trinidad and Tobago and in every mainland South American country except Chile. It previously was called the white-necked robin.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-necked_thrush' where nome_scientifico = 'Turdus albicollis' and descrizione is null;
update specie set descrizione = 'The white-collared blackbird is a species of bird in the family Turdidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-collared_blackbird' where nome_scientifico = 'Turdus albocinctus' and descrizione is null;
update specie set descrizione = 'The creamy-bellied thrush is a species of bird in the family Turdidae. It is found in Argentina, Bolivia, Brazil, Paraguay, Peru, Uruguay, and as a vagrant to Chile and the Falkland Islands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Creamy-bellied_thrush' where nome_scientifico = 'Turdus amaurochalinus' and descrizione is null;
update specie set descrizione = 'The white-throated thrush is a species of bird in the family Turdidae. It is found in Mexico and Central America. It also has strayed to the southwestern United States. It previously was called the white-throated robin, a name also used for the Old World species Irania gutturalis.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_thrush' where nome_scientifico = 'Turdus assimilis' and descrizione is null;
update specie set descrizione = 'The black-throated thrush is a passerine bird in the thrush family. It is sometimes regarded as one subspecies of a polytypic species, "dark-throated thrush", red-throated thrush then being the other subspecies. More recent treatments regard the two as separate species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-throated_thrush' where nome_scientifico = 'Turdus atrogularis' and descrizione is null;
update specie set descrizione = 'The white-chinned thrush, known in Jamaica as the hopping dick is a species of bird in the family Turdidae. It is endemic to Jamaica where it is common and widespread. Its natural habitats are subtropical or tropical moist lowland forests, subtropical or tropical moist montane forests, and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-chinned_thrush' where nome_scientifico = 'Turdus aurantius' and descrizione is null;
update specie set descrizione = 'Il merlo aligrigie è un uccello della famiglia dei Turdidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Turdus_boulboul' where nome_scientifico = 'Turdus boulboul' and descrizione is null;
update specie set descrizione = 'The Japanese thrush is a species of bird in the thrush family Turdidae. The species is also known as the grey thrush or the Japanese grey thrush. The species was once split into two subspecies, with birds breeding in China being treated as the subspecies T. c. lateus,, but today differences are attributed to natural variation and the species is treated as being monotypic.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Japanese_thrush' where nome_scientifico = 'Turdus cardis' and descrizione is null;
update specie set descrizione = 'The Izu thrush or Izu Islands thrush is a bird of the thrush family native to Japan.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Izu_thrush' where nome_scientifico = 'Turdus celaenops' and descrizione is null;
update specie set descrizione = 'The Chiguanco thrush is a species of bird in the family Turdidae. It is found from Ecuador south to Argentina.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chiguanco_thrush' where nome_scientifico = 'Turdus chiguanco' and descrizione is null;
update specie set descrizione = 'The brown-headed thrush, sometimes known as the brown thrush, is a species of bird in the family Turdidae. It breeds in Sakhalin, the Kuril Islands and Japan; it winters in south toward the Ryukyu Islands, Taiwan, Hainan and the northern Philippines. Its natural habitat is temperate forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-headed_thrush' where nome_scientifico = 'Turdus chrysolaus' and descrizione is null;
update specie set descrizione = 'The black-breasted thrush is a species of bird in the family Turdidae. It is found from north-eastern India to northern Vietnam. Although both male and female birds have the same colour on their lower parts, the upper section of males is mostly black in colour, while females are mostly grey-brown. Thus, the bird''s common name refers to the colour of the male bird''s breast. They tend to live in forests located at high altitude.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-breasted_thrush' where nome_scientifico = 'Turdus dissimilis' and descrizione is null;
update specie set descrizione = 'The dusky thrush is a member of the thrush family which breeds eastwards from central Siberia to Kamchatka wintering in Korea, Japan, South China and Myanmar. It is closely related to the more southerly breeding Naumann''s thrush T. naumanni; the two have often been regarded as conspecific. The scientific name comes from Latin Turdus, "thrush" and Ancient Greek eunomos, "orderly".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Dusky_thrush' where nome_scientifico = 'Turdus eunomus' and descrizione is null;
update specie set descrizione = 'Il tordo australe è un uccello della famiglia dei Turdidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Turdus_falcklandii' where nome_scientifico = 'Turdus falcklandii' and descrizione is null;
update specie set descrizione = 'The grey-sided thrush is a species of bird in the thrush family, Turdidae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-sided_thrush' where nome_scientifico = 'Turdus feae' and descrizione is null;
update specie set descrizione = 'The yellow-legged thrush is a species of bird in the family Turdidae. It is found in Argentina, Brazil, Colombia, Guyana, Trinidad and Tobago, and Venezuela. It formerly occurred in Paraguay and has been recorded as a vagrant in Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-legged_thrush' where nome_scientifico = 'Turdus flavipes' and descrizione is null;
update specie set descrizione = 'The chestnut-bellied thrush is a species of bird in the family Turdidae. It is found in Colombia, Ecuador, Peru, and Venezuela. Its natural habitats are subtropical or tropical moist montane forests and heavily degraded former forest.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut-bellied_thrush' where nome_scientifico = 'Turdus fulviventris' and descrizione is null;
update specie set descrizione = 'Il tordo del cacao è un tordo riproduttore residente in Sud America, dal sud-est della Colombia fino al Brasile centrale e orientale, così come sull''isola caraibica di Trinidad e in alcune delle Piccole Antille.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Turdus_fumigatus' where nome_scientifico = 'Turdus fumigatus' and descrizione is null;
update specie set descrizione = 'The great thrush is a species of bird in the family Turdidae. It is found in Bolivia, Colombia, Ecuador, Peru, and Venezuela. It is considered as the largest thrush in South America. The great thrush''s size distinguishes it from the several other uniform slaty-colored thrushes in its range. It inhabits subtropical or tropical moist montane forests and high-altitude shrubland, but can also make use of degraded forest and urban areas.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Great_thrush' where nome_scientifico = 'Turdus fuscater' and descrizione is null;
update specie set descrizione = 'The clay-colored thrush is a common Middle American bird of the thrush family (Turdidae). It is the national bird of Costa Rica, where it is well known as the yigüirro. Other common names include clay-colored robin.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Clay-colored_thrush' where nome_scientifico = 'Turdus grayi' and descrizione is null;
update specie set descrizione = 'The grey-backed thrush is a species of bird in the family Turdidae. It breeds in northeastern China and the Russian Far East and winters in southern China and northern Vietnam. Its natural habitat is temperate forests. A captive bred pair laid five eggs, which hatched 14 days after the first egg was laid. The young left the nest 12 days later.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-backed_thrush' where nome_scientifico = 'Turdus hortulorum' and descrizione is null;
update specie set descrizione = 'The black-billed thrush is a species of bird in the family Turdidae. It is found in Bolivia, Brazil, Colombia, Ecuador, Peru, and Venezuela.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-billed_thrush' where nome_scientifico = 'Turdus ignobilis' and descrizione is null;
update specie set descrizione = 'Il tordo sassello è un uccello della famiglia dei Turdidi.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Turdus_iliacus' where nome_scientifico = 'Turdus iliacus' and descrizione is null;
update specie set descrizione = 'The black thrush is a species of bird in the family Turdidae, the thrushes and allies. It is found in El Salvador, Guatemala, Honduras, and Mexico. It was formerly known as the black robin.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black_thrush' where nome_scientifico = 'Turdus infuscatus' and descrizione is null;
