update specie set descrizione = 'The African thrush or West African thrush is a passerine bird in the thrush family Turdidae. It is common in well-wooded areas over much of the western part of sub-Saharan Africa, it was once considered to be conspecific with the olive thrush but that species has now been split further. Populations are resident (non-migratory).', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/African_thrush' where nome_scientifico = 'Turdus pelios' and descrizione is null;
