update specie set descrizione = 'The Western red-legged thrush is a species of bird in the family Turdidae. Native to the Caribbean, it is found in the Bahamas, Cayman Islands, and Cuba. It formerly occurred on the Swan Islands, Honduras, but was extirpated there.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_red-legged_thrush' where nome_scientifico = 'Turdus plumbeus' and descrizione is null;
update specie set descrizione = 'The Tasman Sea island thrush is an extinct forest bird in the thrush family that was formerly found on Lord Howe Island and Norfolk Island in the Pacific Ocean. It is part of the "island thrush" complex that has been split into 17 species based on a molecular phylogenetic study published in 2023. The two subspecies of the Tasman Sea island thrush became extinct in historical times.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tasman_Sea_island_thrush' where nome_scientifico = 'Turdus poliocephalus' and descrizione is null;
