update specie set descrizione = 'The chestnut thrush is a species of bird in the family Turdidae. It breeds in the western Himalayas and central/southwestern China; it winters in Eastern Himalaya and northern Southeast Asia. Its natural habitat is temperate forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chestnut_thrush' where nome_scientifico = 'Turdus rubrocanus' and descrizione is null;
update specie set descrizione = 'Il tordo golarossa è un uccello della famiglia dei turdidi. A volte viene considerato come una sottospecie di Turdus atrogularis. Studi più recenti considerano le due specie separate. Il nome scientifico deriva dal latino Turdus "tordo" e ruficollis deriva da rufus, "rosso", e collum, "collo".', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Turdus_ruficollis' where nome_scientifico = 'Turdus ruficollis' and descrizione is null;
