update specie set descrizione = 'The Indian blackbird is a member of the thrush family Turdidae. It was formerly considered a subspecies of the common blackbird. It is found only in India and Sri Lanka. The subspecies from most of the Indian subcontinent, simillimus, nigropileus, bourdilloni and spencei, are small, only 19–20 centimetres long, and have broad eye-rings. They also differ in proportions, wing formula, egg colour and voice from the common blackbird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Indian_blackbird' where nome_scientifico = 'Turdus simillimus' and descrizione is null;
update specie set descrizione = 'The Karoo thrush, also known as Smith''s thrush, is a member of the thrush family in Africa. It has traditionally been considered a subspecies of the olive thrush, but is increasingly treated as a separate species. The specific name honours the Scottish military surgeon and zoologist Sir Andrew Smith.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Karoo_thrush' where nome_scientifico = 'Turdus smithi' and descrizione is null;
