update specie set descrizione = 'The sulphury flycatcher is a passerine bird of the family Tyrannidae, the tyrant flycatchers. It is found on Trinidad and in every mainland South American country except Argentina, Chile, Paraguay, and Uruguay.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sulphury_flycatcher' where nome_scientifico = 'Tyrannopsis sulphurea' and descrizione is null;
update specie set descrizione = 'Il tiranno piccolo corona gialla è un uccello passeriforme della famiglia Tyrannidae.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Tyrannulus_elatus' where nome_scientifico = 'Tyrannulus elatus' and descrizione is null;
update specie set descrizione = 'The white-throated kingbird is a species of bird in the family Tyrannidae, the tyrant flycatchers.
It is found in Bolivia, Brazil, Ecuador, Guyana, Peru, Suriname, and Venezuela, in French Guiana as a vagrant, and possibly in Argentina and Colombia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-throated_kingbird' where nome_scientifico = 'Tyrannus albogularis' and descrizione is null;
update specie set descrizione = 'The loggerhead kingbird is a species of sub-oscine passerine bird belonging to the family Tyrannidae, the tyrant flycatchers. This species is found in wooded habitats in the islands of the northern Caribbean, with records of vagrants from Florida.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Loggerhead_kingbird' where nome_scientifico = 'Tyrannus caudifasciatus' and descrizione is null;
update specie set descrizione = 'The thick-billed kingbird is a large member of the family Tyrannidae, the tyrant flycatchers. It is found in the southwestern United States, Mexico, and Guatemala.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Thick-billed_kingbird' where nome_scientifico = 'Tyrannus crassirostris' and descrizione is null;
update specie set descrizione = 'The gray kingbird or grey kingbird, also known as pitirre, petchary or white-breasted kingbird, is a passerine bird in the tyrant flycatchers family Tyrannidae. The species was first described on the island of Hispaniola, then called Santo Domingo, thus the dominicensis name.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Gray_kingbird' where nome_scientifico = 'Tyrannus dominicensis' and descrizione is null;
update specie set descrizione = 'The scissor-tailed flycatcher, known as swallow-tailed flycatcher or scissorstail, is a long-tailed insectivorous bird of the genus Tyrannus, whose members are collectively referred to as kingbirds. It is found in North and Central America, and is Oklahoma''s State Bird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Scissor-tailed_flycatcher' where nome_scientifico = 'Tyrannus forficatus' and descrizione is null;
update specie set descrizione = 'The tropical kingbird is a large tyrant flycatcher. This bird breeds from southern Arizona and the lower Rio Grande Valley of Texas in the United States through Central America, South America as far as south as central Argentina and eastern Peru, and on Trinidad and Tobago. Birds from the northernmost and southern breeding areas migrate to warmer parts of the range after breeding.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Tropical_kingbird' where nome_scientifico = 'Tyrannus melancholicus' and descrizione is null;
update specie set descrizione = 'The snowy-throated kingbird is a species of bird in the family Tyrannidae, the tyrant flycatchers. It is found in Colombia, Ecuador, and Peru.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Snowy-throated_kingbird' where nome_scientifico = 'Tyrannus niveigularis' and descrizione is null;
update specie set descrizione = 'The fork-tailed flycatcher is a passerine bird of the tyrant flycatcher family and is a member of a genus typically referred to as kingbirds. Named for the long, forked tail, particularly in males, fork-tailed flycatchers are seen in shrubland, savanna, lightly forested and grassland areas, from southern Mexico to Argentina. They are frequently observed on conspicuous perches whence they sally after insect prey. Northern populations near southern Mexico tend to be permanent residents, while fork-tailed flycatchers that live further south are migrants with a reputation for wandering as far north as New Brunswick, Canada.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Fork-tailed_flycatcher' where nome_scientifico = 'Tyrannus savana' and descrizione is null;
update specie set descrizione = 'The eastern kingbird is a large tyrant flycatcher native to the Americas. The bird is predominantly dark gray with white underbelly and pointed wings. Eastern kingbirds are conspicuous and are commonly found in open areas with scattered trees and bushes, where they perch while foraging for insects. The Eastern kingbird is migratory, with its breeding range spread across North America and its wintering range in Central and South America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Eastern_kingbird' where nome_scientifico = 'Tyrannus tyrannus' and descrizione is null;
update specie set descrizione = 'The western kingbird is a large tyrant flycatcher found throughout western North America, as far south as Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_kingbird' where nome_scientifico = 'Tyrannus verticalis' and descrizione is null;
update specie set descrizione = 'The western barn owl is a species of barn owl native to Europe, southwestern Asia, and Africa. It was formerly considered a subspecies group together with barn owls native to other parts of the world, but this classification was found to be paraphyletic with respect to some other members of the genus.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Western_barn_owl' where nome_scientifico = 'Tyto alba' and descrizione is null;
