update specie set descrizione = 'The blue-naped mousebird, also formerly called the blue-naped coly is a species of bird belonging to the family Coliidae within the order Coliiformes. They are the sister group to the clade Eucavitaves, which contains the families Leptosomiformes, Trogoniformes (trogons), Bucerotiformes, Piciformes and Coraciformes.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-naped_mousebird' where nome_scientifico = 'Urocolius macrourus' and descrizione is null;
update specie set descrizione = 'The long-tailed koel, also known as the long-tailed cuckoo, Pacific long-tailed cuckoo, sparrow hawk, home owl, screecher, screamer or koekoeā in Māori, is a species of the Cuculidae bird family. It is the only species placed in the genus Urodynamis. It is a migratory bird that spends spring and summer in New Zealand, its only breeding place, and spends winter in the Pacific islands. It is a brood parasite, laying its eggs in the nests of other bird species and leaving them to raise its chicks.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Long-tailed_koel' where nome_scientifico = 'Urodynamis taitensis' and descrizione is null;
