update specie set descrizione = 'The pale-footed bush warbler is a species of oriental warbler in the family Cettiidae that is found in southern Asia. It occurs in the Himalayan region west from Dehradun through the foothills of Nepal to northeastern India. It also occurs in Myanmar, Laos, northern Vietnam and southern China. A single sighting was recorded from Kandy, Sri Lanka in March 1993.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pale-footed_bush_warbler' where nome_scientifico = 'Urosphena pallidipes' and descrizione is null;
