update specie set descrizione = 'The Timor stubtail is a species of bird in the family Cettiidae. It is found on Timor and northern and eastern adjacent islands.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Timor_stubtail' where nome_scientifico = 'Urosphena subulata' and descrizione is null;
update specie set descrizione = 'The Bornean stubtail is a species of bird in the cettiid warbler family Cettiidae. It is endemic to the island of Borneo, where it inhabits forest floors and undergrowth in montane forests at elevations of 750–3,150 m (2,460–10,330 ft). It is a small, short-tailed warbler, measuring 9.5–10 cm (3.7–3.9 in) in length and having an average mass of 10.4 g (0.37 oz). The tops of the head and the upperparts are brown, with whitish underparts that turn grey at the sides of the breast and the flanks. The supercilium is long and buffish-brown, with an equally long dark grey eyestripe and a thin yellow eye-ring. Both sexes are similar.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bornean_stubtail' where nome_scientifico = 'Urosphena whiteheadi' and descrizione is null;
update specie set descrizione = 'The black-backed bush tanager, also known as the black-backed bush-finch, is a species of bird in the family Thraupidae. It is the only member in the genus Urothraupis. It is found in Colombia and Ecuador. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-backed_bush_tanager' where nome_scientifico = 'Urothraupis stolzmanni' and descrizione is null;
