update specie set descrizione = 'The yellow-wattled lapwing is a lapwing that is endemic to the Indian subcontinent. It is found mainly on the dry plains of peninsular India and has a sharp call and is capable of fast flight. Although they do not migrate, they are known to make seasonal movements in response to rains. They are dull grey brown with a black cap, yellow legs and a triangular wattle at the base of the beak. Like other lapwings and plovers, they are ground birds and their nest is a mere collection of tiny pebbles within which their well camouflaged eggs are laid. The chicks are nidifugous, leaving the nest shortly after hatching and following their parents to forage for food.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-wattled_lapwing' where nome_scientifico = 'Vanellus malabaricus' and descrizione is null;
update specie set descrizione = 'The spot-breasted lapwing, also known as the spot-breasted plover, is a species of bird in the family Charadriidae. It is endemic to the Ethiopian Highlands. There are no known subspecies of the bird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Spot-breasted_lapwing' where nome_scientifico = 'Vanellus melanocephalus' and descrizione is null;
update specie set descrizione = 'The black-winged lapwing. black-winged plover or greater black-winged lapwing is an east African species that is found from the Ethiopian highlands in the north to central Kenya, and again at middle to coastal elevations in eastern South Africa. It is a habitat specialist of short grass in well-watered temperate grasslands. They may move about locally to find ideal situations, often at night. In their tightly grouped flying flocks they resemble plovers.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-winged_lapwing' where nome_scientifico = 'Vanellus melanopterus' and descrizione is null;
update specie set descrizione = 'The masked lapwing is a large, common and conspicuous bird native to Australia, New Zealand and New Guinea. It spends most of its time on the ground searching for food such as insects and worms and has several distinctive calls. It is common in Australian fields, open land and where there is lots of water, and is known for its defensive swooping behaviour during the nesting season.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Masked_lapwing' where nome_scientifico = 'Vanellus miles' and descrizione is null;
