update specie set descrizione = 'La pavoncella è un uccello di media grandezza diffuso in buona parte dell''Europa. Frequenta le pianure, i vasti territori coltivati a campi e zone parzialmente umide, ma la si incontra anche nei pascoli, fino a quote medio alte, nella stagione invernale e durante il passo. L''habitat, molto vasto, comprende l''Eurasia settentrionale, il Giappone e il Nordafrica. Particolarmente comune nei Paesi Bassi dove nidifica in gran numero. Si riproduce normalmente nell''Europa centrale e orientale, mentre sverna nell''Europa occidentale e meridionale ed in Nordafrica.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Vanellus_vanellus' where nome_scientifico = 'Vanellus vanellus' and descrizione is null;
update specie set descrizione = 'Il vanga dal becco uncinato è un uccello passeriforme della famiglia Vangidae, endemico del Madagascar. È l''unica specie del genere Vanga.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Vanga_curvirostris' where nome_scientifico = 'Vanga curvirostris' and descrizione is null;
update specie set descrizione = 'La parula alidorate è un parulide. Nidifica nel Canada sud-orientale e centro-meridionale e negli Stati Uniti nord-orientali, dalla regione dei monti Appalachi fino alla zona centro-settentrionale del Paese. La maggior parte della popolazione globale nidifica in Wisconsin, Minnesota e Manitoba. Le popolazioni di parula alidorate stanno lentamente espandendosi verso nord, ma in generale stanno diminuendo in tutto il loro areale, più probabilmente a causa della perdita dell''habitat e della competizione e/o inincrocio con un parente molto stretto, la parula aliazzurre.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Vermivora_chrysoptera' where nome_scientifico = 'Vermivora chrysoptera' and descrizione is null;
