update specie set descrizione = 'The black-whiskered vireo is a small passerine bird in the family Vireonidae, the vireos, greenlets, and shrike-babblers. It is found in Florida, the Bahamas, many Caribbean islands, and northern and Amazonian South America.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-whiskered_vireo' where nome_scientifico = 'Vireo altiloquus' and descrizione is null;
update specie set descrizione = 'The black-capped vireo is a small bird native to the United States and Mexico. It was listed as an endangered species in the United States in 1987. It is the only Vireo that is sexually dichromatic. Recovery of the species'' population contributed to its delisting in 2018. The IUCN lists the species as "near threatened."', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-capped_vireo' where nome_scientifico = 'Vireo atricapilla' and descrizione is null;
update specie set descrizione = 'The Cozumel vireo is a Near Threatened species of bird in the family Vireonidae, the vireos, greenlets, and shrike-babblers. It is endemic to the Mexican island of Cozumel off the Yucatán Peninsula.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cozumel_vireo' where nome_scientifico = 'Vireo bairdi' and descrizione is null;
update specie set descrizione = 'The slaty vireo is a species of bird in the family Vireonidae, the vireos, greenlets, and shrike-babblers. It is endemic to Mexico.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Slaty_vireo' where nome_scientifico = 'Vireo brevipennis' and descrizione is null;
update specie set descrizione = 'The yellow-winged vireo, or Carmiol''s vireo, is a small passerine bird in the family Vireonidae, the vireos, greenlets, and shrike-babblers. It is found in Costa Rica and Panama.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-winged_vireo' where nome_scientifico = 'Vireo carmioli' and descrizione is null;
update specie set descrizione = 'The chivi vireo is a small South American songbird in the family Vireonidae. It was formerly considered a subspecies of the red-eyed vireo. It is usually green to yellow-green in color with off-white underparts, and a gray crown. It has a whitish supercilium extending over its ear coverts, and its lores are dull gray in color. The chivi vireo has nine subspecies. It is found throughout most of northern, eastern and central South America, only being absent from southern Chile and southern Argentina. It inhabits multiple types of habitat across its range, and appears to adjust well to slightly disturbed habitat. The chivi vireo is mainly resident, but at least two of the subspecies inhabiting the south of its range are known to be migratory.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Chivi_vireo' where nome_scientifico = 'Vireo chivi' and descrizione is null;
update specie set descrizione = 'The thick-billed vireo is a species of bird in the family Vireonidae, the vireos, greenlets, and shrike-babblers. It is found on many islands of the West Indies and as an occasional vagrant to south Florida in the United States.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Thick-billed_vireo' where nome_scientifico = 'Vireo crassirostris' and descrizione is null;
update specie set descrizione = 'The yellow-throated vireo is a small American songbird.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-throated_vireo' where nome_scientifico = 'Vireo flavifrons' and descrizione is null;
update specie set descrizione = 'The yellow-green vireo is a small American passerine bird. It is migratory breeding from Mexico to Panama and wintering in the northern and eastern Andes and the western Amazon Basin.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Yellow-green_vireo' where nome_scientifico = 'Vireo flavoviridis' and descrizione is null;
