update specie set descrizione = 'The Philadelphia vireo is a small North American songbird in the vireo family (Vireonidae). "Vireo" is a Latin word referring to a green migratory bird, perhaps the female golden oriole, possibly the European greenfinch. The specific philadelphicus is for the city of Philadelphia.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Philadelphia_vireo' where nome_scientifico = 'Vireo philadelphicus' and descrizione is null;
