update specie set descrizione = 'The blue-black grassquit is a small Neotropical bird in the tanager family, Thraupidae. It is the only member of the genus Volatinia. It is a common and widespread bird that breeds from southern Mexico through Central America, and South America as far as northern Chile, Argentina, and Paraguay, and in Trinidad and Tobago. A male was also observed in Graham County, Arizona, on July 15 and July 17, 2023.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Blue-black_grassquit' where nome_scientifico = 'Volatinia jacarina' and descrizione is null;
