update specie set descrizione = 'The white-naped xenopsaris, also known as the reed becard and white-naped becard, is a species of suboscine bird in the family Tityridae, the only member of the genus Xenopsaris. It is found in South America, in humid subtropical and tropical savanna climates in most of the countries east of the Andes: Venezuela, Brazil, Bolivia, Paraguay, Uruguay, and Argentina. Living in open woodland and other open forest habitats, it is mostly sedentary, though some populations may be migratory. The species, which is closely related to becards and tityras, was thought to be either a tyrant-flycatcher or cotinga, before it was placed in Tityridae.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-naped_xenopsaris' where nome_scientifico = 'Xenopsaris albinucha' and descrizione is null;
