update specie set descrizione = 'The Cuban green woodpecker is a species of woodpecker in the family Picidae and tribe Melanerpini, known locally in Cuban Spanish as carpintero verde. It is the only species within the genus Xiphidiopicus and is one of two woodpeckers endemic to Cuba. It is the most widespread and common woodpecker in Cuba, inhabiting primarily woodlands, as well as dry and wet forests, pine forests and mangroves. The population of the Cuban green woodpecker is stable and its status is listed as "Least Concern".', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Cuban_green_woodpecker' where nome_scientifico = 'Xiphidiopicus percussus' and descrizione is null;
