update specie set descrizione = 'The pompadour cotinga is a species of bird in the family Cotingidae. This species lives in the Amazonian rainforest and has a range that extends across the Amazon Basin and includes Brazil, Peru, Colombia, Venezuela, and the Guianas. The pompadour cotinga is primarily a frugivore but has been known to consume insects on occasion. This species of cotinga is distinct in that the males have a burgundy head and body, bright white wings, and yellow eyes. Like other members of the Cotingidae, this species is sexually dimorphic and the females have a pale grey head and body. Although there are not many documented observations of the nesting behavior of these birds, the males are known to perform elaborate mating displays for the females who then raise the young alone.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Pompadour_cotinga' where nome_scientifico = 'Xipholena punicea' and descrizione is null;
