update specie set descrizione = 'The rufous-vented yuhina is a bird species in the white-eye family Zosteropidae. It is found along the northern parts of the Indian subcontinent, primarily in the Eastern Himalayas, and ranges across Bhutan, India, Tibet, Myanmar, and Nepal. Its natural habitat is subtropical or tropical moist montane forests.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Rufous-vented_yuhina' where nome_scientifico = 'Yuhina occipitalis' and descrizione is null;
update specie set descrizione = 'The grey-capped pygmy woodpecker is an Asian bird species of the woodpecker family (Picidae). It has a subspecies, Yungipicus canicapillus doerriesi, located primarily in Manchuria, eastern Siberia, and Korea. Some taxonomic authorities continue to place this species in the genus Dendrocopos or Picoides.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Grey-capped_pygmy_woodpecker' where nome_scientifico = 'Yungipicus canicapillus' and descrizione is null;
update specie set descrizione = 'The Japanese pygmy woodpecker or simply pygmy woodpecker is a species of woodpecker. It is found in coniferous and deciduous forests in Russia, China, Korea and Japan. This species has also been placed in the genus Dendrocopos or Picoides. The International Union for Conservation of Nature (IUCN) has assessed it as a least-concern species.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Japanese_pygmy_woodpecker' where nome_scientifico = 'Yungipicus kizuki' and descrizione is null;
update specie set descrizione = 'The Sunda pygmy woodpecker, also known as the Sunda woodpecker, is a species of bird in the family Picidae. It is found in Brunei, Indonesia, Malaysia, and Singapore. Some taxonomic authorities continue to place this species in the genus Dendrocopos or Picoides.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Sunda_pygmy_woodpecker' where nome_scientifico = 'Yungipicus moluccensis' and descrizione is null;
update specie set descrizione = 'The brown-capped pygmy woodpecker or Indian pygmy woodpecker is a species of very small woodpecker found in Nepal, India and Sri Lanka. Some taxonomic authorities continue to place this species in the genus Dendrocopos or Picoides. This species is non-migratory and often spotted in pairs or small family groups. They are known for being very active and are not often spotted, despite their constant foraging in the tree canopy.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Brown-capped_pygmy_woodpecker' where nome_scientifico = 'Yungipicus nanus' and descrizione is null;
