update specie set descrizione = 'The zigzag heron is a species of heron in the family Ardeidae, also including egrets and bitterns. It is in the monotypic genus Zebrilus. It is found in Bolivia, Brazil, Colombia, Ecuador, French Guiana, Guyana, Peru, Suriname, and Venezuela. Its natural habitat is subtropical or tropical swamps.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Zigzag_heron' where nome_scientifico = 'Zebrilus undulatus' and descrizione is null;
