update specie set descrizione = 'The white-winged dove is a dove whose native range extends from the Southwestern United States through Mexico, Central America, and the Caribbean. They are large for doves, and can be distinguished from similar doves by the distinctive white edge on their wings. They have a blue eyering and red eyes. The plumage is brownish-gray to gray. Juveniles are duller in color and have brown eyes. The call is likened to the English phrase "who cooks for you". There are three subspecies. It was first described by George Edwards in 1743, and given its binomial name by Linnaeus in 1756. It was moved into the genus Zenaida in 1838.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/White-winged_dove' where nome_scientifico = 'Zenaida asiatica' and descrizione is null;
