update specie set descrizione = 'Il passero dal collare rossiccio è un uccello passeriforme appartenente alla famiglia dei Passerellidi; la specie è presente in una vasta varietà di habitat distribuiti tra il Messico sud-orientale e la Terra del Fuoco, oltre che nell''isola di Hispaniola. Il passero dal collare rossiccio è stato studiato fin dagli anni 1970 per l''estrema varietà dei suoi versi. La specie è nota anche con i nomi comuni tico-tico, chingolo, copetón e comemaíz.', descrizione_fonte = 'Wikipedia (it)', descrizione_url = 'https://it.wikipedia.org/wiki/Zonotrichia_capensis' where nome_scientifico = 'Zonotrichia capensis' and descrizione is null;
