update specie set descrizione = 'The Bassian thrush, also known as the olive-tailed thrush, is a medium-sized mostly insectivorous thrush found from northern Queensland to southeastern Australia. It also occurs in Tasmania, on some larger islands of Bass Strait, and on Kangaroo Island. The thrushes range from 27 to 29 cm in length and average 100 g (3.5 oz) in weight.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Bassian_thrush' where nome_scientifico = 'Zoothera lunulata' and descrizione is null;
