update specie set descrizione = 'The black-crowned white-eye is a songbird species. It is closely related to the Old World babblers, and its family Zosteropidae might better be included in the Tiimalidae. Its subspecies from the Sulawesi region might warrant recognition as distinct species Z. subatrifrons. The Sangihe white-eye and the Seram white-eye were formerly included in Z. atrifrons, as is still, on occasion, the black-fronted white-eye.', descrizione_fonte = 'Wikipedia (en)', descrizione_url = 'https://en.wikipedia.org/wiki/Black-crowned_white-eye' where nome_scientifico = 'Zosterops atrifrons' and descrizione is null;
